        let accdesc : AccessDescriptor = CreateAccDescExLDST(MemOp_LOAD, acqrel, tagchecked,
                                                                privileged);
        return Mem_with_type{size}(address, accdesc);
    end;

    setter
        let acqrel : boolean = FALSE;
        let privileged : boolean = PSTATE.EL != EL0;
        let tagchecked : boolean = FALSE;
        let accdesc : AccessDescriptor = CreateAccDescExLDST(MemOp_STORE, acqrel, tagchecked,
                                                                privileged);
        Mem_with_type{size}(address, accdesc) = value;
