end;

// MemU_unpriv
// ===========

accessor MemU_unpriv{size : integer{8, 16, 32, 64}}(address : bits(32)) <=> value : bits(size)
begin
    getter
        let nontemporal : boolean = FALSE;
        let privileged : boolean  = FALSE;
        let tagchecked : boolean  = FALSE;
        let accdesc : AccessDescriptor = CreateAccDescGPR(MemOp_LOAD, nontemporal, privileged,
                                                            tagchecked);
        return Mem_with_type{size}(address, accdesc);
    end;

    setter
        let nontemporal : boolean = FALSE;
        let privileged : boolean  = FALSE;
        let tagchecked : boolean  = FALSE;
        let accdesc : AccessDescriptor = CreateAccDescGPR(MemOp_STORE, nontemporal, privileged,
                                                          tagchecked);
        Mem_with_type{size}(address, accdesc) = value;
    end;
end;

// Mem_with_type
// =============

accessor Mem_with_type{size : integer{8, 16, 32, 64}}(address : bits(32),
                                                      accdesc_in : AccessDescriptor
                                                     ) <=> value_in : bits(size)
begin
    // Perform a read of 'size' bits. The access byte order is reversed for a big-endian access.
    // Instruction fetches would call AArch32_MemSingle directly.
    getter
        let bytes : integer{} = size DIV 8;
        var accdesc : AccessDescriptor = accdesc_in;
        var value : bits(size);
        // Check alignment on size of element accessed, not overall access size
        let alignment : integer{} = if accdesc.ispair then bytes DIV 2 else bytes;
        var aligned : boolean     = IsAlignedSize(address, alignment);

        if !aligned && AArch32_UnalignedAccessFaults(accdesc) then
            let fault : FaultRecord = AlignmentFault(accdesc, ZeroExtend{64}(address));
            AArch32_Abort(fault);
        end;
        if aligned then
            value = AArch32_MemSingle{size}(address, accdesc, aligned);
        else
            assert bytes > 1;
            value[7:0] = AArch32_MemSingle{8}(address, accdesc, aligned);

            // For subsequent bytes, if they cross to a new translation page which assigns
            // Device memory type, it is CONSTRAINED UNPREDICTABLE whether an unaligned access
            // will generate an Alignment Fault.
            let c : Constraint = ConstrainUnpredictable(Unpredictable_DEVPAGE2);
            assert c IN {Constraint_FAULT, Constraint_NONE};
            if c == Constraint_NONE then aligned = TRUE; end;

            for i = 1 to bytes-1 do
                value[i*:8] = AArch32_MemSingle{8}(address+i, accdesc, aligned);
            end;
        end;

        if BigEndian(accdesc.acctype) then
            value = BigEndianReverse{size}(value);
        end;

        return value;
    end;

    // Perform a write of 'size' bits. The byte order is reversed for a big-endian access.
    setter
        let bytes : integer{}          = size DIV 8;
        var value :  bits(size)        = value_in;
        var accdesc : AccessDescriptor = accdesc_in;

        // Check alignment on size of element accessed, not overall access size
        let alignment : integer{} = if accdesc.ispair then bytes DIV 2 else bytes;
        var aligned : boolean     = IsAlignedSize(address, alignment);

        if !aligned && AArch32_UnalignedAccessFaults(accdesc) then
            let fault : FaultRecord = AlignmentFault(accdesc, ZeroExtend{64}(address));
            AArch32_Abort(fault);
        end;

        if BigEndian(accdesc.acctype) then
            value = BigEndianReverse{size}(value);
        end;
        if aligned then
            AArch32_MemSingle{size}(address, accdesc, aligned) = value;
        else
            assert bytes > 1;
            AArch32_MemSingle{8}(address, accdesc, aligned) = value[7:0];

            // For subsequent bytes, if they cross to a new translation page which assigns
            // Device memory type, it is CONSTRAINED UNPREDICTABLE whether an unaligned access
            // will generate an Alignment Fault.

            let c : Constraint = ConstrainUnpredictable(Unpredictable_DEVPAGE2);
            assert c IN {Constraint_FAULT, Constraint_NONE};
            if c == Constraint_NONE then aligned = TRUE; end;

            for i = 1 to bytes-1 do
                AArch32_MemSingle{8}(address+i, accdesc, aligned) = value[i*:8];
            end;
        end;
        return;
    end;
end;

// AArch32_ESBOperation()
// ======================
// Perform the AArch32 ESB operation for ESB executed in AArch32 state.

func AArch32_ESBOperation()
begin
    var masked : boolean;
    var target_el : bits(2);

    (masked, target_el) = PhysicalSErrorTarget();

    // Check if routed to AArch64 state
    if !masked && !ELUsingAArch32(target_el) then
        AArch64_ESBOperation();
        return;
    end;

    // Check for a masked Physical SError pending that can be synchronized
    // by an Error synchronization event.
    if masked && IsSynchronizablePhysicalSErrorPending() then
        var syndrome : bits(32) = Zeros{};
        syndrome[31] = '1';  // A
        syndrome[15:0] = AArch32_PhysicalSErrorSyndrome();
        DISR() = syndrome;
        ClearPendingPhysicalSError();
    end;

    return;
end;

// AArch32_EncodeAsyncErrorSyndrome()
// ==================================
// Return the encoding for specified  ErrorState for an SError exception taken
// to AArch32 state.

func AArch32_EncodeAsyncErrorSyndrome(errorstate : ErrorState) => bits(2)
begin
    case errorstate of
        when ErrorState_UC =>   return '00';
        when ErrorState_UEU =>  return '01';
        when ErrorState_UEO =>  return '10';
        when ErrorState_UER =>  return '11';
        otherwise => unreachable;
    end;
end;

// AArch32_PhysicalSErrorSyndrome()
// ================================
// Generate SError syndrome.

func AArch32_PhysicalSErrorSyndrome() => bits(16)
begin
    var syndrome : bits(32) = Zeros{};
    let fault : FaultRecord = GetPendingPhysicalSError();
    if PSTATE.EL == EL2 then
        let errstate : ErrorState = PEErrorState(fault);
        syndrome[11:10] = AArch32_EncodeAsyncErrorSyndrome(errstate);   // AET
        syndrome[9]     = fault.extflag;                                // EA
        syndrome[5:0]   = '010001';                                     // DFSC
    else
        let long_format : boolean = TTBCR().EAE == '1';
        syndrome = AArch32_CommonFaultStatus(fault, long_format);
    end;
    return syndrome[15:0];
end;

// AArch32_vESBOperation()
// =======================
// Perform the ESB operation for virtual SError interrupts executed in AArch32 state.
// If FEAT_E3DSE is implemented and there is no unmasked virtual SError exception
// pending, then AArch64_dESBOperation() is called to perform the AArch64 ESB operation
// for a pending delegated SError exception.

func AArch32_vESBOperation()
begin
    assert PSTATE.EL IN {EL0, EL1} && EL2Enabled();

    // Check for EL2 using AArch64 state
    if !ELUsingAArch32(EL2) then
        AArch64_vESBOperation();
        return;
    end;

    // If physical SError interrupts are routed to Hyp mode, and TGE is not set, then a virtual
    // SError interrupt might be pending.
    let vsei_pending : boolean = IsVirtualSErrorPending() && HCR().TGE == '0' && HCR().AMO == '1';
    let vsei_masked : boolean  = (PSTATE.A == '1' || Halted() ||
                                  ExternalDebugInterruptsDisabled(EL1));

    // Check for a masked virtual SError pending
    if vsei_pending && vsei_masked then
        var syndrome : bits(32) = Zeros{};
        syndrome[31]    = '1';           // A
        syndrome[15:14] = VDFSR()[15:14];  // AET
        syndrome[12]    = VDFSR()[12];     // ExT
        syndrome[9]     = TTBCR().EAE;     // LPAE
        if TTBCR().EAE == '1' then         // Long-descriptor format
            syndrome[5:0]    = '010001'; // STATUS
        else                             // Short-descriptor format
            syndrome[10,3:0] = '10110';  // FS
        end;
        VDISR() = syndrome;
        ClearPendingVirtualSError();
    elsif IsFeatureImplemented(FEAT_E3DSE) && !ELUsingAArch32(EL3) then
        AArch64_dESBOperation();
    end;

    return;
end;

// AArch32_ResetGeneralRegisters()
// ===============================

func AArch32_ResetGeneralRegisters()
begin

    for i = 0 to 7 do
        R(i) = ARBITRARY : bits(32);
    end;
    for i = 8 to 12 do
        Rmode(i, M32_User) = ARBITRARY : bits(32);
        Rmode(i, M32_FIQ)  = ARBITRARY : bits(32);
    end;
    if HaveEL(EL2) then Rmode(13, M32_Hyp) = ARBITRARY : bits(32); end;   // No R14_hyp
    for i = 13 to 14 do
        Rmode(i, M32_User)  = ARBITRARY : bits(32);
        Rmode(i, M32_FIQ)   = ARBITRARY : bits(32);
        Rmode(i, M32_IRQ)   = ARBITRARY : bits(32);
        Rmode(i, M32_Svc)   = ARBITRARY : bits(32);
        Rmode(i, M32_Abort) = ARBITRARY : bits(32);
        Rmode(i, M32_Undef) = ARBITRARY : bits(32);
        if HaveEL(EL3) then Rmode(i, M32_Monitor) = ARBITRARY : bits(32); end;
    end;

    return;
end;

// AArch32_ResetSIMDFPRegisters()
// ==============================

func AArch32_ResetSIMDFPRegisters()
begin

    for i = 0 to 15 do
        Q(i) = ARBITRARY : bits(128);
    end;

    return;
end;

// AArch32_ResetSpecialRegisters()
// ===============================

func AArch32_ResetSpecialRegisters()
begin

    // AArch32 special registers
    SPSR_fiq()[31:0] = ARBITRARY : bits(32);
    SPSR_irq()[31:0] = ARBITRARY : bits(32);
    SPSR_svc()[31:0] = ARBITRARY : bits(32);
    SPSR_abt()[31:0] = ARBITRARY : bits(32);
    SPSR_und()[31:0] = ARBITRARY : bits(32);
    if HaveEL(EL2) then
        SPSR_hyp() = ARBITRARY : bits(32);
        ELR_hyp()  = ARBITRARY : bits(32);
    end;
    if HaveEL(EL3) then
        SPSR_mon() = ARBITRARY : bits(32);
    end;

    // External debug special registers
    DLR()   = ARBITRARY : bits(32);
    DSPSR() = ARBITRARY : bits(32);

    return;
end;

// AArch32_ResetSystemRegisters()
// ==============================

impdef func AArch32_ResetSystemRegisters(cold_reset : boolean)
begin
    return;
end;

// ALUExceptionReturn()
// ====================

func ALUExceptionReturn(address : bits(32))
begin
    if PSTATE.EL == EL2 then
        Undefined();
    elsif PSTATE.M IN {M32_User,M32_System} then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_ALUEXCEPTIONRETURN);
        assert c IN {Constraint_UNDEF, Constraint_NOP};
        case c of
            when Constraint_UNDEF =>
                Undefined();
            when Constraint_NOP =>
                ExecuteAsNOP();
        end;
    else
        AArch32_ExceptionReturn(address, SPSR_curr());
    end;
end;

// ALUWritePC()
// ============

func ALUWritePC(address : bits(32))
begin
    if CurrentInstrSet() == InstrSet_A32 then
        BXWritePC(address, BranchType_INDIR);
    else
        BranchWritePC(address, BranchType_INDIR);
    end;
end;

// BXWritePC()
// ===========

func BXWritePC(address_in : bits(32), branch_type : BranchType)
begin
    var address : bits(32) = address_in;
    if address[0] == '1' then
        SelectInstrSet(InstrSet_T32);
        address[0] = '0';
    else
        SelectInstrSet(InstrSet_A32);
        // For branches to an unaligned PC counter in A32 state, the PE takes the branch
        // and does one of:
        // * Forces the address to be aligned
        // * Leaves the PC unaligned, meaning the target generates a PC Alignment fault.
        if address[1] == '1' && ConstrainUnpredictableBool(Unpredictable_A32FORCEALIGNPC) then
            address[1] = '0';
        end;
    end;
    let branch_conditional : boolean = CurrentCond() != '111x';
    BranchTo{32}(address, branch_type, branch_conditional);
end;

// BranchWritePC()
// ===============

func BranchWritePC(address_in : bits(32), branch_type : BranchType)
begin
    var address : bits(32) = address_in;
    if CurrentInstrSet() == InstrSet_A32 then
        address[1:0] = '00';
    else
        address[0] = '0';
    end;
    let branch_conditional : boolean = CurrentCond() != '111x';
    BranchTo{32}(address, branch_type, branch_conditional);
end;

// CBWritePC()
// ===========
// Takes a branch from a CBNZ/CBZ instruction.

func CBWritePC(address_in : bits(32))
begin
    var address : bits(32) = address_in;
    assert CurrentInstrSet() == InstrSet_T32;
    address[0] = '0';
    let branch_conditional : boolean = TRUE;
    BranchTo{32}(address, BranchType_DIR, branch_conditional);
end;

// D - accessor
// ============

accessor D(n : integer) <=> value : bits(64)
begin
    getter
        assert n >= 0 && n <= 31;
        let vreg : bits(128) = V{}(n DIVRM 2);
        return vreg[(n MOD 2)*:64];
    end;
    setter
        assert n >= 0 && n <= 31;
        var vreg : bits(128) = V{}(n DIVRM 2);
        vreg[(n MOD 2)*:64] = value;
        V{128}(n DIVRM 2) = vreg;
    end;
end;

// Din
// ===
// Return the initial value of D input

func Din(n : integer) => bits(64)
begin
    assert n >= 0 && n <= 31;
    return _Dclone[[n]];
end;

// H - accessor
// ============

accessor H(n : integer) <=> value : bits(16)
begin
    getter
        assert n >= 0 && n <= 31;
        return S(n)[15:0];
    end;
    setter
        S(n) = ZeroExtend{32}(value);
    end;
end;

// LR - accessor
// =============

accessor LR() <=> value : bits(32)
begin
    getter
        return R(14);
    end;
    setter
        R(14) = value;
    end;
end;

// LoadWritePC()
// =============

func LoadWritePC(address : bits(32))
begin
    BXWritePC(address, BranchType_INDIR);
end;

// LookUpRIndex()
// ==============

func LookUpRIndex(n : integer, mode : bits(5)) => integer
begin
    assert n >= 0 && n <= 14;

    var result : integer;
    case n of  // Select  index by mode:     usr fiq irq svc abt und hyp
        when 8    =>  result = RBankSelect(mode,  8, 24,  8,  8,  8,  8,  8);
        when 9    =>  result = RBankSelect(mode,  9, 25,  9,  9,  9,  9,  9);
        when 10   =>  result = RBankSelect(mode, 10, 26, 10, 10, 10, 10, 10);
        when 11   =>  result = RBankSelect(mode, 11, 27, 11, 11, 11, 11, 11);
        when 12   =>  result = RBankSelect(mode, 12, 28, 12, 12, 12, 12, 12);
        when 13   =>  result = RBankSelect(mode, 13, 29, 17, 19, 21, 23, 15);
        when 14   =>  result = RBankSelect(mode, 14, 30, 16, 18, 20, 22, 14);
        otherwise =>  result = n;
    end;

    return result;
end;

// Monitor mode registers
// ======================
// The Monitor mode registers do not map to X registers, so must be defined separately

var SP_mon : bits(32);

var LR_mon : bits(32);

// PC32
// ====
// Read 32-bit program counter

func PC32() => bits(32)
begin
    return R(15);               // This includes the offset from AArch32 state
end;

// PCStoreValue()
// ==============

func PCStoreValue() => bits(32)
begin
    // This function returns the PC value. On architecture versions before Armv7, it
    // is permitted to instead return PC+4, provided it does so consistently. It is
    // used only to describe A32 instructions, so it returns the address of the current
    // instruction plus 8 (normally) or 12 (when the alternative is permitted).
    return PC32();
end;

// Q - accessor
// ============

accessor Q(n : integer) <=> value : bits(128)
begin
    getter
        assert n >= 0 && n <= 15;
        return V{128}(n);
    end;
    setter
        assert n >= 0 && n <= 15;
        V{128}(n) = value;
    end;
end;

// Qin
// ===
// Return the initial value of Q input

func Qin(n : integer) => bits(128)
begin
    assert n >= 0 && n <= 15;
    return Din(2*n+1)::Din(2*n);
end;

// R - accessor
// ============

accessor R(n : integer) <=> value : bits(32)
begin
    getter
        if n == 15 then
            let offset : integer{} = (if CurrentInstrSet() == InstrSet_A32 then 8 else 4);
            return _PC[31:0] + offset;
        else
            return Rmode(n, PSTATE.M);
        end;
    end;
    setter
        Rmode(n, PSTATE.M) = value;
        return;
    end;
end;

// R - accessor
// ============

accessor R(lr : integer, hr : integer) <=> value : bits(64)
begin
    getter
        return R(hr) :: R(lr);
    end;

    setter
        R(lr) = value[0+:32];
        R(hr) = value[32+:32];
    end;
end;

// RBankSelect()
// =============

func RBankSelect(mode : bits(5), usr : integer, fiq : integer, irq : integer,
                 svc : integer, abt : integer, und : integer, hyp : integer) => integer
begin

    var result : integer;
    case mode of
        when M32_User   => result = usr;  // User mode
        when M32_FIQ    => result = fiq;  // FIQ mode
        when M32_IRQ    => result = irq;  // IRQ mode
        when M32_Svc    => result = svc;  // Supervisor mode
        when M32_Abort  => result = abt;  // Abort mode
        when M32_Hyp    => result = hyp;  // Hyp mode
        when M32_Undef  => result = und;  // Undefined mode
        when M32_System => result = usr;  // System mode uses User mode registers
        otherwise       => unreachable;   // Monitor mode
    end;

    return result;
end;

// ReadAnyAllocatedRegister()
// ==========================

impdef func ReadAnyAllocatedRegister() => bits(32)
begin
    return Zeros{32};
end;

// ReadAnyAllocatedSPSR()
// ======================

impdef func ReadAnyAllocatedSPSR() => bits(32)
begin
    return Zeros{32};
end;

// Rmode - accessor
// ================

accessor Rmode(n : integer, mode : bits(5)) <=> value : bits(32)
begin
    getter
        assert n >= 0 && n <= 14;

        // Check for attempted use of Monitor mode in Non-secure state.
        if CurrentSecurityState() != SS_Secure then assert mode != M32_Monitor; end;
        assert !BadMode(mode);

        if mode == M32_Monitor then
            if n == 13 then return SP_mon;
            elsif n == 14 then return LR_mon;
            else return _R[[n]][31:0];
            end;
        else
            return _R[[LookUpRIndex(n, mode)]][31:0];
        end;
    end;

    setter
        assert n >= 0 && n <= 14;

        // Check for attempted use of Monitor mode in Non-secure state.
        if CurrentSecurityState() != SS_Secure then assert mode != M32_Monitor; end;
        assert !BadMode(mode);

        if mode == M32_Monitor then
            if n == 13 then SP_mon = value;
            elsif n == 14 then LR_mon = value;
            else _R[[n]][31:0] = value;
            end;
        else
            // It is CONSTRAINED UNPREDICTABLE whether the upper 32 bits of the X
            // register are unchanged or set to zero. This is also tested for on
            // exception entry, as this applies to all AArch32 registers.
            if HaveAArch64() && ConstrainUnpredictableBool(Unpredictable_ZEROUPPER) then
                _R[[LookUpRIndex(n, mode)]] = ZeroExtend{64}(value);
            else
                _R[[LookUpRIndex(n, mode)]][31:0] = value;
            end;
        end;
    end;
end;

// S - accessor
// ============

accessor S(n : integer) <=> value : bits(32)
begin
    getter
        assert n >= 0 && n <= 31;
        let vreg : bits(128) = V{}(n DIVRM 4);
        return vreg[(n MOD 4)*:32];
    end;

    setter
        assert n >= 0 && n <= 31;
        var vreg : bits(128) = V{}(n DIVRM 4);
        vreg[(n MOD 4)*:32] = value;
        V{128}(n DIVRM 4) = vreg;
    end;
end;

// WriteAnyAllocatedRegister()
// ===========================

impdef func WriteAnyAllocatedRegister(value : bits(32))
begin
    return;
end;

// WriteAnyAllocatedSPSR()
// =======================

impdef func WriteAnyAllocatedSPSR(value : bits(32))
begin
    return;
end;

// _Dclone[]
// =========
// Clone the 64-bit Advanced SIMD and VFP extension register bank for use as input to
// instruction pseudocode, to avoid read-after-write for Advanced SIMD and VFP operations.

var _Dclone : array [[32]] of bits(64);

// AArch32_ExceptionReturn()
// =========================

func AArch32_ExceptionReturn(new_pc_in : bits(32), spsr : bits(32))
begin
    var new_pc : bits(32) = new_pc_in;
    SynchronizeContext();
    // Attempts to change to an illegal mode or state will invoke the Illegal Execution state
    // mechanism
    SetPSTATEFromPSR{32}(spsr);
    ClearExclusiveLocal(ProcessorID());
    SendEventLocal();

    if PSTATE.IL == '1' then
        // If the exception return is illegal, PC[1:0] are UNKNOWN
        new_pc[1:0] = ARBITRARY : bits(2);
    else
        // LR[1:0] or LR[0] are treated as being 0, depending on the target instruction set state
        if PSTATE.T == '1' then
            new_pc[0] = '0';                 // T32
        else
            new_pc[1:0] = '00';              // A32
        end;
    end;

    let branch_conditional : boolean = CurrentCond() != '111x';
    BranchTo{32}(new_pc, BranchType_ERET, branch_conditional);
    CheckExceptionCatch(FALSE);              // Check for debug event on exception return
end;

// AArch32_ExecutingCP10or11Instr()
// ================================

func AArch32_ExecutingCP10or11Instr() => boolean
begin
    let instr : bits(32) =  ThisInstr();
    let instr_set : InstrSet = CurrentInstrSet();
    assert instr_set IN {InstrSet_A32, InstrSet_T32};

    if instr_set == InstrSet_A32 then
        return ((instr[27:24] == '1110' || instr[27:25] == '110') && instr[11:8] == '101x');
    else // InstrSet_T32
        return (instr[31:28] == '111x' && (instr[27:24] == '1110' || instr[27:25] == '110') &&
                instr[11:8] == '101x');
    end;
end;

// AArch32_ITAdvance()
// ===================

func AArch32_ITAdvance()
begin
    if PSTATE.IT[2:0] == '000' then
        PSTATE.IT = '00000000';
    else
        PSTATE.IT[4:0] = LSL(PSTATE.IT[4:0], 1);
    end;
    return;
end;

// AArch32_InterruptPending()
// ==========================
// Returns TRUE if there are any pending physical or virtual interrupts, and FALSE otherwise.

func AArch32_InterruptPending() => boolean
begin
    if !ELUsingAArch32(EL2) then
        return AArch64_InterruptPending();
    end;

    let (irq_pending, -) = IRQPending();
    let (fiq_pending, -) = FIQPending();
    let pending_physical_interrupt : boolean = (irq_pending || fiq_pending ||
                                                IsPhysicalSErrorPending());

    var pending_virtual_interrupt : boolean = FALSE;
    if EL2Enabled() && PSTATE.EL IN {EL0, EL1} && HCR().TGE == '0' then
        let virq_pending : boolean = (HCR().IMO == '1' && (VirtualIRQPending() || HCR().VI == '1'));
        let vfiq_pending : boolean = (HCR().FMO == '1' && (VirtualFIQPending() || HCR().VF == '1'));
        let vsei_pending : boolean = (HCR().AMO == '1' &&
                                      (IsVirtualSErrorPending() || HCR().VA == '1'));

        pending_virtual_interrupt = vsei_pending || virq_pending || vfiq_pending;
    end;

    return pending_physical_interrupt || pending_virtual_interrupt;
end;

// AArch32_SysRegRead()
// ====================
// Read from a 32-bit AArch32 System register and write the register's contents to R[t].

impdef func AArch32_SysRegRead(cp_num : integer, instr : bits(32), t : integer)
begin
    let (-, el) = ELFromM32(PSTATE.M);
    let opc1 = instr[21+:3];
    let CRn  = instr[16+:4];
    let CRm  = instr[0+:4];
    let opc2 = instr[5+:3];
end;

// AArch32_SysRegRead64()
// ======================
// Read from a 64-bit AArch32 System register and write the register's contents to R[t] and R[t2].

impdef func AArch32_SysRegRead64(cp_num : integer, instr : bits(32), t : integer, t2 : integer)
begin
    let (-, el) = ELFromM32(PSTATE.M);
    let opc1 = instr[4+:4];
    let CRm  = instr[0+:4];
end;

// AArch32_SysRegReadCanWriteAPSR()
// ================================
// Determines whether the AArch32 System register read instruction can write to APSR flags.

func AArch32_SysRegReadCanWriteAPSR(cp_num : integer, instr : bits(32)) => boolean
begin
    assert UsingAArch32();
    assert (cp_num IN {14,15});
    assert cp_num == UInt(instr[11:8]);

    let opc1 : integer{} = UInt(instr[23:21]);
    let opc2 : integer{} = UInt(instr[7:5]);
    let CRn : integer{}  = UInt(instr[19:16]);
    let CRm : integer{}  = UInt(instr[3:0]);

    if cp_num == 14 && opc1 == 0 && CRn == 0 && CRm == 1 && opc2 == 0 then // DBGDSCRint
        return TRUE;
    end;

    return FALSE;
end;

// AArch32_SysRegWrite()
// =====================
// Read the contents of R[t] and write to a 32-bit AArch32 System register.

impdef func AArch32_SysRegWrite(cp_num : integer, instr : bits(32), t : integer)
begin
    let (-, el) = ELFromM32(PSTATE.M);
    let opc1 = instr[21+:3];
    let CRn  = instr[16+:4];
    let CRm  = instr[ 0+:4];
    let opc2 = instr[ 5+:3];
end;

// AArch32_SysRegWrite64()
// =======================
// Read the contents of R[t] and R[t2] and write to a 64-bit AArch32 System register.

impdef func AArch32_SysRegWrite64(cp_num : integer,
                                  instr : bits(32),
                                  t : integer,
                                  t2 : integer)
begin
    let (-, el) = ELFromM32(PSTATE.M);
    let opc1 = instr[4+:4];
    let CRm  = instr[0+:4];
end;

// AArch32_SysRegWriteM()
// ======================
// Read a value from a virtual address and write it to an AArch32 System register.

impdef func AArch32_SysRegWriteM(cp_num : integer, instr : bits(32), address : bits(32))
begin
    let CRd : bits(4) = instr[15:12];
end;

// AArch32_WriteMode()
// ===================
// Function for dealing with writes to PSTATE.M from AArch32 state only.
// This ensures that PSTATE.EL and PSTATE.SP are always valid.

func AArch32_WriteMode(mode : bits(5))
begin
    let (valid,el) : (boolean, bits(2)) = ELFromM32(mode);
    assert valid;
    PSTATE.M   = mode;
    PSTATE.EL  = el;
    PSTATE.nRW = '1';
    PSTATE.SP  = (if mode IN {M32_User,M32_System} then '0' else '1');
    return;
end;

// AArch32_WriteModeByInstr()
// ==========================
// Function for dealing with writes to PSTATE.M from an AArch32 instruction, and ensuring that
// illegal state changes are correctly flagged in PSTATE.IL.

func AArch32_WriteModeByInstr(mode : bits(5))
begin
    var (valid,el) : (boolean, bits(2)) = ELFromM32(mode);

    // 'valid' is set to FALSE if' mode' is invalid for this implementation or the current value
    // of SCR.NS/SCR_EL3.NS. Additionally, it is illegal for an instruction to write 'mode' to
    // PSTATE.EL if it would result in any of:
    // * A change to a mode that would cause entry to a higher Exception level.
    if UInt(el) > UInt(PSTATE.EL) then
        valid = FALSE;
    end;

    // * A change to or from Hyp mode.
    if (PSTATE.M == M32_Hyp || mode == M32_Hyp) && PSTATE.M != mode then
        valid = FALSE;
    end;

    // * When EL2 is implemented, the value of HCR.TGE is '1', a change to a Non-secure EL1 mode.
    if (PSTATE.M == M32_Monitor && HaveEL(EL2) && el == EL1 && SCR().NS == '1'
            && HCR().TGE == '1') then
        valid = FALSE;
    end;

    if !valid then
        PSTATE.IL = '1';
    else
        AArch32_WriteMode(mode);
    end;
end;

// BadMode()
// =========

readonly func BadMode(mode : bits(5)) => boolean
begin
    // Return TRUE if 'mode' encodes a mode that is not valid for this implementation
    var valid : boolean;
    case mode of
        when M32_Monitor =>
            valid = HaveAArch32EL(EL3);
        when M32_Hyp =>
            valid = HaveAArch32EL(EL2);
        when M32_FIQ, M32_IRQ, M32_Svc, M32_Abort, M32_Undef, M32_System =>
            // If EL3 is implemented and using AArch32, then these modes are EL3 modes in Secure
            // state, and EL1 modes in Non-secure state. If EL3 is not implemented or is using
            // AArch64, then these modes are EL1 modes.
            // Therefore it is sufficient to test this implementation supports EL1 using AArch32
            valid = HaveAArch32EL(EL1);
        when M32_User =>
            valid = HaveAArch32EL(EL0);
        otherwise =>
            valid = FALSE;           // Passed an illegal mode value
    end;
    return !valid;
end;

// BankedRegisterAccessValid()
// ===========================
// Checks for MRS (Banked register) or MSR (Banked register) accesses to registers
// other than the SPSRs that are invalid. This includes ELR_hyp accesses.

func BankedRegisterAccessValid(SYSm : bits(5), mode : bits(5)) => (boolean, Constraint)
begin
    var valid : boolean = TRUE;
    var c : Constraint = Constraint_NONE;
    var banked_unpred : boolean = FALSE;
    case SYSm of
        when '000xx', '00100' =>                          // R8_usr to R12_usr
            banked_unpred = mode != M32_FIQ;
        when '00101' =>                                   // SP_usr
            banked_unpred = mode == M32_System;
        when '00110' =>                                   // LR_usr
            banked_unpred = mode IN {M32_Hyp,M32_System};
        when '010xx', '0110x', '01110' =>                 // R8_fiq to R12_fiq, SP_fiq, LR_fiq
            banked_unpred = mode == M32_FIQ;
        when '1000x' =>                                   // LR_irq, SP_irq
            banked_unpred = mode == M32_IRQ;
        when '1001x' =>                                   // LR_svc, SP_svc
            banked_unpred = mode == M32_Svc;
        when '1010x' =>                                   // LR_abt, SP_abt
            banked_unpred = mode == M32_Abort;
        when '1011x' =>                                   // LR_und, SP_und
            banked_unpred = mode == M32_Undef;
        when '1110x' =>                                   // LR_mon, SP_mon
            banked_unpred = (!HaveEL(EL3) || CurrentSecurityState() != SS_Secure ||
                               mode == M32_Monitor);
        when '11110' =>                                   // ELR_hyp, only from Monitor or Hyp mode
            banked_unpred = !HaveEL(EL2) || ! mode IN {M32_Monitor,M32_Hyp};
        when '11111' =>                                   // SP_hyp, only from Monitor mode
            banked_unpred = !HaveEL(EL2) || mode != M32_Monitor;
        otherwise =>
            valid = FALSE;
            c     = ConstrainUnpredictable(Unpredictable_UnimplementedRegister);
            assert c IN {Constraint_UNDEF, Constraint_NOP, Constraint_ANYREG};
    end;

    if banked_unpred then
        valid = FALSE;
        c     = ConstrainUnpredictable(Unpredictable_BankedRegister);
        assert c IN {Constraint_UNDEF, Constraint_NOP, Constraint_UNKNOWN};
    end;

    return (valid, c);
end;

// CPSRWriteByInstr()
// ==================
// Update PSTATE.[N,Z,C,V,Q,GR,E,A,I,F,M] from a CPSR value written by an MSR instruction.

func CPSRWriteByInstr(value : bits(32), bytemask : bits(4))
begin
    let privileged : boolean = PSTATE.EL != EL0;        // PSTATE.[A,I,F,M] are not writable at EL0

    // Write PSTATE from 'value', ignoring bytes masked by 'bytemask'
    if bytemask[3] == '1' then
        PSTATE.[N,Z,C,V,Q] = value[31:27];
        // Bits [26:24] are ignored
    end;

    if bytemask[2] == '1' then
        if IsFeatureImplemented(FEAT_SSBS) then
            PSTATE.SSBS = value[23];
        end;
        if privileged then
            PSTATE.PAN = value[22];
        end;
        if IsFeatureImplemented(FEAT_DIT) then
            PSTATE.DIT = value[21];
        end;
        // Bit [20] is RES0
        PSTATE.GE = value[19:16];
    end;

    if bytemask[1] == '1' then
        // Bits [15:10] are RES0
        PSTATE.E = value[9];                    // PSTATE.E is writable at EL0
        if privileged then
            PSTATE.A = value[8];
        end;
    end;

    if bytemask[0] == '1' then
        if privileged then
            PSTATE.[I,F] = value[7:6];
            // Bit [5] is RES0
            // AArch32_WriteModeByInstr() sets PSTATE.IL to 1 if this is an illegal mode change.
            AArch32_WriteModeByInstr(value[4:0]);
        end;
    end;
    return;
end;

// ConditionPassed()
// =================

func ConditionPassed() => boolean
begin
    return ConditionHolds(CurrentCond());
end;

// CurrentCond()
// =============
// Returns the condition code that applies to the currently executing instruction

impdef func CurrentCond() => bits(4)
begin
    return Zeros{4};
end;

// InITBlock()
// ===========

func InITBlock() => boolean
begin
    if CurrentInstrSet() == InstrSet_T32 then
        return PSTATE.IT[3:0] != '0000';
    else
        return FALSE;
    end;
end;

// LastInITBlock()
// ===============

func LastInITBlock() => boolean
begin
    return (PSTATE.IT[3:0] == '1000');
end;

// SPSRWriteByInstr()
// ==================

func SPSRWriteByInstr(value : bits(32), bytemask : bits(4))
begin
    var new_spsr : bits(32) = SPSR_curr();

    if bytemask[3] == '1' then
        new_spsr[31:24] = value[31:24];  // N,Z,C,V,Q flags, IT[1:0],J bits
    end;

    if bytemask[2] == '1' then
        new_spsr[23:16] = value[23:16];  // IL bit, GE[3:0] flags
    end;

    if bytemask[1] == '1' then
        new_spsr[15:8] = value[15:8];    // IT[7:2] bits, E bit, A interrupt mask
    end;

    if bytemask[0] == '1' then
        new_spsr[7:0] = value[7:0];      // I,F interrupt masks, T bit, Mode bits
    end;

    SPSR_curr() = new_spsr;              // UNPREDICTABLE if User or System mode

    return;
end;

// SPSRaccessValid()
// =================
// Checks for MRS (Banked register) or MSR (Banked register) accesses to the SPSRs
// that are UNPREDICTABLE

func SPSRaccessValid(SYSm : bits(5), mode : bits(5)) => (boolean, Constraint)
begin
    var valid : boolean = TRUE;
    var c : Constraint = Constraint_NONE;
    var banked_unpred : boolean = FALSE;
    case SYSm of
        when '01110' =>                                                   // SPSR_fiq
            banked_unpred = mode == M32_FIQ;
        when '10000' =>                                                   // SPSR_irq
            banked_unpred = mode == M32_IRQ;
        when '10010' =>                                                   // SPSR_svc
            banked_unpred = mode == M32_Svc;
        when '10100' =>                                                   // SPSR_abt
            banked_unpred = mode == M32_Abort;
        when '10110' =>                                                   // SPSR_und
            banked_unpred = mode == M32_Undef;
        when '11100' =>                                                   // SPSR_mon
            banked_unpred = (!HaveEL(EL3) || mode == M32_Monitor ||
                               CurrentSecurityState() != SS_Secure);
        when '11110' =>                                                   // SPSR_hyp
            banked_unpred = !HaveEL(EL2) || mode != M32_Monitor;
        otherwise =>
            valid = FALSE;
            c = ConstrainUnpredictable(Unpredictable_UnimplementedRegister);
            assert c IN {Constraint_UNDEF, Constraint_NOP, Constraint_ANYREG};
    end;

    if banked_unpred then
        valid = FALSE;
        c     = ConstrainUnpredictable(Unpredictable_BankedRegister);
        assert c IN {Constraint_UNDEF, Constraint_NOP, Constraint_UNKNOWN};
    end;

    return (valid, c);
end;

// SelectInstrSet()
// ================

func SelectInstrSet(iset : InstrSet)
begin
    assert CurrentInstrSet() IN {InstrSet_A32, InstrSet_T32};
    assert iset IN {InstrSet_A32, InstrSet_T32};

    PSTATE.T = if iset == InstrSet_A32 then '0' else '1';

    return;
end;

// AArch32_DTLBI_ALL()
// ===================
// Invalidate all data TLB entries for the indicated translation regime with the
// the indicated security state for all TLBs within the indicated broadcast domain.
// Invalidation applies to all applicable stage 1 and stage 2 entries.

func AArch32_DTLBI_ALL(security : SecurityState, regime : Regime, broadcast : Broadcast,
                       attr : TLBIMemAttr)
begin
    assert PSTATE.EL IN {EL3, EL2, EL1};

    var r : TLBIRecord;
    r.op           = TLBIOp_DALL;
    r.from_aarch64 = FALSE;
    r.security     = security;
    r.regime       = regime;
    r.level        = TLBILevel_Any;
    r.attr         = attr;

    TLBI(r);
    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r); end;
    return;
end;

// AArch32_DTLBI_ASID()
// ====================
// Invalidate all data TLB stage 1 entries matching the indicated VMID (where regime supports)
// and ASID in the parameter Rt in the indicated translation regime with the
// indicated security state for all TLBs within the indicated broadcast domain.
// Note: stage 1 and stage 2 combined entries are in the scope of this operation.

func AArch32_DTLBI_ASID(security : SecurityState, regime : Regime, vmid : bits(16),
                        broadcast : Broadcast, attr : TLBIMemAttr, Rt : bits(32))
begin
    assert PSTATE.EL IN {EL3, EL2, EL1};

    var r : TLBIRecord;
    r.op           = TLBIOp_DASID;
    r.from_aarch64 = FALSE;
    r.security     = security;
    r.regime       = regime;
    r.vmid         = vmid;
    r.use_vmid     = UseVMID(regime);
    r.level        = TLBILevel_Any;
    r.attr         = attr;
    r.asid         = Zeros{8} :: Rt[7:0];

    TLBI(r);
    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r); end;
    return;
end;

