// AArch32_TLBI_VMALLS12()
// =======================
// Invalidate all stage 1 and stage 2 entries for the indicated translation
// regime with the indicated security state for all TLBs within the indicated
// broadcast domain that match the indicated VMID.

func AArch32_TLBI_VMALLS12(security : SecurityState, regime : Regime, vmid : bits(16),
                           broadcast : Broadcast, attr : TLBIMemAttr)
begin
    assert PSTATE.EL IN {EL3, EL2};

    var r : TLBIRecord;
    r.op           = TLBIOp_VMALLS12;
    r.from_aarch64 = FALSE;
    r.security     = security;
    r.regime       = regime;
    r.level        = TLBILevel_Any;
    r.vmid         = vmid;
    r.use_vmid     = TRUE;
    r.attr         = attr;

    TLBI(r);
    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r); end;
    return;
end;

// Sat()
// =====

func Sat{N}(i : integer, unsigned : boolean) => bits(N)
begin
    let result : bits(N) = if unsigned then UnsignedSat{N}(i) else SignedSat{N}(i);
    return result;
end;

// AArch32_CanTrapIC()
// ===================
// Determines whether the execution of the IC instruction can be trapped.

func AArch32_CanTrapIC(cacheop : CacheOp, opscope : CacheOpScope) => boolean
begin
    return (!AArch32_TreatICAsNOP(cacheop, opscope) || ImpDefBool(
            "When IC is treated as NOP, data cache maintenance operations are trapped"));
end;

// AArch32_IC()
// ============
// Perform Instruction Cache Operation.

func AArch32_IC(opscope : CacheOpScope)
begin
    let regval : bits(32) = ARBITRARY : bits(32);
    AArch32_IC(regval, opscope);
end;

// AArch32_IC()
// ============
// Perform Instruction Cache Operation.

func AArch32_IC(regval : bits(32), opscope : CacheOpScope)
begin
    var cache : CacheRecord;

    cache.acctype   = AccessType_IC;
    cache.cachetype = CacheType_Instruction;
    cache.cacheop   = CacheOp_Invalidate;
    cache.opscope   = opscope;
    cache.security  = SecurityStateAtEL(PSTATE.EL);

    if opscope IN {CacheOpScope_ALLU, CacheOpScope_ALLUIS} then
        if opscope == CacheOpScope_ALLUIS then
            cache.shareability = Shareability_ISH;
        else
            cache.shareability = Shareability_NSH;
        end;
        cache.regval = ZeroExtend{64}(regval);
        CACHE_OP(cache);
    else
        assert opscope == CacheOpScope_PoU;

        if EL2Enabled() then
            if PSTATE.EL IN {EL0, EL1} then
                cache.is_vmid_valid = TRUE;
                cache.vmid          = VMID();
            else
                cache.is_vmid_valid = FALSE;
            end;
        else
            cache.is_vmid_valid = FALSE;
        end;

        if PSTATE.EL == EL0 then
            cache.is_asid_valid = TRUE;
            cache.asid          = ASID();
        else
            cache.is_asid_valid = FALSE;
        end;

        cache.shareability = Shareability_NSH;
        cache.vaddress     = ZeroExtend{64}(regval);

        let size : integer    = 0;
        let aligned : boolean = TRUE;
        let accdesc : AccessDescriptor = CreateAccDescIC(cache);
        let memaddrdesc : AddressDescriptor = AArch32_TranslateAddress(regval, accdesc, aligned,
                                                                          size);
        if IsFault(memaddrdesc) then
            AArch32_Abort(memaddrdesc.fault);
        end;

        cache.paddress = memaddrdesc.paddress;
        CACHE_OP(cache);
    end;
    return;
end;

// AArch32_TreatICAsNOP()
// ======================
// Determines whether the execution of the IC instruction is treated as a NOP.

func AArch32_TreatICAsNOP(cacheop : CacheOp, opscope : CacheOpScope) => boolean
begin
    if CTR().DIC == '1' then
        return ImpDefBool("IC is treated as NOP");
    end;

    return FALSE;
end;

// AArch32_RestrictPrediction()
// ============================
// Clear all predictions in the context.

func AArch32_RestrictPrediction(val : bits(32), restriction : RestrictType)
begin

    var c : ExecutionCntxt;
    let target_el : bits(2) = val[25:24];

    // If the target EL is not implemented or the instruction is executed at an
    // EL lower than the specified level, the instruction is treated as a NOP.
    if !HaveEL(target_el) || UInt(target_el) > UInt(PSTATE.EL) then ExecuteAsNOP(); end;

    let ns : bit  = val[26];
    let nse : bit = ARBITRARY : bit;
    let ss : SecurityState = TargetSecurityState(ns, nse);

    c.security  = ss;
    c.target_el = target_el;

    if EL2Enabled() then
        if PSTATE.EL IN {EL0, EL1} then
            c.is_vmid_valid = TRUE;
            c.all_vmid      = FALSE;
            c.vmid          = VMID();

        elsif target_el IN {EL0, EL1} then
            c.is_vmid_valid = TRUE;
            c.all_vmid      = val[27] == '1';
            c.vmid          = ZeroExtend{16}(val[23:16]);   // Only valid if  val[27] == '0';
        else
            c.is_vmid_valid = FALSE;
        end;
    else
        c.is_vmid_valid = FALSE;
    end;

    if PSTATE.EL == EL0 then
        c.is_asid_valid = TRUE;
        c.all_asid      = FALSE;
        c.asid          = ASID();

    elsif target_el == EL0 then
        c.is_asid_valid = TRUE;
        c.all_asid      = val[8] == '1';
        c.asid          = ZeroExtend{16}(val[7:0]);         // Only valid if  val[8] == '0';

    else
        c.is_asid_valid = FALSE;
    end;

    c.restriction = restriction;
    RESTRICT_PREDICTIONS(c);
end;

// AArch32_DefaultTEXDecode()
// ==========================
// Apply short-descriptor format memory region attributes, without TEX remap

func AArch32_DefaultTEXDecode(TEX_in : bits(3), c_in : bit, b_in : bit, s : bit) => MemoryAttributes
begin
    var memattrs : MemoryAttributes;
    var TEX : bits(3) = TEX_in;
    var c : bit = c_in;
    var b : bit = b_in;

    // Reserved values map to allocated values
    if (TEX == '001' && c::b == '01') || (TEX == '010' && c::b != '00') || TEX == '011' then
        var texcb : bits(5);
        (-, texcb) = ConstrainUnpredictableBits{5}(Unpredictable_RESTEXCB);
        TEX = texcb[4:2];  c = texcb[1];  b = texcb[0];
    end;

    // Distinction between Inner Shareable and Outer Shareable is not supported in this format
    // A memory region is either Non-shareable or Outer Shareable
    case TEX::c::b of
        when '00000' =>
            // Device-nGnRnE
            memattrs.memtype      = MemType_Device;
            memattrs.device       = DeviceType_nGnRnE;
            memattrs.shareability = Shareability_OSH;
        when '00001', '01000' =>
            // Device-nGnRE
            memattrs.memtype      = MemType_Device;
            memattrs.device       = DeviceType_nGnRE;
            memattrs.shareability = Shareability_OSH;
        when '00010' =>
            // Write-through Read allocate
            memattrs.memtype      = MemType_Normal;
            memattrs.inner.attrs  = MemAttr_WT;
            memattrs.inner.hints  = MemHint_RA;
            memattrs.outer.attrs  = MemAttr_WT;
            memattrs.outer.hints  = MemHint_RA;
            memattrs.shareability = if s == '1' then Shareability_OSH else Shareability_NSH;
        when '00011' =>
            // Write-back Read allocate
            memattrs.memtype      = MemType_Normal;
            memattrs.inner.attrs  = MemAttr_WB;
            memattrs.inner.hints  = MemHint_RA;
            memattrs.outer.attrs  = MemAttr_WB;
            memattrs.outer.hints  = MemHint_RA;
            memattrs.shareability = if s == '1' then Shareability_OSH else Shareability_NSH;
        when '00100' =>
            // Non-cacheable
            memattrs.memtype      = MemType_Normal;
            memattrs.inner.attrs  = MemAttr_NC;
            memattrs.outer.attrs  = MemAttr_NC;
            memattrs.shareability = Shareability_OSH;
        when '00110' =>
            memattrs = ImpDefMemoryAttributes("IMPLEMENTATION_DEFINED");
        when '00111' =>
            // Write-back Read and Write allocate
            memattrs.memtype      = MemType_Normal;
            memattrs.inner.attrs  = MemAttr_WB;
            memattrs.inner.hints  = MemHint_RWA;
            memattrs.outer.attrs  = MemAttr_WB;
            memattrs.outer.hints  = MemHint_RWA;
            memattrs.shareability = if s == '1' then Shareability_OSH else Shareability_NSH;
        when '1xxxx' =>
            // Cacheable, TEX[1:0] = Outer attrs, {c,b} = Inner attrs
            memattrs.memtype = MemType_Normal;
            memattrs.inner   = DecodeSDFAttr(c::b);
            memattrs.outer   = DecodeSDFAttr(TEX[1:0]);

            if memattrs.inner.attrs == MemAttr_NC && memattrs.outer.attrs == MemAttr_NC then
                memattrs.shareability = Shareability_OSH;
            else
                memattrs.shareability = if s == '1' then Shareability_OSH else Shareability_NSH;
            end;
        otherwise =>
            // Reserved, handled above
            unreachable;
    end;

    // The Transient hint is not supported in this format
    memattrs.inner.transient = FALSE;
    memattrs.outer.transient = FALSE;
    memattrs.tags            = MemTag_Untagged;

    if memattrs.inner.attrs == MemAttr_WB && memattrs.outer.attrs == MemAttr_WB then
        memattrs.xs = '0';
    else
        memattrs.xs = '1';
    end;

    return memattrs;
end;

// AArch32_MAIRAttr()
// ==================
// Retrieve the memory attribute encoding indexed in the given MAIR

func AArch32_MAIRAttr(index : integer, mair : MAIRType) => bits(8)
begin
    assert (index < 8);
    return mair[index*:8];
end;

// AArch32_RemappedTEXDecode()
// ===========================
// Apply short-descriptor format memory region attributes, with TEX remap

func AArch32_RemappedTEXDecode(regime : Regime, TEX : bits(3),
                               c : bit, b : bit, s : bit) => MemoryAttributes
begin

    var memattrs : MemoryAttributes;
    var prrr : PRRR_Type;
    var nmrr : NMRR_Type;

    let region : integer{} = UInt(TEX[0]::c::b);   // TEX[2:1] are ignored in this mapping scheme
    if region == 6 then
        return ImpDefMemoryAttributes("IMPLEMENTATION_DEFINED");
    end;

    if regime == Regime_EL30 then
        prrr = PRRR_S();
        nmrr = NMRR_S();
    elsif HaveEL(EL3) && ELUsingAArch32(EL3) then
        prrr = PRRR_NS();
        nmrr = NMRR_NS();
    else
        prrr = PRRR();
        nmrr = NMRR();
    end;

    let base : integer{} = 2 * region;
    var attrfield : bits(2) = prrr[region*:2];

    if attrfield == '11' then      // Reserved, maps to allocated value
        (-, attrfield) = ConstrainUnpredictableBits{2}(Unpredictable_RESPRRR);
    end;

    case attrfield of
        when '00' =>                  // Device-nGnRnE
            memattrs.memtype      = MemType_Device;
            memattrs.device       = DeviceType_nGnRnE;
            memattrs.shareability = Shareability_OSH;
        when '01' =>                  // Device-nGnRE
            memattrs.memtype      = MemType_Device;
            memattrs.device       = DeviceType_nGnRE;
            memattrs.shareability = Shareability_OSH;
        when '10' =>
            let NSn : bit  = if s == '0' then prrr.NS0 else prrr.NS1;
            let NOSm : bit = prrr[region+24] AND NSn;
            let IRn : bits(2)  = nmrr[base+1:base];
            let ORn : bits(2)  = nmrr[base+17:base+16];

            memattrs.memtype = MemType_Normal;
            memattrs.inner   = DecodeSDFAttr(IRn);
            memattrs.outer   = DecodeSDFAttr(ORn);
            if memattrs.inner.attrs == MemAttr_NC && memattrs.outer.attrs == MemAttr_NC then
                memattrs.shareability = Shareability_OSH;
            else
                let sh : bits(2) = NSn::NOSm;
                memattrs.shareability = DecodeShareability(sh);
            end;
        when '11' =>
            unreachable;
    end;

    // The Transient hint is not supported in this format
    memattrs.inner.transient = FALSE;
    memattrs.outer.transient = FALSE;
    memattrs.tags            = MemTag_Untagged;

    if memattrs.inner.attrs == MemAttr_WB && memattrs.outer.attrs == MemAttr_WB then
        memattrs.xs = '0';
    else
        memattrs.xs = '1';
    end;

    return memattrs;
end;

// AArch32_CheckBreakpoint()
// =========================
// Called before executing the instruction of length "size" bytes at "vaddress" in an AArch32
// translation regime, when either debug exceptions are enabled, or halting debug is enabled
// and halting is allowed.

func AArch32_CheckBreakpoint(fault_in : FaultRecord, vaddress : bits(32),
                             accdesc : AccessDescriptor, size : integer) => FaultRecord
begin
    assert ELUsingAArch32(S1TranslationRegime());
    assert size IN {2,4};

    var fault : FaultRecord = fault_in;
    var match : boolean = FALSE;
    var mismatch : boolean = FALSE;
    var brkptinfo : BreakpointInfo;

    for i = 0 to NumBreakpointsImplemented() - 1 do
        brkptinfo = AArch32_BreakpointMatch(i, vaddress, accdesc, size);
        match = match || brkptinfo.match;
        mismatch = mismatch || brkptinfo.mismatch;
    end;

    if match && HaltOnBreakpointOrWatchpoint() then
        let reason : bits(6) = DebugHalt_Breakpoint;
        Halt(reason);
    elsif (match || mismatch) then
        fault.statuscode = Fault_Debug;
        fault.debugmoe   = DebugException_Breakpoint;
        fault.vaddress   = ZeroExtend{64}(vaddress);
    end;

    return fault;
end;

// AArch32_CheckDebug()
// ====================
// Called on each access to check for a debug exception or entry to Debug state.

func AArch32_CheckDebug(vaddress : bits(32), accdesc : AccessDescriptor,
                        size : integer) => FaultRecord
begin

    var fault : FaultRecord = NoFault(accdesc, ZeroExtend{64}(vaddress));

    let d_side : boolean = IsWatchpointableAccess(accdesc);
    let i_side : boolean = (accdesc.acctype == AccessType_IFETCH);
    let generate_exception : boolean = (AArch32_GenerateDebugExceptions() &&
                                            DBGDSCRext().MDBGen == '1');
    let halt : boolean = HaltOnBreakpointOrWatchpoint();
    // Relative priority of Vector Catch and Breakpoint exceptions not defined in the architecture
    let vector_catch_first : boolean = ConstrainUnpredictableBool(Unpredictable_BPVECTORCATCHPRI);

    if i_side && vector_catch_first && generate_exception then
        fault = AArch32_CheckVectorCatch(fault, vaddress, size);
    end;

    if fault.statuscode == Fault_None && (generate_exception || halt) then
        if d_side then
            fault = AArch32_CheckWatchpoint(fault, vaddress, accdesc, size);
        elsif i_side then
            fault = AArch32_CheckBreakpoint(fault, vaddress, accdesc, size);
        end;
    end;

    if fault.statuscode == Fault_None && i_side && !vector_catch_first && generate_exception then
        return AArch32_CheckVectorCatch(fault, vaddress, size);
    end;

    return fault;
end;

// AArch32_CheckVectorCatch()
// ==========================
// Called before executing the instruction of length "size" bytes at "vaddress" in an AArch32
// translation regime, when debug exceptions are enabled.

func AArch32_CheckVectorCatch(fault_in : FaultRecord, vaddress : bits(32),
                              size : integer) => FaultRecord
begin
    assert ELUsingAArch32(S1TranslationRegime());

    var fault : FaultRecord = fault_in;
    var match : boolean = AArch32_VCRMatch(vaddress);
    if size == 4 && !match && AArch32_VCRMatch(vaddress + 2) then
        match = ConstrainUnpredictableBool(Unpredictable_VCMATCHHALF);
    end;

    if match then
        fault.statuscode = Fault_Debug;
        fault.debugmoe   = DebugException_VectorCatch;
    end;

    return fault;
end;

// AArch32_CheckWatchpoint()
// =========================
// Called before accessing the memory location of "size" bytes at "address",
// when either debug exceptions are enabled for the access, or halting debug
// is enabled and halting is allowed.

func AArch32_CheckWatchpoint(fault_in : FaultRecord, vaddress : bits(32),
                             accdesc : AccessDescriptor, size : integer) => FaultRecord
begin
    assert ELUsingAArch32(S1TranslationRegime());
    var fault : FaultRecord = fault_in;
    var match : boolean = FALSE;

    if !IsWatchpointableAccess(accdesc) then
        return fault;
    end;

    for i = 0 to NumWatchpointsImplemented() - 1 do
        let watchptinfo : WatchpointInfo = AArch32_WatchpointMatch(i, vaddress, size, accdesc);
        match = match || watchptinfo.value_match;
    end;

    if match && HaltOnBreakpointOrWatchpoint() then
        let reason : bits(6) = DebugHalt_Watchpoint;
        EDWAR()  = ZeroExtend{64}(vaddress);
        Halt(reason);
    elsif match then
        fault.statuscode = Fault_Debug;
        fault.debugmoe   = DebugException_Watchpoint;
        fault.vaddress   = ZeroExtend{64}(vaddress);
    end;

    return fault;
end;

// AArch32_IPAIsOutOfRange()
// =========================
// Check intermediate physical address bits not resolved by translation are ZERO

func AArch32_IPAIsOutOfRange(walkparams : S2TTWParams, ipa : bits(40)) => boolean
begin
    // Input Address size
    let iasize : integer{} = AArch32_S2IASize(walkparams.t0sz);

    return iasize < 40 && !IsZero(ipa[39:iasize]);
end;

// AArch32_S1HasAlignmentFaultDueToMemType()
// =========================================
// Returns whether stage 1 output fails alignment requirement on data accesses to memory type

func AArch32_S1HasAlignmentFaultDueToMemType(accdesc : AccessDescriptor, aligned : boolean,
                                             ntlsmd : bit, memattrs : MemoryAttributes) => boolean
begin
    if memattrs.memtype != MemType_Device then
        return FALSE;
    elsif accdesc.a32lsmd && ntlsmd == '0' then
        return memattrs.device != DeviceType_GRE;
    elsif accdesc.acctype == AccessType_DCZero then
        return TRUE;
    elsif !aligned then
        return !(ImpDefBool("Device location supports unaligned access"));
    else
        return FALSE;
    end;
end;

// AArch32_S1LDHasPermissionsFault()
// =================================
// Returns whether an access using stage 1 long-descriptor translation
// violates permissions of target memory

func AArch32_S1LDHasPermissionsFault(regime : Regime, walkparams : S1TTWParams,
                                     perms : Permissions, memtype : MemType, paspace : PASpace,
                                     accdesc : AccessDescriptor) => boolean
begin
    var r,  w,  x : bit;
    var pr, pw : bit;
    var ur, uw : bit;
    var xn : bit;
    if HasUnprivileged(regime) then
        // Apply leaf permissions
        case perms.ap[2:1] of
            when '00' => (pr,pw,ur,uw) = ('1','1','0','0'); // R/W at PL1 only
            when '01' => (pr,pw,ur,uw) = ('1','1','1','1'); // R/W at any PL
            when '10' => (pr,pw,ur,uw) = ('1','0','0','0'); // RO at PL1 only
            when '11' => (pr,pw,ur,uw) = ('1','0','1','0'); // RO at any PL
        end;

        // Apply hierarchical permissions
        case perms.ap_table of
            when '00' => (pr,pw,ur,uw) = ( pr, pw, ur, uw); // No effect
            when '01' => (pr,pw,ur,uw) = ( pr, pw,'0','0'); // Privileged access
            when '10' => (pr,pw,ur,uw) = ( pr,'0', ur,'0'); // Read-only
            when '11' => (pr,pw,ur,uw) = ( pr,'0','0','0'); // Read-only, privileged access
        end;

        xn   = perms.xn OR perms.xn_table;
        let pxn : bit  = perms.pxn OR perms.pxn_table;

        let ux : bit = ur AND NOT(xn OR (uw AND walkparams.wxn));
        let px : bit = pr AND NOT(xn OR pxn OR (pw AND walkparams.wxn) OR (uw AND walkparams.uwxn));

        if IsFeatureImplemented(FEAT_PAN) && accdesc.pan then
            let pan : bit = PSTATE.PAN AND (ur OR uw);
            pr  = pr AND NOT(pan);
            pw  = pw AND NOT(pan);
        end;

        (r,w,x) = if accdesc.el == EL0 then (ur,uw,ux) else (pr,pw,px);

        // Prevent execution from Non-secure space by PE in Secure state if SIF is set
        if accdesc.ss == SS_Secure && paspace == PAS_NonSecure then
            x = x AND NOT(walkparams.sif);
        end;
    else
        // Apply leaf permissions
        case perms.ap[2] of
            when '0' => (r,w) = ('1','1'); // No effect
            when '1' => (r,w) = ('1','0'); // Read-only
        end;

        // Apply hierarchical permissions
        case perms.ap_table[1] of
            when '0' => (r,w) = ( r, w );  // No effect
            when '1' => (r,w) = ( r, '0'); // Read-only
        end;

        xn = perms.xn OR perms.xn_table;
        x  = NOT(xn OR (w AND walkparams.wxn));
    end;

    if accdesc.acctype == AccessType_IFETCH then
        let constraint : Constraint = ConstrainUnpredictable(Unpredictable_INSTRDEVICE);
        if constraint == Constraint_FAULT && memtype == MemType_Device then
            return TRUE;
        else
            return x == '0';
        end;
    elsif accdesc.acctype IN {AccessType_IC, AccessType_DC} then
        return FALSE;
    elsif accdesc.write then
        return w == '0';
    else
        return r == '0';
    end;
end;

// AArch32_S1SDHasPermissionsFault()
// =================================
// Returns whether an access using stage 1 short-descriptor translation
// violates permissions of target memory

func AArch32_S1SDHasPermissionsFault(regime : Regime, perms_in : Permissions, memtype : MemType,
                                     paspace : PASpace, accdesc : AccessDescriptor) => boolean
begin
    var perms : Permissions = perms_in;
    var pr, pw : bit;
    var ur, uw : bit;
    var sctlr : SCTLR_Type;
    if regime == Regime_EL30 then
        sctlr = SCTLR_S();
    elsif HaveEL(EL3) && ELUsingAArch32(EL3) then
        sctlr = SCTLR_NS();
    else
        sctlr = SCTLR();
    end;

    if sctlr.AFE == '0' then
        // Map Reserved encoding '100'
        if perms.ap == '100' then
            perms.ap = ImpDefBits{3}("Reserved short descriptor AP encoding");
        end;

        case perms.ap of
            when '000' => (pr,pw,ur,uw) = ('0','0','0','0'); // No access
            when '001' => (pr,pw,ur,uw) = ('1','1','0','0'); // R/W at PL1 only
            when '010' => (pr,pw,ur,uw) = ('1','1','1','0'); // R/W at PL1, RO at PL0
            when '011' => (pr,pw,ur,uw) = ('1','1','1','1'); // R/W at any PL
            //   '100' is reserved
            when '101' => (pr,pw,ur,uw) = ('1','0','0','0'); // RO at PL1 only
            when '110' => (pr,pw,ur,uw) = ('1','0','1','0'); // RO at any PL (deprecated)
            when '111' => (pr,pw,ur,uw) = ('1','0','1','0'); // RO at any PL
        end;
    else // Simplified access permissions model
        case perms.ap[2:1] of
            when '00' => (pr,pw,ur,uw) = ('1','1','0','0'); // R/W at PL1 only
            when '01' => (pr,pw,ur,uw) = ('1','1','1','1'); // R/W at any PL
            when '10' => (pr,pw,ur,uw) = ('1','0','0','0'); // RO at PL1 only
            when '11' => (pr,pw,ur,uw) = ('1','0','1','0'); // RO at any PL
        end;
    end;

    let ux : bit = ur AND NOT(perms.xn OR (uw AND sctlr.WXN));
    let px : bit = pr AND NOT(perms.xn OR perms.pxn OR (pw AND sctlr.WXN) OR (uw AND sctlr.UWXN));

    if IsFeatureImplemented(FEAT_PAN) && accdesc.pan then
        let pan : bit = PSTATE.PAN AND (ur OR uw);
        pr  = pr AND NOT(pan);
        pw  = pw AND NOT(pan);
    end;

    var (r,w,x) : (bit, bit, bit) = if accdesc.el == EL0 then (ur,uw,ux) else (pr,pw,px);

    // Prevent execution from Non-secure space by PE in Secure state if SIF is set
    if accdesc.ss == SS_Secure && paspace == PAS_NonSecure then
        x = x AND NOT(if ELUsingAArch32(EL3) then SCR().SIF else SCR_EL3().SIF);
    end;
    if accdesc.acctype == AccessType_IFETCH then
        if (memtype == MemType_Device &&
              ConstrainUnpredictable(Unpredictable_INSTRDEVICE) == Constraint_FAULT) then
            return TRUE;
        else
            return x == '0';
        end;
    elsif accdesc.acctype IN {AccessType_IC, AccessType_DC} then
        return FALSE;
    elsif accdesc.write then
        return w == '0';
    else
        return r == '0';
    end;
end;

// AArch32_S2HasAlignmentFaultDueToMemType()
// =========================================
// Returns whether stage 2 output fails alignment requirement on data accesses due to memory type

func AArch32_S2HasAlignmentFaultDueToMemType(accdesc : AccessDescriptor, aligned : boolean,
                                             memattrs : MemoryAttributes) => boolean
begin

    if memattrs.memtype != MemType_Device then
        return FALSE;
    elsif accdesc.acctype == AccessType_DCZero then
        return TRUE;
    elsif !aligned then
        return !(ImpDefBool("Device location supports unaligned access"));
    else
        return FALSE;
    end;
end;

// AArch32_S2HasPermissionsFault()
// ===============================
// Returns whether stage 2 access violates permissions of target memory

func AArch32_S2HasPermissionsFault(walkparams : S2TTWParams, perms : Permissions,
                                   memtype : MemType, accdesc : AccessDescriptor) => boolean
begin
    let r : bit = perms.s2ap[0];
    let w : bit = perms.s2ap[1];
    var x : bit;
    var ux : bit;
    var px : bit;
    if IsFeatureImplemented(FEAT_XNX) then
        case perms.s2xn::perms.s2xnx of
            when '00' =>  (px, ux) = ( r, r );
            when '01' =>  (px, ux) = ('0', r );
            when '10' =>  (px, ux) = ('0', '0');
            when '11' =>  (px, ux) = ( r, '0');
        end;

        x = if accdesc.el == EL0 then ux else px;
    else
        x = r AND NOT(perms.s2xn);
    end;

    if accdesc.acctype == AccessType_TTW then
        return (walkparams.ptw == '1' && memtype == MemType_Device) || r == '0';

    elsif accdesc.acctype == AccessType_IFETCH then
        let constraint : Constraint = ConstrainUnpredictable(Unpredictable_INSTRDEVICE);
        return (constraint == Constraint_FAULT && memtype == MemType_Device) || x == '0';

    elsif accdesc.acctype IN {AccessType_IC, AccessType_DC} then
        return FALSE;

    elsif accdesc.write then
        return w == '0';

    else
        return r == '0';
    end;
end;

// AArch32_S2InconsistentSL()
// ==========================
// Detect inconsistent configuration of stage 2 T0SZ and SL fields

func AArch32_S2InconsistentSL(walkparams : S2TTWParams) => boolean
begin
    let startlevel : integer      = AArch32_S2StartLevel(walkparams.sl0);
    let levels : integer          = FINAL_LEVEL - startlevel;
    let granulebits : AddressSize = TGxGranuleBits(walkparams.tgx);
    let stride : integer{}        = granulebits - 3;

    // Input address size must at least be large enough to be resolved from the start level
    let sl_min_iasize : integer = (
        levels * stride // Bits resolved by table walk, except initial level
        + granulebits   // Bits directly mapped to output address
        + 1);           // At least 1 more bit to be decoded by initial level

    // Can accomodate 1 more stride in the level + concatenation of up to 2^4 tables
    let sl_max_iasize : integer = sl_min_iasize + (stride-1) + 4;
    // Configured Input Address size
    let iasize : AddressSize        = AArch32_S2IASize(walkparams.t0sz);

    return iasize < sl_min_iasize || iasize > sl_max_iasize;
end;

// AArch32_VAIsOutOfRange()
// ========================
// Check virtual address bits not resolved by translation are identical
// and of accepted value

func AArch32_VAIsOutOfRange(regime : Regime, walkparams : S1TTWParams, va : bits(32)) => boolean
begin
    if regime == Regime_EL2 then
        // Input Address size
        let iasize : integer{} = AArch32_S1IASize(walkparams.t0sz);
        return walkparams.t0sz != '000' && !IsZero(va[31:iasize]);
    elsif walkparams.t1sz != '000' && walkparams.t0sz != '000' then
        // Lower range Input Address size
        let lo_iasize : integer{} = AArch32_S1IASize(walkparams.t0sz);
        // Upper range Input Address size
        let up_iasize : integer{} = AArch32_S1IASize(walkparams.t1sz);
        return !IsZero(va[31:lo_iasize]) && !IsOnes(va[31:up_iasize]);
    else
        return FALSE;
    end;
end;

// AArch32_GetS1TLBContext()
// =========================
// Gather translation context for accesses with VA to match against TLB entries

func AArch32_GetS1TLBContext(regime : Regime, ss : SecurityState, va : bits(32)) => TLBContext
begin
    var tlbcontext : TLBContext;

    case regime of
        when Regime_EL2  => tlbcontext = AArch32_TLBContextEL2(va);
        when Regime_EL10 => tlbcontext = AArch32_TLBContextEL10(ss, va);
        when Regime_EL30 => tlbcontext = AArch32_TLBContextEL30(va);
    end;

    tlbcontext.includes_s1 = TRUE;
    // The following may be amended for EL1&0 Regime if caching of stage 2 is successful
    tlbcontext.includes_s2 = FALSE;
    return tlbcontext;
end;

// AArch32_GetS2TLBContext()
// =========================
// Gather translation context for accesses with IPA to match against TLB entries

func AArch32_GetS2TLBContext(ipa : FullAddress) => TLBContext
begin
    assert ipa.paspace == PAS_NonSecure;

    var tlbcontext : TLBContext;

    tlbcontext.ss          = SS_NonSecure;
    tlbcontext.regime      = Regime_EL10;
    tlbcontext.ipaspace    = ipa.paspace;
    tlbcontext.vmid        = ZeroExtend{16}(VTTBR().VMID);
    tlbcontext.tg          = TGx_4KB;
    tlbcontext.includes_s1 = FALSE;
    tlbcontext.includes_s2 = TRUE;
    tlbcontext.ia          = ZeroExtend{64}(ipa.address);
    tlbcontext.cnp         = if IsFeatureImplemented(FEAT_TTCNP) then VTTBR().CnP else '0';

    return tlbcontext;
end;

// AArch32_TLBContextEL10()
// ========================
// Gather translation context for accesses under EL10 regime
// (PL10 when EL3 is A64) to match against TLB entries

func AArch32_TLBContextEL10(ss : SecurityState, va : bits(32)) => TLBContext
begin
    var tlbcontext : TLBContext;
    var ttbcr : TTBCR_Type;
    var ttbr0 : TTBR0_Type;
    var ttbr1 : TTBR1_Type;
    var contextidr : CONTEXTIDR_Type;

    if HaveEL(EL3) && ELUsingAArch32(EL3) then
        ttbcr      = TTBCR_NS();
        ttbr0      = TTBR0_NS();
        ttbr1      = TTBR1_NS();
        contextidr = CONTEXTIDR_NS();
    else
        ttbcr      = TTBCR();
        ttbr0      = TTBR0();
        ttbr1      = TTBR1();
        contextidr = CONTEXTIDR();
    end;

    tlbcontext.ss     = ss;
    tlbcontext.regime = Regime_EL10;

    if AArch32_EL2Enabled(ss) then
        tlbcontext.vmid = ZeroExtend{16}(VTTBR().VMID);
    end;

    if ttbcr.EAE == '1' then
        tlbcontext.asid = ZeroExtend{16}(if ttbcr.A1 == '0' then ttbr0.ASID else ttbr1.ASID);
    else
        tlbcontext.asid = ZeroExtend{16}(contextidr.ASID);
    end;

    tlbcontext.tg = TGx_4KB;
    tlbcontext.ia = ZeroExtend{64}(va);

    if IsFeatureImplemented(FEAT_TTCNP) && ttbcr.EAE == '1' then
        if AArch32_GetVARange(va, ttbcr.T0SZ, ttbcr.T1SZ) == VARange_LOWER then
            tlbcontext.cnp = ttbr0.CnP;
        else
            tlbcontext.cnp = ttbr1.CnP;
        end;
    else
        tlbcontext.cnp = '0';
    end;

    return tlbcontext;
end;

// AArch32_TLBContextEL2()
// =======================
// Gather translation context for accesses under EL2 regime to match against TLB entries

func AArch32_TLBContextEL2(va : bits(32)) => TLBContext
begin
    var tlbcontext : TLBContext;

    tlbcontext.ss     = SS_NonSecure;
    tlbcontext.regime = Regime_EL2;
    tlbcontext.ia     = ZeroExtend{64}(va);
    tlbcontext.tg     = TGx_4KB;
    tlbcontext.cnp    = if IsFeatureImplemented(FEAT_TTCNP) then HTTBR().CnP else '0';

    return tlbcontext;
end;

// AArch32_TLBContextEL30()
// ========================
// Gather translation context for accesses under EL30 regime
// (PL10 in Secure state and EL3 is A32) to match against TLB entries

func AArch32_TLBContextEL30(va : bits(32)) => TLBContext
begin
    var tlbcontext : TLBContext;

    tlbcontext.ss     = SS_Secure;
    tlbcontext.regime = Regime_EL30;

    if TTBCR_S().EAE == '1' then
        tlbcontext.asid = ZeroExtend{16}(if TTBCR_S().A1 == '0' then TTBR0_S().ASID
                                                                      else TTBR1_S().ASID);
    else
        tlbcontext.asid = ZeroExtend{16}(CONTEXTIDR_S().ASID);
    end;

    tlbcontext.tg = TGx_4KB;
    tlbcontext.ia = ZeroExtend{64}(va);

    if IsFeatureImplemented(FEAT_TTCNP) && TTBCR_S().EAE == '1' then
        if AArch32_GetVARange(va, TTBCR_S().T0SZ, TTBCR_S().T1SZ) == VARange_LOWER then
            tlbcontext.cnp = TTBR0_S().CnP;
        else
            tlbcontext.cnp = TTBR1_S().CnP;
        end;
    else
        tlbcontext.cnp = '0';
    end;

    return tlbcontext;
end;

// AArch32_EL2Enabled()
// ====================
// Returns whether EL2 is enabled for the given Security State

func AArch32_EL2Enabled(ss : SecurityState) => boolean
begin
    if ss == SS_Secure then
        if !(HaveEL(EL2) && IsFeatureImplemented(FEAT_SEL2)) then
            return FALSE;
        elsif HaveEL(EL3) then
            return SCR_EL3().EEL2 == '1';
        else
            return ImpDefBool("Secure-only implementation");
        end;
    else
        return HaveEL(EL2);
    end;
end;

// AArch32_FullTranslate()
// =======================
// Perform address translation as specified by VMSA-A32

func AArch32_FullTranslate(va : bits(32), accdesc : AccessDescriptor,
                           aligned : boolean) => AddressDescriptor
begin

    // Prepare fault fields in case a fault is detected
    var fault : FaultRecord = NoFault(accdesc, ZeroExtend{64}(va));
    let regime : Regime = TranslationRegime(accdesc.el);

    // First Stage Translation
    var ipa : AddressDescriptor;
    if regime == Regime_EL2 || TTBCR().EAE == '1' then
        (fault, ipa)    = AArch32_S1TranslateLD(fault, regime, va, aligned, accdesc);
    else
        (fault, ipa, -) = AArch32_S1TranslateSD(fault, regime, va, aligned, accdesc);
    end;

    if fault.statuscode != Fault_None then
        return CreateFaultyAddressDescriptor(fault);
    end;

    if regime == Regime_EL10 && EL2Enabled() then
        ipa.vaddress = ZeroExtend{64}(va);
        var pa : AddressDescriptor;
        (fault, pa) = AArch32_S2Translate(fault, ipa, aligned, accdesc);

        if fault.statuscode != Fault_None then
            return CreateFaultyAddressDescriptor(fault);
        else
            return pa;
        end;
    else
        return ipa;
    end;
end;

// AArch32_OutputDomain()
// ======================
// Determine the domain the translated output address

func AArch32_OutputDomain(regime : Regime, domain : bits(4)) => bits(2)
begin
    var Dn : bits(2);
    if regime == Regime_EL30 then
        Dn = DACR_S()[UInt(domain)*:2];
    elsif HaveEL(EL3) && ELUsingAArch32(EL3) then
        Dn = DACR_NS()[UInt(domain)*:2];
    else
        Dn = DACR()[UInt(domain)*:2];
    end;

    if Dn == '10' then
        // Reserved value maps to an allocated value
        (-, Dn) = ConstrainUnpredictableBits{2}(Unpredictable_RESDACR);
    end;

    return Dn;
end;

// AArch32_S1DisabledOutput()
// ==========================
// Flat map the VA to IPA/PA, depending on the regime, assigning default memory attributes

func AArch32_S1DisabledOutput(fault_in : FaultRecord, regime : Regime,
                              va : bits(32), aligned : boolean,
                              accdesc : AccessDescriptor) => (FaultRecord, AddressDescriptor)
begin

    var fault : FaultRecord = fault_in;
    // No memory page is guarded when stage 1 address translation is disabled
    SetInGuardedPage(FALSE);

    var memattrs : MemoryAttributes;
    var default_cacheable : bit;
    if regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) then
        if ELStateUsingAArch32(EL2, accdesc.ss == SS_Secure) then
            default_cacheable = HCR().DC;
        else
            default_cacheable = HCR_EL2().DC;
        end;
    else
        default_cacheable = '0';
    end;

    if default_cacheable == '1' then
        // Use default cacheable settings
        memattrs.memtype      = MemType_Normal;
        memattrs.inner.attrs  = MemAttr_WB;
        memattrs.inner.hints  = MemHint_RWA;
        memattrs.outer.attrs  = MemAttr_WB;
        memattrs.outer.hints  = MemHint_RWA;
        memattrs.shareability = Shareability_NSH;
        if (EL2Enabled() && !ELStateUsingAArch32(EL2, accdesc.ss == SS_Secure) &&
              IsFeatureImplemented(FEAT_MTE2) && HCR_EL2().DCT == '1') then
            memattrs.tags     = MemTag_AllocationTagged;
        else
            memattrs.tags     = MemTag_Untagged;
        end;
        memattrs.xs           = '0';
    elsif accdesc.acctype == AccessType_IFETCH then
        memattrs.memtype      = MemType_Normal;
        memattrs.shareability = Shareability_OSH;
        memattrs.tags         = MemTag_Untagged;
        if AArch32_S1ICacheEnabled(regime) then
            memattrs.inner.attrs = MemAttr_WT;
            memattrs.inner.hints = MemHint_RA;
            memattrs.outer.attrs = MemAttr_WT;
            memattrs.outer.hints = MemHint_RA;
        else
            memattrs.inner.attrs = MemAttr_NC;
            memattrs.outer.attrs = MemAttr_NC;
        end;
        memattrs.xs           = '1';
    else
        // Treat memory region as Device
        memattrs.memtype      = MemType_Device;
        memattrs.device       = DeviceType_nGnRnE;
        memattrs.shareability = Shareability_OSH;
        memattrs.tags         = MemTag_Untagged;
        memattrs.xs           = '1';
    end;

    var ntlsmd : bit;
    if IsFeatureImplemented(FEAT_LSMAOC) then
        case regime of
            when Regime_EL30 => ntlsmd = SCTLR_S().nTLSMD;
            when Regime_EL2  => ntlsmd = HSCTLR().nTLSMD;
            when Regime_EL10 =>
                if HaveEL(EL3) && ELUsingAArch32(EL3) then
                    ntlsmd = SCTLR_NS().nTLSMD;
                else
                    ntlsmd = SCTLR().nTLSMD;
                end;
        end;
    else
        ntlsmd = '1';
    end;

    if AArch32_S1HasAlignmentFaultDueToMemType(accdesc, aligned, ntlsmd, memattrs) then
        fault.statuscode  = Fault_Alignment;
        return (fault, ARBITRARY : AddressDescriptor);
    elsif (accdesc.exclusive &&
            !(regime == Regime_EL10 && EL2Enabled() &&
               ((!ELUsingAArch32(EL2) && HCR_EL2().DC == '1') ||
                  (ELUsingAArch32(EL2) && HCR().DC == '1'))) &&
            ConstrainUnpredictableBool(Unpredictable_Atomic_MMU_IMPDEF_FAULT)) then
        fault.statuscode = Fault_Exclusive;
    end;

    var oa : FullAddress;
    oa.address = ZeroExtend{56}(va);
    oa.paspace = if accdesc.ss == SS_Secure then PAS_Secure else PAS_NonSecure;
    let ipa : AddressDescriptor = CreateAddressDescriptor(ZeroExtend{64}(va),
                                                          oa, memattrs, accdesc);

    return (fault, ipa);
end;

// AArch32_S1Enabled()
// ===================
// Returns whether stage 1 translation is enabled for the active translation regime

func AArch32_S1Enabled(regime : Regime, ss : SecurityState) => boolean
begin
    if regime == Regime_EL2 then
        return HSCTLR().M == '1';
    elsif regime == Regime_EL30 then
        return SCTLR_S().M == '1';
    elsif !AArch32_EL2Enabled(ss) then
        return (if HaveEL(EL3) && ELUsingAArch32(EL3) then SCTLR_NS().M else SCTLR().M) == '1';
    elsif ELStateUsingAArch32(EL2, ss == SS_Secure) then
        if HaveEL(EL3) && ELUsingAArch32(EL3) then
            return HCR().[TGE,DC] == '00' && SCTLR_NS().M == '1';
        else
            return HCR().[TGE,DC] == '00' && SCTLR().M == '1';
        end;
    else
        return EL2Enabled() && HCR_EL2().[TGE,DC] == '00' && SCTLR().M == '1';
    end;
end;

// AArch32_S1TranslateLD()
// =======================
// Perform a stage 1 translation using long-descriptor format mapping VA to IPA/PA
// depending on the regime

func AArch32_S1TranslateLD(fault_in : FaultRecord, regime : Regime,
                           va : bits(32), aligned : boolean,
                           accdesc : AccessDescriptor) => (FaultRecord, AddressDescriptor)
begin
    var fault : FaultRecord = fault_in;

    if !AArch32_S1Enabled(regime, accdesc.ss) then
        return AArch32_S1DisabledOutput(fault, regime, va, aligned, accdesc);
    end;

    let walkparams : S1TTWParams = AArch32_GetS1TTWParams(regime, va);

    if AArch32_VAIsOutOfRange(regime, walkparams, va) then
        fault.level      = 1;
        fault.statuscode = Fault_Translation;
        return (fault, ARBITRARY : AddressDescriptor);
    end;

    var walkstate : TTWState;
    (fault, walkstate) = AArch32_S1WalkLD(fault, regime, walkparams, accdesc, va);

    if fault.statuscode != Fault_None then
        return (fault, ARBITRARY : AddressDescriptor);
    end;

    SetInGuardedPage(FALSE);  // AArch32-VMSA does not guard any pages

    if AArch32_S1HasAlignmentFaultDueToMemType(accdesc, aligned, walkparams.ntlsmd,
                                               walkstate.memattrs) then
        fault.statuscode = Fault_Alignment;
    elsif AArch32_S1LDHasPermissionsFault(regime, walkparams,
                                          walkstate.permissions,
                                          walkstate.memattrs.memtype,
                                          walkstate.baseaddress.paspace,
                                          accdesc) then
        fault.statuscode = Fault_Permission;
    end;

    if fault.statuscode != Fault_None then
        return (fault, ARBITRARY : AddressDescriptor);
    end;

    var memattrs : MemoryAttributes;
    if ((accdesc.acctype == AccessType_IFETCH &&
            (walkstate.memattrs.memtype == MemType_Device || !AArch32_S1ICacheEnabled(regime))) ||
        (accdesc.acctype != AccessType_IFETCH &&
             walkstate.memattrs.memtype == MemType_Normal && !AArch32_S1DCacheEnabled(regime))) then
        // Treat memory attributes as Normal Non-Cacheable
        memattrs = NormalNCMemAttr();
        memattrs.xs = walkstate.memattrs.xs;
    else
        memattrs = walkstate.memattrs;
    end;

    // Shareability value of stage 1 translation subject to stage 2 is IMPLEMENTATION DEFINED
    // to be either effective value or descriptor value
    if (regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) &&
        (if ELStateUsingAArch32(EL2, accdesc.ss==SS_Secure) then HCR().VM
                                                            else HCR_EL2().VM) == '1' &&
        !(ImpDefBool("Apply effective shareability at stage 1"))) then
        memattrs.shareability = walkstate.memattrs.shareability;
    else
        memattrs.shareability = EffectiveShareability(memattrs);
    end;

    // Output Address
    let oa : FullAddress = StageOA(ZeroExtend{64}(va), walkparams.d128, walkparams.tgx, walkstate);
    let ipa : AddressDescriptor = CreateAddressDescriptor(ZeroExtend{64}(va),
                                                          oa, memattrs, accdesc);

    return (fault, ipa);
end;

// AArch32_S1TranslateSD()
// =======================
// Perform a stage 1 translation using short-descriptor format mapping VA to IPA/PA
// depending on the regime

func AArch32_S1TranslateSD(fault_in : FaultRecord, regime : Regime,
                           va : bits(32), aligned : boolean,
                           accdesc : AccessDescriptor) => (FaultRecord, AddressDescriptor, SDFType)
begin

    var fault : FaultRecord = fault_in;

    if !AArch32_S1Enabled(regime, accdesc.ss) then
        var ipa : AddressDescriptor;
        (fault, ipa) = AArch32_S1DisabledOutput(fault, regime, va, aligned, accdesc);
        return (fault, ipa, ARBITRARY : SDFType);
    end;

    var walkstate : TTWState;
    (fault, walkstate) = AArch32_S1WalkSD(fault, regime, accdesc, va);

    if fault.statuscode != Fault_None then
        return (fault, ARBITRARY : AddressDescriptor, ARBITRARY : SDFType);
    end;

    let domain : bits(2) = AArch32_OutputDomain(regime, walkstate.domain);
    SetInGuardedPage(FALSE);  // AArch32-VMSA does not guard any pages

    var ntlsmd : bit;
    if IsFeatureImplemented(FEAT_LSMAOC) then
        case regime of
            when Regime_EL30 => ntlsmd = SCTLR_S().nTLSMD;
            when Regime_EL10 =>
                if HaveEL(EL3) && ELUsingAArch32(EL3) then
                    ntlsmd = SCTLR_NS().nTLSMD;
                else
                    ntlsmd = SCTLR().nTLSMD;
                end;
        end;
    else
        ntlsmd = '1';
    end;

    if AArch32_S1HasAlignmentFaultDueToMemType(accdesc, aligned, ntlsmd, walkstate.memattrs) then
        fault.statuscode = Fault_Alignment;
    elsif (! accdesc.acctype IN {AccessType_IC, AccessType_DC} &&
           domain == Domain_NoAccess) then
        fault.statuscode = Fault_Domain;
    elsif domain == Domain_Client then
        if AArch32_S1SDHasPermissionsFault(regime, walkstate.permissions,
                                           walkstate.memattrs.memtype,
                                           walkstate.baseaddress.paspace,
                                           accdesc) then
            fault.statuscode = Fault_Permission;
        end;
    end;

    if fault.statuscode != Fault_None then
        fault.domain = walkstate.domain;
        return (fault, ARBITRARY : AddressDescriptor, walkstate.sdftype);
    end;

    var memattrs : MemoryAttributes;
    if ((accdesc.acctype == AccessType_IFETCH &&
            (walkstate.memattrs.memtype == MemType_Device || !AArch32_S1ICacheEnabled(regime))) ||
        (accdesc.acctype != AccessType_IFETCH &&
             walkstate.memattrs.memtype == MemType_Normal && !AArch32_S1DCacheEnabled(regime))) then
        // Treat memory attributes as Normal Non-Cacheable
        memattrs = NormalNCMemAttr();
        memattrs.xs = walkstate.memattrs.xs;
    else
        memattrs = walkstate.memattrs;
    end;
    // Shareability value of stage 1 translation subject to stage 2 is IMPLEMENTATION DEFINED
    // to be either effective value or descriptor value
    if (regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) &&
        (if ELStateUsingAArch32(EL2, accdesc.ss==SS_Secure) then HCR().VM
                                                            else HCR_EL2().VM) == '1' &&
        !(ImpDefBool("Apply effective shareability at stage 1"))) then
        memattrs.shareability = walkstate.memattrs.shareability;
    else
        memattrs.shareability = EffectiveShareability(memattrs);
    end;
    // Output Address
    let oa : FullAddress = AArch32_SDStageOA(walkstate.baseaddress, va, walkstate.sdftype);
    let ipa : AddressDescriptor = CreateAddressDescriptor(ZeroExtend{64}(va),
                                                          oa, memattrs, accdesc);

    return (fault, ipa, walkstate.sdftype);
end;

// AArch32_S2Translate()
// =====================
// Perform a stage 2 translation mapping an IPA to a PA

func AArch32_S2Translate(fault_in : FaultRecord, ipa : AddressDescriptor,
                         aligned : boolean, accdesc : AccessDescriptor
                        ) => (FaultRecord, AddressDescriptor)
begin

    var fault : FaultRecord = fault_in;
    assert IsZero(ipa.paddress.address[55:40]);
    if !ELStateUsingAArch32(EL2, accdesc.ss == SS_Secure) then
        let s1aarch64 : boolean = FALSE;
        return AArch64_S2Translate(fault, ipa, s1aarch64, aligned, accdesc);
    end;
    // Prepare fault fields in case a fault is detected
    fault.statuscode  = Fault_None;
    fault.secondstage = TRUE;
    fault.s2fs1walk   = accdesc.acctype == AccessType_TTW;
    fault.ipaddress   = ipa.paddress;

    let walkparams : S2TTWParams = AArch32_GetS2TTWParams();

    if walkparams.vm == '0' then
        // Stage 2 is disabled
        return (fault, ipa);
    end;

    if AArch32_IPAIsOutOfRange(walkparams, ipa.paddress.address[39:0]) then
        fault.statuscode = Fault_Translation;
        fault.level      = 1;
        return (fault, ARBITRARY : AddressDescriptor);
    end;

    var walkstate : TTWState;
    (fault, walkstate) = AArch32_S2Walk(fault, walkparams, accdesc, ipa);

    if fault.statuscode != Fault_None then
        return (fault, ARBITRARY : AddressDescriptor);
    end;

    if AArch32_S2HasAlignmentFaultDueToMemType(accdesc, aligned, walkstate.memattrs) then
        fault.statuscode = Fault_Alignment;
    elsif AArch32_S2HasPermissionsFault(walkparams,
                                        walkstate.permissions,
                                        walkstate.memattrs.memtype,
                                        accdesc) then
        fault.statuscode = Fault_Permission;
    end;
    var s2_memattrs : MemoryAttributes;
    if ((accdesc.acctype == AccessType_TTW &&
             walkstate.memattrs.memtype == MemType_Device) ||
        (accdesc.acctype == AccessType_IFETCH &&
            (walkstate.memattrs.memtype == MemType_Device || HCR2().ID == '1')) ||
        (accdesc.acctype != AccessType_IFETCH &&
             walkstate.memattrs.memtype == MemType_Normal && HCR2().CD == '1')) then
        // Treat memory attributes as Normal Non-Cacheable
        s2_memattrs = NormalNCMemAttr();
        s2_memattrs.xs = walkstate.memattrs.xs;
    else
        s2_memattrs = walkstate.memattrs;
    end;

    let s2aarch64 : boolean = FALSE;
    let memattrs : MemoryAttributes = S2CombineS1MemAttrs(ipa.memattrs, s2_memattrs, s2aarch64);
    let ipa_64 : bits(64) = ZeroExtend{}(ipa.paddress.address[39:0]);
    // Output Address
    let oa : FullAddress = StageOA(ipa_64, walkparams.d128, walkparams.tgx, walkstate);
    let pa : AddressDescriptor = CreateAddressDescriptor(ipa.vaddress, oa, memattrs, accdesc);

    return (fault, pa);
end;

// AArch32_SDStageOA()
// ===================
// Given the final walk state of a short-descriptor translation walk,
// map the untranslated input address bits to the base output address

func AArch32_SDStageOA(baseaddress : FullAddress, va : bits(32), sdftype : SDFType) => FullAddress
begin
    let tsize : integer{} = SDFSize(sdftype);

    // Output Address
    var oa : FullAddress;
    oa.address = baseaddress.address[55:tsize] :: va[tsize-1:0];
    oa.paspace = baseaddress.paspace;
    return oa;
end;

// AArch32_TranslateAddress()
// ==========================
// Main entry point for translating an address

func AArch32_TranslateAddress(va : bits(32), accdesc : AccessDescriptor,
                              aligned : boolean, size : integer) => AddressDescriptor
begin

    let regime : Regime = TranslationRegime(PSTATE.EL);
    if !RegimeUsingAArch32(regime) then
        return AArch64_TranslateAddress(ZeroExtend{64}(va), accdesc, aligned, size);
    end;

    var result : AddressDescriptor = AArch32_FullTranslate(va, accdesc, aligned);

    if !IsFault(result) && accdesc.acctype != AccessType_IFETCH then
        // For an instruction fetch, CheckDebug will be called
        // after the instruction is read from memory
        result.fault = AArch32_CheckDebug(va, accdesc, size);
    end;

    // Update virtual address for abort functions
    result.vaddress = ZeroExtend{64}(va);

    return result;
end;

// SDFSize()
// =========
// Returns the short-descriptor format translation granule size

func SDFSize(sdftype : SDFType) => AddressSize
begin
    case sdftype of
        when SDFType_SmallPage =>    return 12;
        when SDFType_LargePage =>    return 16;
        when SDFType_Section =>      return 20;
        when SDFType_Supersection => return 24;
        otherwise => unreachable;
    end;
end;

// AArch32_DecodeDescriptorTypeLD()
// ================================
// Determine whether the long-descriptor is a page, block or table

func AArch32_DecodeDescriptorTypeLD(descriptor : bits(64), level : integer) => DescriptorType
begin
    if descriptor[1:0] == '11' && level == FINAL_LEVEL then
        return DescriptorType_Leaf;
    elsif descriptor[1:0] == '11' then
        return DescriptorType_Table;
    elsif descriptor[1:0] == '01' && level != FINAL_LEVEL then
        return DescriptorType_Leaf;
    else
        return DescriptorType_Invalid;
    end;
end;

// AArch32_DecodeDescriptorTypeSD()
// ================================
// Determine the type of the short-descriptor

func AArch32_DecodeDescriptorTypeSD(descriptor : bits(32), level : integer) => SDFType
begin
    if level == 1 && descriptor[1:0] == '01' then
        return SDFType_Table;
    elsif level == 1 && descriptor[18,1] == '01' then
        return SDFType_Section;
    elsif level == 1 && descriptor[18,1] == '11' then
        return SDFType_Supersection;
    elsif level == 2 && descriptor[1:0] == '01' then
        return SDFType_LargePage;
    elsif level == 2 && descriptor[1:0] == '1x' then
        return SDFType_SmallPage;
    else
        return SDFType_Invalid;
    end;
end;

// AArch32_S1IASize()
// ==================
// Retrieve the number of bits containing the input address for stage 1 translation

func AArch32_S1IASize(txsz : bits(3)) => AddressSize
begin
    return 32 - UInt(txsz);
end;

// AArch32_S1WalkLD()
// ==================
// Traverse stage 1 translation tables in long format to obtain the final descriptor

func AArch32_S1WalkLD(fault_in : FaultRecord, regime : Regime,
                      walkparams : S1TTWParams, accdesc : AccessDescriptor,
                      va : bits(32)) => (FaultRecord, TTWState)
begin
    var fault : FaultRecord = fault_in;
    var txsz : bits(3);
    var ttbr : bits(64);
    var epd : bit;
    var varange : VARange;
    if regime == Regime_EL2 then
        ttbr = HTTBR();
        txsz = walkparams.t0sz;
        varange = VARange_LOWER;
    else
        varange = AArch32_GetVARange(va, walkparams.t0sz, walkparams.t1sz);
        var ttbr0 : bits(64);
        var ttbr1 : bits(64);
        var ttbcr : TTBCR_Type;
        if regime == Regime_EL30 then
            ttbcr = TTBCR_S();
            ttbr0 = TTBR0_S();
            ttbr1 = TTBR1_S();
        elsif HaveEL(EL3) && ELUsingAArch32(EL3) then
            ttbcr = TTBCR_NS();
            ttbr0 = TTBR0_NS();
            ttbr1 = TTBR1_NS();
        else
            ttbcr = TTBCR();
            ttbr0 = TTBR0();
            ttbr1 = TTBR1();
        end;

        assert ttbcr.EAE == '1';
        if varange == VARange_LOWER then
            txsz = walkparams.t0sz;
            ttbr = ttbr0;
            epd  = ttbcr.EPD0;
        else
            txsz = walkparams.t1sz;
            ttbr = ttbr1;
            epd  = ttbcr.EPD1;
        end;
    end;

    if regime != Regime_EL2 && epd == '1' then
        fault.level      = 1;
        fault.statuscode = Fault_Translation;
        return (fault, ARBITRARY : TTWState);
    end;

    // Input Address size
    let iasize : AddressSize      = AArch32_S1IASize(txsz);
    let granulebits : integer{} = TGxGranuleBits(walkparams.tgx) as integer{12, 14, 16};
    let stride : integer{}      = granulebits - 3;
    let startlevel : integer  = FINAL_LEVEL - (((iasize-1) - granulebits) DIVRM stride);
    let levels : integer      = FINAL_LEVEL - startlevel;

    if !IsZero(ttbr[47:40]) then
        fault.statuscode = Fault_AddressSize;
        fault.level      = 0;
        return (fault, ARBITRARY : TTWState);
    end;

    var baseaddress : FullAddress;
    let baselsb = ((iasize - (levels*stride + granulebits)) + 3) as AddressSize;
    baseaddress.paspace = if accdesc.ss == SS_Secure then PAS_Secure else PAS_NonSecure;
    baseaddress.address = ZeroExtend{56}(ttbr[39:baselsb]::Zeros{baselsb});

    var walkstate : TTWState;
    walkstate.baseaddress = baseaddress;
    walkstate.level       = startlevel;
    walkstate.istable     = TRUE;
    // In regimes that support global and non-global translations, translation
    // table entries from lookup levels other than the final level of lookup
    // are treated as being non-global
    walkstate.nG          = if HasUnprivileged(regime) then '1' else '0';
    walkstate.memattrs    = WalkMemAttrs(walkparams.sh, walkparams.irgn, walkparams.orgn);
    walkstate.permissions.ap_table  = '00';
    walkstate.permissions.xn_table  = '0';
    walkstate.permissions.pxn_table = '0';

    var descriptor : bits(64);
    var walkaddress : AddressDescriptor;

    walkaddress.vaddress = ZeroExtend{64}(va);

    if !AArch32_S1DCacheEnabled(regime) then
        walkaddress.memattrs = NormalNCMemAttr();
        walkaddress.memattrs.xs = walkstate.memattrs.xs;
    else
        walkaddress.memattrs = walkstate.memattrs;
    end;

    // Shareability value of stage 1 translation subject to stage 2 is IMPLEMENTATION DEFINED
    // to be either effective value or descriptor value
    if (regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) &&
        (if ELStateUsingAArch32(EL2, accdesc.ss==SS_Secure) then HCR().VM
                                                            else HCR_EL2().VM) == '1' &&
        !(ImpDefBool("Apply effective shareability at stage 1"))) then
        walkaddress.memattrs.shareability = walkstate.memattrs.shareability;
    else
        walkaddress.memattrs.shareability = EffectiveShareability(walkaddress.memattrs);
    end;

    var desctype : DescriptorType;
    var msb_residual : integer = iasize - 1;
    repeat
        fault.level = walkstate.level;
        let indexlsb = ((FINAL_LEVEL - walkstate.level)*stride + granulebits) as AddressSize;
        let indexmsb = msb_residual as AddressSize;
        let index : bits(40) = ZeroExtend{}(va[indexmsb:indexlsb]::'000');

        walkaddress.paddress.address = (walkstate.baseaddress.address OR
                                            ZeroExtend{56}(index));
        walkaddress.paddress.paspace = walkstate.baseaddress.paspace;

        let toplevel : boolean = walkstate.level == startlevel;
        let walkaccess : AccessDescriptor = CreateAccDescS1TTW(toplevel, varange, accdesc);
        // If there are two stages of translation, then the first stage table walk addresses
        // are themselves subject to translation
        if regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) then
            let s2aligned : boolean = TRUE;
            let (s2fault, s2walkaddress) = AArch32_S2Translate(fault, walkaddress, s2aligned,
                                                               walkaccess);
            // Check for a fault on the stage 2 walk
            if s2fault.statuscode != Fault_None then
                return (s2fault, ARBITRARY : TTWState);
            end;

            (fault, descriptor) = FetchDescriptor{64}(walkparams.ee, s2walkaddress, walkaccess,
                                                      fault);
        else
            (fault, descriptor) = FetchDescriptor{64}(walkparams.ee, walkaddress, walkaccess,
                                                      fault);
        end;

        if fault.statuscode != Fault_None then
            return (fault, ARBITRARY : TTWState);
        end;

        desctype = AArch32_DecodeDescriptorTypeLD(descriptor, walkstate.level);

        case desctype of
            when DescriptorType_Table =>
                if !IsZero(descriptor[47:40]) then
                    fault.statuscode = Fault_AddressSize;
                    return (fault, ARBITRARY : TTWState);
                end;

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[39:12]::
                                                                       Zeros{12});
                if walkstate.baseaddress.paspace == PAS_Secure && descriptor[63] == '1' then
                    walkstate.baseaddress.paspace = PAS_NonSecure;
                end;
                if walkparams.hpd == '0' then
                    walkstate.permissions.xn_table  = (walkstate.permissions.xn_table  OR
                                                        descriptor[60]);
                    walkstate.permissions.ap_table  = (walkstate.permissions.ap_table  OR
                                                        descriptor[62:61]);
                    walkstate.permissions.pxn_table = (walkstate.permissions.pxn_table OR
                                                        descriptor[59]);
                end;
                walkstate.level = walkstate.level + 1;
                msb_residual = indexlsb - 1;

            when DescriptorType_Invalid =>
                fault.statuscode = Fault_Translation;
                return (fault, ARBITRARY : TTWState);

            when DescriptorType_Leaf =>
                walkstate.istable = FALSE;
        end;

    until desctype == DescriptorType_Leaf looplimit 3;

    // Check the output address is inside the supported range
    if !IsZero(descriptor[47:40]) then
        fault.statuscode = Fault_AddressSize;
        return (fault, ARBITRARY : TTWState);
    end;

    // Check the access flag
    if descriptor[10] == '0' then
        fault.statuscode = Fault_AccessFlag;
        return (fault, ARBITRARY : TTWState);
    end;

    walkstate.permissions.xn  = descriptor[54];
    walkstate.permissions.pxn = descriptor[53];
    walkstate.permissions.ap  = descriptor[7:6]::'1';
    walkstate.contiguous      = descriptor[52];
    if regime == Regime_EL2 then
        // All EL2 regime accesses are treated as Global
        walkstate.nG = '0';
    elsif accdesc.ss == SS_Secure && walkstate.baseaddress.paspace == PAS_NonSecure then
        // When a PE is using the Long-descriptor translation table format,
        // and is in Secure state, a translation must be treated as non-global,
        // regardless of the value of the nG bit,
        // if NSTable is set to 1 at any level of the translation table walk.
        walkstate.nG = '1';
    else
        walkstate.nG = descriptor[11];
    end;

    let indexlsb = ((FINAL_LEVEL - walkstate.level)*stride + granulebits) as AddressSize;
    walkstate.baseaddress.address = ZeroExtend{56}(descriptor[39:indexlsb]::
                                                           Zeros{indexlsb});
    if walkstate.baseaddress.paspace == PAS_Secure && descriptor[5] == '1' then
        walkstate.baseaddress.paspace = PAS_NonSecure;
    end;

    let memattr : bits(3) = descriptor[4:2];
    let sh : bits(2)      = descriptor[9:8];
    let attr : bits(8)    = AArch32_MAIRAttr(UInt(memattr), walkparams.mair);
    let s1aarch64 : boolean = FALSE;
    walkstate.memattrs = S1DecodeMemAttrs(attr, sh, s1aarch64);

    return (fault, walkstate);
end;

// AArch32_S1WalkSD()
// ==================
// Traverse stage 1 translation tables in short format to obtain the final descriptor

func AArch32_S1WalkSD(fault_in : FaultRecord, regime : Regime,
                      accdesc : AccessDescriptor, va : bits(32)) => (FaultRecord, TTWState)
begin
    var fault : FaultRecord = fault_in;
    var sctlr : SCTLR_Type;
    var ttbcr : TTBCR_Type;
    var ttbr0 : TTBR0_Type;
    var ttbr1 : TTBR1_Type;
    // Determine correct translation control registers to use.
    if regime == Regime_EL30 then
        sctlr = SCTLR_S();
        ttbcr = TTBCR_S();
        ttbr0 = TTBR0_S();
        ttbr1 = TTBR1_S();
    elsif HaveEL(EL3) && ELUsingAArch32(EL3) then
        sctlr = SCTLR_NS();
        ttbcr = TTBCR_NS();
        ttbr0 = TTBR0_NS();
        ttbr1 = TTBR1_NS();
    else
        sctlr = SCTLR();
        ttbcr = TTBCR();
        ttbr0 = TTBR0();
        ttbr1 = TTBR1();
    end;

    assert ttbcr.EAE == '0';
    let ee : bit  = sctlr.EE;
    let afe : bit = sctlr.AFE;
    let tre : bit = sctlr.TRE;
    let ttbcr_n : integer{} = UInt(ttbcr.N);
    let varange : VARange = (if ttbcr_n == 0 || IsZero(va[31:(32-ttbcr_n)]) then VARange_LOWER
                                else VARange_UPPER);
    let n : integer{} = if varange == VARange_LOWER then ttbcr_n else 0;
    var ttb : bits(32);
    var pd : bits(1);
    var irgn : bits(2);
    var rgn : bits(2);
    var s : bits(1);
    var nos : bits(1);
    if varange == VARange_LOWER then
        ttb  = ttbr0.TTB0::Zeros{7};
        pd   = ttbcr.PD0;
        irgn = ttbr0.IRGN;
        rgn  = ttbr0.RGN;
        s    = ttbr0.S;
        nos  = ttbr0.NOS;
    else
        ttb  = ttbr1.TTB1::Zeros{7};
        pd   = ttbcr.PD1;
        irgn = ttbr1.IRGN;
        rgn  = ttbr1.RGN;
        s    = ttbr1.S;
        nos  = ttbr1.NOS;
    end;

    // Check if Translation table walk disabled for translations with this Base register.
    if pd == '1' then
        fault.level      = 1;
        fault.statuscode = Fault_Translation;
        return (fault, ARBITRARY : TTWState);
    end;

    var baseaddress : FullAddress;
    baseaddress.paspace = if accdesc.ss == SS_Secure then PAS_Secure else PAS_NonSecure;
    baseaddress.address = ZeroExtend{56}(ttb[31:14-n]::Zeros{14-n});

    let startlevel : integer = 1;
    var walkstate : TTWState;
    walkstate.baseaddress = baseaddress;
    // In regimes that support global and non-global translations, translation
    // table entries from lookup levels other than the final level of lookup
    // are treated as being non-global. Translations in Short-Descriptor Format
    // always support global & non-global translations.
    walkstate.nG          = '1';
    walkstate.memattrs    = WalkMemAttrs(s::nos, irgn, rgn);
    walkstate.level       = startlevel;
    walkstate.istable     = TRUE;

    var domain : bits(4);
    var descriptor : bits(32);
    var walkaddress : AddressDescriptor;

    walkaddress.vaddress = ZeroExtend{64}(va);

    if !AArch32_S1DCacheEnabled(regime) then
        walkaddress.memattrs = NormalNCMemAttr();
        walkaddress.memattrs.xs = walkstate.memattrs.xs;
    else
        walkaddress.memattrs = walkstate.memattrs;
    end;

    // Shareability value of stage 1 translation subject to stage 2 is IMPLEMENTATION DEFINED
    // to be either effective value or descriptor value
    if (regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) &&
        (if ELStateUsingAArch32(EL2, accdesc.ss==SS_Secure) then HCR().VM
                                                            else HCR_EL2().VM) == '1' &&
        !(ImpDefBool("Apply effective shareability at stage 1"))) then
        walkaddress.memattrs.shareability = walkstate.memattrs.shareability;
    else
        walkaddress.memattrs.shareability = EffectiveShareability(walkaddress.memattrs);
    end;

    var nG : bit;
    var ns : bit;
    var pxn : bit;
    var ap : bits(3);
    var tex : bits(3);
    var c : bit;
    var b : bit;
    var xn : bit;
    repeat
        fault.level = walkstate.level;

        var index : bits(32);
        if walkstate.level == 1 then
            index = ZeroExtend{32}(va[31-n:20]::'00');
        else
            index = ZeroExtend{32}(va[19:12]::'00');
        end;

        walkaddress.paddress.address = (walkstate.baseaddress.address OR
                                            ZeroExtend{56}(index));
        walkaddress.paddress.paspace = walkstate.baseaddress.paspace;

        let toplevel : boolean = walkstate.level == startlevel;
        let walkaccess : AccessDescriptor = CreateAccDescS1TTW(toplevel, varange, accdesc);
        if regime == Regime_EL10 && AArch32_EL2Enabled(accdesc.ss) then
            let s2aligned : boolean = TRUE;
            let (s2fault, s2walkaddress) = AArch32_S2Translate(fault, walkaddress, s2aligned,
                                                               walkaccess);

            if s2fault.statuscode != Fault_None then
                return (s2fault, ARBITRARY : TTWState);
            end;

            (fault, descriptor) = FetchDescriptor{32}(ee, s2walkaddress, walkaccess, fault);
        else
            (fault, descriptor) = FetchDescriptor{32}(ee, walkaddress, walkaccess, fault);
        end;

        if fault.statuscode != Fault_None then
            return (fault, ARBITRARY : TTWState);
        end;

        walkstate.sdftype = AArch32_DecodeDescriptorTypeSD(descriptor, walkstate.level);

        case walkstate.sdftype of
            when SDFType_Invalid =>
                fault.domain     = domain;
                fault.statuscode = Fault_Translation;
                return (fault, ARBITRARY : TTWState);

            when SDFType_Table =>
                domain = descriptor[8:5];
                ns     = descriptor[3];
                pxn    = descriptor[2];

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[31:10]::
                                                                       Zeros{10});
                walkstate.level = 2;

            when SDFType_SmallPage =>
                nG  = descriptor[11];
                s   = descriptor[10];
                ap  = descriptor[9,5:4];
                tex = descriptor[8:6];
                c   = descriptor[3];
                b   = descriptor[2];
                xn  = descriptor[0];

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[31:12]::
                                                                       Zeros{12});
                walkstate.istable = FALSE;

            when SDFType_LargePage =>
                xn  = descriptor[15];
                tex = descriptor[14:12];
                nG  = descriptor[11];
                s   = descriptor[10];
                ap  = descriptor[9,5:4];
                c   = descriptor[3];
                b   = descriptor[2];

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[31:16]::
                                                                       Zeros{16});
                walkstate.istable = FALSE;

            when SDFType_Section =>
                ns     = descriptor[19];
                nG     = descriptor[17];
                s      = descriptor[16];
                ap     = descriptor[15,11:10];
                tex    = descriptor[14:12];
                domain = descriptor[8:5];
                xn     = descriptor[4];
                c      = descriptor[3];
                b      = descriptor[2];
                pxn    = descriptor[0];

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[31:20]::
                                                                       Zeros{20});
                walkstate.istable = FALSE;

            when SDFType_Supersection =>
                ns     = descriptor[19];
                nG     = descriptor[17];
                s      = descriptor[16];
                ap     = descriptor[15,11:10];
                tex    = descriptor[14:12];
                xn     = descriptor[4];
                c      = descriptor[3];
                b      = descriptor[2];
                pxn    = descriptor[0];
                domain = '0000';

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[8:5,23:20,31:24]::
                                                                       Zeros{24});

                walkstate.istable = FALSE;
        end;

    until walkstate.sdftype != SDFType_Table looplimit 2;

    if afe == '1' && ap[0] == '0' then
        fault.domain     = domain;
        fault.statuscode = Fault_AccessFlag;
        return (fault, ARBITRARY : TTWState);
    end;

    // Decode the TEX, C, B and S bits to produce target memory attributes
    if tre == '1' then
        walkstate.memattrs = AArch32_RemappedTEXDecode(regime, tex, c, b, s);
    elsif RemapRegsHaveResetValues() then
        walkstate.memattrs = AArch32_DefaultTEXDecode(tex, c, b, s);
    else
        walkstate.memattrs = ImpDefMemoryAttributes("IMPLEMENTATION_DEFINED");
    end;

    walkstate.permissions.ap  = ap;
    walkstate.permissions.xn  = xn;
    walkstate.permissions.pxn = pxn;
    walkstate.domain = domain;
    walkstate.nG     = nG;

    if accdesc.ss == SS_Secure && ns == '0' then
        walkstate.baseaddress.paspace = PAS_Secure;
    else
        walkstate.baseaddress.paspace = PAS_NonSecure;
    end;

    return (fault, walkstate);
end;

// AArch32_S2IASize()
// ==================
// Retrieve the number of bits containing the input address for stage 2 translation

func AArch32_S2IASize(t0sz : bits(4)) => AddressSize
begin
    return 32 - SInt(t0sz);
end;

// AArch32_S2StartLevel()
// ======================
// Determine the initial lookup level when performing a stage 2 translation
// table walk

func AArch32_S2StartLevel(sl0 : bits(2)) => integer
begin
    return 2 - UInt(sl0);
end;

// AArch32_S2Walk()
// ================
// Traverse stage 2 translation tables in long format to obtain the final descriptor

func AArch32_S2Walk(fault_in : FaultRecord, walkparams : S2TTWParams,
                    accdesc : AccessDescriptor, ipa : AddressDescriptor) => (FaultRecord, TTWState)
begin
    var fault : FaultRecord = fault_in;

    if walkparams.sl0 == '1x' || AArch32_S2InconsistentSL(walkparams) then
        fault.statuscode = Fault_Translation;
        fault.level      = 1;
        return (fault, ARBITRARY : TTWState);
    end;

    // Input Address size
    let iasize : AddressSize      = AArch32_S2IASize(walkparams.t0sz);
    let startlevel : integer  = AArch32_S2StartLevel(walkparams.sl0);
    let levels : integer      = FINAL_LEVEL - startlevel;
    let granulebits : AddressSize = TGxGranuleBits(walkparams.tgx);
    let stride : integer{}      = granulebits - 3;

    if !IsZero(VTTBR()[47:40]) then
        fault.statuscode = Fault_AddressSize;
        fault.level      = 0;
        return (fault, ARBITRARY : TTWState);
    end;

    var baseaddress : FullAddress;
    let baselsb = ((iasize - (levels*stride + granulebits)) + 3) as AddressSize;
    baseaddress.paspace = PAS_NonSecure;
    baseaddress.address = ZeroExtend{56}(VTTBR()[39:baselsb]::Zeros{baselsb});

    var walkstate : TTWState;
    walkstate.baseaddress = baseaddress;
    walkstate.level       = startlevel;
    walkstate.istable     = TRUE;
    walkstate.memattrs    = WalkMemAttrs(walkparams.sh, walkparams.irgn,
                                         walkparams.orgn);

    var descriptor : bits(64);
    let walkaccess : AccessDescriptor = CreateAccDescS2TTW(accdesc);
    var walkaddress : AddressDescriptor;

    walkaddress.vaddress = ipa.vaddress;

    if HCR2().CD == '1' then
        walkaddress.memattrs = NormalNCMemAttr();
        walkaddress.memattrs.xs = walkstate.memattrs.xs;
    else
        walkaddress.memattrs = walkstate.memattrs;
    end;

    walkaddress.memattrs.shareability = EffectiveShareability(walkaddress.memattrs);

    var msb_residual : integer = iasize - 1;
    var desctype : DescriptorType;
    repeat
        fault.level = walkstate.level;

        let indexlsb = ((FINAL_LEVEL - walkstate.level)*stride + granulebits) as AddressSize;
        let indexmsb = msb_residual as AddressSize;
        let index : bits(40) = ZeroExtend{}(ipa.paddress.address[indexmsb:indexlsb]::'000');

        walkaddress.paddress.address = (walkstate.baseaddress.address OR
                                        ZeroExtend{56}(index));
        walkaddress.paddress.paspace = walkstate.baseaddress.paspace;

        (fault, descriptor) = FetchDescriptor{64}(walkparams.ee, walkaddress, walkaccess, fault);

        if fault.statuscode != Fault_None then
            return (fault, ARBITRARY : TTWState);
        end;

        desctype = AArch32_DecodeDescriptorTypeLD(descriptor, walkstate.level);

        case desctype of
            when DescriptorType_Table =>
                if !IsZero(descriptor[47:40]) then
                    fault.statuscode = Fault_AddressSize;
                    return (fault, ARBITRARY : TTWState);
                end;

                walkstate.baseaddress.address = ZeroExtend{56}(descriptor[39:12]::
                                                                       Zeros{12});
                walkstate.level = walkstate.level + 1;
                msb_residual = indexlsb - 1;

            when DescriptorType_Invalid =>
                fault.statuscode = Fault_Translation;
                return (fault, ARBITRARY : TTWState);

            when DescriptorType_Leaf =>
                walkstate.istable = FALSE;
        end;

    until desctype == DescriptorType_Leaf looplimit 3;

    // Check the output address is inside the supported range
    if !IsZero(descriptor[47:40]) then
        fault.statuscode = Fault_AddressSize;
        return (fault, ARBITRARY : TTWState);
    end;

    // Check the access flag
    if descriptor[10] == '0' then
        fault.statuscode = Fault_AccessFlag;
        return (fault, ARBITRARY : TTWState);
    end;

    // Unpack the descriptor into address and upper and lower block attributes
    let indexlsb = ((FINAL_LEVEL - walkstate.level)*stride + granulebits) as AddressSize;
    walkstate.baseaddress.address = ZeroExtend{56}(descriptor[39:indexlsb]::
                                                           Zeros{indexlsb});

    walkstate.permissions.s2ap = descriptor[7:6];
    walkstate.permissions.s2xn = descriptor[54];
    if IsFeatureImplemented(FEAT_XNX) then
        walkstate.permissions.s2xnx = descriptor[53];
    else
        walkstate.permissions.s2xnx = '0';
    end;

    let memattr : bits(4) = descriptor[5:2];
    let sh : bits(2)      = descriptor[9:8];
    let s2aarch64 : boolean = FALSE;
    walkstate.memattrs   = S2DecodeMemAttrs(memattr, sh, s2aarch64);
    walkstate.contiguous = descriptor[52];

    return (fault, walkstate);
end;

// RemapRegsHaveResetValues()
// ==========================

impdef func RemapRegsHaveResetValues() => boolean
begin
    return TRUE;
end;

// AArch32_GetS1TTWParams()
// ========================
// Returns stage 1 translation table walk parameters from respective controlling
// System registers.

func AArch32_GetS1TTWParams(regime : Regime, va : bits(32)) => S1TTWParams
begin
    var walkparams : S1TTWParams;

    case regime of
        when Regime_EL2 =>  walkparams = AArch32_S1TTWParamsEL2();
        when Regime_EL10 => walkparams = AArch32_S1TTWParamsEL10(va);
        when Regime_EL30 => walkparams = AArch32_S1TTWParamsEL30(va);
    end;

    return walkparams;
end;

// AArch32_GetS2TTWParams()
// ========================
// Gather walk parameters for stage 2 translation

func AArch32_GetS2TTWParams() => S2TTWParams
begin
    var walkparams : S2TTWParams;

    walkparams.tgx  = TGx_4KB;
    walkparams.s    = VTCR().S;
    walkparams.t0sz = VTCR().T0SZ;
    walkparams.sl0  = VTCR().SL0;
    walkparams.irgn = VTCR().IRGN0;
    walkparams.orgn = VTCR().ORGN0;
    walkparams.sh   = VTCR().SH0;
    walkparams.ee   = HSCTLR().EE;
    walkparams.ptw  = HCR().PTW;
    walkparams.vm   = HCR().VM OR HCR().DC;

    // VTCR.S must match VTCR.T0SZ[3]
    if walkparams.s != walkparams.t0sz[3] then
        (-, walkparams.t0sz) = ConstrainUnpredictableBits{4}(Unpredictable_RESVTCRS);
    end;

    return walkparams;
end;

// AArch32_GetVARange()
// ====================
// Select the translation base address for stage 1 long-descriptor walks

func AArch32_GetVARange(va : bits(32), t0sz : bits(3), t1sz : bits(3)) => VARange
begin
    // Lower range Input Address size
    let lo_iasize : AddressSize = AArch32_S1IASize(t0sz);
    // Upper range Input Address size
    let up_iasize : AddressSize = AArch32_S1IASize(t1sz);

    if t1sz == '000' && t0sz == '000' then
        return VARange_LOWER;
    elsif t1sz == '000' then
        return if IsZero(va[31:lo_iasize]) then VARange_LOWER else VARange_UPPER;
    elsif t0sz == '000' then
        return if IsOnes(va[31:up_iasize]) then VARange_UPPER else VARange_LOWER;
    elsif IsZero(va[31:lo_iasize]) then
        return VARange_LOWER;
    elsif IsOnes(va[31:up_iasize]) then
        return VARange_UPPER;
    else
        // Will be reported as a Translation Fault
        return ARBITRARY : VARange;
    end;
end;

// AArch32_S1DCacheEnabled()
// =========================
// Determine cacheability of stage 1 data accesses

func AArch32_S1DCacheEnabled(regime : Regime) => boolean
begin
    case regime of
        when Regime_EL30 => return SCTLR_S().C == '1';
        when Regime_EL2 =>  return HSCTLR().C == '1';
        when Regime_EL10 =>
            return (if HaveEL(EL3) && ELUsingAArch32(EL3) then SCTLR_NS().C else SCTLR().C) == '1';
    end;
end;

// AArch32_S1ICacheEnabled()
// =========================
// Determine cacheability of stage 1 instruction fetches

func AArch32_S1ICacheEnabled(regime : Regime) => boolean
begin
    case regime of
        when Regime_EL30 => return SCTLR_S().I == '1';
        when Regime_EL2 =>  return HSCTLR().I == '1';
        when Regime_EL10 =>
            return (if HaveEL(EL3) && ELUsingAArch32(EL3) then SCTLR_NS().I else SCTLR().I) == '1';
    end;
end;

// AArch32_S1TTWParamsEL10()
// =========================
// Gather stage 1 translation table walk parameters for EL1&0 regime
// (with EL2 enabled or disabled).

func AArch32_S1TTWParamsEL10(va : bits(32)) => S1TTWParams
begin
    var mair : bits(64);
    var sif : bit;
    var ttbcr : TTBCR_Type;
    var ttbcr2 : TTBCR2_Type;
    var sctlr : SCTLR_Type;

    if ELUsingAArch32(EL3) then
        ttbcr  = TTBCR_NS();
        ttbcr2 = TTBCR2_NS();
        sctlr  = SCTLR_NS();
        mair   = MAIR1_NS()::MAIR0_NS();
        sif    = SCR().SIF;
    else
        ttbcr  = TTBCR();
        ttbcr2 = TTBCR2();
        sctlr  = SCTLR();
        mair   = MAIR1()::MAIR0();
        sif    = if HaveEL(EL3) then SCR_EL3().SIF else '0';
    end;

    assert ttbcr.EAE == '1';
    var walkparams : S1TTWParams;

    walkparams.t0sz   = ttbcr.T0SZ;
    walkparams.t1sz   = ttbcr.T1SZ;
    walkparams.ee     = sctlr.EE;
    walkparams.wxn    = sctlr.WXN;
    walkparams.uwxn   = sctlr.UWXN;
    walkparams.ntlsmd = if IsFeatureImplemented(FEAT_LSMAOC) then sctlr.nTLSMD else '1';
    walkparams.mair   = mair;
    walkparams.sif    = sif;

    let varange : VARange = AArch32_GetVARange(va, walkparams.t0sz, walkparams.t1sz);
    if varange == VARange_LOWER then
        walkparams.sh   = ttbcr.SH0;
        walkparams.irgn = ttbcr.IRGN0;
        walkparams.orgn = ttbcr.ORGN0;
        walkparams.hpd  = (if IsFeatureImplemented(FEAT_AA32HPD) then ttbcr.T2E AND ttbcr2.HPD0
                           else '0');
    else
        walkparams.sh   = ttbcr.SH1;
        walkparams.irgn = ttbcr.IRGN1;
        walkparams.orgn = ttbcr.ORGN1;
        walkparams.hpd  = (if IsFeatureImplemented(FEAT_AA32HPD) then ttbcr.T2E AND ttbcr2.HPD1
                           else '0');
    end;

    return walkparams;
end;

// AArch32_S1TTWParamsEL2()
// ========================
// Gather stage 1 translation table walk parameters for EL2 regime

func AArch32_S1TTWParamsEL2() => S1TTWParams
begin
    var walkparams : S1TTWParams;

    walkparams.tgx  = TGx_4KB;
    walkparams.t0sz = HTCR().T0SZ;
    walkparams.irgn = HTCR().IRGN0;
    walkparams.orgn = HTCR().ORGN0;
    walkparams.sh   = HTCR().SH0;
    walkparams.hpd  = if IsFeatureImplemented(FEAT_AA32HPD) then HTCR().HPD else '0';
    walkparams.ee   = HSCTLR().EE;
    walkparams.wxn  = HSCTLR().WXN;
    if IsFeatureImplemented(FEAT_LSMAOC) then
        walkparams.ntlsmd = HSCTLR().nTLSMD;
    else
        walkparams.ntlsmd = '1';
    end;

    walkparams.mair = HMAIR1()::HMAIR0();

    return walkparams;
end;

// AArch32_S1TTWParamsEL30()
// =========================
// Gather stage 1 translation table walk parameters for EL3&0 regime

func AArch32_S1TTWParamsEL30(va : bits(32)) => S1TTWParams
begin
    assert TTBCR_S().EAE == '1';
    var walkparams : S1TTWParams;

    walkparams.t0sz   = TTBCR_S().T0SZ;
    walkparams.t1sz   = TTBCR_S().T1SZ;
    walkparams.ee     = SCTLR_S().EE;
    walkparams.wxn    = SCTLR_S().WXN;
    walkparams.uwxn   = SCTLR_S().UWXN;
    walkparams.ntlsmd = if IsFeatureImplemented(FEAT_LSMAOC) then SCTLR_S().nTLSMD else '1';
    walkparams.mair   = MAIR1_S()::MAIR0_S();
    walkparams.sif    = SCR().SIF;

    let varange : VARange = AArch32_GetVARange(va, walkparams.t0sz, walkparams.t1sz);
    if varange == VARange_LOWER then
        walkparams.sh   = TTBCR_S().SH0;
        walkparams.irgn = TTBCR_S().IRGN0;
        walkparams.orgn = TTBCR_S().ORGN0;
        walkparams.hpd  = (if IsFeatureImplemented(FEAT_AA32HPD)
                           then TTBCR_S().T2E AND TTBCR2_S().HPD0
                           else '0');
    else
        walkparams.sh   = TTBCR_S().SH1;
        walkparams.irgn = TTBCR_S().IRGN1;
        walkparams.orgn = TTBCR_S().ORGN1;
        walkparams.hpd  = (if IsFeatureImplemented(FEAT_AA32HPD)
                           then TTBCR_S().T2E AND TTBCR2_S().HPD1
                           else '0');
    end;

    return walkparams;
end;

// BRBCycleCountingEnabled()
// =========================
// Returns TRUE if the recording of cycle counts is allowed,
// FALSE otherwise.

func BRBCycleCountingEnabled() => boolean
begin
    if HaveEL(EL2) && BRBCR_EL2().CC == '0' then return FALSE; end;
    if BRBCR_EL1().CC == '0' then return FALSE; end;
    return TRUE;
end;

// BRBEBranch()
// ============
// Called to write branch record for the following branches when BRBE is active:
// direct branches,
// indirect branches,
// direct branches with link,
// indirect branches with link,
// returns from subroutines.

func BRBEBranch(br_type : BranchType, cond : boolean, target_address : bits(64))
begin
    if BranchRecordAllowed(PSTATE.EL) && FilterBranchRecord(br_type, cond) then
        var branch_type : bits(6);
        case br_type of
            when BranchType_DIR =>
                branch_type = if cond then '001000' else '000000';
            when BranchType_INDIR =>      branch_type = '000001';
            when BranchType_DIRCALL =>    branch_type = '000010';
            when BranchType_INDCALL =>    branch_type = '000011';
            when BranchType_RET =>        branch_type = '000101';
            otherwise =>                  unreachable;
        end;

        var ccu : bit;
        var cc : bits(14);
        (ccu, cc) = BranchEncCycleCount();
        let el : bits(2)        = PSTATE.EL;
        let mispredict : bit    = (if BRBEMispredictAllowed() && BranchMispredict() then '1'
                                   else '0');

        UpdateBranchRecordBuffer(ccu, cc, branch_type, el, mispredict,
                                 '11', PC64(), target_address);

        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;

    return;
end;

// BRBEBranchOnISB()
// =================
// Returns TRUE if ISBs generate Branch records, and FALSE otherwise.

func BRBEBranchOnISB() => boolean
begin
    return ImpDefBool("ISB generates Branch records");
end;

// BRBEDebugStateEntry()
// =====================
// Called to write Debug state entry branch record when BRBE is active.

func BRBEDebugStateEntry(source_address : bits(64))
begin
    if BranchRecordAllowed(PSTATE.EL) then
        let branch_type : bits(6) = '100001';
        var ccu : bit;
        var cc : bits(14);
        (ccu, cc) = BranchEncCycleCount();
        let el : bits(2)     = '00';
        let mispredict : bit = '0';

        // Debug state is a prohibited region, therefore target_address=0
        UpdateBranchRecordBuffer(ccu, cc, branch_type, el, mispredict,
                                 '10', source_address, Zeros{64});

        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;

    return;
end;

// BRBEDebugStateExit()
// ====================
// Called to write Debug state exit branch record when BRBE is active.

func BRBEDebugStateExit(target_address : bits(64))
begin
    if BranchRecordAllowed(PSTATE.EL) then
        // Debug state is a prohibited region, therefore ccu=1, cc=0, source_address=0
        let branch_type : bits(6) = '111001';
        let ccu : bit             = '1';
        let cc : bits(14)         = Zeros{};
        let el : bits(2)          = PSTATE.EL;
        let mispredict : bit      = '0';

        UpdateBranchRecordBuffer(ccu, cc, branch_type, el, mispredict,
                                 '01', Zeros{64}, target_address);

        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;

    return;
end;

// BRBEException()
// ===============
// Called to write exception branch record when BRBE is active.

func BRBEException(erec : ExceptionRecord, source_valid : boolean,
                   source_address_in : bits(64),
                   target_address_in : bits(64), target_el : bits(2),
                   trappedsyscallinst : boolean)
begin
    var target_address : bits(64) = target_address_in;
    let except : Exception = erec.exceptype;
    let iss : bits(25)     = erec.syndrome.iss;
    case target_el of
        when EL3 =>
            if !IsFeatureImplemented(FEAT_BRBEv1p1) || (MDCR_EL3().E3BREC == MDCR_EL3().E3BREW) then
                return;
            end;
        when EL2 =>  if BRBCR_EL2().EXCEPTION == '0' then return; end;
        when EL1 =>  if BRBCR_EL1().EXCEPTION == '0' then return; end;
    end;

    let target_valid : boolean = BranchRecordAllowed(target_el);

    if source_valid || target_valid then
        var branch_type : bits(6);
        case except of
            when Exception_Uncategorized =>         branch_type = '100011'; // Trap
            when Exception_WFxTrap =>               branch_type = '100011'; // Trap
            when Exception_CP15RTTrap =>            branch_type = '100011'; // Trap
            when Exception_CP15RRTTrap =>           branch_type = '100011'; // Trap
            when Exception_CP14RTTrap =>            branch_type = '100011'; // Trap
            when Exception_CP14DTTrap =>            branch_type = '100011'; // Trap
            when Exception_AdvSIMDFPAccessTrap =>   branch_type = '100011'; // Trap
            when Exception_FPIDTrap =>              branch_type = '100011'; // Trap
            when Exception_PACTrap =>               branch_type = '100011'; // Trap
            when Exception_CP14RRTTrap =>           branch_type = '100011'; // Trap
            when Exception_LDST64BTrap =>           branch_type = '100011'; // Trap
            when Exception_BranchTarget =>          branch_type = '101011'; // Inst Fault
            when Exception_IllegalState =>          branch_type = '100011'; // Trap
            when Exception_SupervisorCall =>
                if !trappedsyscallinst then      branch_type = '100010'; // Call
                else                             branch_type = '100011'; // Trap
                end;
            when Exception_HypervisorCall =>        branch_type = '100010'; // Call
            when Exception_MonitorCall =>
                if !trappedsyscallinst then      branch_type = '100010'; // Call
                else                             branch_type = '100011'; // Trap
                end;
            when Exception_SystemRegisterTrap =>    branch_type = '100011'; // Trap
            when Exception_SystemRegister128Trap => branch_type = '100011'; // Trap
            when Exception_SVEAccessTrap =>         branch_type = '100011'; // Trap
            when Exception_SMEAccessTrap =>         branch_type = '100011'; // Trap
            when Exception_ERetTrap =>              branch_type = '100011'; // Trap
            when Exception_PACFail =>               branch_type = '101100'; // Data Fault
            when Exception_InstructionAbort =>      branch_type = '101011'; // Inst Fault
            when Exception_PCAlignment =>           branch_type = '101010'; // Alignment
            when Exception_DataAbort =>             branch_type = '101100'; // Data Fault
            when Exception_NV2DataAbort =>          branch_type = '101100'; // Data Fault
            when Exception_SPAlignment =>           branch_type = '101010'; // Alignment
            when Exception_FPTrappedException =>    branch_type = '100011'; // Trap
            when Exception_SError =>                branch_type = '100100'; // System Error
            when Exception_Breakpoint =>            branch_type = '100110'; // Inst debug
            when Exception_SoftwareStep =>          branch_type = '100110'; // Inst debug
            when Exception_Watchpoint =>            branch_type = '100111'; // Data debug
            when Exception_NV2Watchpoint =>         branch_type = '100111'; // Data debug
            when Exception_SoftwareBreakpoint =>    branch_type = '100110'; // Inst debug
            when Exception_IRQ =>                   branch_type = '101110'; // IRQ
            when Exception_FIQ =>                   branch_type = '101111'; // FIQ
            when Exception_MemCpyMemSet =>          branch_type = '100011'; // Trap
            when Exception_GCSFail =>
                if iss[23:20] == '0000' then        branch_type = '101100'; // Data Fault
                elsif iss[23:20] == '0001' then     branch_type = '101011'; // Inst Fault
                elsif iss[23:20] == '0010' then     branch_type = '100011'; // Trap
                else                                unreachable;
                end;
            when Exception_Profiling =>             branch_type = '100110'; // Inst debug
            when Exception_GPC =>
                if iss[20] == '1' then              branch_type = '101011'; // Inst fault
                else                                branch_type = '101100'; // Data fault
                end;
            otherwise =>                            unreachable;
        end;

        var ccu : bit;
        var cc : bits(14);
        (ccu, cc) = BranchEncCycleCount();
        let el : bits(2) = if target_valid then target_el else '00';
        let mispredict : bit = '0';
        let sv : bit = if source_valid then '1' else '0';
        let tv : bit = if target_valid then '1' else '0';
        let source_address : bits(64) = if source_valid then source_address_in else Zeros{64};

        if !target_valid then
            target_address = Zeros{64};
        else
            target_address = AArch64_BranchAddr(target_address, target_el);
        end;

        UpdateBranchRecordBuffer(ccu, cc, branch_type, el, mispredict,
                                 sv::tv, source_address, target_address);

        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;

    return;
end;

// BRBEExceptionReturn()
// =====================
// Called to write exception return branch record when BRBE is active.

func BRBEExceptionReturn(target_address_in : bits(64), source_el : bits(2),
                         source_valid : boolean, source_address_in : bits(64))
begin
    var target_address : bits(64) = target_address_in;
    case source_el of
        when EL3 =>
            if !IsFeatureImplemented(FEAT_BRBEv1p1) || (MDCR_EL3().E3BREC == MDCR_EL3().E3BREW) then
                return;
            end;
        when EL2 =>  if BRBCR_EL2().ERTN == '0' then return; end;
        when EL1 =>  if BRBCR_EL1().ERTN == '0' then return; end;
    end;

    let target_valid : boolean = BranchRecordAllowed(PSTATE.EL);

    if source_valid || target_valid then
        let branch_type : bits(6) = '000111';
        var ccu : bit;
        var cc : bits(14);
        (ccu, cc) = BranchEncCycleCount();
        let el : bits(2)     = if target_valid then PSTATE.EL else '00';
        let mispredict : bit = (if source_valid && BRBEMispredictAllowed() &&
                                BranchMispredict() then '1' else '0');
        let sv : bit = if source_valid then '1' else '0';
        let tv : bit = if target_valid then '1' else '0';
        let source_address : bits(64) = if source_valid then source_address_in else Zeros{64};
        if !target_valid then
            target_address = Zeros{64};
        end;

        UpdateBranchRecordBuffer(ccu, cc, branch_type, el, mispredict,
                                 sv::tv, source_address, target_address);

        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;

    return;
end;

// BRBEFreeze()
// ============
// Generates BRBE freeze event.

func BRBEFreeze()
begin
    BRBFCR_EL1().PAUSED = '1';
    BRBTS_EL1() = GetTimestamp(BRBETimeStamp());
end;

// BRBEISB()
// =========
// Handles ISB instruction for BRBE.

func BRBEISB()
begin
    let branch_conditional : boolean = FALSE;
    BRBEBranch(BranchType_DIR, branch_conditional, PC64() + 4);
end;

// BRBEMispredictAllowed()
// =======================
// Returns TRUE if the recording of branch misprediction is allowed,
// FALSE otherwise.

func BRBEMispredictAllowed() => boolean
begin
    if HaveEL(EL2) && BRBCR_EL2().MPRED == '0' then return FALSE; end;
    if BRBCR_EL1().MPRED == '0' then return FALSE; end;
    return TRUE;
end;

// BRBETimeStamp()
// ===============
// Returns captured timestamp.

func BRBETimeStamp() => TimeStamp
begin
    if HaveEL(EL2) then
        var TS_el2 : bits(2) = BRBCR_EL2().TS;
        if !IsFeatureImplemented(FEAT_ECV) && TS_el2 == '10' then
            // Reserved value
            (-, TS_el2) = ConstrainUnpredictableBits{2}(Unpredictable_EL2TIMESTAMP);
        end;
        case TS_el2 of
            when '00' =>
                // Falls out to check BRBCR_EL1.TS
                pass;
            when '01' =>
                return TimeStamp_Virtual;
            when '10' =>
                assert IsFeatureImplemented(FEAT_ECV); // Otherwise ConstrainUnpredictableBits
                                                       // removes this case
                return TimeStamp_OffsetPhysical;
            when '11' =>
                return TimeStamp_Physical;
        end;
    end;

    var TS_el1 : bits(2) = BRBCR_EL1().TS;
    if TS_el1 == '00' || (!IsFeatureImplemented(FEAT_ECV) && TS_el1 == '10') then
        // Reserved value
        (-, TS_el1) = ConstrainUnpredictableBits{2}(Unpredictable_EL1TIMESTAMP);
    end;
    case TS_el1 of
        when '01' =>
            return TimeStamp_Virtual;
        when '10' =>
            return TimeStamp_OffsetPhysical;
        when '11' =>
            return TimeStamp_Physical;
        otherwise =>
            unreachable;           // ConstrainUnpredictableBits removes this case
    end;
end;

// BRB_IALL()
// ==========
// Called to perform invalidation of branch records

func BRB_IALL()
begin
    let nbrberecords : integer = GetBRBENumRecords();
    for i = 0 to nbrberecords - 1 do
        Records_SRC[[i]] = Zeros{64};
        Records_TGT[[i]] = Zeros{64};
        Records_INF[[i]] = Zeros{64};
    end;
end;

// BRB_INJ()
// =========
// Called to perform manual injection of branch records.

func BRB_INJ()
begin
    UpdateBranchRecordBuffer(BRBINFINJ_EL1().CCU, BRBINFINJ_EL1().CC,
                             BRBINFINJ_EL1().TYPE, BRBINFINJ_EL1().EL,
                             BRBINFINJ_EL1().MPRED, BRBINFINJ_EL1().VALID, BRBSRCINJ_EL1().ADDRESS,
                             BRBTGTINJ_EL1().ADDRESS);
    BRBINFINJ_EL1() = ARBITRARY : bits(64);
    BRBSRCINJ_EL1() = ARBITRARY : bits(64);
    BRBTGTINJ_EL1() = ARBITRARY : bits(64);

    if ConstrainUnpredictableBool(Unpredictable_BRBFILTRATE) then
        PMUEvent(PMU_EVENT_BRB_FILTRATE);
    end;
end;

// BranchEncCycleCount()
// =====================

// The first return result is '1' if either of the following is true, and '0' otherwise:
// - This is the first Branch record after the PE exited a Prohibited Region.
// - This is the first Branch record after cycle counting has been enabled.
// If the first return return is '0', the second return result is the encoded cycle count
// since the last branch.
// The format of this field uses a mantissa and exponent to express the cycle count value.
//  - bits[7:0] indicate the mantissa M.
//  - bits[13:8] indicate the exponent E.
// The cycle count is expressed using the following function:
//   cycle_count = (if IsZero(E) then UInt(M) else UInt('1'::M::Zeros(UInt(E)-1)))
// A value of all ones in both the mantissa and exponent indicates the cycle count value
// exceeded the size of the cycle counter.
// If the cycle count is not known, the second return result is zero.

func BranchEncCycleCount() => (bit, bits(14))
begin
    var cc : integer = BranchRawCycleCount();
    if !BRBCycleCountingEnabled() || FirstBranchAfterProhibited() then
        return ('1', Zeros{14});
    end;

    // The format of this field uses a mantissa and exponent to express the cycle count value.
    //  - bits[7:0] indicate the mantissa M.
    //  - bits[13:8] indicate the exponent E.
    // The cycle count is expressed using the following function:
    //   cycle_count = IsZero(E) then UInt(M) else UInt('1'::M::Zeros(UInt(E)-1))
    // A value of all ones in both the mantissa and exponent indicates the cycle count value
    // exceeded the size of the cycle counter.

    var E : bits(6);
    var M : bits(8);

    if cc < 2^8 then
        E = Zeros{6};
        M = cc[7:0];
    elsif cc >= 2^20 then
        E = Ones{6};
        M = Ones{8};
    else
        E = 1[5:0];
        while cc >= 2^9 looplimit 11 do
            E = E + 1;
            cc = cc DIVRM 2;
        end;
        M = cc[7:0];
    end;

    return ('0', E::M);
end;

// BranchMispredict()
// ==================
// Returns TRUE if the branch being executed was mispredicted, FALSE otherwise.

impdef func BranchMispredict() => boolean
begin
    return FALSE;
end;

// BranchRawCycleCount()
// =====================
// If the cycle count is known, the return result is the cycle count since the last branch.

impdef func BranchRawCycleCount() => integer
begin
    return 0;
end;

// BranchRecordAllowed()
// =====================
// Returns TRUE if branch recording is allowed, FALSE otherwise.

func BranchRecordAllowed(el : bits(2)) => boolean
begin
    if ELUsingAArch32(el) then
        return FALSE;
    end;

    if BRBFCR_EL1().PAUSED == '1' then
        return FALSE;
    end;

    if el == EL3 && IsFeatureImplemented(FEAT_BRBEv1p1) then
        return (MDCR_EL3().E3BREC != MDCR_EL3().E3BREW);
    end;

    if HaveEL(EL3) && (MDCR_EL3().SBRBE == '00' ||
        (CurrentSecurityState() == SS_Secure && MDCR_EL3().SBRBE == '01')) then
        return FALSE;
    end;

    case el of
        when EL3 =>  return FALSE;                // FEAT_BRBEv1p1 not implemented
        when EL2 =>  return BRBCR_EL2().E2BRE == '1';
        when EL1 =>  return BRBCR_EL1().E1BRE == '1';
        when EL0 =>
            if EL2Enabled() && HCR_EL2().TGE == '1' then
                return BRBCR_EL2().E0HBRE == '1';
            else
                return BRBCR_EL1().E0BRE == '1';
            end;
    end;
end;

// Contents of the Branch Record Buffer
//=====================================

var Records_SRC : array [[64]] of BRBSRC_EL1_Type;

var Records_TGT : array [[64]] of BRBTGT_EL1_Type;

var Records_INF : array [[64]] of BRBINF_EL1_Type;

// FilterBranchRecord()
// ====================
// Returns TRUE if the branch record is not filtered out, FALSE otherwise.

func FilterBranchRecord(br : BranchType, cond : boolean) => boolean
begin
    case br of
        when BranchType_DIRCALL =>
            return BRBFCR_EL1().DIRCALL != BRBFCR_EL1().EnI;
        when BranchType_INDCALL =>
            return BRBFCR_EL1().INDCALL != BRBFCR_EL1().EnI;
        when BranchType_RET =>
            return BRBFCR_EL1().RTN != BRBFCR_EL1().EnI;
        when BranchType_DIR =>
            if cond then
                return BRBFCR_EL1().CONDDIR != BRBFCR_EL1().EnI;
            else
                return BRBFCR_EL1().DIRECT != BRBFCR_EL1().EnI;
            end;
        when BranchType_INDIR =>
            return BRBFCR_EL1().INDIRECT != BRBFCR_EL1().EnI;
        otherwise =>  unreachable;
    end;
    return FALSE;
end;

// FirstBranchAfterProhibited()
// ============================
// Returns TRUE if branch recorded is the first branch after a prohibited region,
// FALSE otherwise.

impdef func FirstBranchAfterProhibited() => boolean
begin
    return FALSE;
end;

// GetBRBENumRecords()
// ===================
// Returns the number of branch records implemented.

func GetBRBENumRecords() => integer
begin
    assert UInt(BRBIDR0_EL1().NUMREC) IN {0x08, 0x10, 0x20, 0x40};
    return ImpDefInt("Number of BRBE Branch records");
end;

// Getter functions for branch records
// ===================================
// Functions used by MRS instructions that access branch records

func BRBSRC_EL1(n : integer) => BRBSRC_EL1_Type
begin
    assert n IN {0..31};
    let record_index : integer = UInt(BRBFCR_EL1().BANK::n[4:0]);
    if record_index < GetBRBENumRecords() then
        return Records_SRC[[record_index]];
    else
        return Zeros{64};
    end;
end;

func BRBTGT_EL1(n : integer) => BRBTGT_EL1_Type
begin
    assert n IN {0..31};
    let record_index : integer = UInt(BRBFCR_EL1().BANK::n[4:0]);
    if record_index < GetBRBENumRecords() then
        return Records_TGT[[record_index]];
    else
        return Zeros{64};
    end;
end;

func BRBINF_EL1(n : integer) => BRBINF_EL1_Type
begin
    assert n IN {0..31};
    let record_index : integer = UInt(BRBFCR_EL1().BANK::n[4:0]);
    if record_index < GetBRBENumRecords() then
        return Records_INF[[record_index]];
    else
        return Zeros{64};
    end;
end;

// ShouldBRBEFreeze()
// ==================
// Returns TRUE if the BRBE freeze event conditions have been met, and FALSE otherwise.

func ShouldBRBEFreeze() => boolean
begin
    if !BranchRecordAllowed(PSTATE.EL) then
        return FALSE;
    end;

    var include_r1 : boolean;
    var include_r2 : boolean;
    let include_r3 : boolean = FALSE;

    if HaveEL(EL2) then
        include_r1 = (BRBCR_EL1().FZP == '1');
        include_r2 = (BRBCR_EL2().FZP == '1');
    else
        include_r1 = TRUE;
        include_r2 = TRUE;
    end;

    return CheckPMUOverflowCondition(PMUOverflowCondition_BRBEFreeze,
                                     include_r1, include_r2, include_r3);
end;

// UpdateBranchRecordBuffer()
// ==========================
// Add a new Branch record to the buffer.

func UpdateBranchRecordBuffer(ccu : bit, cc : bits(14), branch_type : bits(6), el : bits(2),
                              mispredict : bit, valid : bits(2),
                              source_address : bits(64), target_address : bits(64))
begin
    // Shift the Branch Records in the buffer
    let nbrberecords : integer = GetBRBENumRecords();
    for i = nbrberecords - 1 downto 1 do
        Records_SRC[[i]] = Records_SRC[[i - 1]];
        Records_TGT[[i]] = Records_TGT[[i - 1]];
        Records_INF[[i]] = Records_INF[[i - 1]];
    end;

    Records_INF[[0]].CCU        = ccu;
    Records_INF[[0]].CC         = cc;

    Records_INF[[0]].EL         = el;
    Records_INF[[0]].VALID      = valid;
    Records_INF[[0]].MPRED      = mispredict;
    Records_INF[[0]].TYPE       = branch_type;

    Records_SRC[[0]] = source_address;
    Records_TGT[[0]] = target_address;

    return;
end;

// AArch64_BreakpointMatch()
// =========================
// Breakpoint matching in an AArch64 translation regime.
// Returns BreakpointInfo structure that contains breakpoint type, a boolean to indicate the
// type of breakpoint, matched address and whether the breakpoint is active and matched
// successfully. For Address Mismatch breakpoints, the returned boolean is the inverted result.

func AArch64_BreakpointMatch(n : integer, vaddress : bits(64), accdesc : AccessDescriptor,
                             size : integer) => BreakpointInfo
begin
    assert !ELUsingAArch32(S1TranslationRegime());
    assert n < NumBreakpointsImplemented();
    var brkptinfo : BreakpointInfo;

    let linking_enabled : boolean = (DBGBCR_EL1(n).BT IN {'0x11', '1xx1'} ||
                                     (IsFeatureImplemented(FEAT_ABLE) && DBGBCR_EL1(n).BT2 == '1'));

    // A breakpoint that has linking enabled does not generate debug events in isolation
    if linking_enabled then
        brkptinfo.bptype = BreakpointType_Inactive;
        brkptinfo.match = FALSE;
        return brkptinfo;
    end;

    let enabled : boolean    = IsBreakpointEnabled(n);
    let linked : boolean     = DBGBCR_EL1(n).BT == '0x01';
    let isbreakpnt : boolean = TRUE;
    let linked_to : boolean  = FALSE;
    let from_linking_enabled : boolean = FALSE;
    let lbnx : bits(2) = if IsFeatureImplemented(FEAT_Debugv8p9) then DBGBCR_EL1(n).LBNX else '00';
    let linked_n : integer{} = UInt(lbnx :: DBGBCR_EL1(n).LBN);
    let ssce : bit = if IsFeatureImplemented(FEAT_RME) then DBGBCR_EL1(n).SSCE else '0';
    let state_match = AArch64_StateMatch(DBGBCR_EL1(n).SSC, ssce, DBGBCR_EL1(n).HMC,
                                         DBGBCR_EL1(n).PMC, linked, linked_n, isbreakpnt,
                                         vaddress, accdesc);

    var (bp_type, value_match) = AArch64_BreakpointValueMatch(n, vaddress, linked_to, isbreakpnt,
                                                              from_linking_enabled);

    if HaveAArch32() && size == 4 then                    // Check second halfword
        // If the breakpoint address and BAS of an Address breakpoint match the address of the
        // second halfword of an instruction, but not the address of the first halfword, it is
        // CONSTRAINED UNPREDICTABLE whether or not this breakpoint generates a Breakpoint debug
        // event.
        let (-, match_i) = AArch64_BreakpointValueMatch(n, vaddress + 2, linked_to, isbreakpnt,
                                                        from_linking_enabled);
        if !value_match && match_i then
            value_match = ConstrainUnpredictableBool(Unpredictable_BPMATCHHALF);
        end;
    end;

    if vaddress[1] == '1' && DBGBCR_EL1(n).BAS == '1111' then
        // The above notwithstanding, if DBGBCR_EL1(n).BAS == '1111', then it is CONSTRAINED
        // UNPREDICTABLE whether or not a Breakpoint debug event is generated for an instruction
        // at the address DBGBVR_EL1(n)+2.
        if value_match then
            value_match = ConstrainUnpredictableBool(Unpredictable_BPMATCHHALF);
        end;
    end;

    if !(state_match && enabled) then
        brkptinfo.bptype = BreakpointType_Inactive;
        brkptinfo.match = FALSE;
    else
        brkptinfo.bptype = bp_type;
        brkptinfo.match = value_match;
    end;
    return brkptinfo;
end;

// AArch64_BreakpointValueMatch()
// ==============================
// Returns breakpoint type to indicate the type of breakpoint and a boolean to indicate
// whether the breakpoint matched successfully. For Address Mismatch breakpoints, the
// returned boolean is the inverted result. If the breakpoint type return value is Inactive,
// then the boolean result is FALSE.

func AArch64_BreakpointValueMatch(n_in : integer, vaddress : bits(64),
                                  linked_to : boolean, isbreakpnt : boolean,
                                  from_linking_enabled : boolean
                                 ) => (BreakpointType, boolean) recurselimit 2
begin

    // "n_in" is the identity of the breakpoint unit to match against.
    // "vaddress" is the current instruction address, ignored if linked_to is TRUE and for Context
    //   matching breakpoints.
    // "linked_to" is TRUE if this is a call from StateMatch for linking.
    // "isbreakpnt"  TRUE is this is a call from BreakpointMatch or from StateMatch for a
    // linked breakpoint or from BreakpointValueMatch for a linked breakpoint with linking enabled.
    // "from_linking_enabled" is TRUE if this is a call from BreakpointValueMatch for a linked
    // breakpoint with linking enabled.
    var n : integer = n_in;
    var c : Constraint;
    var dbgtype : bits(5);

    // If a non-existent breakpoint then it is CONSTRAINED UNPREDICTABLE whether this gives
    // no match or the breakpoint is mapped to another UNKNOWN implemented breakpoint.
    if n >= NumBreakpointsImplemented() then
        (c, n) = ConstrainUnpredictableInteger(0, NumBreakpointsImplemented() - 1,
                                               Unpredictable_BPNOTIMPL);
        assert c IN {Constraint_DISABLED, Constraint_UNKNOWN};
        if c == Constraint_DISABLED then return (BreakpointType_Inactive, FALSE); end;
    end;

    // If this breakpoint is not enabled, it cannot generate a match.
    // (This could also happen on a call from StateMatch for linking).
    if !IsBreakpointEnabled(n) then return (BreakpointType_Inactive, FALSE); end;

    // If BT is set to a reserved type, behaves either as disabled or as a not-reserved type.
    if IsFeatureImplemented(FEAT_ABLE) then
        dbgtype = DBGBCR_EL1(n).[BT2,BT];
    else
        dbgtype = '0' :: DBGBCR_EL1(n).BT;
    end;

    (c, dbgtype) = AArch64_ReservedBreakpointType(n, dbgtype);
    if c == Constraint_DISABLED then return (BreakpointType_Inactive, FALSE); end;
    // Otherwise the value returned by ConstrainUnpredictableBits must be a not-reserved value

    // Determine what to compare against.
    let match_addr : boolean      = (dbgtype == 'x0x0x');
    let mismatch : boolean        = (dbgtype == 'x010x');
    let match_vmid : boolean      = (dbgtype == 'x10xx');
    let match_cid : boolean       = (dbgtype == 'x001x');
    let match_cid1 : boolean      = (dbgtype IN {'x101x', 'xx11x'});
    let match_cid2 : boolean      = (dbgtype == 'x11xx');
    let linking_enabled : boolean = (dbgtype IN {'xxx11', 'x1xx1', '1xxxx'});

    // If this is a call from StateMatch, return FALSE if the breakpoint is not
    // programmed with linking enabled.
    if linked_to && !linking_enabled then
        return (BreakpointType_Inactive, FALSE);
    end;

    // If called from BreakpointMatch return FALSE for breakpoint with linking enabled.
    if !linked_to && linking_enabled then
        return (BreakpointType_Inactive, FALSE);
    end;

    let linked : boolean = (dbgtype == 'x0x01');
    if from_linking_enabled then  // A breakpoint with linking enabled has called this function.
        assert linked_to && isbreakpnt;
        if linked then
            // A breakpoint with linking enabled is linked to a linked breakpoint. This is
            // architecturally UNPREDICTABLE, but treated as disabled in the pseudo code to
            // avoid potential recursion in BreakpointValueMatch().
            return (BreakpointType_Inactive, FALSE);
        end;
    end;

    // If a linked breakpoint is linked to an address matching breakpoint,
    // the behavior is CONSTRAINED UNPREDICTABLE.
    if linked_to && match_addr && isbreakpnt then
        if !ConstrainUnpredictableBool(Unpredictable_BPLINKEDADDRMATCH) then
            return (BreakpointType_Inactive, FALSE);
        end;
    end;

    // A breakpoint programmed for address mismatch does not match in AArch32 state.
    if mismatch && UsingAArch32() then
        return (BreakpointType_Inactive, FALSE);
    end;

    var bvr_match : boolean  = FALSE;
    var bxvr_match : boolean = FALSE;
    var bp_type : BreakpointType;
    var mask : integer{0..31};

    if IsFeatureImplemented(FEAT_BWE) then
        mask = UInt(DBGBCR_EL1(n).MASK);

        // If the mask is set to a reserved value, the behavior is CONSTRAINED UNPREDICTABLE.
        if mask IN {1, 2} then
            (c, mask) = (ConstrainUnpredictableInteger(3, 31, Unpredictable_RESBPMASK)
                             as (Constraint, integer{3..31}));
            assert c IN {Constraint_DISABLED, Constraint_NONE, Constraint_UNKNOWN};
            case c of
                when Constraint_DISABLED => return (BreakpointType_Inactive, FALSE);  // Disabled
                when Constraint_NONE =>     mask = 0;                                 // No masking
                // Otherwise the value returned by ConstrainUnpredictableBits must
                // be a not-reserved value.
            end;
        end;

        if mask != 0 then
            // When DBGBCR_EL1(n).MASK is a valid nonzero value, the behavior is
            // CONSTRAINED UNPREDICTABLE if any of the following are true:
            //     - DBGBCR_EL1(n).[BT2,BT] is programmed for a Context matching breakpoint.
            //     - DBGBCR_EL1(n).BAS is not '1111' and AArch32 is supported at EL0.
            if ((match_cid || match_cid1 || match_cid2) ||
                (DBGBCR_EL1(n).BAS != '1111' && HaveAArch32())) then
                if !ConstrainUnpredictableBool(Unpredictable_BPMASK) then
                    return (BreakpointType_Inactive, FALSE);
                end;
            end;
        else
            // A stand-alone mismatch of a single address is not supported.
            if mismatch then
                return (BreakpointType_Inactive, FALSE);
            end;
        end;

    else
        mask = 0;
    end;

    // Do the comparison.
    if match_addr then
        var byte_select_match : boolean;
        let byte : integer = UInt(vaddress[1:0]);

        if HaveAArch32() then
            // T32 instructions can be executed at EL0 in an AArch64 translation regime.
            assert byte IN {0,2};                       // "vaddress" is halfword aligned
            byte_select_match = (DBGBCR_EL1(n).BAS[byte] == '1');
        else
            assert byte == 0;                           // "vaddress" is word aligned
            byte_select_match = TRUE;                   // DBGBCR_EL1(n).BAS[byte] is RES1
        end;

        // When FEAT_LVA3 is not implemented, if the DBGBVR_EL1(n).RESS field bits are not a
        // sign extension of the MSB of DBGBVR_EL1(n).VA, it is UNPREDICTABLE whether they
        // appear to be included in the match.
        // If 'vaddress' is outside of the current virtual address space, then the access
        // generates a Translation fault.
        let dbgtop : AddressSize = DebugAddrTop();
        let unpredictable_ress : boolean = (dbgtop < 55 && !IsOnes(DBGBVR_EL1(n)[63:dbgtop]) &&
                                            !IsZero(DBGBVR_EL1(n)[63:dbgtop]) &&
                                      ConstrainUnpredictableBool(Unpredictable_DBGxVR_RESS));
        let cmpmsb : integer{} = if unpredictable_ress then 63 else dbgtop;
        let cmplsb : integer{} = if mask > 2 then mask else 2;
        bvr_match = ((vaddress[cmpmsb:cmplsb] == DBGBVR_EL1(n)[cmpmsb:cmplsb]) &&
                     byte_select_match);
        if mask > 2 then
            // If masked bits of DBGBVR_EL1(n) are not zero, the behavior
            // is CONSTRAINED UNPREDICTABLE.
            let masktop : integer{} = mask - 1;
            if bvr_match && !IsZero(DBGBVR_EL1(n)[masktop:2]) then
                bvr_match = ConstrainUnpredictableBool(Unpredictable_BPMASKEDBITS);
            end;
        end;

    elsif match_cid then
        if IsInHost() then
            bvr_match = (CONTEXTIDR_EL2()[31:0] == DBGBVR_EL1(n)[31:0]);
        else
            bvr_match = (PSTATE.EL IN {EL0, EL1} && CONTEXTIDR_EL1()[31:0] == DBGBVR_EL1(n)[31:0]);
        end;

    elsif match_cid1 then
        bvr_match = (PSTATE.EL IN {EL0, EL1} && !IsInHost() &&
                     CONTEXTIDR_EL1()[31:0] == DBGBVR_EL1(n)[31:0]);
    end;

    if match_vmid then
        let vmid : bits(16) = VMID();
        var bvr_vmid : bits(16);

        if !IsFeatureImplemented(FEAT_VMID16) || VTCR_EL2().VS == '0' then
            bvr_vmid = ZeroExtend{16}(DBGBVR_EL1(n)[39:32]);
        else
            bvr_vmid = DBGBVR_EL1(n)[47:32];
        end;

        bxvr_match = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() && !IsInHost() && vmid == bvr_vmid);

    elsif match_cid2 then
        bxvr_match = (PSTATE.EL != EL3 && EL2Enabled() &&
                      DBGBVR_EL1(n)[63:32] == CONTEXTIDR_EL2()[31:0]);
    end;

    let bvr_match_valid : boolean  = (match_addr || match_cid || match_cid1);
    let bxvr_match_valid : boolean = (match_vmid || match_cid2);

    var value_match : boolean = ((!bxvr_match_valid || bxvr_match) &&
                                 (!bvr_match_valid || bvr_match));

    // A watchpoint might be linked to a linked address matching breakpoint with linking enabled,
    // which is in turn linked to a context matching breakpoint.
    if linked_to && linked then
        // If called from StateMatch and breakpoint is a linked breakpoint then it must be a
        // watchpoint that is linked to an address matching breakpoint which is linked to a
        // context matching breakpoint.
        assert !isbreakpnt && match_addr && IsFeatureImplemented(FEAT_ABLE);
        let lbnx : bits(2) = (if IsFeatureImplemented(FEAT_Debugv8p9) then DBGBCR_EL1(n).LBNX
                                                                      else '00');
        let linked_linked_n : integer{} = UInt(lbnx :: DBGBCR_EL1(n).LBN);
        var linked_value_match : boolean;
        let linked_vaddress = ARBITRARY : bits(64);
        let linked_linked_to = TRUE;
        let linked_isbreakpnt = TRUE;
        let linked_from_linking_enabled = TRUE;
        (bp_type, linked_value_match) = AArch64_BreakpointValueMatch(linked_linked_n,
                                                                     linked_vaddress,
                                                                     linked_linked_to,
                                                                     linked_isbreakpnt,
                                                                     linked_from_linking_enabled);
        value_match = value_match && linked_value_match;
    end;

    if match_addr && !mismatch then
        bp_type = BreakpointType_AddrMatch;
    elsif match_addr && mismatch then
        bp_type = BreakpointType_AddrMismatch;
    elsif match_vmid || match_cid || match_cid1 || match_cid2 then
        bp_type = BreakpointType_CtxtMatch;
    else
        unreachable;
    end;

    return (bp_type, value_match);
end;

// AArch64_ReservedBreakpointType()
// ================================
// Checks if the given DBGBCR_EL1(n).[BT2,BT] values are reserved and will
// generate Constrained Unpredictable behavior, otherwise returns Constraint_NONE.

func AArch64_ReservedBreakpointType(n : integer, bt_in : bits(5)) => (Constraint, bits(5))
begin
    var bt : bits(5)            = bt_in;
    var reserved : boolean      = FALSE;
    let context_aware : boolean = IsContextAwareBreakpoint(n);

    if bt[4] == '0' then
        // Context matching
        if bt != '00x0x' && !context_aware then
            reserved = TRUE;
        end;

        // EL2 extension
        if bt == '01xxx' && !HaveEL(EL2) then
            reserved = TRUE;
        end;

        // Context matching
        if (bt IN {'0011x','011xx'} && !IsFeatureImplemented(FEAT_VHE) &&
              !IsFeatureImplemented(FEAT_Debugv8p2)) then
            reserved = TRUE;
        end;

        // Reserved
        if bt == '0010x' && !IsFeatureImplemented(FEAT_BWE) && !HaveAArch32EL(EL1) then
            reserved = TRUE;
        end;
    else
        // Reserved
        if bt != '10x0x' then
            reserved = TRUE;
        end;
    end;

    if reserved then
        var c : Constraint;
        (c, bt) = ConstrainUnpredictableBits{5}(Unpredictable_RESBPTYPE);
        assert c IN {Constraint_DISABLED, Constraint_UNKNOWN};
        if c == Constraint_DISABLED then
            return (c, ARBITRARY : bits(5));
        // Otherwise the value returned by ConstrainUnpredictableBits must be a not-reserved value
        end;
    end;

    return (Constraint_NONE, bt);
end;

// AArch64_StateMatch()
// ====================
// Determine whether a breakpoint or watchpoint is enabled in the current mode and state.

func AArch64_StateMatch(ssc_in : bits(2), ssce_in : bit, hmc_in : bit,
                        pxc_in : bits(2), linked_in : boolean, linked_n_in : integer,
                        isbreakpnt : boolean, vaddress : bits(64),
                        accdesc : AccessDescriptor) => boolean
begin
    if !IsFeatureImplemented(FEAT_RME) then assert ssce_in == '0'; end;

    // "ssc_in","ssce_in","hmc_in","pxc_in" are the control fields from
    // the DBGBCR_EL1(n) or DBGWCR_EL1(n) register.
    // "linked_in" is TRUE if this is a linked breakpoint/watchpoint type.
    // "linked_n_in" is the linked breakpoint number from the DBGBCR_EL1(n) or
    // DBGWCR_EL1(n) register.
    // "isbreakpnt" is TRUE for breakpoints, FALSE for watchpoints.
    // "vaddress" is the program counter for a linked watchpoint or the same value passed to
    // AArch64_CheckBreakpoint for a linked breakpoint.
    // "accdesc" describes the properties of the access being matched.
    var ssc : bits(2)      = ssc_in;
    var ssce : bit         = ssce_in;
    var hmc : bit          = hmc_in;
    var pxc : bits(2)      = pxc_in;
    var linked : boolean   = linked_in;
    var linked_n : integer = linked_n_in;

    // If parameters are set to a reserved type, behaves as either disabled or a defined type
    var c : Constraint;
    (c, ssc, ssce, hmc, pxc) = CheckValidStateMatch(ssc, ssce, hmc, pxc, isbreakpnt);
    if c == Constraint_DISABLED then return FALSE; end;
    // Otherwise the hmc,ssc,ssce,pxc values are either valid or the values returned by
    // CheckValidStateMatch are valid.

    let EL3_match : boolean = HaveEL(EL3) && hmc == '1' && ssc[0] == '0';
    let EL2_match : boolean = HaveEL(EL2) && ((hmc == '1' && (ssc::pxc != '1000')) || ssc == '11');
    let EL1_match : boolean = pxc[0] == '1';
    let EL0_match : boolean = pxc[1] == '1';

    var priv_match : boolean;
    case accdesc.el of
        when EL3 =>  priv_match = EL3_match;
        when EL2 =>  priv_match = EL2_match;
        when EL1 =>  priv_match = EL1_match;
        when EL0 =>  priv_match = EL0_match;
    end;

    // Security state match
    var ss_match : boolean;
    case ssce::ssc of
        when '000' => ss_match = hmc == '1' || accdesc.ss != SS_Root;
        when '001' => ss_match = accdesc.ss == SS_NonSecure;
        when '010' => ss_match = (hmc == '1' && accdesc.ss == SS_Root) || accdesc.ss == SS_Secure;
        when '011' => ss_match = (hmc == '1' && accdesc.ss != SS_Root) || accdesc.ss == SS_Secure;
        when '101' => ss_match = accdesc.ss == SS_Realm;
    end;

    var linked_match : boolean = FALSE;

    if linked then
        // "linked_n" must be an enabled context-aware breakpoint unit. If it is not context-aware
        // then it is CONSTRAINED UNPREDICTABLE whether this gives no match, gives a match without
        // linking, or linked_n is mapped to some UNKNOWN breakpoint that is context-aware.
        if !IsContextAwareBreakpoint(linked_n) then
            let (first_ctx_cmp, last_ctx_cmp) : (integer, integer) = ContextAwareBreakpointRange();
            (c, linked_n) = ConstrainUnpredictableInteger(first_ctx_cmp, last_ctx_cmp,
                                                          Unpredictable_BPNOTCTXCMP);
            assert c IN {Constraint_DISABLED, Constraint_NONE, Constraint_UNKNOWN};

            case c of
                when Constraint_DISABLED => return FALSE;   // Disabled
                when Constraint_NONE     => linked = FALSE; // No linking
                // Otherwise ConstrainUnpredictableInteger returned a context-aware breakpoint
            end;
        end;
    end;

    if linked then
        let linked_to : boolean = TRUE;
        var bp_type : BreakpointType;
        let from_linking_enabled : boolean = FALSE;
        (bp_type, linked_match) = AArch64_BreakpointValueMatch(linked_n, vaddress,
                                                               linked_to, isbreakpnt,
                                                               from_linking_enabled);
        if bp_type == BreakpointType_AddrMismatch then
            linked_match = !linked_match;
        end;
    end;

    return priv_match && ss_match && (!linked || linked_match);
end;

// DebugAddrTop()
// ==============
// Returns the value for the top bit used in Breakpoint and Watchpoint address comparisons.

func DebugAddrTop() => AddressSize
begin
    if IsFeatureImplemented(FEAT_LVA3) then
        return 55;
    elsif IsFeatureImplemented(FEAT_LVA) then
        return 52;
    else
        return 48;
    end;
end;

// EffectiveMDSELR_EL1_BANK()
// ==========================
// Return the effective value of MDSELR_EL1.BANK.

func EffectiveMDSELR_EL1_BANK() => bits(2)
begin
    // If 16 or fewer breakpoints and 16 or fewer watchpoints are implemented,
    // then the field is RES0.
    let num_bp : integer = NumBreakpointsImplemented();
    let num_wp : integer = NumWatchpointsImplemented();
    if num_bp <= 16 && num_wp <= 16 then
        return '00';
    end;

    // At EL3, the Effective value of this field is zero if MDCR_EL3.EBWE is 0.
    // At EL2, the Effective value is zero if the Effective value of MDCR_EL2.EBWE is 0.
    // That is, if either MDCR_EL3.EBWE is 0 or MDCR_EL2.EBWE is 0.
    // At EL1, the Effective value is zero if the Effective value of MDSCR_EL2.EMBWE is 0.
    // That is, if any of MDCR_EL3.EBWE, MDCR_EL2.EBWE, or MDSCR_EL1.EMBWE is 0.
    if ((HaveEL(EL3) && MDCR_EL3().EBWE == '0') ||
          (PSTATE.EL != EL3 && EL2Enabled() && MDCR_EL2().EBWE == '0') ||
          (PSTATE.EL == EL1 && MDSCR_EL1().EMBWE == '0')) then
        return '00';
    end;

    var bank : bits(2) = MDSELR_EL1().BANK;

    // Values are reserved depending on the number of breakpoints or watchpoints
    // implemented.
    if ((bank == '11' && num_bp <= 48 && num_wp <= 48) ||
          (bank == '10' && num_bp <= 32 && num_wp <= 32)) then
        // Reserved value
        (-, bank) = ConstrainUnpredictableBits{2}(Unpredictable_RESMDSELR);
        // The value returned by ConstrainUnpredictableBits must be a not-reserved value
    end;

    return bank;
end;

// IsBreakpointEnabled()
// =====================
// Returns TRUE if the effective value of DBGBCR_EL1(n).E is '1', and FALSE otherwise.

func IsBreakpointEnabled(n : integer) => boolean
begin
    if (n > 15 &&
          ((!HaltOnBreakpointOrWatchpoint() && !SelfHostedExtendedBPWPEnabled()) ||
          (HaltOnBreakpointOrWatchpoint() && EDSCR2().EHBWE == '0'))) then
        return FALSE;
    end;

    return DBGBCR_EL1(n).E == '1';
end;

// SelfHostedExtendedBPWPEnabled()
// ===============================
// Returns TRUE if the extended breakpoints and watchpoints are enabled, and FALSE otherwise
// from a self-hosted debug perspective.

func SelfHostedExtendedBPWPEnabled() => boolean
begin
    if NumBreakpointsImplemented() <= 16 && NumWatchpointsImplemented() <= 16 then
        return FALSE;
    end;

    if ((HaveEL(EL3) && MDCR_EL3().EBWE == '0') ||
          (EL2Enabled() && MDCR_EL2().EBWE == '0')) then
        return FALSE;
    end;

    return MDSCR_EL1().EMBWE == '1';
end;

// CheckForPMUException()
// ======================
// Take a PMU exception if enabled, permitted, and unmasked.

func CheckForPMUException()
begin
    var enabled : boolean;
    var target_el : bits(2);
    var pmu_exception : boolean;
    var synchronous : boolean;
    (enabled, target_el) = PMUExceptionEnabled();
    if !enabled || PMUExceptionMasked(target_el, PSTATE.EL, PSTATE.PM) then
        pmu_exception = FALSE;
    elsif IsFeatureImplemented(FEAT_SEBEP) && PSTATE.PPEND == '1' then
        pmu_exception = TRUE;
        synchronous = TRUE;
    else
        let include_r1 : boolean = TRUE;
        let include_r2 : boolean = TRUE;
        let include_r3 : boolean = TRUE;
        pmu_exception = CheckPMUOverflowCondition(PMUOverflowCondition_PMUException,
                                                  include_r1, include_r2, include_r3);
        synchronous = FALSE;
    end;
    if pmu_exception then
        let fsc : bits(5) = '00000';
        TakeProfilingException(target_el, fsc, synchronous);
    end;
end;

// EffectivePMEE()
// ===============
// Return the Effective value of PMEE from MDCR_ELx or PMECR_EL1, handling reserved encodings:
// '10' (MDCR_ELx), '10' and '01' (PMECR_EL1).

func EffectivePMEE(el : bits(2), for_interrupt : boolean) => bits(2)
begin
    var val : bits(2);
    case el of
        when EL1  => val = PMECR_EL1().PMEE;
        when EL2  => val = MDCR_EL2().PMEE;
        when EL3  => val = MDCR_EL3().PMEE;
        otherwise => unreachable;
    end;

    if (val == '10' || (el == EL1 && val == '01')) then
        var c : Constraint;
        (c, val) = ConstrainUnpredictableBits{2}(Unpredictable_RESPMEE);
        assert c IN {Constraint_DISABLED, Constraint_UNKNOWN};
        if c == Constraint_DISABLED then
            val = if for_interrupt then '11' else '00';
            // Otherwise the value returned by ConstrainUnpredictableBits must be
            // a non-reserved value
        end;
    end;
    return val;
end;

// ExceptionReturnPPEND()
// ======================
// Sets ShouldSetPPEND to the value to write to PSTATE.PPEND
// on an exception return.
// This function is called before any change in Exception level.

func ExceptionReturnPPEND(spsr : bits(64))
begin
    var enabled_at_source : boolean;
    var masked_at_source : boolean;
    if spsr[33] == '1' then                             // SPSR.PPEND
        var target_except : bits(2);
        (enabled_at_source, target_except) = PMUExceptionEnabled();
        if Restarting() then
            masked_at_source = TRUE;
        else
            masked_at_source = PMUExceptionMasked(target_except, PSTATE.EL, PSTATE.PM);
        end;

        var target_eret : bits(2);
        if IllegalExceptionReturn{64}(spsr) then
            target_eret = PSTATE.EL;
        else
            var valid : boolean;
            (valid, target_eret) = ELFromSPSR{64}(spsr);
            assert valid;
        end;

        let target_pm : bit = spsr[32];              // SPSR.PM
        let masked_at_dest : boolean = PMUExceptionMasked(target_except, target_eret, target_pm);
        if enabled_at_source && masked_at_source && !masked_at_dest then
            PSTATE.PPEND = '1';
            ShouldSetPPEND = FALSE;
            // PSTATE.PPEND will not be changed again by this instruction.
        end;
    end;

    // If PSTATE.PPEND has not been set by this function, ShouldSetPPEND is
    // unchanged, meaning PSTATE.PPEND might either be set by the current instruction
    // causing a counter overflow, or cleared to zero at the end of instruction.

    return;
end;

// IsSupportingPMUSynchronousMode()
// ================================
// Returns TRUE if the event support synchronous mode,
// and FALSE otherwise.

impdef func IsSupportingPMUSynchronousMode(pmuevent : bits(16)) => boolean
begin
    return TRUE;
end;

// PMUExceptionEnabled()
// =====================
// The first return value is TRUE if the PMU exception is enabled, and FALSE otherwise.
// The second return value is the target Exception level for an enabled PMU exception.

func PMUExceptionEnabled() => (boolean, bits(2))
begin

    if !IsFeatureImplemented(FEAT_EBEP) then
        return (FALSE, ARBITRARY : bits(2));
    end;

    var enabled : boolean;
    var target : bits(2) = ARBITRARY : bits(2);
    let for_interrupt : boolean = FALSE;
    let pmee_el3 : bits(2) = EffectivePMEE(EL3, for_interrupt);
    let pmee_el2 : bits(2) = EffectivePMEE(EL2, for_interrupt);
    let pmee_el1 : bits(2) = EffectivePMEE(EL1, for_interrupt);

    if HaveEL(EL3) && pmee_el3 != '01' then
        enabled = pmee_el3 == '11';
        if enabled then target = EL3; end;

    elsif EL2Enabled() && pmee_el2 != '01' then
        enabled = pmee_el2 == '11';
        if enabled then target = EL2; end;

    else
        enabled = pmee_el1 == '11';
        if enabled then
            target = if EL2Enabled() && HCR_EL2().TGE == '1' then EL2 else EL1;
        end;
    end;

    return (enabled, target);
end;

// PMUExceptionMasked()
// ====================
// Return TRUE if the PMU Exception is masked at the specified target Exception level
// relative to the specified source Exception level, and by the value of PSTATE.PM,
// and FALSE otherwise.

func PMUExceptionMasked(target_el : bits(2), from_el : bits(2), pm : bit) => boolean
begin
    assert IsFeatureImplemented(FEAT_EBEP);
    let for_interrupt : boolean = FALSE;

    if Halted() then
        return TRUE;
    elsif UInt(target_el) < UInt(from_el) then
        return TRUE;
    elsif (from_el == EL2 && target_el == EL2 &&
             EffectivePMEE(EL2, for_interrupt) != '11') then
        return TRUE;
    elsif target_el == from_el && (PMECR_EL1().KPME == '0' || pm == '1') then
        return TRUE;
    end;

    return FALSE;
end;

// PMUInterruptEnabled()
// =====================
// Return TRUE if the PMU interrupt request (PMUIRQ) is enabled, FALSE otherwise.

func PMUInterruptEnabled() => boolean
begin
    if !IsFeatureImplemented(FEAT_EBEP) then
        return TRUE;
    end;

    var enabled : boolean;
    let for_interrupt : boolean = TRUE;
    let pmee_el3 : bits(2) = EffectivePMEE(EL3, for_interrupt);
    let pmee_el2 : bits(2) = EffectivePMEE(EL2, for_interrupt);
    let pmee_el1 : bits(2) = EffectivePMEE(EL1, for_interrupt);

    if HaveEL(EL3) && pmee_el3 != '01' then
        enabled = pmee_el3 == '00';

    elsif EL2Enabled() && pmee_el2 != '01' then
        enabled = pmee_el2 == '00';

    else
        enabled = pmee_el1 == '00';
    end;

    return enabled;
end;

// AArch64_GenerateDebugExceptions()
// =================================

func AArch64_GenerateDebugExceptions() => boolean
begin
    let ss : SecurityState = CurrentSecurityState();
    return AArch64_GenerateDebugExceptionsFrom(PSTATE.EL, ss, PSTATE.D);
end;

// AArch64_GenerateDebugExceptionsFrom()
// =====================================

func AArch64_GenerateDebugExceptionsFrom(from_el : bits(2), from_state : SecurityState,
                                         mask : bit) => boolean
begin

    if OSLSR_EL1().OSLK == '1' || DoubleLockStatus() || Halted() then
        return FALSE;
    end;

    let route_to_el2 : boolean = (HaveEL(EL2) &&
                                  (from_state != SS_Secure || IsSecureEL2Enabled()) &&
                                  (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1'));
    let target : bits(2) = (if route_to_el2 then EL2 else EL1);
    var enabled : boolean;
    if HaveEL(EL3) && from_state == SS_Secure then
        enabled = MDCR_EL3().SDD == '0';
        if from_el == EL0 && ELUsingAArch32(EL1) then
            enabled = enabled || SDER32_EL3().SUIDEN == '1';
        end;
    else
        enabled = TRUE;
    end;

    if from_el == target then
        enabled = enabled && MDSCR_EL1().KDE == '1' && mask == '0';
    else
        enabled = enabled && UInt(target) > UInt(from_el);
    end;

    return enabled;
end;

// AArch64_TRCIT()
// ===============
// Determines whether an Instrumentation trace packet should
// be generated and then generates an instrumentation trace packet
// containing the value of the register passed as an argument

func AArch64_TRCIT(Xt : bits(64))
begin
    let ss = CurrentSecurityState();
    if TraceInstrumentationAllowed(ss, PSTATE.EL) then
        TraceInstrumentation(Xt);
    end;
end;

// TraceInstrumentation()
// ======================
// Generates an instrumentation trace packet
// containing the value of the register passed as an argument

impdef func TraceInstrumentation(Xt : bits(64))
begin
    return;
end;

// AArch64_IncrementCycleCounter()
// ===============================
// Increment the cycle counter and possibly set overflow bits.

func AArch64_IncrementCycleCounter()
begin
    if !CountPMUEvents(CYCLE_COUNTER_ID) then return; end;
    var d : bit = PMCR_EL0().D;   // Check divide-by-64
    var lc : bit = PMCR_EL0().LC;
    var lc_enabled : boolean;
    (lc_enabled, -) = PMUExceptionEnabled();
    lc = if lc_enabled then '1' else lc;
    // Effective value of 'D' bit is 0 when Effective value of LC is '1'
    if lc == '1' then d = '0'; end;
    if d == '1' && !HasElapsed64Cycles() then return; end;

    let old_value : integer = UInt(PMCCNTR_EL0());
    let new_value : integer = old_value + 1;
    PMCCNTR_EL0() = new_value[63:0];

    let ovflw : integer{} = if HaveAArch32() && lc == '0' then 32 else 64;

    if old_value[64:ovflw] != new_value[64:ovflw] then
        PMOVSSET_EL0().C = '1';
    end;

    return;
end;

// AArch64_IncrementEventCounter()
// ===============================
// Increment the specified event counter 'idx' by the specified amount 'increment'.
// 'Vm' is the value event counter 'idx-1' is being incremented by if 'idx' is odd,
// zero otherwise.
// Returns the amount the counter was incremented by.

func AArch64_IncrementEventCounter(idx : integer, increment_in : integer, Vm : integer) => integer
begin
    var old_value : integer;
    var new_value : integer;

    old_value = UInt(PMEVCNTR_EL0(idx));
    let increment : integer = PMUCountValue(idx, increment_in, Vm);
    new_value = old_value + increment;

    var lp : bit;
    if IsFeatureImplemented(FEAT_PMUv3p5) then
        PMEVCNTR_EL0(idx) = new_value[63:0];
        var pmuexception_enabled : boolean;
        (pmuexception_enabled, -) = PMUExceptionEnabled();
        if pmuexception_enabled then
            lp = '1';
        else
            case GetPMUCounterRange(idx) of
                when PMUCounterRange_R1 =>
                    lp = PMCR_EL0().LP;
                when PMUCounterRange_R2 =>
                    lp = MDCR_EL2().HLP;
                when PMUCounterRange_R3 =>
                    lp = '1';
                otherwise =>
                    unreachable;
            end;
        end;
    else
        lp = '0';
        PMEVCNTR_EL0(idx) = ZeroExtend{64}(new_value[31:0]);
    end;
    let ovflw : integer{} = if lp == '1' then 64 else 32;
    if old_value[64:ovflw] != new_value[64:ovflw] then
        PMOVSSET_EL0()[idx] = '1';
        // Check for the CHAIN event from an even counter
        if (idx[0] == '0' && idx + 1 < NUM_PMU_COUNTERS && lp == '0' &&
              (GetPMUCounterRange(idx) == GetPMUCounterRange(idx+1) ||
                 ConstrainUnpredictableBool(Unpredictable_COUNT_CHAIN))) then
            // If PMU counters idx and idx+1 are not in same range,
            // it is CONSTRAINED UNPREDICTABLE if CHAIN event is counted
            PMUEvent(PMU_EVENT_CHAIN, 1, idx + 1);
        end;
    end;
    if (IsFeatureImplemented(FEAT_SEBEP) &&
            IsSupportingPMUSynchronousMode(PMEVTYPER_EL0(idx).evtCount) &&
            PMINTENSET_EL1()[idx] == '1' && PMOVSSET_EL0()[idx] == '1' && increment != 0) then
        SyncCounterOverflowed = TRUE;
    end;

    return increment;
end;

// AArch64_PMUCycle()
// ==================
// Called at the end of each cycle to increment event counters and
// check for PMU overflow. In pseudocode, a cycle ends after the
// execution of the operational pseudocode.

func AArch64_PMUCycle()
begin
    if !IsFeatureImplemented(FEAT_PMUv3) then
        return;
    end;
    PMUEvent(PMU_EVENT_CPU_CYCLES);
    let counters : integer = NUM_PMU_COUNTERS;
    var Vm : integer = 0;
    if counters != 0 then
        for idx = 0 to counters - 1 do
            if CountPMUEvents(idx) then
                let accumulated : integer = PMUEventAccumulator[[idx]];
                if (idx MOD 2) == 0 then Vm = 0; end;
                Vm = AArch64_IncrementEventCounter(idx, accumulated, Vm);
            end;
            PMUEventAccumulator[[idx]] = 0;
        end;
    end;
    AArch64_IncrementCycleCounter();
    CheckForPMUOverflow();
end;

// TakeProfilingException()
// ========================
// Takes a Profiling exception.

func TakeProfilingException(target_el : bits(2), fsc : bits(5), synchronous : boolean)
begin
    var except : ExceptionRecord = ExceptionSyndrome(Exception_Profiling);
    except.syndrome.iss[5:1] = fsc;
    if synchronous then
        except.syndrome.iss[0] = '1';
    end;

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// CheckForSPEException()
// ======================
// Take an SPE Profiling exception if pending, permitted, and unmasked.

func CheckForSPEException()
begin
    if !IsFeatureImplemented(FEAT_SPE_EXC) then
        return;
    end;

    if Halted() || Restarting() then
        return;
    end;

    var route_to_el3 : boolean = FALSE;
    var route_to_el2 : boolean = FALSE;
    var route_to_el1 : boolean = FALSE;

    if HaveEL(EL3) && MDCR_EL3().PMSEE == '1x' then
        let pending : boolean = PMBSR_EL3().S == '1';
        let masked : boolean = PSTATE.EL == EL3;
        route_to_el3 = pending && !masked;
    end;

    var owning_ss : SecurityState;
    var owning_el : bits(2);
    (owning_ss, owning_el) = ProfilingBufferOwner();
    let in_owning_ss : boolean = IsCurrentSecurityState(owning_ss);

    if EffectivePMSCR_EL2_EE() == '1x' then
        let pending : boolean = PMBSR_EL2().S == '1';
        let masked : boolean = (!in_owning_ss || PSTATE.EL == EL3 ||
                                   (PSTATE.EL == EL2 && (PMSCR_EL2().EE != '11' ||
                                                         PMSCR_EL2().KE == '0' || PSTATE.PM == '1'))
                                );
        route_to_el2 = pending && !masked;
    end;

    if EffectivePMSCR_EL1_EE() == '11' then
        let pending : boolean = PMBSR_EL1().S == '1';
        let masked : boolean = (!in_owning_ss || PSTATE.EL IN {EL3, EL2} ||
                                   (PSTATE.EL == EL1 && (PMSCR_EL1().KE == '0' || PSTATE.PM == '1'))
                                );
        if EffectiveTGE() == '1' then
            route_to_el2 = route_to_el2 || (pending && !masked);
        else
            route_to_el1 = pending && !masked;
        end;
    end;

    let fsc : bits(5) = '00001';        // SPE exception
    let synchronous : boolean = FALSE;

    // The relative priorities of the following checks is IMPLEMENTATION DEFINED
    if route_to_el3 then
        TakeProfilingException(EL3, fsc, synchronous);
    end;
    if route_to_el2 then
        TakeProfilingException(EL2, fsc, synchronous);
    end;
    if route_to_el1 then
        TakeProfilingException(EL1, fsc, synchronous);
    end;
end;

// CheckMDCR_EL3_NSPBTrap()
// ========================
// Check if the register access is trappable by MDCR_EL3().[NSPBE, NSPB]

func CheckMDCR_EL3_NSPBTrap() => boolean
begin
    var state_bits : bits(3);
    var reserved : boolean;
    (state_bits, reserved) = EffectiveMDCR_EL3_NSPB();
    return ((reserved && ConstrainUnpredictableBool(Unpredictable_RESERVEDNSxB_Trap)) ||
             state_bits[0] == '0' || state_bits[1] != SCR_EL3().NS ||
             (IsFeatureImplemented(FEAT_RME) && state_bits[2] != SCR_EL3().NSE));
end;

// CollectContextIDR1()
// ====================

func CollectContextIDR1() => boolean
begin
    if !StatisticalProfilingEnabled() then return FALSE; end;
    if PSTATE.EL == EL2 then return FALSE; end;
    if EL2Enabled() && HCR_EL2().TGE == '1' then return FALSE; end;
    return PMSCR_EL1().CX == '1';
end;

// CollectContextIDR2()
// ====================

func CollectContextIDR2() => boolean
begin
    if !StatisticalProfilingEnabled() then return FALSE; end;
    if !EL2Enabled() then return FALSE; end;
    return PMSCR_EL2().CX == '1';
end;

// CollectPhysicalAddress()
// ========================

func CollectPhysicalAddress() => boolean
begin
    if !StatisticalProfilingEnabled() then return FALSE; end;
    let (owning_ss, owning_el) : (SecurityState, bits(2)) = ProfilingBufferOwner();
    if HaveEL(EL2) && (owning_ss != SS_Secure || IsSecureEL2Enabled()) then
        return PMSCR_EL2().PA == '1' && (owning_el == EL2 || PMSCR_EL1().PA == '1');
    else
        return PMSCR_EL1().PA == '1';
    end;
end;

// CollectTimeStamp()
// ==================

func CollectTimeStamp() => TimeStamp
begin
    if !StatisticalProfilingEnabled() then return TimeStamp_None; end;
    let (-, owning_el) = ProfilingBufferOwner();

    if owning_el == EL2 then
        if PMSCR_EL2().TS == '0' then return TimeStamp_None; end;
    else
        if PMSCR_EL1().TS == '0' then return TimeStamp_None; end;
    end;

    var PCT_el1 : bits(2);
    if !IsFeatureImplemented(FEAT_ECV) then
        PCT_el1 = '0'::PMSCR_EL1().PCT[0];                         // PCT[1] is RES0
    else
        PCT_el1 = PMSCR_EL1().PCT;
        if PCT_el1 == '10' then
            // Reserved value
            (-, PCT_el1) = ConstrainUnpredictableBits{2}(Unpredictable_PMSCR_PCT);
        end;
    end;
    if EL2Enabled() then
        var PCT_el2 : bits(2);
        if !IsFeatureImplemented(FEAT_ECV) then
            PCT_el2 = '0'::PMSCR_EL2().PCT[0];                     // PCT[1] is RES0
        else
            PCT_el2 = PMSCR_EL2().PCT;
            if PCT_el2 == '10' then
                // Reserved value
                (-, PCT_el2) = ConstrainUnpredictableBits{2}(Unpredictable_PMSCR_PCT);
            end;
        end;
        case PCT_el2 of
            when '00' =>
                return if IsInHost() then TimeStamp_Physical else TimeStamp_Virtual;
            when '01' =>
                if owning_el == EL2 then return TimeStamp_Physical; end;
            when '11' =>
                assert IsFeatureImplemented(FEAT_ECV);          // FEAT_ECV must be implemented
                if owning_el == EL1 && PCT_el1 == '00' then
                    return if IsInHost() then TimeStamp_Physical else TimeStamp_Virtual;
                else
                    return TimeStamp_OffsetPhysical;
                end;
            otherwise =>
                unreachable;
        end;
    end;

    case PCT_el1 of
        when '00' => return if IsInHost() then TimeStamp_Physical else TimeStamp_Virtual;
        when '01' => return TimeStamp_Physical;
        when '11' =>
            assert IsFeatureImplemented(FEAT_ECV);              // FEAT_ECV must be implemented
            return TimeStamp_OffsetPhysical;
        otherwise => unreachable;
    end;
end;

// DefaultSPEEvent()
// =================
// Return the target ELx for an indirect write to PMBSR_ELx for an Other buffer management
// event or anything other than a buffer management event.

func DefaultSPEEvent() => bits(2)
begin
    return ReportSPEEvent(Zeros{6}, ARBITRARY : bits(6));
end;

// EffectiveMDCR_EL3_NSPB()
// ========================
// Return the Effective value of MDCR_EL3().[NSPBE, NSPB] field and whether it is a reserved value.

readonly func EffectiveMDCR_EL3_NSPB() => (bits(3), boolean)
begin
    var state_bits : bits(3);
    var reserved : boolean = FALSE;

    if IsFeatureImplemented(FEAT_RME) then
        state_bits = MDCR_EL3().[NSPBE, NSPB];
        if state_bits == '10x' || (!IsFeatureImplemented(FEAT_Secure) && state_bits == '00x') then
            // Reserved value
            reserved = TRUE;
            (-, state_bits) = ConstrainUnpredictableBits{3}(Unpredictable_RESERVEDNSxB);
        end;
    else
        state_bits = '0' :: MDCR_EL3().NSPB;
    end;

    return (state_bits, reserved);
end;

// EffectivePMBLIMITR_EL1_nVM()
// ============================

func EffectivePMBLIMITR_EL1_nVM() => bit
begin
    if !IsFeatureImplemented(FEAT_SPE_nVM) then
        return '0';
    end;
    if HaveEL(EL2) then
        let (owning_ss, owning_el) : (SecurityState, bits(2)) = ProfilingBufferOwner();
        if ((owning_ss != SS_Secure || IsSecureEL2Enabled()) && owning_el == EL1 &&
              PMSCR_EL2().EnVM == '0') then
            return '0';
        end;
    end;
    return PMBLIMITR_EL1().nVM;
end;

// EffectivePMSCR_EL1_EE()
// =======================
// Return the Effective value of PMSCR_EL1.EE for the purpose of controlling the
// SPE Profiling exception.

func EffectivePMSCR_EL1_EE() => bits(2)
begin
    if EffectivePMSCR_EL2_EE() == '00' then
        return '00';
    end;

    var ee : bits(2) = PMSCR_EL1().EE;
    if ee IN {'01', '10'} then            // Reserved value
        if IsFeatureImplemented(FEAT_NV) then
            ee[0] = ee[1];
        else
            var c : Constraint;
            (c, ee) = ConstrainUnpredictableBits{2}(Unpredictable_RESPMSEE);
            assert c IN {Constraint_DISABLED, Constraint_UNKNOWN};
            if c == Constraint_DISABLED then
                ee = '00';
            end;
            // Otherwise the value returned by ConstrainUnpredictableBits must be
            // a non-reserved value
        end;
    end;

    return ee;
end;

// EffectivePMSCR_EL2_EE()
// =======================
// Return the Effective value of PMSCR_EL2.EE.

readonly func EffectivePMSCR_EL2_EE() => bits(2)
begin
    if !IsFeatureImplemented(FEAT_SPE_EXC) then
        return '00';
    end;

    if HaveEL(EL3) && MDCR_EL3().PMSEE == '00' then
        return '00';
    end;

    let check_el2 : boolean = HaveEL(EL2) && (EffectiveSCR_EL3_NS() == '1' ||
                                                 IsSecureEL2Enabled());
    return if check_el2 then PMSCR_EL2().EE else '01';
end;

// GetPMBSR_EL1_FSC()
// ==================
// Query the PMBSR_EL1.FSC field.

func GetPMBSR_EL1_FSC() => bits(6)
begin
    var FSC : bits(6);

    FSC = PMBSR_EL1()[5:0];
    return FSC;
end;

// GetPMBSR_EL2_FSC()
// ==================
// Query the PMBSR_EL2.FSC field.

func GetPMBSR_EL2_FSC() => bits(6)
begin
    var FSC : bits(6);

    FSC = PMBSR_EL2()[5:0];
    return FSC;
end;

// GetPMBSR_EL3_FSC()
// ==================
// Query the PMBSR_EL3.FSC field.

func GetPMBSR_EL3_FSC() => bits(6)
begin
    var FSC : bits(6);

    FSC = PMBSR_EL3()[5:0];
    return FSC;
end;

// OtherSPEManagementEvent()
// =========================
// Report an Other buffer management event, with the status code 'bsc'

func OtherSPEManagementEvent(bsc : bits(6))
begin
    let target_el : bits(2) = DefaultSPEEvent();
    if PMBSR_EL(target_el).S == '0' then
        PMBSR_EL(target_el).S = '1';        // Assert interrupt or exception
        PMBSR_EL(target_el).EC = '000000';  // Other buffer management event
        PMBSR_EL(target_el).MSS = ZeroExtend{16}(bsc);
        PMBSR_EL(target_el).MSS2 = Zeros{24};
    end;
end;

// PMBSR_EL - accessor
// ===================

accessor PMBSR_EL(el : bits(2)) <=> value : PMBSRType
begin
    getter
        var r : bits(64);
        case el of
            when EL1 =>   r = PMBSR_EL1();
            when EL2 =>   r = PMBSR_EL2();
            when EL3 =>   r = PMBSR_EL3();
            otherwise =>  unreachable;
        end;
        return r;
    end;
    setter
        let r : bits(64) = value;
        case el of
            when EL1 =>   PMBSR_EL1() = r;
            when EL2 =>   PMBSR_EL2() = r;
            when EL3 =>   PMBSR_EL3() = r;
            otherwise =>  unreachable;
        end;
        return;
    end;
end;

// ProfilingBufferEnabled()
// ========================

readonly func ProfilingBufferEnabled() => boolean
begin
    if !IsFeatureImplemented(FEAT_SPE) || Halted() then
        return FALSE;
    end;

    let (owning_ss, owning_el) : (SecurityState, bits(2)) = ProfilingBufferOwner();
    let state_bits : bits(2) = EffectiveSCR_EL3_NSE() :: EffectiveSCR_EL3_NS();

    var state_match : boolean;
    case owning_ss of
        when SS_Secure =>     state_match = state_bits == '00';
        when SS_NonSecure =>  state_match = state_bits == '01';
        when SS_Realm =>      state_match = state_bits == '11';
    end;

    let stopped : boolean = SPEProfilingStopped();

    return (!ELUsingAArch32(owning_el) && state_match &&
            PMBLIMITR_EL1().E == '1' && !stopped);
end;

// ProfilingBufferOwner()
// ======================

readonly func ProfilingBufferOwner() => (SecurityState, bits(2))
begin
    var owning_ss : SecurityState;

    var state_bits : bits(3);
    if HaveEL(EL3) then
        (state_bits, -) = EffectiveMDCR_EL3_NSPB();
    else
        state_bits = if SecureOnlyImplementation() then '001' else '011';
    end;

    case state_bits of
        when '00x' => owning_ss = SS_Secure;
        when '01x' => owning_ss = SS_NonSecure;
        when '11x' => owning_ss = SS_Realm;
    end;

    var owning_el : bits(2);
    if HaveEL(EL2) && (owning_ss != SS_Secure || IsSecureEL2Enabled()) then
        owning_el = if MDCR_EL2().E2PB == '00' then EL2 else EL1;
    else
        owning_el = EL1;
    end;

    return (owning_ss, owning_el);
end;

// ProfilingSynchronizationBarrier()
// =================================
// Barrier to ensure that all existing profiling data has been formatted, and profiling buffer
// addresses have been translated such that writes to the profiling buffer have been initiated.
// A following DSB completes when writes to the profiling buffer have completed.

impdef func ProfilingSynchronizationBarrier()
begin
    return;
end;

// ReportSPEEvent()
// ================
// Return the target ELx for an indirect write to PMBSR_ELx.
// When the indirect write is due to a buffer management event:
// 'ec_bits' is the Event Class for the management event.
// 'fsc_bits' is the Fault Status Code when this is a fault, ignored otherwise.
// Otherwise, 'ec_bits' should be Zeros().

func ReportSPEEvent(ec_bits : bits(6), fsc_bits : bits(6)) => bits(2)
begin
    var target_el : bits(2);
    var route_to_el3 : boolean = FALSE;
    var route_to_el2 : boolean = FALSE;

    if IsFeatureImplemented(FEAT_SPE_EXC) then
        let s1fault : boolean = (ec_bits == '100100');   // Stage 1 fault
        let s2fault : boolean = (ec_bits == '100101');   // Stage 2 fault

        var gpcfault, gpfault : boolean;
        if IsFeatureImplemented(FEAT_RME) then
            // Granule Protection Check fault, other than GPF. That is, a GPT address size fault,
            // GPT walk fault, or synchronous External abort on GPT fetch.
            gpcfault = (ec_bits == '011110');
            // Other Granule Protection Fault, reported as Stage 1 or Stage 2 fault.
            gpfault  =  ((s1fault || s2fault) && fsc_bits IN {'10001x', '1001xx', '101000'});
        else
            gpcfault = FALSE;
            gpfault  = FALSE;
        end;
        let sync_ext_abort : boolean = ((s1fault || s2fault) &&
                                           fsc_bits IN {'010000', '01001x', '0101xx', '011011'});

        var owning_ss : SecurityState;
        var owning_el : bits(2);
        (owning_ss, owning_el) = ProfilingBufferOwner();

        if HaveEL(EL3) && MDCR_EL3().PMSEE == '1x' then
            route_to_el3 = (MDCR_EL3().PMSEE == '11' ||
                            gpcfault || (gpfault && SCR_EL3().GPF == '1') ||
                            (sync_ext_abort && EffectiveEA() == '1'));
        end;

        if EffectivePMSCR_EL2_EE() == '1x' then
            route_to_el2 = (PMSCR_EL2().EE == '11' || (s1fault && owning_el == EL2) || s2fault ||
                            gpcfault || (gpfault && HCR_EL2().GPF == '1') ||
                            (sync_ext_abort && EffectiveHCR_TEA() == '1'));
        end;
    end;

    if route_to_el3 then
        target_el = EL3;
    elsif route_to_el2 then
        target_el = EL2;
    else
        target_el = EL1;
    end;

    return target_el;
end;

// SPE Implementation Constants
// ============================

constant SPEMaxAddrs : integer{} = 32;

constant SPEMaxCounters : integer{} = 32;

constant SPEMaxRecordSize : integer{} = 2048;

// SPEAddByteToRecord()
// ====================
// Add one byte to a record and increase size property appropriately.

func SPEAddByteToRecord(b : bits(8))
begin
    assert SPERecordSize < SPEMaxRecordSize;
    SPERecordData[[SPERecordSize]] = b;
    SPERecordSize = SPERecordSize + 1;
end;

// SPEAddPacketToRecord()
// ======================
// Add passed header and payload data to the record.
// Payload must be a multiple of 8.

func SPEAddPacketToRecord{N}(header_hi : bits(2), header_lo : bits(4),
                             payload : bits(N))
begin
    assert N MOD 8 == 0;
    var sz : bits(2);
    case N of
        when 8 => sz  = '00';
        when 16 => sz = '01';
        when 32 => sz = '10';
        when 64 => sz = '11';
        otherwise => unreachable;
    end;

    let header : bits(8) = header_hi::sz::header_lo;
    SPEAddByteToRecord(header);
    for i = 0 to (N DIV 8)-1 do
        SPEAddByteToRecord(payload[i*:8]);
    end;
end;

// SPEBranch()
// ===========
// Called on every branch if SPE is present. Maintains previous branch target
// and branch related SPE functionality.

func SPEBranch{N}(target : bits(N), branch_type : BranchType, conditional : boolean,
                  taken_flag : boolean)
begin
    let is_isb : boolean = FALSE;
    SPEBranch{N}(target, branch_type, conditional, taken_flag, is_isb);
end;

func SPEBranch{N}(target : bits(N), branch_type : BranchType, conditional : boolean,
                  taken_flag : boolean, is_isb : boolean)
begin
    // If the PE implements branch prediction, data about (mis)prediction is collected
    // through the PMU events.

    var collect_prev_br : boolean;
    let collect_prev_br_eret : boolean = ImpDefBool("SPE prev br on eret");
    let collect_prev_br_exception : boolean = (ImpDefBool(
                                                  "SPE prev br on exception"));
    let collect_prev_br_isb : boolean = ImpDefBool("SPE prev br on isb");
    case branch_type of
        when BranchType_EXCEPTION =>
            collect_prev_br = collect_prev_br_exception;
        when BranchType_ERET =>
            collect_prev_br = collect_prev_br_eret;
        otherwise =>
            collect_prev_br = !is_isb || collect_prev_br_isb;
    end;

    // Implements previous branch target functionality
    if (taken_flag && IsFeatureImplemented(FEAT_SPE_PBT) && StatisticalProfilingEnabled() &&
            collect_prev_br) then

        if SPESampleInFlight then
            let previous_target : bits(64) = SPESamplePreviousBranchAddress;
            SPESampleAddress[[SPEAddrPosPrevBranchTarget]][63:0] = previous_target[63:0];
            let previous_branch_valid : boolean = SPESamplePreviousBranchAddressValid;
            SPESampleAddressValid[[SPEAddrPosPrevBranchTarget]] = previous_branch_valid;
        end;
        // Save the target address for it to be added to a future record.
        SPESamplePreviousBranchAddress[55:0] = target[55:0];

        var ns : bit;
        var nse : bit;
        case CurrentSecurityState() of
            when SS_Secure =>
                ns = '0';
                nse = '0';
            when SS_NonSecure =>
                ns = '1';
                nse = '0';
            when SS_Realm =>
                ns  = '1';
                nse = '1';
            otherwise => unreachable;
        end;

        SPESamplePreviousBranchAddress[63] = ns;
        SPESamplePreviousBranchAddress[60] = nse;
        SPESamplePreviousBranchAddress[62:61] = PSTATE.EL;
        SPESamplePreviousBranchAddressValid   = TRUE;
    end;

    if !StatisticalProfilingEnabled() then
        if taken_flag then
            // Invalidate previous branch address, if profiling is disabled
            // or prohibited.
            SPESamplePreviousBranchAddressValid = FALSE;
        end;
        return;
    end;

    if SPESampleInFlight then
        SPESampleOpAttr.branch_is_direct = branch_type IN {BranchType_DIR, BranchType_DIRCALL};
        SPESampleOpAttr.branch_has_link  = branch_type IN {BranchType_DIRCALL, BranchType_INDCALL};
        SPESampleOpAttr.procedure_return = branch_type == BranchType_RET;
        SPESampleOpAttr.op_type          = SPEOpType_Branch;
        SPESampleOpAttr.is_conditional   = conditional;
        SPESampleOpAttr.cond_pass        = taken_flag;

        // Save the target address.
        if taken_flag then
            var ns : bit;
            var nse : bit;
            case CurrentSecurityState() of
                when SS_Secure =>
                    ns = '0';
                    nse = '0';
                when SS_NonSecure =>
                    ns = '1';
                    nse = '0';
                when SS_Realm =>
                    ns  = '1';
                    nse = '1';
                otherwise => unreachable;
            end;
            let el : bits(2) = PSTATE.EL;

            SPESampleAddress[[SPEAddrPosBranchTarget]][55:0]  = target[55:0];
            SPESampleAddress[[SPEAddrPosBranchTarget]][63:56] = ns::el::nse::Zeros{4};
            SPESampleAddressValid[[SPEAddrPosBranchTarget]]   = TRUE;
        end;
    end;
end;

// SPEBufferIsFull()
// =================
// Return true if another full size sample record would not fit in the
// profiling buffer.

func SPEBufferIsFull() => boolean
begin
    let write_pointer_limit : integer = UInt(PMBLIMITR_EL1().LIMIT::Zeros{12});
    let current_write_pointer : integer = UInt(PMBPTR_EL1());
    let record_max_size : integer = 1<<UInt(PMSIDR_EL1().MaxSize);
    return current_write_pointer > (write_pointer_limit - record_max_size);
end;

// SPECollectRecord()
// ==================
// Returns TRUE if the sampled class of instructions or operations, as
// determined by PMSFCR_EL1, are recorded and FALSE otherwise.

func SPECollectRecord(events : bits(64), total_latency : integer, optype : SPEOpType) => boolean
begin
    // Filtering by events
    var is_rejected_event : boolean;
    var is_rejected_nevent : boolean;
    (is_rejected_event, is_rejected_nevent) = SPEFilterByEvents(events);

    // Filtering by type
    let is_rejected_type : boolean = SPEFilterByType(SPESampleOpAttr);

    // Filtering by latency
    let is_rejected_latency : boolean = SPEFilterByLatency(total_latency);

    let is_rejected_data_source : boolean = SPEFilterByDataSource(optype);

    var return_value : boolean;
    return_value = !(is_rejected_nevent || is_rejected_event ||
                     is_rejected_type || is_rejected_latency ||
                     is_rejected_data_source);

    if return_value then
        PMUEvent(PMU_EVENT_SAMPLE_FILTRATE);
    end;

    return return_value;
end;

// SPECompleteSample()
// ===================
// Called to complete the sampling process.

func SPECompleteSample()
begin
    assert SPESampleInFlight;

    PMUEvent(PMU_EVENT_SAMPLE_FEED);

    // Stop any pending counters
    for counter_index = 0 to (SPEMaxCounters - 1) do
        if SPESampleCounterPending[[counter_index]] then
            SPEStopCounter(counter_index);
        end;
    end;

    // Record any IMPLEMENTATION DEFINED events
    let impdef_events : bits(64) = ImpDefBits{}("SPE EVENTS");
    SPESampleEvents[63:48] = impdef_events[63:48];
    // The number of bits available for IMPLEMENTATION DEFINED events
    // is reduced by FEAT_SPEv1p4
    if !IsFeatureImplemented(FEAT_SPEv1p4) then
        SPESampleEvents[31:24] = impdef_events[31:24];
    end;
    SPESampleEvents[15:12] = impdef_events[15:12];
    // Bit 24 encodes whether the sample was collected in Streaming SVE mode.
    if IsFeatureImplemented(FEAT_SPE_SME) then
        SPESampleEvents[24] = PSTATE.SM;
    end;
    SPESampleEvents[6] = if (SPESampleOpAttr.is_conditional &&
                                 !SPESampleOpAttr.cond_pass) then '1' else '0';

    var collect_record : boolean;
    collect_record = SPECollectRecord(SPESampleEvents,
                                      SPESampleCounter[[SPECounterPosTotalLatency]],
                                      SPESampleOpAttr.op_type);
    var discard : boolean = FALSE;
    if IsFeatureImplemented(FEAT_SPEv1p2) then
        discard = PMBLIMITR_EL1().FM == '10';
    end;
    if collect_record && !discard then
        SPEConstructRecord();
        if SPEBufferIsFull() then
            let bsc : bits(6) = '000001';     // Buffer full event
            OtherSPEManagementEvent(bsc);
            PMUEvent(PMU_EVENT_SAMPLE_BUFFER_FULL);
        end;
    end;

    SPESampleInFlight = FALSE;

    SPEResetSampleStorage();
end;

// Order of addresses in sample storage and architectural index values
constant SPEAddrPosPCVirtual : integer = 0;

constant SPEAddrPosBranchTarget : integer = 1;

constant SPEAddrPosDataVirtual : integer = 2;

constant SPEAddrPosDataPhysical : integer = 3;

constant SPEAddrPosPrevBranchTarget : integer = 4;

// Order of counters in sample storage and architectural index values
constant SPECounterPosTotalLatency : integer = 0;

constant SPECounterPosIssueLatency : integer = 1;

constant SPECounterPosTranslationLatency : integer = 2;

constant SPECounterPosAltIssueLatency : integer = 4;

// Sample in-flight flag
var SPESampleInFlight : boolean = FALSE;

// Globally declared variables which store data about the sample.

// Context storage
var SPESampleContextEL1 : bits(32);

var SPESampleContextEL1Valid : boolean;

var SPESampleContextEL2 : bits(32);

var SPESampleContextEL2Valid : boolean;

// Counter storage
var SPESampleCounter : array [[SPEMaxCounters]] of integer;

var SPESampleCounterValid : array [[SPEMaxCounters]] of boolean;

var SPESampleCounterPending : array [[SPEMaxCounters]] of boolean;

// Address storage
var SPESampleAddress : array [[SPEMaxAddrs]] of bits(64);

var SPESampleAddressValid : array [[SPEMaxAddrs]] of boolean;

var SPESamplePreviousBranchAddress : bits(64);

var SPESamplePreviousBranchAddressValid : boolean;

// Data source storage
var SPESampleDataSource : bits(16);

var SPESampleDataSourceValid : boolean;

// OpAttr storage
var SPESampleOpAttr : SPEOpAttr;

// Timestamp storage
var SPESampleTimestamp : bits(64);

var SPESampleTimestampValid : boolean;

// Event storage
var SPESampleEvents : bits(64);

// SPEConstructClass()
// ===================
// Constructs the encodings for the class and subclass fields.

func SPEConstructClass() => (bits(2), bits(8))
begin
    var op_class : bits(2);
    var op_subclass : bits(8);
    let cond : bit = if SPESampleOpAttr.is_conditional then '1' else '0';
    let fp : bit = if SPESampleOpAttr.is_floating_point then '1' else '0';
    let ldst : bit = if SPESampleOpAttr.op_type == SPEOpType_Store then '1' else '0';
    let ar : bit = if SPESampleOpAttr.is_acquire_release then '1' else '0';
    let excl : bit = if SPESampleOpAttr.is_exclusive then '1' else '0';
    let at : bit = if SPESampleOpAttr.at then '1' else '0';
    let indirect : bit = if SPESampleOpAttr.branch_is_direct then '0' else '1';
    let pred : bit = if SPESampleOpAttr.is_predicated then '1' else '0';
    let sg : bit = if SPESampleOpAttr.is_gather_scatter then '1' else '0';
    let evl : bits(3) = SPESampleOpAttr.evl;
    let simd : bit = if SPESampleOpAttr.is_simd then '1' else '0';
    let ets : bits(4) = SPESampleOpAttr.ets;
    // Since this implementation of SPE samples instruction instead of micro-operations, a
    // Branch with link or Procedure return instruction will never be recorded as a "Load/store,
    // GCS" format Operation Type packet. Therefore the COMMON bit is hard-wired to '1'.
    let common : bit = '1';
    if SPESampleOpAttr.op_type == SPEOpType_Other then
        op_class = '00';
        op_subclass = Zeros{5}::simd::fp::cond;
    elsif SPESampleOpAttr.op_type == SPEOpType_OtherSVE then
        op_class = '00';
        op_subclass = '0'::evl::'1'::pred::fp::'0';
    elsif SPESampleOpAttr.op_type == SPEOpType_OtherSME then
        op_class = '00';
        op_subclass = '1'::ets[3:1]::'1'::ets[0]::fp::'0';
    elsif SPESampleOpAttr.op_type == SPEOpType_Branch then
        op_class = '10';
        var cr : bits(2) = '00';
        var gcs : bit = '0';
        if IsFeatureImplemented(FEAT_SPE_CRR) then
            if SPESampleOpAttr.branch_has_link then
                cr = '01';
            elsif SPESampleOpAttr.procedure_return then
                cr = '10';
            else
                cr = '11';
            end;
        end;
        if IsFeatureImplemented(FEAT_GCS) then
            if (SPESampleOpAttr.ldst_type == SPELDSTType_GCS &&
               (SPESampleOpAttr.branch_has_link || SPESampleOpAttr.procedure_return)) then
                gcs = '1';
            end;
        end;
        op_subclass = Zeros{3}::cr::gcs::indirect::cond;
    elsif SPESampleOpAttr.op_type IN {SPEOpType_Load, SPEOpType_Store, SPEOpType_LoadAtomic} then
        op_class = '01';
        case SPESampleOpAttr.ldst_type of
            when SPELDSTType_NV2 =>
                op_subclass = '0011000'::ldst;
            when SPELDSTType_Extended =>
                op_subclass = '000'::ar::excl::at::'1'::ldst;
            when SPELDSTType_General =>
                op_subclass = Zeros{7}::ldst;
            when SPELDSTType_SIMDFP =>
                op_subclass = '0000010'::ldst;
            when SPELDSTType_SVESME =>
                op_subclass = sg::evl::'1'::pred::'0'::ldst;
            when SPELDSTType_Unspecified =>
                op_subclass = '0001000'::ldst;
            when SPELDSTType_Tags =>
                op_subclass = '0001010'::ldst;
            when SPELDSTType_MemCopy =>
                op_subclass = '0010000'::ldst;
            when SPELDSTType_MemSet =>
                op_subclass = '00100101';
            when SPELDSTType_GCS =>
                op_subclass = '01000'::common::'0'::ldst;
            when SPELDSTType_GCSSS2 =>
                // GCSSS2 is converted to GCS, should not appear here
                unreachable;
            otherwise =>
                unreachable;
        end;
    else
        unreachable;
    end;
    return (op_class, op_subclass);
end;

// SPEConstructRecord()
// ====================
// Create new record and populate it with packets using sample storage data.
// This is an example implementation, packets may appear in
// any order as long as the record ends with an End or Timestamp packet.

func SPEConstructRecord()
begin
    // Empty the record.
    SPEEmptyRecord();

    // Add contextEL1 if available
    if SPESampleContextEL1Valid then
        SPEAddPacketToRecord{32}('01', '0100', SPESampleContextEL1);
    end;

     // Add contextEL2 if available
    if SPESampleContextEL2Valid then
        SPEAddPacketToRecord{32}('01', '0101', SPESampleContextEL2);
    end;

    // Add valid counters
    for counter_index = 0 to (SPEMaxCounters - 1) do
        if SPESampleCounterValid[[counter_index]] then
            if counter_index >= 8 then
                // Need extended format
                SPEAddByteToRecord('001000'::counter_index[4:3]);
            end;
            // Check for overflow
            let large_counters : boolean = ImpDefBool("SPE 16bit counters");
            if large_counters then
                if SPESampleCounter[[counter_index]] > 0xFFFF then
                    SPESampleCounter[[counter_index]] = 0xFFFF;
                end;
            else
                if SPESampleCounter[[counter_index]] > 0xFFF then
                    SPESampleCounter[[counter_index]] = 0xFFF;
                end;
            end;

            // Add byte0 for short format (byte1 for extended format)
            SPEAddPacketToRecord{16}('10', '1'::counter_index[2:0],
                                     SPESampleCounter[[counter_index]][15:0]);
        end;
    end;

    // Add valid addresses
    if IsFeatureImplemented(FEAT_SPE_PBT) then
        // Under the some conditions, it is IMPLEMENTATION_DEFINED whether
        // previous branch packet is present.
        let include_prev_br : boolean = (ImpDefBool(
                                            "SPE get prev br if not br"));
        if SPESampleOpAttr.op_type != SPEOpType_Branch && !include_prev_br then
            SPESampleAddressValid[[SPEAddrPosPrevBranchTarget]] = FALSE;
        end;
    end;

    // Data Virtual address should not be collected if this was an NV2 access and Statistical
    // Profiling is disabled at EL2.
    if !StatisticalProfilingEnabled(EL2) && SPESampleOpAttr.ldst_type == SPELDSTType_NV2 then
        SPESampleAddressValid[[SPEAddrPosDataVirtual]] = FALSE;
    end;

    for address_index = 0 to (SPEMaxAddrs - 1) do
        if SPESampleAddressValid[[address_index]] then
            if address_index >= 8 then
                // Need extended format
                SPEAddByteToRecord('001000'::address_index[4:3]);
            end;
            // Add byte0 for short format (byte1 for extended format)
            SPEAddPacketToRecord{64}('10', '0'::address_index[2:0],
                                     SPESampleAddress[[address_index]]);
        end;
    end;

    // Add Data Source
    if SPESampleDataSourceValid then
        let ds_payload_size : integer{} = SPEGetDataSourcePayloadSize();
        SPEAddPacketToRecord{8 * ds_payload_size}('01', '0011',
                                                  SPESampleDataSource[8*ds_payload_size-1:0]);
    end;

    var op_class : bits(2);
    var op_subclass : bits(8);
    (op_class, op_subclass) = SPEConstructClass();
    // Add operation details
    SPEAddPacketToRecord{8}('01', '10'::op_class, op_subclass);

    // Add events
    // Get size of payload in bytes.
    let payload_size : integer{} = SPEGetEventsPayloadSize();
    SPEAddPacketToRecord{8 * payload_size}('01', '0010', SPESampleEvents[8*payload_size-1:0]);

    // Add Timestamp to end the record if one is available.
    // Otherwise end with an End packet.
    if SPESampleTimestampValid then
        SPEAddPacketToRecord{64}('01', '0001', SPESampleTimestamp);
    else
        SPEAddByteToRecord('00000001');
    end;

    // Add padding
    while SPERecordSize MOD (1<<UInt(PMBIDR_EL1().Align)) != 0 looplimit 2048 do
        SPEAddByteToRecord(Zeros{8});
    end;
    SPEWriteToBuffer();
    CTI_SignalEvent(CrossTriggerIn_SPESample);
end;

// SPECycle()
// ==========
// Function called at the end of every cycle. Responsible for asserting interrupts
// and advancing counters.

func SPECycle()
begin
    if !IsFeatureImplemented(FEAT_SPE) then
        return;
    end;

    // Increment pending counters
    if SPESampleInFlight then
        for i = 0 to (SPEMaxCounters - 1) do
            if SPESampleCounterPending[[i]] then
                SPESampleCounter[[i]] = SPESampleCounter[[i]] + 1;
            end;
        end;
    end;

    // Assert PMBIRQ if appropriate.
    if SPEInterruptEnabled() && PMBSR_EL1().S == '1' then
        SetInterruptRequestLevel(InterruptID_PMBIRQ, HIGH);
    else
        SetInterruptRequestLevel(InterruptID_PMBIRQ, LOW);
    end;
end;

// SPEEmptyRecord()
// ================
// Reset record data.

func SPEEmptyRecord()
begin
    SPERecordSize = 0;
    for i = 0 to (SPEMaxRecordSize - 1) do
        SPERecordData[[i]] = Zeros{8};
    end;
end;

// SPEEncodeETS()
// ==============
// Encodes an integer tile size length into the ets field for the SPE operation type packet.

func SPEEncodeETS(size : integer) => bits(4)
begin
    var ets : bits(4);
    if size <= 128 then
        ets = '0000';
    elsif size <= 256 then
        ets = '0001';
    elsif size <= 512 then
        ets = '0010';
    elsif size <= 1024 then
        ets = '0011';
    elsif size <= 2048 then
        ets = '0100';
    elsif size <= 4096 then
        ets = '0101';
    elsif size <= 8192 then
        ets = '0110';
    elsif size <= 16384 then
        ets = '0111';
    elsif size <= 32768 then
        ets = '1000';
    elsif size <= 65536 then
        ets = '1001';
    elsif size <= 131072 then
        ets = '1010';
    elsif size <= 262144 then
        ets = '1011';
    else
        ets = '1111';
    end;
    return ets;
end;

// SPEEncodeEVL()
// ==============
// Encodes an integer vector length into the evl field for the SPE operation type packet.

func SPEEncodeEVL(vl : integer) => bits(3)
begin
    var evl : bits(3);
    if vl <= 32 then
        evl = '000';
    elsif vl <= 64 then
        evl = '001';
    elsif vl <= 128 then
        evl = '010';
    elsif vl <= 256 then
        evl = '011';
    elsif vl <= 512 then
        evl = '100';
    elsif vl <= 1024 then
        evl = '101';
    elsif vl <= 2048 then
        evl = '110';
    else
        if IsFeatureImplemented(FEAT_SPE_SME) then
            evl = '111';
        else
            unreachable;
        end;
    end;
    return evl;
end;

// SPEEvent()
// ==========
// Called when a PMU event is generated by the sampled structure.
// Sets appropriate bit in SPESampleStorage.events.

func SPEEvent(pmuevent : bits(16))
begin
    if !SPESampleInFlight then
        return;
    end;
    case pmuevent of
        when PMU_EVENT_DSNP_HIT_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[23] = '1';                                  // Snoop hit
            end;
        when PMU_EVENT_L1D_LFB_HIT_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[22] = '1';                                  // Recent fetch
            end;
        when PMU_EVENT_L2D_LFB_HIT_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[22] = '1';                                  // Recent fetch
            end;
        when PMU_EVENT_L3D_LFB_HIT_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[22] = '1';                                  // Recent fetch
            end;
        when PMU_EVENT_LL_LFB_HIT_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[22] = '1';                                  // Recent fetch
            end;
        when PMU_EVENT_L1D_CACHE_HITM_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[21] = '1';                                  // Modified
            end;
        when PMU_EVENT_L2D_CACHE_HITM_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[21] = '1';                                  // Modified
            end;
        when PMU_EVENT_L3D_CACHE_HITM_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[21] = '1';                                  // Modified
            end;
        when PMU_EVENT_LL_CACHE_HITM_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[21] = '1';                                  // Modified
            end;
        when PMU_EVENT_L2D_CACHE_LMISS_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[20] = '1';                                  // L2 miss
            end;
        when PMU_EVENT_L2D_CACHE_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[19] = '1';                                  // L2 access
            end;
        when PMU_EVENT_SVE_PRED_EMPTY_SPEC =>
            if IsFeatureImplemented(FEAT_SPEv1p1) then
                SPESampleEvents[18] = '1';                                  // Empty predicate
            end;
        when PMU_EVENT_SVE_PRED_NOT_FULL_SPEC =>
            if IsFeatureImplemented(FEAT_SPEv1p1) then
                SPESampleEvents[17] = '1';                                  // Partial predicate
            end;
        when PMU_EVENT_LDST_ALIGN_LAT =>
            if IsFeatureImplemented(FEAT_SPEv1p1) then
                SPESampleEvents[11] = '1';                                  // Misaligned
            end;
        when PMU_EVENT_REMOTE_ACCESS =>         SPESampleEvents[10]  = '1';    // Remote access
        when PMU_EVENT_LL_CACHE_MISS =>         SPESampleEvents[9]   = '1';    // LLC miss
        when PMU_EVENT_LL_CACHE =>              SPESampleEvents[8]   = '1';    // LLC access
        when PMU_EVENT_BR_MIS_PRED =>           SPESampleEvents[7]   = '1';    // Mispredicted
        when PMU_EVENT_BR_MIS_PRED_RETIRED =>   SPESampleEvents[7]   = '1';    // Not taken
        when PMU_EVENT_DTLB_WALK =>             SPESampleEvents[5]   = '1';    // TLB walk
        when PMU_EVENT_L1D_TLB =>               SPESampleEvents[4]   = '1';    // TLB access
        when PMU_EVENT_L1D_CACHE_REFILL =>
            if !IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[3] = '1';                                   // L1 refill
            end;
        when PMU_EVENT_L1D_CACHE_LMISS_RD =>
            if IsFeatureImplemented(FEAT_SPEv1p4) then
                SPESampleEvents[3] = '1';                                   // L1 miss
            end;
        when PMU_EVENT_L1D_CACHE =>             SPESampleEvents[2]   = '1';    // L1 access
        when PMU_EVENT_INST_RETIRED =>          SPESampleEvents[1]   = '1';    // Retire
        when PMU_EVENT_EXC_TAKEN =>             SPESampleEvents[0]   = '1';    // Exception
        otherwise => return;
    end;
    return;
end;

// SPEFilterByDataSource()
// =======================
// Carry out filtering by data source.

func SPEFilterByDataSource(optype : SPEOpType) => boolean
begin
    // Filtering by Data Source
    var is_rejected_data_source : boolean = FALSE;
    if (IsFeatureImplemented(FEAT_SPE_FDS) && SPESampleDataSourceValid &&
       (optype IN {SPEOpType_Load, SPEOpType_LoadAtomic})) then
        let data_source : bits(16) = SPESampleDataSource;
        let index : integer = UInt(data_source[5:0]);
        let is_ds : boolean = PMSDSFR_EL1()[index] == '1';
        if is_ds then PMUEvent(PMU_EVENT_SAMPLE_FEED_DS); end;
        if PMSFCR_EL1().FDS == '1' then
            // Filtering by Data Source is enabled
            is_rejected_data_source = !is_ds;
        end;
    end;
    return is_rejected_data_source;
end;

// SPEFilterByEvents()
// ===================
// Carries out filtering by the event bits.

func SPEFilterByEvents(events : bits(64)) => (boolean, boolean)
begin
    // "mask" defines which Events packet bits are checked by the filter
    var mask : bits(64) = Zeros{};
    let impdef_mask : bits(64) = ImpDefBits{}("SPE mask");

    mask[63:48] = impdef_mask[63:48];
    if IsFeatureImplemented(FEAT_SPE_SME) && IsFeatureImplemented(FEAT_SPEv1p4) then
        mask[25:24] = '11';                 // Streaming mode, SMCU
    end;
    if IsFeatureImplemented(FEAT_SPEv1p4) then
        mask[23:19] = '11111';              // Snoop hit, recent fetch, modified,
                                            // L2 miss, L2 access
    else
        mask[31:24] = impdef_mask[31:24];
    end;
    if IsFeatureImplemented(FEAT_SPEv1p1) && IsFeatureImplemented(FEAT_SVE) then
        mask[18:17] = '11';                 // Predicates
    end;
    mask[15:12] = impdef_mask[15:12];
    if IsFeatureImplemented(FEAT_SPEv1p1) then
        mask[11] = '1';                     // Data alignment
    end;
    if IsFeatureImplemented(FEAT_SPEv1p4) then
        mask[10:8] = '111';                 // Remote access, LLC access, LLC miss
    else
        mask[10:8] = impdef_mask[10:8];
    end;
    mask[7] = '1';                          // Mispredicted
    if IsFeatureImplemented(FEAT_SPE_FnE) then
        mask[6] = '1';                      // Not taken
    end;
    mask[5,3,1] = '111';                    // TLB walk, L1 miss, retired
    if IsFeatureImplemented(FEAT_SPEv1p4) then
        mask[4,2] = '11';                   // TLB access, L1 access
    else
        mask[4,2] = impdef_mask[4,2];
    end;

    let e : bits(64) = events AND mask;

    // Filtering by event
    let evfr : bits(64) = PMSEVFR_EL1() AND mask;
    var is_rejected_event : boolean = FALSE;
    let is_evt : boolean = IsZero(NOT(e) AND evfr);
    if PMSFCR_EL1().FE == '1' then
        // Filtering by event is enabled
        if !IsZero(evfr) then
            // Not a CONSTRAINED UNPREDICTABLE case
            is_rejected_event = !is_evt;
        else
            is_rejected_event = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
        end;
    end;

    // Filtering by inverse event
    var is_rejected_nevent : boolean = FALSE;
    var is_nevt : boolean;
    if IsFeatureImplemented(FEAT_SPE_FnE) then
        let nevfr : bits(64) = PMSNEVFR_EL1() AND mask;
        is_nevt = IsZero(e AND nevfr);
        if PMSFCR_EL1().FnE == '1' then
            // Inverse filtering by event is enabled
            if !IsZero(nevfr) then
                // Not a CONSTRAINED UNPREDICTABLE case
                is_rejected_nevent = !is_nevt;
            else
                is_rejected_nevent = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
            end;
        end;
    else
        is_nevt = TRUE; // not implemented
    end;
    if is_evt && is_nevt then
        PMUEvent(PMU_EVENT_SAMPLE_FEED_EVENT);
    end;
    if (IsFeatureImplemented(FEAT_SPE_FnE) && PMSFCR_EL1().[FnE,FE]== '11' &&
          !IsZero(PMSEVFR_EL1() AND PMSNEVFR_EL1() AND mask)) then
        // CONSTRAINED UNPREDICTABLE case due to combination of filter and inverse filter
        is_rejected_nevent = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
        is_rejected_event = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
    end;

    return (is_rejected_event, is_rejected_nevent);
end;

// SPEFilterByLatency()
// ====================
// Carries out filtering by latency.

func SPEFilterByLatency(total_latency : integer) => boolean
begin

    let is_lat : boolean = (total_latency >= UInt(PMSLATFR_EL1().MINLAT));
    if is_lat then PMUEvent(PMU_EVENT_SAMPLE_FEED_LAT); end;

    var is_rejected_latency : boolean = FALSE;
    if PMSFCR_EL1().FL == '1' then
        // Filtering by latency is enabled
        if !IsZero(PMSLATFR_EL1().MINLAT) then
            // Not a CONSTRAINED UNPREDICTABLE case
            is_rejected_latency = is_rejected_latency || !is_lat;
        else
            is_rejected_latency = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
        end;
    end;

    return is_rejected_latency;
end;

// SPEFilterByType()
// =================
// Returns TRUE if the operation is to be discarded because of its OpAttrs, and FALSE otherwise.

func SPEFilterByType(opattr : SPEOpAttr) => boolean
begin
    // Bit positions in the PMSFCR_EL1().[TYPE, TYPEm] fields
    let B : integer    = 0;
    let LD : integer   = 1;
    let ST : integer   = 2;
    let FP : integer   = 3;
    let SIMD : integer = 4;

    var flags : bits(5) = Zeros{};
    var ctrl : bits(5)  = Zeros{};
    // With GCS, Branch Link and Procedure Return instructions write and read the GCS.
    // BL and RET instructions with GCS enabled call SPESampleLoadStore() before
    // branch/packet construction, setting ldst_type to indicate a GCS access.
    let is_gcs_ldst : boolean = (opattr.op_type == SPEOpType_Branch &&
                                 opattr.ldst_type == SPELDSTType_GCS);
    let is_load : boolean     = (opattr.op_type IN {SPEOpType_Load, SPEOpType_LoadAtomic}
                                || (is_gcs_ldst && opattr.procedure_return));
    let is_store : boolean    = (opattr.op_type IN {SPEOpType_Store, SPEOpType_LoadAtomic}
                                 || (is_gcs_ldst && opattr.branch_has_link));
    flags[B]    = (if opattr.op_type == SPEOpType_Branch then '1' else '0');
    flags[LD]   = (if is_load then '1' else '0');
    flags[ST]   = (if is_store then '1' else '0');
    flags[FP]   = (if opattr.is_floating_point then '1' else '0');
    flags[SIMD] = (if opattr.is_simd then '1' else '0');
    ctrl[2:0]   = PMSFCR_EL1().TYPE[2:0];
    var mask : bits(5) = Zeros{};
    if IsFeatureImplemented(FEAT_SPE_EFT) then
        ctrl[4:3] = PMSFCR_EL1().TYPE[4:3];
        mask[4:0] = PMSFCR_EL1().TYPEm;
    end;

    let ctrl_or : bits(5)  = (ctrl AND (NOT mask));
    let ctrl_and : bits(5) = (ctrl AND mask);

    let is_op : boolean = ((IsZero(ctrl_or) || !IsZero(flags AND ctrl_or)) &&
                               ((flags AND mask) == ctrl_and));

    if flags[B]    == '1' then PMUEvent(PMU_EVENT_SAMPLE_FEED_BR); end;
    if flags[LD]   == '1' then PMUEvent(PMU_EVENT_SAMPLE_FEED_LD); end;
    if flags[ST]   == '1' then PMUEvent(PMU_EVENT_SAMPLE_FEED_ST); end;
    if flags[FP]   == '1' then PMUEvent(PMU_EVENT_SAMPLE_FEED_FP); end;
    if flags[SIMD] == '1' then PMUEvent(PMU_EVENT_SAMPLE_FEED_SIMD); end;

    var is_rejected_type : boolean = FALSE;
    if PMSFCR_EL1().FT == '1' then
        // Filtering by type is enabled
        if IsFeatureImplemented(FEAT_SPE_EFT) || !IsZero(ctrl) then
            is_rejected_type = !is_op;
        else
            is_rejected_type = ConstrainUnpredictableBool(Unpredictable_BADPMSFCR);
        end;
    end;
    if is_op && (!IsZero(ctrl) || !IsZero(mask)) then PMUEvent(PMU_EVENT_SAMPLE_FEED_OP); end;

    return is_rejected_type;
end;

// SPEFreezeOnEvent()
// ==================
// Returns TRUE if PMU event counter idx should be frozen due to an SPE event, and FALSE otherwise.

func SPEFreezeOnEvent(idx : integer) => boolean
begin
    let counters : integer = NUM_PMU_COUNTERS;
    assert (idx >= 0 &&
            (idx < counters || idx == CYCLE_COUNTER_ID ||
             (idx == INSTRUCTION_COUNTER_ID && IsFeatureImplemented(FEAT_PMUv3_ICNTR))));

    if !IsFeatureImplemented(FEAT_SPEv1p2) || !IsFeatureImplemented(FEAT_PMUv3p7) then
        return FALSE;
    end;
    if idx == CYCLE_COUNTER_ID && !IsFeatureImplemented(FEAT_SPE_DPFZS) then
        // FZS does not affect the cycle counter when FEAT_SPE_DPFZS is not implemented
        return FALSE;
    end;

    let freeze_on_event : boolean = PMBLIMITR_EL1().[E,PMFZ] == '11';
    let stopped : boolean = SPEProfilingStopped();

    case GetPMUCounterRange(idx) of
        when PMUCounterRange_R1 =>
            return freeze_on_event && stopped && PMCR_EL0().FZS == '1';
        when PMUCounterRange_R2 =>
            return freeze_on_event && stopped && MDCR_EL2().HPMFZS == '1';
        otherwise =>
            return FALSE;
    end;
end;

// SPEGetDataSource()
// ==================
// Returns a tuple indicating the data source for an access passed to SPESampleLoadStore, and
// whether the data source is valid.

impdef func SPEGetDataSource(is_load : boolean,
                             accdesc : AccessDescriptor,
                             addrdesc : AddressDescriptor) => (boolean, bits(16))
begin
    return (TRUE, Zeros{16});
end;

// SPEGetDataSourcePayloadSize()
// =============================
// Returns the size of the Data Source payload in bytes.

func SPEGetDataSourcePayloadSize() => integer{1..2}
begin
    return ImpDefInt("SPE Data Source packet payload size") as integer{1..2};
end;

// SPEGetEventsPayloadSize()
// =========================
// Returns the size in bytes of the Events packet payload as an integer.

func SPEGetEventsPayloadSize() => integer{1..4}
begin
    return ImpDefInt("SPE Events packet payload size") as integer{1..4};
end;

// SPEGetRandomBoolean()
// =====================
// Returns a random or pseudo-random boolean value.

impdef func SPEGetRandomBoolean() => boolean
begin
    return SPEGetRandomInterval()[0] == '1';
end;

// SPEGetRandomInterval()
// ======================
// Returns a random or pseudo-random byte for resetting COUNT or ECOUNT.

impdef func SPEGetRandomInterval() => bits(8)
begin
    return _PC[0+:8];
end;

// SPEISB()
// ========
// Called by ISB instruction, correctly calls SPEBranch to save previous branches.

func SPEISB()
begin
    let address : bits(64)           = PC64() + 4;
    let branch_type : BranchType     = BranchType_DIR;
    let branch_conditional : boolean = FALSE;
    let taken : boolean              = FALSE;
    let is_isb : boolean             = TRUE;

    SPEBranch{64}(address, branch_type, branch_conditional, taken, is_isb);
end;

// SPEInterruptEnabled()
// =====================
// Return TRUE if the SPE interrupt request (PMBIRQ) is enabled, FALSE otherwise.

func SPEInterruptEnabled() => boolean
begin
    return EffectivePMSCR_EL1_EE() == '00';
end;

// SPELDSTType
// ===========
// Type of a load or store operation.

type SPELDSTType of enumeration {
    SPELDSTType_NV2,
    SPELDSTType_Extended,
    SPELDSTType_General,
    SPELDSTType_SIMDFP,
    SPELDSTType_SVESME,
    SPELDSTType_Tags,
    SPELDSTType_MemCopy,
    SPELDSTType_MemSet,
    SPELDSTType_GCS,
    SPELDSTType_GCSSS2,
    SPELDSTType_Unspecified
};

// SPEMultiAccessSample()
// ======================
// Called by instructions which make at least one store and one load access, where the configuration
// of the operation type filter affects which access is sampled.

func SPEMultiAccessSample() => boolean
begin
    // If loads or stores are filtered out, the other should be recorded.
    // If neither or both are filtered out, pick one in an unbiased way.

    // Bit positions in the PMSFCR().[TYPE, TYPEm] fields.
    let LD : integer = 1;
    let ST : integer = 2;

    // Are loads allowed by filter?
    let loads_pass_filter : boolean  = PMSFCR_EL1().FT == '1' && PMSFCR_EL1().TYPE[LD] == '1';
    // Are stores allowed by filter?
    let stores_pass_filter : boolean = PMSFCR_EL1().FT == '1' && PMSFCR_EL1().TYPE[ST] == '1';

    var record_load : boolean;
    if loads_pass_filter && !stores_pass_filter then
        // Only loads pass filter
        record_load = TRUE;
    elsif !loads_pass_filter && stores_pass_filter then
        // Only stores pass filter
        record_load = FALSE;
    else
        // Both loads and stores pass the filter or neither pass the filter.
        // Pick between the load or the store access (pseudo-)randomly.
        record_load = SPEGetRandomBoolean();
    end;
    return record_load;
end;

// SPEOpType
// =========
// Types of operation filtered by SPECollectRecord().

type SPEOpType of enumeration {
    SPEOpType_Load,        // Any memory-read operation other than atomics, compare-and-swap,
                           // and swap
    SPEOpType_Store,       // Any memory-write operation, including atomics without return
    SPEOpType_LoadAtomic,  // Atomics with return, compare-and-swap and swap
    SPEOpType_Branch,      // Software write to the PC
    SPEOpType_OtherSVE,    // Other SVE operation
    SPEOpType_OtherSME,    // Other SME operation
    SPEOpType_Other,       // Any other class of operation
    SPEOpType_Invalid
};

// SPEProfilingStopped()
// =====================

readonly func SPEProfilingStopped() => boolean
begin
    var stopped : boolean = (PMBSR_EL1().S == '1');
    if IsFeatureImplemented(FEAT_SPE_EXC) then
        if HaveEL(EL3) && MDCR_EL3().PMSEE == '1x' then
            stopped = stopped || (PMBSR_EL3().S == '1');
        end;
        if EffectivePMSCR_EL2_EE() == '1x' then
            stopped = stopped || (PMBSR_EL2().S == '1');
        end;
    end;
    return stopped;
end;

// SPEResetSampleCounter()
// =======================
// Reset PMSICR_EL1.Counter

func SPEResetSampleCounter()
begin
    PMSICR_EL1().COUNT[31:8] = PMSIRR_EL1().INTERVAL;
    if PMSIRR_EL1().RND == '1' && !IsFeatureImplemented(FEAT_SPE_ERnd) then
        PMSICR_EL1().COUNT[7:0] = SPEGetRandomInterval();
    else
        PMSICR_EL1().COUNT[7:0] = Zeros{8};
    end;
end;

// SPEResetSampleStorage()
// =======================
// Reset all variables inside sample storage.

func SPEResetSampleStorage()
begin
    // Context values
    SPESampleContextEL1      = Zeros{32};
    SPESampleContextEL1Valid = FALSE;
    SPESampleContextEL2      = Zeros{32};
    SPESampleContextEL2Valid = FALSE;

    // Counter values
    for i = 0 to (SPEMaxCounters - 1) do
        SPESampleCounter[[i]]        = 0;
        SPESampleCounterValid[[i]]   = FALSE;
        SPESampleCounterPending[[i]] = FALSE;
    end;

    // Address values
    for i = 0 to (SPEMaxAddrs - 1) do
        SPESampleAddressValid[[i]] = FALSE;
        SPESampleAddress[[i]]      = Zeros{64};
    end;

    // Data source values
    SPESampleDataSource      = Zeros{16};
    SPESampleDataSourceValid = FALSE;

    // Timestamp values
    SPESampleTimestamp      = Zeros{64};
    SPESampleTimestampValid = FALSE;

    // Event values
    SPESampleEvents = Zeros{64};

    // Operation attributes
    SPESampleOpAttr.op_type = SPEOpType_Invalid;
    SPESampleOpAttr.ldst_type          = SPELDSTType_Unspecified;
    SPESampleOpAttr.branch_is_direct   = FALSE;
    SPESampleOpAttr.branch_has_link    = FALSE;
    SPESampleOpAttr.procedure_return   = FALSE;
    SPESampleOpAttr.is_conditional     = FALSE;
    SPESampleOpAttr.is_floating_point  = FALSE;
    SPESampleOpAttr.is_simd            = FALSE;
    SPESampleOpAttr.cond_pass          = FALSE;
    SPESampleOpAttr.at                 = FALSE;
    SPESampleOpAttr.is_acquire_release = FALSE;
    SPESampleOpAttr.is_exclusive       = FALSE;
    SPESampleOpAttr.is_predicated      = FALSE;
    SPESampleOpAttr.evl                = '000';
    SPESampleOpAttr.is_gather_scatter  = FALSE;
    SPESampleOpAttr.addr_valid         = FALSE;
end;

var SPERecordData : array [[SPEMaxRecordSize]] of bits(8);

var SPERecordSize : integer;

// SPESampleAddAddressPCVirtual()
// ==============================
// Save the current PC address to sample storage.

func SPESampleAddAddressPCVirtual()
begin
    var ns : bit;
    var nse : bit;
    case CurrentSecurityState() of
        when SS_Secure =>
            ns = '0';
            nse = '0';
        when SS_NonSecure =>
            ns = '1';
            nse = '0';
        when SS_Realm =>
            ns = '1';
            nse = '1';
        otherwise => unreachable;
    end;
    let el : bits(2) = PSTATE.EL;

    let pc : bits(64) = ThisInstrAddr{}();
    SPESampleAddress[[SPEAddrPosPCVirtual]][55:0] = pc[55:0];
    SPESampleAddress[[SPEAddrPosPCVirtual]][63:56] = ns::el::nse::Zeros{4};
    SPESampleAddressValid[[SPEAddrPosPCVirtual]]   = TRUE;
end;

// SPESampleAddContext()
// =====================
// Save contexts to sample storage if appropriate.

func SPESampleAddContext()
begin
    if CollectContextIDR1() then
        SPESampleContextEL1 = CONTEXTIDR_EL1()[31:0];
        SPESampleContextEL1Valid = TRUE;
    end;
    if CollectContextIDR2() then
        SPESampleContextEL2 = CONTEXTIDR_EL2()[31:0];
        SPESampleContextEL2Valid = TRUE;
    end;
end;

// SPESampleAddTimeStamp()
// =======================
// Save the appropriate type of timestamp to sample storage.

func SPESampleAddTimeStamp()
begin
    let timestamp : TimeStamp = CollectTimeStamp();
    case timestamp of
        when TimeStamp_None =>
            SPESampleTimestampValid = FALSE;
        otherwise =>
            SPESampleTimestampValid = TRUE;
            SPESampleTimestamp = GetTimestamp(timestamp);
    end;
end;

// SPESampleCollision()
// ====================
// Called when there is an SPE sample collision.

func SPESampleCollision()
begin
    // Sample collision with the previous sample
    PMUEvent(PMU_EVENT_SAMPLE_COLLISION);
    let target_el : bits(2)  = DefaultSPEEvent();
    PMBSR_EL(target_el).COLL = '1';
end;

// SPESampleExtendedLoadStore()
// ============================
// Sets the subclass of the operation type packet for
// extended load/store operations.

func SPESampleExtendedLoadStore(ar : boolean, excl : boolean, at : boolean, is_load : boolean)
begin
    SPESampleOpAttr.is_acquire_release = ar;
    SPESampleOpAttr.is_exclusive       = excl;
    SPESampleOpAttr.ldst_type          = SPELDSTType_Extended;
    SPESampleOpAttr.at                 = at;
    if is_load then
        if at then
            SPESampleOpAttr.op_type = SPEOpType_LoadAtomic;
        else
            SPESampleOpAttr.op_type = SPEOpType_Load;
        end;
    else
        SPESampleOpAttr.op_type = SPEOpType_Store;
    end;
end;

// SPESampleGCSSS2()
// =================
// Sets the subclass of the operation type packet for GCSSS2 load/store operations.

func SPESampleGCSSS2()
begin
    // GCSSS2 does a read and a write.
    let record_load : boolean = SPEMultiAccessSample();
    SPESampleOpAttr.op_type = if record_load then SPEOpType_Load else SPEOpType_Store;
    SPESampleOpAttr.ldst_type = SPELDSTType_GCSSS2;
end;

// SPESampleGeneralPurposeLoadStore()
// ==================================
// Sets the subclass of the operation type packet for general
// purpose load/store operations.

func SPESampleGeneralPurposeLoadStore(is_load : boolean)
begin
    SPESampleOpAttr.ldst_type = SPELDSTType_General;
    SPESampleOpAttr.op_type = if is_load then SPEOpType_Load else SPEOpType_Store;
end;

// SPESampleLoadStore()
// ====================
// Called if a sample is in flight when writing or reading memory,
// indicating that the operation being sampled is in the Load, Store or atomic category.

func SPESampleLoadStore(is_load : boolean, accdesc : AccessDescriptor,
                        addrdesc : AddressDescriptor)
begin
    // Check if this access type is suitable to be sampled.
    // This implementation of SPE always samples the first access made by a suitable instruction.
    // FEAT_MOPS instructions are an exception, where the first load or first store access may be
    // selected based on the configuration of the sample filters.
    if accdesc.acctype IN {AccessType_SPE,
                           AccessType_IFETCH,
                           AccessType_TRBE,
                           AccessType_DC,
                           AccessType_TTW,
                           AccessType_AT} then
        return;
    end;

    var sample_access : boolean = FALSE;
    // For FEAT_MOPS and FEAT_GCS GCSSS2 instructions which perform both loads and stores, the
    // filter configuration will influence which part of the access is chosen to be sampled.
    if (SPESampleOpAttr.ldst_type IN
          {SPELDSTType_MemCopy, SPELDSTType_MemSet, SPELDSTType_GCSSS2}) then
        // SPEMultiAccessSample() will have been called before this function,
        //and chooses whether to sample a load or a store.
        var sample_load : boolean;
        sample_load = SPESampleOpAttr.op_type IN {SPEOpType_Load, SPEOpType_LoadAtomic};

        // If no valid data has been collected, and this operation is acceptable for sampling.
        if !SPESampleOpAttr.addr_valid && (is_load == sample_load) then
            sample_access = TRUE;
        end;
    else
        if !SPESampleOpAttr.addr_valid then
            sample_access = TRUE;
        end;
    end;

    if sample_access then
        // Data access virtual address
        SPESetDataVirtualAddress(addrdesc.vaddress);

        // Data access physical address
        if CollectPhysicalAddress() then
            SPESetDataPhysicalAddress(addrdesc, accdesc);
        end;

        SPESampleOpAttr.addr_valid = TRUE;
    end;

    if SPESampleOpAttr.op_type == SPEOpType_Invalid then
        // Set as unspecified load/store by default, instructions will overwrite this if it does not
        // apply to them.
        SPESampleOpAttr.op_type = if is_load then SPEOpType_Load else SPEOpType_Store;

        if accdesc.acctype == AccessType_NV2 then
            // NV2 register load/store
            SPESampleOpAttr.ldst_type = SPELDSTType_NV2;
        end;
    end;

    // Set SPELDSTType to GCS for all GCS instruction, overwriting type GCSSS2.
    // After selection of which operation of a GCSSS2 instruction to sample, GCSSS2 is treated the
    // same as other GCS instructions.
    if accdesc.acctype == AccessType_GCS then
        SPESampleOpAttr.ldst_type = SPELDSTType_GCS;
        // If the GCS access is from a BL or RET, this will get overwritten to SPEOpType_Branch.
        SPESampleOpAttr.op_type = if is_load then SPEOpType_Load else SPEOpType_Store;
    end;
    (SPESampleDataSourceValid, SPESampleDataSource) = SPEGetDataSource(is_load, accdesc, addrdesc);
end;

// SPESampleMemCopy()
// ==================
// Sets the subclass of the operation type packet for Memory Copy load/store
// operations.

func SPESampleMemCopy()
begin
    // MemCopy does a read and a write.
    let record_load : boolean = SPEMultiAccessSample();
    SPESampleOpAttr.op_type   = if record_load then SPEOpType_Load else SPEOpType_Store;
    SPESampleOpAttr.ldst_type = SPELDSTType_MemCopy;
end;

// SPESampleMemSet()
// =================
// Callback used by memory set instructions to pass data back to the SPU.

func SPESampleMemSet()
begin
    SPESampleOpAttr.op_type   = SPEOpType_Store;
    SPESampleOpAttr.ldst_type = SPELDSTType_MemSet;
end;

// SPESampleOnSharedResource()
// ===========================
// Called when the sampled instruction is executed on an SMCU or other shared resource, sets bit 25
// of the events packet to 0b1.

func SPESampleOnSharedResource()
begin
    SPESampleEvents[25] = '1';
end;

// SPESampleOpOther()
// ==================
// Add other operation to sample storage.

func SPESampleOpOther(conditional : boolean, cond_pass : boolean,
                      is_fp : boolean, is_simd : boolean)
begin
    SPESampleOpAttr.is_simd = is_simd;
    SPESampleOpOther(conditional, cond_pass, is_fp);
end;

func SPESampleOpOther(conditional : boolean, cond_pass : boolean, is_fp : boolean)
begin
    SPESampleOpAttr.cond_pass = cond_pass;
    SPESampleOpAttr.is_floating_point = is_fp;
    SPESampleOpOther(conditional);
end;

func SPESampleOpOther(conditional : boolean)
begin
    SPESampleOpAttr.is_conditional = conditional;
    SPESampleOpAttr.op_type = SPEOpType_Other;
end;

// SPESampleOpSMEArrayOther()
// ==========================
// Sets the subclass of the operation type packet to Other, SME array.

func SPESampleOpSMEArrayOther(floating_point : boolean, size : integer)
begin
    // If the sampled effective vector or tile size is not a power of two, or is less than 128 bits,
    // the value is rounded up before it is encoded in the ets field.

    SPESampleOpAttr.is_floating_point = floating_point;
    SPESampleOpAttr.ets               = SPEEncodeETS(size);
    SPESampleOpAttr.op_type           = SPEOpType_OtherSME;
    SPESampleOpAttr.is_simd           = TRUE;
end;

// SPESampleOpSVEOther()
// =====================
// Callback used by SVE, Other operations to pass data back to the SPU.

func SPESampleOpSVEOther(vl : integer, predicated : boolean, floating_point : boolean)
begin
    SPESampleOpAttr.is_predicated     = predicated;
    SPESampleOpAttr.is_floating_point = floating_point;
    SPESampleOpAttr.evl               = SPEEncodeEVL(vl);
    SPESampleOpAttr.op_type           = SPEOpType_OtherSVE;
end;

// SPESampleOpSVESMELoadStore()
// ============================
// Callback used by SVE or SME loads and stores to pass data to SPE.

func SPESampleOpSVESMELoadStore(is_gather_scatter : boolean, vl : integer, predicated : boolean,
                                is_load : boolean)
begin
    SPESampleOpAttr.is_gather_scatter = is_gather_scatter;
    SPESampleOpAttr.is_predicated     = predicated;
    SPESampleOpAttr.evl               = SPEEncodeEVL(vl);
    assert SPESampleOpAttr.evl != '111';
    SPESampleOpAttr.op_type = if is_load then SPEOpType_Load else SPEOpType_Store;
    SPESampleOpAttr.ldst_type = SPELDSTType_SVESME;
end;

// SPESampleSIMDFPLoadStore()
// ==========================
// Sets the subclass of the operation type packet for SIMD & FP
// load store operations.

func SPESampleSIMDFPLoadStore(is_load : boolean, scalar : boolean)
begin
    SPESampleOpAttr.ldst_type = SPELDSTType_SIMDFP;
    SPESampleOpAttr.op_type   = if is_load then SPEOpType_Load else SPEOpType_Store;
    SPESampleOpAttr.is_simd   = !scalar;
    // Scalar operations in SIMD&FP are treated as floating point.
    SPESampleOpAttr.is_floating_point = scalar;
end;

// SPESetDataPhysicalAddress()
// ===========================
// Called from SampleLoadStore() to save data physical packet.

func SPESetDataPhysicalAddress(addrdesc : AddressDescriptor, accdesc : AccessDescriptor)
begin
    var ns : bit;
    var nse : bit;
    var ch : bit;
    var lat : bits(4);
    case addrdesc.paddress.paspace of
        when PAS_Secure =>
            ns = '0';
            nse = '0';
        when PAS_NonSecure =>
            ns = '1';
            nse = '0';
        when PAS_Realm =>
            ns  = '1';
            nse = '1';
        otherwise => unreachable;
    end;

    if IsFeatureImplemented(FEAT_MTE2) then
        if accdesc.tagchecked then
            ch = '1';
            lat = AArch64_LogicalAddressTag(addrdesc.vaddress);
        else
            ch = '0';
            // If the access is Unchecked, this is an IMPLEMENTATION_DEFINED choice
            // between 0b0000 and the Logical Address Tag
            var zero_unchecked : boolean;
            zero_unchecked = ImpDefBool("SPE PAT for tag unchecked access zero");
            if !zero_unchecked then
                lat = AArch64_LogicalAddressTag(addrdesc.vaddress);
            else
                lat = Zeros{4};
            end;
        end;
    else
        ch = '0';
        lat = '0000';
    end;

    let paddr : bits(56) = addrdesc.paddress.address;
    SPESampleAddress[[SPEAddrPosDataPhysical]][55:0] = ZeroExtend{56}(paddr);
    SPESampleAddress[[SPEAddrPosDataPhysical]][63:56] = ns::ch::'0'::nse::lat;
    SPESampleAddressValid[[SPEAddrPosDataPhysical]] = TRUE;
end;

// SPESetDataVirtualAddress()
// ==========================
// Called from SampleLoadStore() to save data virtual packet.
// Also used by exclusive load/stores to save virtual addresses if exclusive monitor is lost
// before a read/write is completed.

func SPESetDataVirtualAddress(vaddress : bits(64))
begin
    var tbi : bit;
    tbi = EffectiveTBI(vaddress, FALSE, PSTATE.EL);
    var non_tbi_is_zeros : boolean;
    non_tbi_is_zeros = ImpDefBool("SPE non-tbi tag is zero");
    if tbi == '1' || !non_tbi_is_zeros then
        SPESampleAddress[[SPEAddrPosDataVirtual]][63:0] = vaddress[63:0];
    else
        SPESampleAddress[[SPEAddrPosDataVirtual]][55:0] = vaddress[55:0];
        SPESampleAddress[[SPEAddrPosDataVirtual]][63:56] = Zeros{8};
    end;
    SPESampleAddressValid[[SPEAddrPosDataVirtual]] = TRUE;
end;

// SPEStartCounter()
// =================
// Enables incrementing of the counter at the passed index when SPECycle is called.

func SPEStartCounter(counter_index : integer)
begin
    assert counter_index < SPEMaxCounters;
    SPESampleCounterPending[[counter_index]] = TRUE;
end;

// SPEStartSample()
// ================
// Called to start the sampling process. Returns TRUE if a new sample is to be collected, and
// FALSE otherwise.

func SPEStartSample() => boolean
begin
    if !StatisticalProfilingEnabled() then
        return FALSE;
    end;
    PMUEvent(PMU_EVENT_SAMPLE_POP);
    if !SPEToCollectSample() then
        return FALSE;
    end;

    if SPESampleInFlight then
        SPESampleCollision();
        return FALSE;
    end;

    SPESampleInFlight = TRUE;

    SPEStartCounter(SPECounterPosTotalLatency);
    SPEStartCounter(SPECounterPosIssueLatency);
    SPESampleAddAddressPCVirtual();

    // Many operations are type other and not conditional, can save footprint
    // and overhead by having this as the default and not calling SPESampleOpOther
    // if conditional == FALSE
    SPESampleOpOther(FALSE);

    SPESampleAddContext();

    // Timestamp may be collected at any point in the sampling operation.
    // Collecting prior to execution is one possible choice.
    // This choice is IMPLEMENTATION DEFINED.
    SPESampleAddTimeStamp();

    return TRUE;
end;

// SPEStopCounter()
// ================
// Disables incrementing of the counter at the passed index when SPECycle is called.

func SPEStopCounter(counter_index : integer)
begin
    SPESampleCounterValid[[counter_index]] = TRUE;
    SPESampleCounterPending[[counter_index]] = FALSE;
end;

// SPEToCollectSample()
// ====================
// Returns TRUE if the instruction which is about the executed should be sampled, and FALSE
// otherwise.

func SPEToCollectSample() => boolean
begin
    if IsZero(PMSICR_EL1().COUNT) then
        SPEResetSampleCounter();
    else
        PMSICR_EL1().COUNT = PMSICR_EL1().COUNT - 1;
        if IsZero(PMSICR_EL1().COUNT) then
            if PMSIRR_EL1().RND == '1' && IsFeatureImplemented(FEAT_SPE_ERnd) then
                PMSICR_EL1().ECOUNT = SPEGetRandomInterval();
                return IsZero(PMSICR_EL1().ECOUNT);
            else
                return TRUE;
            end;
        end;
    end;
    if (PMSIRR_EL1().RND == '1' && IsFeatureImplemented(FEAT_SPE_ERnd) &&
          !IsZero(PMSICR_EL1().ECOUNT)) then
        PMSICR_EL1().ECOUNT = PMSICR_EL1().ECOUNT - 1;
        if IsZero(PMSICR_EL1().ECOUNT) then
            return TRUE;
        end;
    end;
    return FALSE;
end;

// SPEWriteToBuffer()
// ==================
// Write the active record to the Profiling Buffer.

func SPEWriteToBuffer()
begin
    assert ProfilingBufferEnabled();

    // Check alignment
    let align : integer{} = UInt(PMBIDR_EL1().Align);
    let aligned : boolean = IsAlignedP2(PMBPTR_EL1().PTR, align);

    let ttw_abort_as_fault : boolean = (ImpDefBool(
                                           "Report SPE ExtAbort on TTW as fault"));

    var owning_ss : SecurityState;
    var owning_el : bits(2);
    (owning_ss, owning_el) = ProfilingBufferOwner();
    let accdesc : AccessDescriptor = CreateAccDescSPE(owning_ss, owning_el);

    let start_vaddr : bits(64) = PMBPTR_EL1();
    for i = 0 to SPERecordSize - 1 do
        // If a previous write did not cause an issue
        if !SPEProfilingStopped() then
            let address : bits(64) = PMBPTR_EL1();
            var memstatus : PhysMemRetStatus;
            var addrdesc : AddressDescriptor;
            (memstatus, addrdesc) = DebugMemWrite(address, accdesc, aligned,
                                                  SPERecordData[[i]]);

            let fault : FaultRecord = addrdesc.fault;
            let ttw_abort : boolean = fault.statuscode IN {Fault_SyncExternalOnWalk,
                                                           Fault_SyncParityOnWalk};

            if IsFault(fault.statuscode) && (!ttw_abort || ttw_abort_as_fault) then
                DebugWriteFault(address, fault);
            elsif IsFault(memstatus) || (ttw_abort && !ttw_abort_as_fault) then
                DebugWriteExternalAbort(memstatus, addrdesc, start_vaddr);
            end;

            // Move pointer if no Buffer Management Event has been caused.
            if !SPEProfilingStopped() then
                PMBPTR_EL1() = PMBPTR_EL1() + 1;
            end;
        end;
    end;

    return;
end;

// StatisticalProfilingEnabled()
// =============================
// Return TRUE if Statistical Profiling is Enabled in the current EL, FALSE otherwise.

func StatisticalProfilingEnabled() => boolean
begin
    return StatisticalProfilingEnabled(PSTATE.EL);
end;

// StatisticalProfilingEnabled()
// =============================
// Return TRUE if Statistical Profiling is Enabled in the specified EL, FALSE otherwise.

func StatisticalProfilingEnabled(el : bits(2)) => boolean
begin
    if !IsFeatureImplemented(FEAT_SPE) || UsingAArch32() || !ProfilingBufferEnabled() then
        return FALSE;
    end;

    let tge_set : boolean = EL2Enabled() && HCR_EL2().TGE == '1';
    let (owning_ss, owning_el) : (SecurityState, bits(2)) = ProfilingBufferOwner();
    if (UInt(owning_el) <  UInt(el) || (tge_set && owning_el == EL1) ||
            owning_ss != SecurityStateAtEL(el))  then
        return FALSE;
    end;
    var spe_bit : bit;
    case el of
        when EL3 =>  unreachable;
        when EL2 =>  spe_bit = PMSCR_EL2().E2SPE;
        when EL1 =>  spe_bit = PMSCR_EL1().E1SPE;
        when EL0 =>  spe_bit = (if tge_set then PMSCR_EL2().E0HSPE else PMSCR_EL1().E0SPE);
    end;

    return spe_bit == '1';
end;

// TimeStamp
// =========

type TimeStamp of enumeration {
    TimeStamp_None,              // No timestamp
    TimeStamp_CoreSight,         // CoreSight time (IMPLEMENTATION DEFINED)
    TimeStamp_Physical,          // Physical counter value with no offset
    TimeStamp_OffsetPhysical,    // Physical counter value minus CNTPOFF_EL2
    TimeStamp_Virtual  };        // Physical counter value minus CNTVOFF_EL2

// AArch64_TakeExceptionInDebugState()
// ===================================
// Take an exception in Debug state to an Exception level using AArch64.

noreturn func AArch64_TakeExceptionInDebugState(target_el : bits(2), exception_in : ExceptionRecord)
begin
    assert HaveEL(target_el) && !ELUsingAArch32(target_el) && UInt(target_el) >= UInt(PSTATE.EL);
    assert target_el != EL3 || EDSCR().SDD == '0';
    var except : ExceptionRecord = exception_in;
    var sync_errors : boolean;
    if IsFeatureImplemented(FEAT_IESB) then
        sync_errors = SCTLR_EL(target_el).IESB == '1';
        if IsFeatureImplemented(FEAT_DoubleFault) then
            sync_errors = sync_errors || (SCR_EL3().[EA,NMEA] == '11' && target_el == EL3);
        end;
        // The Effective value of SCTLR[].IESB might be zero in Debug state.
        if !ConstrainUnpredictableBool(Unpredictable_IESBinDebug) then
            sync_errors = FALSE;
        end;
    else
        sync_errors = FALSE;
    end;

    if !IsFeatureImplemented(FEAT_ExS) || SCTLR_EL(target_el).EIS == '1' then
        // Synchronize the context, including Instruction Fetch Barrier effect
        SynchronizeContext();
    end;

    // If coming from AArch32 state, the top parts of the X[] registers might be set to zero
    let from_32 : boolean = UsingAArch32();
    if from_32 then AArch64_MaybeZeroRegisterUppers(); end;
    if from_32 && IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then
        ResetSVEState();
    else
        MaybeZeroSVEUppers(target_el);
    end;

    AArch64_ReportException(except, target_el);

    if IsFeatureImplemented(FEAT_GCS) then
        PSTATE.EXLOCK = '0';  // Effective value of GCSCR_ELx.EXLOCKEN is 0 in Debug state
    end;

    PSTATE.EL  = target_el;
    PSTATE.nRW = '0';
    PSTATE.SP  = '1';

    SPSR_ELx() = ARBITRARY : bits(64);
    ELR_ELx() = ARBITRARY : bits(64);
    // PSTATE.[SS,D,A,I,F] are not observable and ignored in Debug state, so behave as if UNKNOWN.
    PSTATE.[SS,D,A,I,F] = ARBITRARY : bits(5);
    if IsFeatureImplemented(FEAT_SSBS) then PSTATE.SSBS = ARBITRARY : bit; end;
    if IsFeatureImplemented(FEAT_EBEP) then PSTATE.PM = ARBITRARY : bit; end;
    if IsFeatureImplemented(FEAT_SEBEP) then PSTATE.PPEND = '0'; end;
    if IsFeatureImplemented(FEAT_MTE) then PSTATE.TCO = '1'; end;
    PSTATE.IL = '0';
    if IsFeatureImplemented(FEAT_UAO) then PSTATE.UAO = '0'; end;
    if IsFeatureImplemented(FEAT_UINJ) then PSTATE.UINJ = '0'; end;
    if IsFeatureImplemented(FEAT_PAuth_LR) then PSTATE.PACM = '0'; end;
    if (IsFeatureImplemented(FEAT_PAN) && (PSTATE.EL == EL1 ||
          (PSTATE.EL == EL2 && ELIsInHost(EL0))) &&
          SCTLR_ELx().SPAN == '0') then
        PSTATE.PAN = '1';
    end;
    if from_32 then                             // Coming from AArch32
        PSTATE.IT = '00000000';
        PSTATE.T = '0';                         // PSTATE.J is RES0
    end;
    if IsFeatureImplemented(FEAT_BTI) then PSTATE.BTYPE = '00'; end;
    DLR_EL0() = ARBITRARY : bits(64);
    DSPSR_EL0() = ARBITRARY : bits(64);

    EDSCR().ERR = '1';
    UpdateEDSCRFields();                        // Update EDSCR PE state flags.

    if sync_errors then
        SynchronizeErrors();
    end;

    EndOfInstruction();
end;

// AArch64_WatchpointByteMatch()
// =============================

func AArch64_WatchpointByteMatch(n : integer, vaddress : bits(64)) => boolean
begin
    let dbgtop : AddressSize        = DebugAddrTop();
    let cmpbottom : integer{}       = if DBGWVR_EL1(n)[2] == '1' then 2 else 3;// Word or doubleword
    var bottom : integer{}          = cmpbottom;
    let select : integer{}          = UInt(vaddress[cmpbottom-1:0]);
    var byte_select_match : boolean = (DBGWCR_EL1(n).BAS[select] != '0');
    var mask : integer{}            = UInt(DBGWCR_EL1(n).MASK);

    // If DBGWCR_EL1(n).MASK is a nonzero value and DBGWCR_EL1(n).BAS is not set to '11111111', or
    // DBGWCR_EL1(n).BAS specifies a non-contiguous set of bytes behavior is CONSTRAINED
    // UNPREDICTABLE.
    if mask > 0 && !IsOnes(DBGWCR_EL1(n).BAS) then
        byte_select_match = ConstrainUnpredictableBool(Unpredictable_WPMASKANDBAS);
    else
        let LSB : bits(8) = (DBGWCR_EL1(n).BAS AND NOT(DBGWCR_EL1(n).BAS - 1));
        let MSB : bits(8) = (DBGWCR_EL1(n).BAS + LSB);
        if !IsZero(MSB AND (MSB - 1)) then          // Not contiguous
            byte_select_match = ConstrainUnpredictableBool(Unpredictable_WPBASCONTIGUOUS);
            bottom            = 3;                  // For the whole doubleword
        end;
    end;

    // If the address mask is set to a reserved value, the behavior is CONSTRAINED UNPREDICTABLE.
    if mask > 0 && mask <= 2 then
        var c : Constraint;
        (c, mask) = (ConstrainUnpredictableInteger(3, 31, Unpredictable_RESWPMASK)
                        as (Constraint, integer{0..31}));
        assert c IN {Constraint_DISABLED, Constraint_NONE, Constraint_UNKNOWN};
        case c of
            when Constraint_DISABLED =>  return FALSE; // Disabled
            when Constraint_NONE =>      mask = 0;     // No masking
            // Otherwise the value returned by ConstrainUnpredictableInteger is a not-reserved value
        end;
    end;

    // When FEAT_LVA3 is not implemented, if the DBGWVR_EL1(n).RESS field bits are not a
    // sign extension of the MSB of DBGWVR_EL1(n).VA, it is UNPREDICTABLE whether they
    // appear to be included in the match.
    let unpredictable_ress : boolean = (dbgtop < 55 && !IsOnes(DBGWVR_EL1(n)[63:dbgtop]) &&
                                        !IsZero(DBGWVR_EL1(n)[63:dbgtop]) &&
                                        ConstrainUnpredictableBool(Unpredictable_DBGxVR_RESS));
    let cmpmsb : integer{}    = if unpredictable_ress then 63 else dbgtop;
    let cmplsb : integer{}    = if mask > bottom then mask else bottom;
    let bottombit : integer{} = bottom;
    var WVR_match : boolean   = (vaddress[cmpmsb:cmplsb] == DBGWVR_EL1(n)[cmpmsb:cmplsb]);
    if mask > bottom then
        // If masked bits of DBGWVR_EL1(n) are not zero, the behavior is CONSTRAINED UNPREDICTABLE.
        if WVR_match && !IsZero(DBGWVR_EL1(n)[cmplsb-1:bottombit]) then
            WVR_match = ConstrainUnpredictableBool(Unpredictable_WPMASKEDBITS);
        end;
    end;

    return (WVR_match && byte_select_match);
end;

// AArch64_WatchpointMatch()
// =========================
// Watchpoint matching in an AArch64 translation regime.

func AArch64_WatchpointMatch(n : integer, vaddress : bits(64), size : integer,
                             accdesc : AccessDescriptor) => WatchpointInfo
begin
    assert !ELUsingAArch32(S1TranslationRegime());
    assert n < NumWatchpointsImplemented();

    let enabled : boolean    = IsWatchpointEnabled(n);
    let linked : boolean     = DBGWCR_EL1(n).WT == '1';
    let isbreakpnt : boolean = FALSE;
    let lbnx : bits(2) = if IsFeatureImplemented(FEAT_Debugv8p9) then DBGWCR_EL1(n).LBNX else '00';
    let linked_n : integer{}  = UInt(lbnx :: DBGWCR_EL1(n).LBN);
    let ssce : bit            = if IsFeatureImplemented(FEAT_RME) then DBGWCR_EL1(n).SSCE else '0';
    let mismatch : boolean    = IsFeatureImplemented(FEAT_BWE2) && DBGWCR_EL1(n).WT2 == '1';
    let state_match : boolean = AArch64_StateMatch(DBGWCR_EL1(n).SSC, ssce, DBGWCR_EL1(n).HMC,
                                                   DBGWCR_EL1(n).PAC,
                                                   linked, linked_n, isbreakpnt, PC64(), accdesc);

    var watchptinfo : WatchpointInfo;
    var ls_match : boolean;
    case DBGWCR_EL1(n).LSC[1:0] of
        when '00' => ls_match = FALSE;
        when '01' => ls_match = accdesc.read;
        when '10' => ls_match = accdesc.write || accdesc.acctype == AccessType_DC;
        when '11' => ls_match = TRUE;
    end;

    var value_match : boolean = FALSE;
    watchptinfo.vaddress = vaddress;
    for byte = 0 to size - 1 do
        if (!value_match &&
              !AddressInNaturallyAlignedBlock(watchptinfo.vaddress, vaddress + byte)) then
            // Watchpoint should report an address which is in
            // the naturally aligned block of the matched address.
            watchptinfo.vaddress = vaddress + byte;
        end;
        value_match = value_match || AArch64_WatchpointByteMatch(n, vaddress + byte);
    end;

    watchptinfo.watchpt_num = n;
    watchptinfo.value_match = value_match;
    if !(state_match && ls_match && enabled) then
        watchptinfo.wptype = WatchpointType_Inactive;
        watchptinfo.value_match = FALSE;
    elsif mismatch then
        watchptinfo.wptype = WatchpointType_AddrMismatch;
    else
        watchptinfo.wptype = WatchpointType_AddrMatch;
    end;
    return watchptinfo;
end;

// IsWatchpointEnabled()
// =====================
// Returns TRUE if the effective value of DBGWCR_EL1(n).E is '1', and FALSE otherwise.

func IsWatchpointEnabled(n : integer) => boolean
begin
    if (n > 15 &&
          ((!HaltOnBreakpointOrWatchpoint() && !SelfHostedExtendedBPWPEnabled()) ||
           (HaltOnBreakpointOrWatchpoint() && EDSCR2().EHBWE == '0'))) then
        return FALSE;
    end;
    return DBGWCR_EL1(n).E == '1';
end;

// AArch64_Abort()
// ===============
// Abort and Debug exception handling in an AArch64 translation regime.

func AArch64_Abort(fault : FaultRecord)
begin
    if IsDebugException(fault) then
        if fault.accessdesc.acctype == AccessType_IFETCH then
            if UsingAArch32() && fault.debugmoe == DebugException_VectorCatch then
                AArch64_VectorCatchException(fault);
            else
                AArch64_BreakpointException(fault);
            end;
        else
            AArch64_WatchpointException(fault);
        end;
    elsif fault.gpcf.gpf != GPCF_None && ReportAsGPCException(fault) then
        TakeGPCException(fault);
    elsif fault.statuscode == Fault_TagCheck then
        AArch64_RaiseTagCheckFault(fault);
    elsif IsExternalAbort(fault) && !IsExternalSyncAbort(fault) then
        PendSErrorInterrupt(fault);
    elsif fault.accessdesc.acctype == AccessType_IFETCH then
        AArch64_InstructionAbort(fault);
    else
        AArch64_DataAbort(fault);
    end;
end;

// AArch64_AbortSyndrome()
// =======================
// Creates an exception syndrome record for Abort and Watchpoint exceptions
// from an AArch64 translation regime.

func AArch64_AbortSyndrome(exceptype : Exception, fault : FaultRecord,
                           target_el : bits(2)) => ExceptionRecord
begin
    var except : ExceptionRecord = ExceptionSyndrome(exceptype);

    except.syndrome = AArch64_FaultSyndrome(exceptype, fault, target_el);
    if exceptype IN {Exception_NV2Watchpoint, Exception_Watchpoint} then
        except.vaddress = fault.watchptinfo.vaddress;
    elsif fault.statuscode == Fault_TagCheck then
        if IsFeatureImplemented(FEAT_MTE_TAGGED_FAR) then
            except.vaddress = ZeroExtend{64}(fault.vaddress);
        else
            except.vaddress = ARBITRARY : bits(4) :: fault.vaddress[59:0];
        end;
    else
        except.vaddress = ZeroExtend{64}(fault.vaddress);
    end;

    if IPAValid(fault) then
        except.ipavalid = TRUE;
        except.NS = if fault.ipaddress.paspace == PAS_NonSecure then '1' else '0';
        except.ipaddress = fault.ipaddress.address;
    else
        except.ipavalid = FALSE;
    end;

    if except.syndrome.iss[14] == '1' then
        except.pavalid  = TRUE;
        except.paddress = fault.paddress;
    else
        except.pavalid  = FALSE;
        except.paddress = ARBITRARY : FullAddress;
    end;

    return except;
end;

// AArch64_CheckPCAlignment()
// ==========================

func AArch64_CheckPCAlignment()
begin
    let pc : bits(64) = ThisInstrAddr{}();

    if pc[1:0] != '00' then
        AArch64_PCAlignmentFault();
    end;
end;

// AArch64_DataAbort()
// ===================

func AArch64_DataAbort(fault : FaultRecord)
begin
    var target_el : bits(2);
    if IsExternalAbort(fault) then
        target_el = SyncExternalAbortTarget(fault);
    else
        let route_to_el2 = (EL2Enabled() && PSTATE.EL IN {EL0, EL1} &&
                            (HCR_EL2().TGE == '1' ||
                            (IsFeatureImplemented(FEAT_RME) && fault.gpcf.gpf != GPCF_None &&
                             HCR_EL2().GPF == '1') ||
                             (IsFeatureImplemented(FEAT_NV2) &&
                              fault.accessdesc.acctype == AccessType_NV2) ||
                             IsSecondStage(fault)));

        if PSTATE.EL == EL3 then
            target_el = EL3;
        elsif PSTATE.EL == EL2 || route_to_el2 then
            target_el = EL2;
        else
            target_el = EL1;
        end;
    end;

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let route_to_serr : boolean = (IsExternalAbort(fault) &&
                                      AArch64_RouteToSErrorOffset(target_el));
    let vect_offset : integer = if route_to_serr then 0x180 else 0x0;

    var except : ExceptionRecord;
    if IsFeatureImplemented(FEAT_NV2) && fault.accessdesc.acctype == AccessType_NV2 then
        except = AArch64_AbortSyndrome(Exception_NV2DataAbort, fault, target_el);
    else
        except = AArch64_AbortSyndrome(Exception_DataAbort, fault, target_el);
    end;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_EffectiveTCF()
// ======================
// Indicate if a Tag Check Fault should cause a synchronous exception,
// be asynchronously accumulated, or have no effect on the PE.

func AArch64_EffectiveTCF(el : bits(2), read : boolean) => TCFType
begin
    var tcf : bits(2);

    let regime : Regime = TranslationRegime(el);

    case regime of
        when Regime_EL3 =>  tcf = SCTLR_EL3().TCF;
        when Regime_EL2 =>  tcf = SCTLR_EL2().TCF;
        when Regime_EL20 => tcf = if el == EL0 then SCTLR_EL2().TCF0 else SCTLR_EL2().TCF;
        when Regime_EL10 => tcf = if el == EL0 then SCTLR_EL1().TCF0 else SCTLR_EL1().TCF;
        otherwise =>        unreachable;
    end;

    if tcf == '11' then        // Reserved value
        if !IsFeatureImplemented(FEAT_MTE_ASYM_FAULT) then
            (-,tcf) = ConstrainUnpredictableBits{2}(Unpredictable_RESTCF);
        end;
    end;

    case tcf of
        when '00' =>   // Tag Check Faults have no effect on the PE
            return TCFType_Ignore;
        when '01' =>   // Tag Check Faults cause a synchronous exception
            return TCFType_Sync;
        when '10' =>
            if IsFeatureImplemented(FEAT_MTE_ASYNC) then
                // If asynchronous faults are implemented,
                // Tag Check Faults are asynchronously accumulated
                return TCFType_Async;
            else
                // Otherwise, Tag Check Faults have no effect on the PE
                return TCFType_Ignore;
            end;
        when '11' =>
            if IsFeatureImplemented(FEAT_MTE_ASYM_FAULT) then
                // Tag Check Faults cause a synchronous exception on reads or on
                // a read/write access, and are asynchronously accumulated on writes
                if read then
                    return TCFType_Sync;
                else
                    return TCFType_Async;
                end;
            else
                // Otherwise, Tag Check Faults have no effect on the PE
                return TCFType_Ignore;
            end;
        otherwise =>
            unreachable;
    end;
end;

// AArch64_InstructionAbort()
// ==========================

func AArch64_InstructionAbort(fault : FaultRecord)
begin
    // External aborts on instruction fetch must be taken synchronously
    if IsFeatureImplemented(FEAT_DoubleFault) then
        assert fault.statuscode != Fault_AsyncExternal;
    end;

    var target_el : bits(2);
    if IsExternalAbort(fault) then
        target_el = SyncExternalAbortTarget(fault);
    else
        let route_to_el2 : boolean = (EL2Enabled() && PSTATE.EL IN {EL0, EL1} &&
                                      (HCR_EL2().TGE == '1' ||
                                      (IsFeatureImplemented(FEAT_RME) &&
                                       fault.gpcf.gpf != GPCF_None &&
                                       HCR_EL2().GPF == '1') ||
                                       IsSecondStage(fault)));

        if PSTATE.EL == EL3 then
            target_el = EL3;
        elsif PSTATE.EL == EL2 || route_to_el2 then
            target_el = EL2;
        else
            target_el = EL1;
        end;
    end;

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    var vect_offset : integer;

    if IsExternalAbort(fault) && AArch64_RouteToSErrorOffset(target_el) then
        vect_offset = 0x180;
    else
        vect_offset = 0x0;
    end;

    let except : ExceptionRecord = AArch64_AbortSyndrome(Exception_InstructionAbort, fault,
                                                            target_el);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_PCAlignmentFault()
// ==========================
// Called on unaligned program counter in AArch64 state.

func AArch64_PCAlignmentFault()
begin

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_PCAlignment);
    except.vaddress = ThisInstrAddr{64}();
    var target_el : bits(2) = EL1;
    if UInt(PSTATE.EL) > UInt(EL1) then
        target_el = PSTATE.EL;
    elsif EL2Enabled() && HCR_EL2().TGE == '1' then
        target_el = EL2;
    end;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_RaiseTagCheckFault()
// ============================
// Raise a Tag Check Fault exception.

func AArch64_RaiseTagCheckFault(fault : FaultRecord)
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;
    var target_el : bits(2) = EL1;
    if UInt(PSTATE.EL) > UInt(EL1) then
        target_el = PSTATE.EL;
    elsif PSTATE.EL == EL0 && EL2Enabled() && HCR_EL2().TGE == '1' then
        target_el = EL2;
    end;

    let except : ExceptionRecord = AArch64_AbortSyndrome(Exception_DataAbort, fault, target_el);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_ReportTagCheckFault()
// =============================
// Records a Tag Check Fault exception into the appropriate TFSR_ELx.

func AArch64_ReportTagCheckFault(el : bits(2), ttbr : bit)
begin
    case el of
        when EL3 => assert ttbr == '0'; TFSR_EL3().TF0   = '1';
        when EL2 => if ttbr == '0' then TFSR_EL2().TF0   = '1'; else TFSR_EL2().TF1   = '1'; end;
        when EL1 => if ttbr == '0' then TFSR_EL1().TF0   = '1'; else TFSR_EL1().TF1   = '1'; end;
        when EL0 => if ttbr == '0' then TFSRE0_EL1().TF0 = '1'; else TFSRE0_EL1().TF1 = '1'; end;
    end;
end;

// AArch64_RouteToSErrorOffset()
// =============================
// Returns TRUE if synchronous External abort exceptions are taken to the
// appropriate SError vector offset, and FALSE otherwise.

func AArch64_RouteToSErrorOffset(target_el : bits(2)) => boolean
begin
    if !IsFeatureImplemented(FEAT_DoubleFault) then return FALSE; end;

    var ease_bit : bit;
    case target_el of
        when EL3 =>
            ease_bit = SCR_EL3().EASE;
        when EL2 =>
            if IsFeatureImplemented(FEAT_DoubleFault2) && IsSCTLR2EL2Enabled() then
                ease_bit = SCTLR2_EL2().EASE;
            else
                ease_bit = '0';
            end;
        when EL1 =>
            if IsFeatureImplemented(FEAT_DoubleFault2) && IsSCTLR2EL1Enabled() then
                ease_bit = SCTLR2_EL1().EASE;
            else
                ease_bit = '0';
            end;
    end;
    return (ease_bit == '1');
end;

// AArch64_SPAlignmentFault()
// ==========================
// Called on an unaligned stack pointer in AArch64 state.

func AArch64_SPAlignmentFault()
begin

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    let except : ExceptionRecord = ExceptionSyndrome(Exception_SPAlignment);

    var target_el : bits(2) = EL1;
    if UInt(PSTATE.EL) > UInt(EL1) then
        target_el = PSTATE.EL;
    elsif EL2Enabled() && HCR_EL2().TGE == '1' then
        target_el = EL2;
    end;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// BranchTargetException()
// =======================
// Raise branch target exception.

func AArch64_BranchTargetException(vaddress : bits(52))
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_BranchTarget);
    except.syndrome.iss[1:0]   = PSTATE.BTYPE;
    except.syndrome.iss[24:2]  = Zeros{23};         // RES0

    var target_el : bits(2) = EL1;
    if UInt(PSTATE.EL) > UInt(EL1) then
        target_el = PSTATE.EL;
    elsif PSTATE.EL == EL0 && EL2Enabled() && HCR_EL2().TGE == '1' then
        target_el = EL2;
    end;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// TCFType
// =======

type TCFType of enumeration { TCFType_Sync, TCFType_Async, TCFType_Ignore };

// TakeGPCException()
// ==================
// Report Granule Protection Exception faults

func TakeGPCException(fault : FaultRecord)
begin
    assert IsFeatureImplemented(FEAT_RME);
    assert IsFeatureImplemented(FEAT_LSE);
    assert IsFeatureImplemented(FEAT_HAFDBS);
    assert IsFeatureImplemented(FEAT_DoubleFault);

    var except : ExceptionRecord;

    except.exceptype = Exception_GPC;
    except.vaddress  = ZeroExtend{64}(fault.vaddress);
    except.paddress  = fault.paddress;
    except.pavalid   = TRUE;

    if IPAValid(fault) then
        except.ipavalid  = TRUE;
        except.NS        = if fault.ipaddress.paspace == PAS_NonSecure then '1' else '0';
        except.ipaddress = fault.ipaddress.address;
    else
        except.ipavalid  = FALSE;
    end;

    except.syndrome.iss2[11] = if fault.hdbssf then '1' else '0';   // HDBSSF
    if fault.accessdesc.acctype == AccessType_GCS then
        except.syndrome.iss2[8] = '1'; //GCS
    end;

    // Populate the fields grouped in ISS
    except.syndrome.iss[24:22] = Zeros{3}; // RES0
    except.syndrome.iss[21]    = if fault.gpcfs2walk then '1' else '0';  // S2PTW
    if fault.accessdesc.acctype == AccessType_IFETCH then
        except.syndrome.iss[20] = '1';     // InD
    else
        except.syndrome.iss[20] = '0';     // InD
    end;
    except.syndrome.iss[19:14] = EncodeGPCSC(fault.gpcf); // GPCSC
    if IsFeatureImplemented(FEAT_NV2) && fault.accessdesc.acctype == AccessType_NV2 then
        except.syndrome.iss[13] = '1';     // VNCR
    else
        except.syndrome.iss[13] = '0';     // VNCR
    end;
    except.syndrome.iss[12:11]  = '00';     // RES0
    except.syndrome.iss[10:9]   = '00';     // RES0

    if fault.accessdesc.acctype IN {AccessType_DC, AccessType_IC, AccessType_AT} then
        except.syndrome.iss[8] = '1'; // CM
    else
        except.syndrome.iss[8] = '0'; // CM
    end;

    except.syndrome.iss[7] = if fault.s2fs1walk then '1' else '0'; // S1PTW

    if fault.accessdesc.acctype IN {AccessType_DC, AccessType_IC, AccessType_AT} then
        except.syndrome.iss[6] = '1';                              // WnR
    elsif fault.statuscode IN {Fault_HWUpdateAccessFlag, Fault_Exclusive} then
        except.syndrome.iss[6] = ARBITRARY : bit;                      // WnR
    elsif fault.accessdesc.atomicop && IsExternalAbort(fault) then
        except.syndrome.iss[6] = ARBITRARY : bit;                      // WnR
    else
        except.syndrome.iss[6] = if fault.write then '1' else '0'; // WnR
    end;

    except.syndrome.iss[5:0] = EncodeLDFSC(fault.statuscode, fault.level); // xFSC

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let target_el : bits(2) = EL3;

    var vect_offset : integer;
    if IsExternalAbort(fault) && AArch64_RouteToSErrorOffset(target_el) then
        vect_offset = 0x180;
    else
        vect_offset = 0x0;
    end;

    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_TakeDelegatedSErrorException()
// ======================================

func AArch64_TakeDelegatedSErrorException()
begin
    assert IsFeatureImplemented(FEAT_E3DSE) && PSTATE.EL != EL3 && SCR_EL3().[EnDSE,DSE] == '11';

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset = 0x180;
    var except : ExceptionRecord = ExceptionSyndrome(Exception_SError);

    var target_el : bits(2);
    var dsei_masked : boolean;
    (dsei_masked, target_el)  = AArch64_DelegatedSErrorTarget();
    assert !dsei_masked;
    except.syndrome.iss[24]   = VSESR_EL3().IDS;
    except.syndrome.iss[23:0] = VSESR_EL3().ISS;
    ClearPendingDelegatedSError();

    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_TakePhysicalFIQException()
// ==================================

func AArch64_TakePhysicalFIQException()
begin

    let route_to_el3 : boolean = HaveEL(EL3) && SCR_EL3().FIQ == '1';
    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                  (HCR_EL2().TGE == '1' || HCR_EL2().FMO == '1'));
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x100;
    let except : ExceptionRecord = ExceptionSyndrome(Exception_FIQ);

    if route_to_el3 then
        AArch64_TakeException(EL3, except, preferred_exception_return, vect_offset);
    elsif PSTATE.EL == EL2 || route_to_el2 then
        assert PSTATE.EL != EL3;
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        assert PSTATE.EL IN {EL0, EL1};
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_TakePhysicalIRQException()
// ==================================
// Take an enabled physical IRQ exception.

func AArch64_TakePhysicalIRQException()
begin

    let route_to_el3 : boolean = HaveEL(EL3) && SCR_EL3().IRQ == '1';
    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                 (HCR_EL2().TGE == '1' || HCR_EL2().IMO == '1'));
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x80;

    let except : ExceptionRecord = ExceptionSyndrome(Exception_IRQ);

    if route_to_el3 then
        AArch64_TakeException(EL3, except, preferred_exception_return, vect_offset);
    elsif PSTATE.EL == EL2 || route_to_el2 then
        assert PSTATE.EL != EL3;
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        assert PSTATE.EL IN {EL0, EL1};
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_TakePhysicalSErrorException()
// =====================================

func AArch64_TakePhysicalSErrorException(implicit_esb : boolean)
begin
    var masked : boolean;
    var target_el : bits(2);

    (masked, target_el) = PhysicalSErrorTarget();
    assert !masked;

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer    = 0x180;
    let fault : FaultRecord      = GetPendingPhysicalSError();
    var except : ExceptionRecord = ExceptionSyndrome(Exception_SError);
    let is_esb : boolean         = FALSE;
    let syndrome : bits(25)      = AArch64_PhysicalSErrorSyndrome(is_esb, implicit_esb);

    if IsSErrorEdgeTriggered() then
        ClearPendingPhysicalSError();
    end;

    if except.syndrome.iss[14] == '1' then
        except.pavalid  = TRUE;
        except.paddress = fault.paddress;
    else
        except.pavalid  = FALSE;
        except.paddress = ARBITRARY : FullAddress;
    end;
    except.syndrome.iss = syndrome;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_TakeVirtualFIQException()
// =================================

func AArch64_TakeVirtualFIQException()
begin
    assert PSTATE.EL IN {EL0, EL1} && EL2Enabled();
    // Virtual IRQ enabled if TGE==0 and FMO==1
    assert HCR_EL2().TGE == '0' && HCR_EL2().FMO == '1';

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x100;

    let except : ExceptionRecord = ExceptionSyndrome(Exception_FIQ);

    AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
end;

// AArch64_TakeVirtualIRQException()
// =================================

func AArch64_TakeVirtualIRQException()
begin
    assert PSTATE.EL IN {EL0, EL1} && EL2Enabled();
    // Virtual IRQ enabled if TGE==0 and IMO==1
    assert HCR_EL2().TGE == '0' && HCR_EL2().IMO == '1';

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x80;

    let except : ExceptionRecord = ExceptionSyndrome(Exception_IRQ);

    AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
end;

// AArch64_TakeVirtualSErrorException()
// ====================================

func AArch64_TakeVirtualSErrorException()
begin

    assert PSTATE.EL IN {EL0, EL1} && EL2Enabled();
    // Virtual SError enabled if TGE==0 and AMO==1 or TMEA==1
    assert (HCR_EL2().TGE == '0' &&
            (HCR_EL2().AMO == '1' || (IsHCRXEL2Enabled() && HCRX_EL2().TMEA == '1')));

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer                 = 0x180;
    var except : ExceptionRecord              = ExceptionSyndrome(Exception_SError);

    if IsFeatureImplemented(FEAT_RAS) then
        except.syndrome.iss[24]   = VSESR_EL2().IDS;
        except.syndrome.iss[23:0] = VSESR_EL2().ISS;
    else
        let syndrome : bits(25)       = ImpDefBits{}("Virtual SError syndrome");
        let impdef_syndrome : boolean = syndrome[24] == '1';
        if impdef_syndrome then except.syndrome.iss = syndrome; end;
    end;

    ClearPendingVirtualSError();
    AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
end;

// AArch64_BreakpointException()
// =============================

func AArch64_BreakpointException(fault : FaultRecord)
begin
    assert PSTATE.EL != EL3;

    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                  (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1'));

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    var target_el : bits(2);
    let vect_offset : integer = 0x0;
    target_el = if (PSTATE.EL == EL2 || route_to_el2) then EL2 else EL1;

    let vaddress : bits(64)      = ARBITRARY : bits(64);
    let except : ExceptionRecord = AArch64_AbortSyndrome(Exception_Breakpoint, fault, target_el);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_SoftwareBreakpoint()
// ============================

func AArch64_SoftwareBreakpoint(immediate : bits(16))
begin

    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} &&
                                  EL2Enabled() && (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1'));

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_SoftwareBreakpoint);
    except.syndrome.iss[15:0]    = immediate;

    if UInt(PSTATE.EL) > UInt(EL1) then
        AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
    elsif route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_SoftwareStepException()
// ===============================

func AArch64_SoftwareStepException()
begin
    assert PSTATE.EL != EL3;

    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                  (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1'));

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_SoftwareStep);
    if SoftwareStep_DidNotStep() then
        except.syndrome.iss[24] = '0';
    else
        except.syndrome.iss[24] = '1';
        except.syndrome.iss[6] = if SoftwareStep_SteppedEX() then '1' else '0';
    end;
    except.syndrome.iss[5:0] = '100010';                // IFSC = Debug Exception

    if PSTATE.EL == EL2 || route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_VectorCatchException()
// ==============================
// Vector Catch taken from EL0 or EL1 to EL2. This can only be called when debug exceptions are
// being routed to EL2, as Vector Catch is a legacy debug event.

func AArch64_VectorCatchException(fault : FaultRecord)
begin
    assert PSTATE.EL != EL2;
    assert EL2Enabled() && (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1');

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    let vaddress : bits(64)      = ARBITRARY : bits(64);
    let except : ExceptionRecord = AArch64_AbortSyndrome(Exception_VectorCatch, fault, EL2);

    AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
end;

// AArch64_WatchpointException()
// =============================

func AArch64_WatchpointException(fault : FaultRecord)
begin
    assert PSTATE.EL != EL3;

    let route_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                  (HCR_EL2().TGE == '1' || MDCR_EL2().TDE == '1'));

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    var target_el : bits(2);
    let vect_offset : integer = 0x0;
    target_el = if (PSTATE.EL == EL2 || route_to_el2) then EL2 else EL1;

    var except : ExceptionRecord;
    if IsFeatureImplemented(FEAT_NV2) && fault.accessdesc.acctype == AccessType_NV2 then
        except = AArch64_AbortSyndrome(Exception_NV2Watchpoint, fault, target_el);
    else
        except = AArch64_AbortSyndrome(Exception_Watchpoint, fault, target_el);
    end;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_ExceptionClass()
// ========================
// Returns the Exception Class and Instruction Length fields to be reported in ESR

func AArch64_ExceptionClass(exceptype : Exception, target_el : bits(2)) => (integer,bit)
begin

    var il_is_valid : boolean = TRUE;
    let from_32 : boolean = UsingAArch32();
    var ec : integer;
    case exceptype of
        when Exception_Uncategorized =>         ec = 0x00; il_is_valid = FALSE;
        when Exception_WFxTrap       =>         ec = 0x01;
        when Exception_CP15RTTrap    =>         ec = 0x03; assert from_32;
        when Exception_CP15RRTTrap   =>         ec = 0x04; assert from_32;
        when Exception_CP14RTTrap    =>         ec = 0x05; assert from_32;
        when Exception_CP14DTTrap    =>         ec = 0x06; assert from_32;
        when Exception_AdvSIMDFPAccessTrap =>   ec = 0x07;
        when Exception_FPIDTrap      =>         ec = 0x08;
        when Exception_PACTrap       =>         ec = 0x09;
        when Exception_LDST64BTrap   =>         ec = 0x0A;
        when Exception_GPC           =>         ec = 0x1E;
        when Exception_CP14RRTTrap   =>         ec = 0x0C; assert from_32;
        when Exception_BranchTarget  =>         ec = 0x0D;
        when Exception_IllegalState  =>         ec = 0x0E; il_is_valid = FALSE;
        when Exception_SupervisorCall =>        ec = if from_32 then 0x11 else 0x15;
        when Exception_HypervisorCall =>        ec = if from_32 then 0x12 else 0x16;
        when Exception_MonitorCall =>           ec = if from_32 then 0x13 else 0x17;
        when Exception_SystemRegisterTrap =>    ec = 0x18; assert !from_32;
        when Exception_SystemRegister128Trap => ec = 0x14; assert !from_32;
        when Exception_SVEAccessTrap =>         ec = 0x19; assert !from_32;
        when Exception_ERetTrap =>              ec = 0x1A; assert !from_32;
        when Exception_PACFail =>               ec = 0x1C; assert !from_32;
        when Exception_SMEAccessTrap =>         ec = 0x1D; assert !from_32;
        when Exception_InstructionAbort =>
            ec = if target_el == PSTATE.EL then 0x21 else 0x20;
            il_is_valid = FALSE;
        when Exception_PCAlignment =>           ec = 0x22; il_is_valid = FALSE;
        when Exception_DataAbort =>             ec = if target_el == PSTATE.EL then 0x25 else 0x24;
        when Exception_NV2DataAbort =>          ec = 0x25;
        when Exception_SPAlignment =>           ec = 0x26; il_is_valid = FALSE; assert !from_32;
        when Exception_MemCpyMemSet =>          ec = 0x27;
        when Exception_GCSFail =>               ec = 0x2D; assert !from_32;
        when Exception_FPTrappedException =>    ec = if from_32 then 0x28 else 0x2C;
        when Exception_SError =>                ec = 0x2F; il_is_valid = FALSE;
        when Exception_Breakpoint =>
            ec = if target_el == PSTATE.EL then 0x31 else 0x30;
            il_is_valid = FALSE;
        when Exception_SoftwareStep =>
            ec = if target_el == PSTATE.EL then 0x33 else 0x32;
            il_is_valid = FALSE;
        when Exception_Watchpoint =>
            ec = if target_el == PSTATE.EL then 0x35 else 0x34;
            il_is_valid = FALSE;
        when Exception_NV2Watchpoint =>         ec = 0x35; il_is_valid = FALSE;
        when Exception_SoftwareBreakpoint =>    ec = if from_32 then 0x38 else 0x3C;
        when Exception_VectorCatch =>           ec = 0x3A; il_is_valid = FALSE; assert from_32;
        when Exception_Profiling =>             ec = 0x3D;
        otherwise =>                            unreachable;
    end;

    var il : bit;
    if il_is_valid then
        il = if ThisInstrLength() == 32 then '1' else '0';
    else
        il = '1';
    end;
    assert from_32 || il == '1';            // AArch64 instructions always 32-bit

    return (ec,il);
end;

// AArch64_ReportException()
// =========================
// Report syndrome information for exception taken to AArch64 state.

func AArch64_ReportException(except : ExceptionRecord, target_el : bits(2))
begin

    let exceptype : Exception = except.exceptype;

    var (ec,il) = AArch64_ExceptionClass(exceptype, target_el);
    let iss : bits(25)  = except.syndrome.iss;
    let iss2 : bits(24) = except.syndrome.iss2;

    // IL is not valid for Data Abort exceptions without valid instruction syndrome information
    if ec IN {0x24,0x25} && iss[24] == '0' then
        il = '1';
    end;

    ESR_EL(target_el) = (Zeros{8}  ::   // [63:56]
                         iss2      ::   // [55:32]
                         ec[5:0]   ::   // [31:26]
                         il        ::   // [25]
                         iss);          // [24:0]

    if exceptype IN {
        Exception_InstructionAbort,
        Exception_PCAlignment,
        Exception_DataAbort,
        Exception_NV2DataAbort,
        Exception_NV2Watchpoint,
        Exception_GPC,
        Exception_Watchpoint
    } then
        FAR_EL(target_el) = except.vaddress;
    else
        FAR_EL(target_el) = ARBITRARY : bits(64);
    end;

    if except.ipavalid then
        HPFAR_EL2()[47:4] = except.ipaddress[55:12];
        if IsSecureEL2Enabled() && CurrentSecurityState() == SS_Secure then
            HPFAR_EL2().NS = except.NS;
        else
            HPFAR_EL2().NS = '0';
        end;
    elsif target_el == EL2 then
        HPFAR_EL2()[47:4] = ARBITRARY : bits(44);
    end;

    if except.pavalid then
        var faultaddr : bits(64) = ZeroExtend{}(except.paddress.address);
        if IsFeatureImplemented(FEAT_RME) then
            case except.paddress.paspace of
                when PAS_Secure =>     faultaddr[63:62] = '00';
                when PAS_NonSecure =>  faultaddr[63:62] = '10';
                when PAS_Root =>       faultaddr[63:62] = '01';
                when PAS_Realm =>      faultaddr[63:62] = '11';
            end;
            if exceptype == Exception_GPC then
                faultaddr[11:0] = Zeros{12};
            end;
        else
            faultaddr[63] = if except.paddress.paspace == PAS_NonSecure then '1' else '0';
        end;
        PFAR_EL(target_el) = faultaddr;
    elsif (IsFeatureImplemented(FEAT_PFAR) ||
             (IsFeatureImplemented(FEAT_RME) && target_el == EL3)) then
        PFAR_EL(target_el) = ARBITRARY : bits(64);
    end;
    return;
end;

// AArch64_ResetControlRegisters()
// ===============================
// Resets System registers and memory-mapped control registers that have architecturally-defined
// reset values to those values.

impdef func AArch64_ResetControlRegisters(cold_reset : boolean)
begin
    return;
end;

// AArch64_TakeReset()
// ===================
// Reset into AArch64 state

func AArch64_TakeReset(cold_reset : boolean)
begin
    assert HaveAArch64();

    // Enter the highest implemented Exception level in AArch64 state
    PSTATE.nRW = '0';
    if HaveEL(EL3) then
        PSTATE.EL = EL3;
    elsif HaveEL(EL2) then
        PSTATE.EL = EL2;
    else
        PSTATE.EL = EL1;
    end;

    // Reset System registers and other system components
    AArch64_ResetControlRegisters(cold_reset);

    // Reset all other PSTATE fields
    PSTATE.SP = '1';                    // Select stack pointer
    PSTATE.[D,A,I,F]  = '1111';         // All asynchronous exceptions masked
    PSTATE.SS = '0';                    // Clear software step bit
    PSTATE.DIT = '0';                   // PSTATE.DIT is reset to 0 when resetting into AArch64
    if IsFeatureImplemented(FEAT_PAuth_LR) then
        PSTATE.PACM = '0';              // PAC modifier
    end;
    if IsFeatureImplemented(FEAT_SME) then
        PSTATE.[SM,ZA] = '00';          // Disable Streaming SVE mode & ZA storage
        ResetSMEState('0');
    end;
    if IsFeatureImplemented(FEAT_SSBS) then
        PSTATE.SSBS = ImpDefBit("PSTATE.SSBS bit at reset");
    end;
    if IsFeatureImplemented(FEAT_GCS) then
        PSTATE.EXLOCK = '0';            // PSTATE.EXLOCK is reset to 0 when resetting into AArch64
    end;
    if IsFeatureImplemented(FEAT_UINJ) then
        PSTATE.UINJ = '0';              // PSTATE.UINJ is reset to 0 when resetting into AArch64
    end;
    PSTATE.IL = '0';                    // Clear Illegal Execution state bit

    // All registers, bits and fields not reset by the above pseudocode or by the BranchTo() call
    // below are UNKNOWN bitstrings after reset. In particular, the return information registers
    // ELR_ELx and SPSR_ELx have UNKNOWN values, so that it
    // is impossible to return from a reset in an architecturally defined way.
    AArch64_ResetGeneralRegisters();
    if IsFeatureImplemented(FEAT_SME) || IsFeatureImplemented(FEAT_SVE) then
        ResetSVERegisters();
    else
        AArch64_ResetSIMDFPRegisters();
    end;
    AArch64_ResetSpecialRegisters();
    ResetExternalDebugRegisters(cold_reset);

    var rv : bits(64);                      // IMPLEMENTATION DEFINED reset vector

    if HaveEL(EL3) then
        rv = RVBAR_EL3();
    elsif HaveEL(EL2) then
        rv = RVBAR_EL2();
    else
        rv = RVBAR_EL1();
    end;

    // The reset vector must be correctly aligned
    let pamax : AddressSize = AArch64_PAMax();
    assert IsZero(rv[63:pamax]) && IsZero(rv[1:0]);

    let branch_conditional : boolean = FALSE;
    EDPRSR().R = '0';                 // Leaving Reset State.
    BranchTo{64}(rv, BranchType_RESET, branch_conditional);
end;

// AArch64_FPTrappedException()
// ============================

func AArch64_FPTrappedException(is_ase : boolean, accumulated_exceptions : bits(8))
begin
    var except : ExceptionRecord = ExceptionSyndrome(Exception_FPTrappedException);
    if is_ase then
        if ImpDefBool("vector instructions set TFV to 1") then
            except.syndrome.iss[23] = '1';                          // TFV
        else
            except.syndrome.iss[23] = '0';                          // TFV
        end;
    else
        except.syndrome.iss[23]     = '1';                          // TFV
    end;
    except.syndrome.iss[10:8] = ARBITRARY : bits(3);                // VECITR
    if except.syndrome.iss[23] == '1' then
        except.syndrome.iss[7,4:0] = accumulated_exceptions[7,4:0]; // IDF,IXF,UFF,OFF,DZF,IOF
    else
        except.syndrome.iss[7,4:0] = ARBITRARY : bits(6);
    end;

    let route_to_el2 : boolean = EL2Enabled() && HCR_EL2().TGE == '1';

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    if UInt(PSTATE.EL) > UInt(EL1) then
        AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
    elsif route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_CallHypervisor()
// ========================
// Performs a HVC call

func AArch64_CallHypervisor(immediate : bits(16))
begin
    assert HaveEL(EL2);

    if UsingAArch32() then AArch32_ITAdvance(); end;
    SSAdvance();
    let preferred_exception_return : bits(64) = NextInstrAddr{}();
    let vect_offset : integer{} = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_HypervisorCall);
    except.syndrome.iss[15:0] = immediate;

    if IsFeatureImplemented(FEAT_PAuth_LR) then PSTATE.PACM = '0'; end;
    if PSTATE.EL == EL3 then
        AArch64_TakeException(EL3, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_CallSecureMonitor()
// ===========================

func AArch64_CallSecureMonitor(immediate : bits(16))
begin
    assert HaveEL(EL3) && !ELUsingAArch32(EL3);
    if UsingAArch32() then AArch32_ITAdvance(); end;
    HSAdvance();
    SSAdvance();
    let preferred_exception_return : bits(64) = NextInstrAddr{}();
    let vect_offset : integer{} = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_MonitorCall);
    except.syndrome.iss[15:0] = immediate;
    if IsFeatureImplemented(FEAT_PAuth_LR) then PSTATE.PACM = '0'; end;
    AArch64_TakeException(EL3, except, preferred_exception_return, vect_offset);
end;

// AArch64_CallSupervisor()
// ========================
// Calls the Supervisor

func AArch64_CallSupervisor(immediate : bits(16))
begin
    if UsingAArch32() then AArch32_ITAdvance(); end;
    SSAdvance();
    let route_to_el2 : boolean = PSTATE.EL == EL0 && EL2Enabled() && HCR_EL2().TGE == '1';

    let preferred_exception_return : bits(64) = NextInstrAddr{}();
    let vect_offset : integer{} = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_SupervisorCall);
    except.syndrome.iss[15:0] = immediate;
    if IsFeatureImplemented(FEAT_PAuth_LR) then PSTATE.PACM = '0'; end;
    if UInt(PSTATE.EL) > UInt(EL1) then
        AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
    elsif route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_TakeException()
// =======================
// Take an exception to an Exception level using AArch64.

noreturn func AArch64_TakeException(target_el : bits(2), exception_in : ExceptionRecord,
                                    preferred_exception_return : bits(64), vect_offset_in : integer)
begin
    assert HaveEL(target_el) && !ELUsingAArch32(target_el) && UInt(target_el) >= UInt(PSTATE.EL);
    if Halted() then
        AArch64_TakeExceptionInDebugState(target_el, exception_in);
    end;
    var except : ExceptionRecord = exception_in;
    var sync_errors : boolean;
    var iesb_req : boolean;
    if IsFeatureImplemented(FEAT_IESB) then
        sync_errors = SCTLR_EL(target_el).IESB == '1';
        if IsFeatureImplemented(FEAT_DoubleFault) then
            sync_errors = sync_errors || (SCR_EL3().[EA,NMEA] == '11' && target_el == EL3);
        end;
        if sync_errors && InsertIESBBeforeException(target_el) then
            SynchronizeErrors();
            if except.exceptype != Exception_SError then
                iesb_req = FALSE;
                sync_errors = FALSE;
                TakeUnmaskedPhysicalSErrorInterrupts(iesb_req);
            end;
        end;
    else
        sync_errors = FALSE;
    end;

    var brbe_source_allowed : boolean = FALSE;
    var brbe_source_address : bits(64) = Zeros{};
    if IsFeatureImplemented(FEAT_BRBE) then
        brbe_source_allowed = BranchRecordAllowed(PSTATE.EL);
        brbe_source_address = preferred_exception_return;
    end;

    if !IsFeatureImplemented(FEAT_ExS) || SCTLR_EL(target_el).EIS == '1' then
        // Synchronize the context, including Instruction Fetch Barrier effect
        SynchronizeContext();
    elsif !(except.exceptype == Exception_SoftwareBreakpoint ||
             (except.exceptype IN {Exception_SupervisorCall,
                                   Exception_HypervisorCall,
                                   Exception_MonitorCall} &&
              !except.trappedsyscallinst)) then
        InstructionFetchBarrier();
    end;

    // If coming from AArch32 state, the top parts of the X[] registers might be set to zero
    let from_32 : boolean = UsingAArch32();
    if from_32 then AArch64_MaybeZeroRegisterUppers(); end;
    if from_32 && IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then
        ResetSVEState();
    else
        MaybeZeroSVEUppers(target_el);
    end;

    var vect_offset : integer = vect_offset_in;
    if UInt(target_el) > UInt(PSTATE.EL) then
        var lower_32 : boolean;
        if target_el == EL3 then
            if EL2Enabled() then
                lower_32 = ELUsingAArch32(EL2);
            else
                lower_32 = ELUsingAArch32(EL1);
            end;
        elsif IsInHost() && PSTATE.EL == EL0 && target_el == EL2 then
            lower_32 = ELUsingAArch32(EL0);
        else
            lower_32 = ELUsingAArch32(target_el - 1);
        end;
        vect_offset = vect_offset + (if lower_32 then 0x600 else 0x400);

    elsif PSTATE.SP == '1' then
        vect_offset = vect_offset + 0x200;
    end;

    var spsr : bits(64) = GetPSRFromPSTATE{}(AArch64_NonDebugState);

    if PSTATE.EL == EL1 && target_el == EL1 && EL2Enabled() then
        if EffectiveHCR_EL2_NVx() IN {'x01', '111'} then
            spsr[3:2] = '10';
        end;
    end;

    if IsFeatureImplemented(FEAT_BTI) && !UsingAArch32() then
        var zero_btype : boolean;
        // SPSR_ELx[].BTYPE is only guaranteed valid for these exception types
        if except.exceptype IN {Exception_SError, Exception_IRQ, Exception_FIQ,
                                Exception_SoftwareStep, Exception_PCAlignment,
                                Exception_InstructionAbort, Exception_Breakpoint,
                                Exception_VectorCatch, Exception_SoftwareBreakpoint,
                                Exception_IllegalState, Exception_BranchTarget} then
            zero_btype = FALSE;
        else
            zero_btype = ConstrainUnpredictableBool(Unpredictable_ZEROBTYPE);
        end;
        if zero_btype then spsr[11:10] = '00'; end;
    end;

    if (IsFeatureImplemented(FEAT_NV2) &&
          except.exceptype == Exception_NV2DataAbort && target_el == EL3) then
        // External aborts are configured to be taken to EL3
        except.exceptype = Exception_DataAbort;
    end;
    if ! except.exceptype IN {Exception_IRQ, Exception_FIQ} then
        AArch64_ReportException(except, target_el);
    end;

    if IsFeatureImplemented(FEAT_BRBE) then
        let brbe_target_address : bits(64) = VBAR_EL(target_el)[63:11]::vect_offset[10:0];
        BRBEException(except, brbe_source_allowed, brbe_source_address,
                      brbe_target_address, target_el,
                      except.trappedsyscallinst);
    end;

    if IsFeatureImplemented(FEAT_GCS) then
        if PSTATE.EL == target_el then
            if GetCurrentEXLOCKEN() then
                PSTATE.EXLOCK = '1';
            else
                PSTATE.EXLOCK = '0';
            end;
        else
            PSTATE.EXLOCK = '0';
        end;
    end;

    PSTATE.EL = target_el;
    PSTATE.nRW = '0';
    PSTATE.SP = '1';

    SPSR_ELx() = spsr;
    ELR_ELx() = preferred_exception_return;
    PSTATE.SS = '0';
    if IsFeatureImplemented(FEAT_SSBS) then PSTATE.SSBS = SCTLR_ELx().DSSBS; end;
    if IsFeatureImplemented(FEAT_EBEP) then PSTATE.PM = '1'; end;
    if IsFeatureImplemented(FEAT_SEBEP) then
        PSTATE.PPEND = '0';
        ShouldSetPPEND = FALSE;
    end;
    if IsFeatureImplemented(FEAT_NMI) then
        PSTATE.ALLINT = NOT SCTLR_ELx().SPINTMASK;
    end;
    PSTATE.[D,A,I,F] = '1111';
    if IsFeatureImplemented(FEAT_MTE) then PSTATE.TCO = '1'; end;
    PSTATE.IL = '0';
    if IsFeatureImplemented(FEAT_UAO) then PSTATE.UAO = '0'; end;
    if IsFeatureImplemented(FEAT_UINJ) then PSTATE.UINJ = '0'; end;
    if IsFeatureImplemented(FEAT_PAuth_LR) then PSTATE.PACM = '0'; end;
    if (IsFeatureImplemented(FEAT_PAN) && (PSTATE.EL == EL1 ||
          (PSTATE.EL == EL2 && ELIsInHost(EL0))) &&
          SCTLR_ELx().SPAN == '0') then
        PSTATE.PAN = '1';
    end;
    if from_32 then                             // Coming from AArch32
        PSTATE.IT = '00000000';
        PSTATE.T = '0';                         // PSTATE.J is RES0
    end;
    if IsFeatureImplemented(FEAT_BTI) then PSTATE.BTYPE = '00'; end;
    let branch_conditional : boolean = FALSE;
    BranchTo{64}(VBAR_ELx()[63:11]::vect_offset[10:0], BranchType_EXCEPTION, branch_conditional);
    CheckExceptionCatch(TRUE);                  // Check for debug event on exception entry

    if sync_errors then
        SynchronizeErrors();
        iesb_req = TRUE;
        TakeUnmaskedPhysicalSErrorInterrupts(iesb_req);
    end;

    EndOfInstruction();
end;

// AArch64_AArch32SystemAccessTrap()
// =================================
// Trapped AArch32 System register access.

func AArch64_AArch32SystemAccessTrap(target_el : bits(2), ec : integer)
begin
    assert HaveEL(target_el) && target_el != EL0 && UInt(target_el) >= UInt(PSTATE.EL);

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    let except : ExceptionRecord = AArch64_AArch32SystemAccessTrapSyndrome(ThisInstr(), ec);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_AArch32SystemAccessTrapSyndrome()
// =========================================
// Returns the syndrome information for traps on AArch32 MCR, MCRR, MRC, MRRC, and VMRS,
// VMSR instructions, other than traps that are due to HCPTR or CPACR.

func AArch64_AArch32SystemAccessTrapSyndrome(instr : bits(32), ec : integer) => ExceptionRecord
begin
    var except : ExceptionRecord;

    case ec of
        when 0x0 =>    except = ExceptionSyndrome(Exception_Uncategorized);
        when 0x3 =>    except = ExceptionSyndrome(Exception_CP15RTTrap);
        when 0x4 =>    except = ExceptionSyndrome(Exception_CP15RRTTrap);
        when 0x5 =>    except = ExceptionSyndrome(Exception_CP14RTTrap);
        when 0x6 =>    except = ExceptionSyndrome(Exception_CP14DTTrap);
        when 0x7 =>    except = ExceptionSyndrome(Exception_AdvSIMDFPAccessTrap);
        when 0x8 =>    except = ExceptionSyndrome(Exception_FPIDTrap);
        when 0xC =>    except = ExceptionSyndrome(Exception_CP14RRTTrap);
        otherwise =>   unreachable;
    end;

    var iss : bits(20) = Zeros{};

    if except.exceptype == Exception_Uncategorized then
        return except;
    elsif except.exceptype IN {Exception_FPIDTrap, Exception_CP14RTTrap,
                               Exception_CP15RTTrap} then
        // Trapped MRC/MCR, VMRS on FPSID
        if except.exceptype != Exception_FPIDTrap then    // When trap is not for VMRS
            iss[19:17] = instr[7:5];           // opc2
            iss[16:14] = instr[23:21];         // opc1
            iss[13:10] = instr[19:16];         // CRn
            iss[4:1]   = instr[3:0];           // CRm
        else
            iss[19:17] = '000';
            iss[16:14] = '111';
            iss[13:10] = instr[19:16];         // reg
            iss[4:1]   = '0000';
        end;

        if instr[20] == '1' && instr[15:12] == '1111' then    // MRC, Rt==15
            iss[9:5] = '11111';
        elsif instr[20] == '0' && instr[15:12] == '1111' then // MCR, Rt==15
            iss[9:5] = ARBITRARY : bits(5);
        else
            iss[9:5] = LookUpRIndex(UInt(instr[15:12]), PSTATE.M)[4:0];
        end;
    elsif except.exceptype IN {Exception_CP14RRTTrap, Exception_AdvSIMDFPAccessTrap,
                               Exception_CP15RRTTrap} then
        // Trapped MRRC/MCRR, VMRS/VMSR
        iss[19:16] = instr[7:4];          // opc1
        if instr[19:16] == '1111' then    // Rt2==15
            iss[14:10] = ARBITRARY : bits(5);
        else
            iss[14:10] = LookUpRIndex(UInt(instr[19:16]), PSTATE.M)[4:0];
        end;

        if instr[15:12] == '1111' then    // Rt==15
            iss[9:5] = ARBITRARY : bits(5);
        else
            iss[9:5] = LookUpRIndex(UInt(instr[15:12]), PSTATE.M)[4:0];
        end;
        iss[4:1]   = instr[3:0];         // CRm
    elsif except.exceptype == Exception_CP14DTTrap then
        // Trapped LDC/STC
        iss[19:12] = instr[7:0];         // imm8
        iss[4]     = instr[23];          // U
        iss[2:1]   = instr[24,21];       // P,W
        if instr[19:16] == '1111' then   // Rn==15, LDC(Literal addressing)/STC
            iss[9:5] = ARBITRARY : bits(5);
            iss[3]   = '1';
        end;
    end;
    iss[0] = instr[20];                  // Direction

    except.syndrome.iss[24:20] = ConditionSyndrome();
    except.syndrome.iss[19:0]  = iss;

    return except;
end;

// AArch64_AdvSIMDFPAccessTrap()
// =============================
// Trapped access to Advanced SIMD or FP registers due to CPACR.

func AArch64_AdvSIMDFPAccessTrap(target_el : bits(2))
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    var except : ExceptionRecord;
    let vect_offset : integer = 0x0;

    let route_to_el2 : boolean = (target_el == EL1 && EL2Enabled() && HCR_EL2().TGE == '1');

    if route_to_el2 then
        except = ExceptionSyndrome(Exception_Uncategorized);
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        except = ExceptionSyndrome(Exception_AdvSIMDFPAccessTrap);
        except.syndrome.iss[24:20] = ConditionSyndrome();
        AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
    end;

    return;
end;

// AArch64_CheckCP15InstrCoarseTraps()
// ===================================
// Check for coarse-grained AArch32 traps to System registers in the
// coproc=0b1111 encoding space by HSTR_EL2, HCR_EL2, and SCTLR_ELx.

func AArch64_CheckCP15InstrCoarseTraps(CRn : integer, nreg : integer, CRm : integer)
begin
    let trapped_encoding : boolean = ((CRn == 9  && CRm IN {0,1,2,    5,6,7,8   }) ||
                                      (CRn == 10 && CRm IN {0,1,    4,      8   }) ||
                                      (CRn == 11 && CRm IN {0,1,2,3,4,5,6,7,8,15}));

    // Check for MRC and MCR disabled by SCTLR_EL1.TIDCP.
    if (IsFeatureImplemented(FEAT_TIDCP1) && PSTATE.EL == EL0 && !IsInHost() &&
           !ELUsingAArch32(EL1) && SCTLR_EL1().TIDCP == '1' && trapped_encoding) then
        if EL2Enabled() && HCR_EL2().TGE == '1' then
            AArch64_AArch32SystemAccessTrap(EL2, 0x3);
        else
            AArch64_AArch32SystemAccessTrap(EL1, 0x3);
        end;
    end;

    // Check for coarse-grained Hyp traps
    if PSTATE.EL IN {EL0, EL1} && EL2Enabled() then
        // Check for MRC and MCR disabled by SCTLR_EL2.TIDCP.
        if (IsFeatureImplemented(FEAT_TIDCP1) && PSTATE.EL == EL0 && IsInHost() &&
              SCTLR_EL2().TIDCP == '1' && trapped_encoding) then
            AArch64_AArch32SystemAccessTrap(EL2, 0x3);
        end;

        let major : integer = if nreg == 1 then CRn else CRm;
        // Check for MCR, MRC, MCRR, and MRRC disabled by HSTR_EL2().CRn/HSTR().CRm
        // and MRC and MCR disabled by HCR_EL2.TIDCP.
        if ((!IsInHost() && ! major IN {4,14} && HSTR_EL2()[major] == '1') ||
                (HCR_EL2().TIDCP == '1' && nreg == 1 && trapped_encoding)) then
            if (PSTATE.EL == EL0 &&
                    ImpDefBool("UNDEF unallocated CP15 access at EL0")) then
                Undefined();
            end;
            AArch64_AArch32SystemAccessTrap(EL2, 0x3);
        end;
    end;
end;

// AArch64_CheckFPAdvSIMDEnabled()
// ===============================

func AArch64_CheckFPAdvSIMDEnabled()
begin
    AArch64_CheckFPEnabled();
    // Check for illegal use of Advanced
    // SIMD in Streaming SVE Mode
    if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' && !IsFullA64Enabled() then
        SMEAccessTrap(SMEExceptionType_Streaming, PSTATE.EL);
    end;
end;

// AArch64_CheckFPAdvSIMDTrap()
// ============================
// Check against CPTR_EL2 and CPTR_EL3.

func AArch64_CheckFPAdvSIMDTrap()
begin
    if HaveEL(EL3) && CPTR_EL3().TFP == '1' && EL3SDDUndefPriority() then
        Undefined();
    end;

    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        // Check if access disabled in CPTR_EL2
        if ELIsInHost(EL2) then
            var disabled : boolean;
            case CPTR_EL2().FPEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        else
            if CPTR_EL2().TFP == '1' then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        end;
    end;

    if HaveEL(EL3) then
        // Check if access disabled in CPTR_EL3
        if CPTR_EL3().TFP == '1' then
            if EL3SDDUndef() then
                Undefined();
            else
                AArch64_AdvSIMDFPAccessTrap(EL3);
            end;
        end;
    end;
end;

// AArch64_CheckFPEnabled()
// ========================
// Check against CPACR

func AArch64_CheckFPEnabled()
begin
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        // Check if access disabled in CPACR_EL1
        var disabled : boolean;
        case CPACR_EL1().FPEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then AArch64_AdvSIMDFPAccessTrap(EL1); end;
    end;

    AArch64_CheckFPAdvSIMDTrap();               // Also check against CPTR_EL2 and CPTR_EL3
end;

// AArch64_CheckForERetTrap()
// ==========================
// Check for trap on ERET, ERETAA, ERETAB instruction

func AArch64_CheckForERetTrap(eret_with_pac : boolean, pac_uses_key_a : boolean)
begin
    if PSTATE.EL == EL1 && EL2Enabled() then
        var route_to_el2 : boolean = FALSE;

        // Check for a fine-grained trap by the hypervisor.
        if (IsFeatureImplemented(FEAT_FGT) && (!HaveEL(EL3) || SCR_EL3().FGTEn == '1') &&
              HFGITR_EL2().ERET == '1') then
            route_to_el2 = TRUE;
        // Check for a trap by the Effective value of the HCR_EL2.NV bit
        elsif EffectiveHCR_EL2_NVx()[0] == '1' then
            // Check for a trap by NVHCR_EL2.TGE based on the SPSR_EL1().M[3:2] value
            if EffectiveHCRX_EL2_NVTGE() == '1' then
                route_to_el2 = NVHCR_EL2().TGE == '0' && SPSR_EL1().M[3:2] == '0x';
            else
                route_to_el2 = TRUE;
            end;
        end;

        if route_to_el2 then
            let preferred_exception_return : bits(64) = ThisInstrAddr{}();
            let vect_offset : integer = 0x0;
            var except : ExceptionRecord = ExceptionSyndrome(Exception_ERetTrap);

            if !eret_with_pac then                             // ERET
                except.syndrome.iss[1] = '0';
                except.syndrome.iss[0] = '0';                  // RES0
            else
                except.syndrome.iss[1] = '1';
                except.syndrome.iss[0] = if pac_uses_key_a then '0' else '1';
            end;

            AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
        end;
    end;

    return;
end;

// AArch64_CheckForSMCUndefOrTrap()
// ================================
// Check for UNDEFINED or trap on SMC instruction

func AArch64_CheckForSMCUndefOrTrap(imm : bits(16))
begin
    if PSTATE.EL == EL0 then Undefined(); end;
    if (!(PSTATE.EL == EL1 && EL2Enabled() && HCR_EL2().TSC == '1') &&
        HaveEL(EL3) && SCR_EL3().SMD == '1') then
        Undefined();
    end;
    var route_to_el2 : boolean = FALSE;
    if !HaveEL(EL3) then
        if (PSTATE.EL == EL1 && EL2Enabled() && HCR_EL2().TSC == '1' &&
              (EffectiveHCR_EL2_NVx() == 'xx1' ||
              (ImpDefBool("Trap SMC execution at EL1 to EL2")))) then
            route_to_el2 = TRUE;
        else
            Undefined();
        end;
    else
        route_to_el2 = PSTATE.EL == EL1 && EL2Enabled() && HCR_EL2().TSC == '1';
    end;
    if route_to_el2 then
        let preferred_exception_return : bits(64) = ThisInstrAddr{}();
        let vect_offset : integer = 0x0;
        var except : ExceptionRecord = ExceptionSyndrome(Exception_MonitorCall);
        except.syndrome.iss[15:0] = imm;
        except.trappedsyscallinst = TRUE;
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_CheckForSVCTrap()
// =========================
// Check for trap on SVC instruction

func AArch64_CheckForSVCTrap(immediate : bits(16))
begin
    if IsFeatureImplemented(FEAT_FGT) then
        var route_to_el2 : boolean = FALSE;
        if PSTATE.EL == EL0 then
            route_to_el2 = (!UsingAArch32() && !ELUsingAArch32(EL1) &&
                           EL2Enabled() && HFGITR_EL2().SVC_EL0 == '1' &&
                           (!IsInHost() && (!HaveEL(EL3) || SCR_EL3().FGTEn == '1')));

        elsif PSTATE.EL == EL1 then
            route_to_el2 = (EL2Enabled() && HFGITR_EL2().SVC_EL1 == '1' &&
                           (!HaveEL(EL3) || SCR_EL3().FGTEn == '1'));
        end;

        if route_to_el2 then
            var except : ExceptionRecord = ExceptionSyndrome(Exception_SupervisorCall);
            except.syndrome.iss[15:0] = immediate;
            except.trappedsyscallinst = TRUE;
            let preferred_exception_return : bits(64) = ThisInstrAddr{}();
            let vect_offset : integer = 0x0;

            AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
        end;
    end;
end;

// AArch64_CheckForWFxTrap()
// =========================
// Checks for a trap on a WFE, WFET, WFI or WFIT instruction.

func AArch64_CheckForWFxTrap(wfxtype : WFxType) => (boolean, bits(2))
begin
    let is_wfe : boolean = wfxtype IN {WFxType_WFE, WFxType_WFET};
    var target_el : bits(2);
    var trap : boolean = FALSE;

    if HaveEL(EL3) && EL3SDDUndefPriority() && PSTATE.EL != EL3 then
        // Check for traps described by the Secure Monitor.
        // If the trap is enabled, the instruction will be UNDEFINED because EDSCR.SDD is 1.
        trap      = (if is_wfe then SCR_EL3().TWE else SCR_EL3().TWI) == '1';
        target_el = EL3;
    end;

    if !trap && PSTATE.EL == EL0 then
        // Check for traps described by the OS which may be EL1 or EL2.
        trap      = (if is_wfe then SCTLR_ELx().nTWE else SCTLR_ELx().nTWI) == '0';
        target_el = EL1;
    end;

    if !trap && PSTATE.EL IN {EL0, EL1} && EL2Enabled() && !IsInHost() then
        // Check for traps described by the Hypervisor.
        trap      = (if is_wfe then HCR_EL2().TWE else HCR_EL2().TWI) == '1';
        target_el = EL2;
    end;

    if !trap && HaveEL(EL3) && PSTATE.EL != EL3 then
        // Check for traps described by the Secure Monitor.
        trap      = (if is_wfe then SCR_EL3().TWE else SCR_EL3().TWI) == '1';
        target_el = EL3;
    end;
    return (trap, target_el);
end;

// AArch64_CheckIllegalState()
// ===========================
// Check PSTATE.IL bit and generate Illegal Execution state exception if set.

func AArch64_CheckIllegalState()
begin
    if PSTATE.IL == '1' then
        let route_to_el2 : boolean = PSTATE.EL == EL0 && EL2Enabled() && HCR_EL2().TGE == '1';

        let preferred_exception_return : bits(64) = ThisInstrAddr{}();
        let vect_offset : integer = 0x0;

        let except : ExceptionRecord = ExceptionSyndrome(Exception_IllegalState);

        if UInt(PSTATE.EL) > UInt(EL1) then
            AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
        elsif route_to_el2 then
            AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
        else
            AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
        end;
    end;
end;

// AArch64_MonitorModeTrap()
// =========================
// Trapped use of Monitor mode features in a Secure EL1 AArch32 mode

func AArch64_MonitorModeTrap()
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer                 = 0x0;

    let except : ExceptionRecord              = ExceptionSyndrome(Exception_Uncategorized);

    if IsSecureEL2Enabled() then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    end;
    AArch64_TakeException(EL3, except, preferred_exception_return, vect_offset);
end;

// AArch64_SystemAccessTrap()
// ==========================
// Trapped access to AArch64 System register or system instruction.

func AArch64_SystemAccessTrap(target_el : bits(2), ec : integer)
begin
    assert HaveEL(target_el) && target_el != EL0 && UInt(target_el) >= UInt(PSTATE.EL);

    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    let except : ExceptionRecord = AArch64_SystemAccessTrapSyndrome(ThisInstr(), ec);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// AArch64_SystemAccessTrapSyndrome()
// ==================================
// Returns the syndrome information for traps on AArch64 MSR/MRS instructions.

func AArch64_SystemAccessTrapSyndrome(instr_in : bits(32), ec : integer) => ExceptionRecord
begin
    var except : ExceptionRecord;
    var instr : bits(32) = instr_in;
    case ec of
        when 0x0 =>                      // Trapped access due to unknown reason.
            except = ExceptionSyndrome(Exception_Uncategorized);
        when 0x7 =>                      // Trapped access to SVE, Advance SIMD&FP System register.
            except = ExceptionSyndrome(Exception_AdvSIMDFPAccessTrap);
            except.syndrome.iss[24:20] = ConditionSyndrome();
        when 0x14 =>                     // Trapped access to 128-bit System register or
                                         // 128-bit System instruction.
            except = ExceptionSyndrome(Exception_SystemRegister128Trap);
            instr = ThisInstr();
            except.syndrome.iss[21:20] = instr[20:19]; // Op0
            except.syndrome.iss[19:17] = instr[7:5];   // Op2
            except.syndrome.iss[16:14] = instr[18:16]; // Op1
            except.syndrome.iss[13:10] = instr[15:12]; // CRn
            except.syndrome.iss[9:6]   = instr[4:1];   // Rt
            except.syndrome.iss[4:1]   = instr[11:8];  // CRm
            except.syndrome.iss[0]     = instr[21];    // Direction
        when 0x18 =>                     // Trapped access to System register or system instruction.
            except = ExceptionSyndrome(Exception_SystemRegisterTrap);
            instr = ThisInstr();
            except.syndrome.iss[21:20] = instr[20:19]; // Op0
            except.syndrome.iss[19:17] = instr[7:5];   // Op2
            except.syndrome.iss[16:14] = instr[18:16]; // Op1
            except.syndrome.iss[13:10] = instr[15:12]; // CRn
            except.syndrome.iss[9:5]   = instr[4:0];   // Rt
            except.syndrome.iss[4:1]   = instr[11:8];  // CRm
            except.syndrome.iss[0]     = instr[21];    // Direction
        when 0x19 =>                        // Trapped access to SVE System register
            except = ExceptionSyndrome(Exception_SVEAccessTrap);
        when 0x1D =>                        // Trapped access to SME System register
            except = ExceptionSyndrome(Exception_SMEAccessTrap);
        otherwise =>
            unreachable;
    end;

    return except;
end;

// AArch64_Undefined()
// ===================

noreturn func AArch64_Undefined()
begin

    let route_to_el2 : boolean = PSTATE.EL == EL0 && EL2Enabled() && HCR_EL2().TGE == '1';
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    let except : ExceptionRecord = ExceptionSyndrome(Exception_Uncategorized);

    if UInt(PSTATE.EL) > UInt(EL1) then
        AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
    elsif route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(EL1, except, preferred_exception_return, vect_offset);
    end;
end;

// AArch64_WFxTrap()
// =================
// Generate an exception for a trapped WFE, WFI, WFET or WFIT instruction.

func AArch64_WFxTrap(wfxtype : WFxType, target_el : bits(2))
begin
    assert UInt(target_el) > UInt(PSTATE.EL);
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;
    var except : ExceptionRecord = ExceptionSyndrome(Exception_WFxTrap);
    except.syndrome.iss[24:20] = ConditionSyndrome();
    case wfxtype of
        when WFxType_WFI =>
            except.syndrome.iss[1:0] = '00';
        when WFxType_WFE =>
            except.syndrome.iss[1:0] = '01';
        when WFxType_WFIT =>
            except.syndrome.iss[1:0] = '10';
            except.syndrome.iss[2]   = '1';   // Register field is valid
            except.syndrome.iss[9:5] = ThisInstr()[4:0];
        when WFxType_WFET =>
            except.syndrome.iss[1:0] = '11';
            except.syndrome.iss[2]   = '1';   // Register field is valid
            except.syndrome.iss[9:5] = ThisInstr()[4:0];
    end;

    if target_el == EL1 && EL2Enabled() && HCR_EL2().TGE == '1' then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
    end;
end;

// CheckLDST64BEnabled()
// =====================
// Checks for trap on ST64B and LD64B instructions

func CheckLDST64BEnabled()
begin
    var trap : boolean = FALSE;
    let iss : bits(25) = ZeroExtend{}('10');  // 0x2
    var target_el : bits(2);

    if PSTATE.EL == EL0 then
        if !IsInHost() then
            trap = SCTLR_EL1().EnALS == '0';
            target_el = if EL2Enabled() && HCR_EL2().TGE == '1' then EL2 else EL1;
        else
            trap = SCTLR_EL2().EnALS == '0';
            target_el = EL2;
        end;
    else
        target_el = EL1;
    end;

    if (!trap && EL2Enabled() &&
        ((PSTATE.EL == EL0 && !IsInHost()) || PSTATE.EL == EL1)) then
        trap = !IsHCRXEL2Enabled() || HCRX_EL2().EnALS == '0';
        target_el = EL2;
    end;

    if trap then LDST64BTrap(target_el, iss); end;
end;

// CheckST64BV0Enabled()
// =====================
// Checks for trap on ST64BV0 instruction

func CheckST64BV0Enabled()
begin
    var trap : boolean = FALSE;
    let iss : bits(25) = ZeroExtend{}('1');  // 0x1
    var target_el : bits(2);

    if (PSTATE.EL != EL3 && HaveEL(EL3) &&
        SCR_EL3().EnAS0 == '0' && EL3SDDUndefPriority()) then
        Undefined();
    end;

    if PSTATE.EL == EL0 then
        if !IsInHost() then
            trap = SCTLR_EL1().EnAS0 == '0';
            target_el = if EL2Enabled() && HCR_EL2().TGE == '1' then EL2 else EL1;
        else
            trap = SCTLR_EL2().EnAS0 == '0';
            target_el = EL2;
        end;
    end;

    if (!trap && EL2Enabled() &&
        ((PSTATE.EL == EL0 && !IsInHost()) || PSTATE.EL == EL1)) then
        trap = !IsHCRXEL2Enabled() || HCRX_EL2().EnAS0 == '0';
        target_el = EL2;
    end;

    if !trap && PSTATE.EL != EL3 then
        trap = HaveEL(EL3) && SCR_EL3().EnAS0 == '0';
        target_el = EL3;
    end;

    if trap then
        if target_el == EL3 && EL3SDDUndef() then
            Undefined();
        else
            LDST64BTrap(target_el, iss);
        end;
    end;
end;

// CheckST64BVEnabled()
// ====================
// Checks for trap on ST64BV instruction

func CheckST64BVEnabled()
begin
    var trap : boolean = FALSE;
    let iss : bits(25) = Zeros{};
    var target_el : bits(2);

    if PSTATE.EL == EL0 then
        if !IsInHost() then
            trap = SCTLR_EL1().EnASR == '0';
            target_el = if EL2Enabled() && HCR_EL2().TGE == '1' then EL2 else EL1;
        else
            trap = SCTLR_EL2().EnASR == '0';
            target_el = EL2;
        end;
    end;

    if (!trap && EL2Enabled() &&
        ((PSTATE.EL == EL0 && !IsInHost()) || PSTATE.EL == EL1)) then
        trap = !IsHCRXEL2Enabled() || HCRX_EL2().EnASR == '0';
        target_el = EL2;
    end;

    if trap then LDST64BTrap(target_el, iss); end;
end;

// LDST64BTrap()
// =============
// Trapped access to LD64B, ST64B, ST64BV and ST64BV0 instructions

func LDST64BTrap(target_el : bits(2), iss : bits(25))
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_LDST64BTrap);
    except.syndrome.iss = iss;
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// WFETrapDelay()
// ==============
// Returns TRUE when delay in trap to WFE is enabled with value to amount of delay,
// FALSE otherwise.

func WFETrapDelay(target_el : bits(2)) => (boolean, integer)
begin
    var delay_enabled : boolean;
    var delay : integer;
    case target_el of
        when EL1 =>
            if !IsInHost() then
                delay_enabled = SCTLR_EL1().TWEDEn == '1';
                delay         = 1 << (UInt(SCTLR_EL1().TWEDEL) + 8);
            else
                delay_enabled = SCTLR_EL2().TWEDEn == '1';
                delay         = 1 << (UInt(SCTLR_EL2().TWEDEL) + 8);
            end;
        when EL2 =>
            assert EL2Enabled();
            delay_enabled = HCR_EL2().TWEDEn == '1';
            delay         = 1 << (UInt(HCR_EL2().TWEDEL) + 8);
        when EL3 =>
            delay_enabled = SCR_EL3().TWEDEn == '1';
            delay         = 1 << (UInt(SCR_EL3().TWEDEL) + 8);
    end;
    return (delay_enabled, delay);
end;

// WaitForEventUntilDelay()
// ========================
// Returns TRUE if WaitForEvent() returns before WFE trap delay expires,
// FALSE otherwise.

impdef func WaitForEventUntilDelay(delay_enabled : boolean, delay : integer) => boolean
begin
    return FALSE;
end;

// AArch64_FaultSyndrome()
// =======================
// Creates an exception syndrome value and updates the virtual address for Abort and Watchpoint
// exceptions taken to an Exception level using AArch64.

func AArch64_FaultSyndrome(exceptype : Exception, fault : FaultRecord,
                           target_el : bits(2)) => IssType
begin
    assert fault.statuscode != Fault_None;

    var isstype : IssType;
    isstype.iss  = Zeros{25};
    isstype.iss2 = Zeros{24};

    let d_side : boolean = exceptype IN {Exception_DataAbort, Exception_NV2DataAbort,
                                         Exception_Watchpoint, Exception_NV2Watchpoint};
    if IsFeatureImplemented(FEAT_RAS) && fault.statuscode == Fault_SyncExternal then
        let errstate : ErrorState = PEErrorState(fault);
        isstype.iss[12:11] = AArch64_EncodeSyncErrorSyndrome(errstate);  // SET
    end;

    if d_side then
        if (IsFeatureImplemented(FEAT_EAESR) && exceptype == Exception_DataAbort &&
              !fault.s2fs1walk && ! fault.accessdesc.acctype IN {AccessType_DC,
                                                                 AccessType_IC,
                                                                 AccessType_AT,
                                                                 AccessType_NV2}) then
            // LST2 field
            if fault.accessdesc.atomicop then
                isstype.iss2[15:13] = '001';    // Data Abort is from an Atomic instruction
            elsif (fault.accessdesc.acctype == AccessType_DCZero &&
                     fault.accessdesc.cachetype IN {CacheType_Data, CacheType_Data_Tag}) then
                isstype.iss2[15:13] = '010';    // Data Abort is from a DC ZVA or DC GZVA
            end;

            // Unpriv field
            if (fault.accessdesc.el == EL0 && PSTATE.EL != EL0 &&
                  fault.accessdesc.acctype IN {AccessType_GPR,
                                               AccessType_GCS,
                                               AccessType_ASIMD}) then
                isstype.iss2[12] = '1';         // Data Abort is from an unprivileged load or store
            end;
        end;

        if fault.accessdesc.acctype == AccessType_GCS then
            isstype.iss2[8] = '1';
        end;
        if exceptype IN {Exception_Watchpoint, Exception_NV2Watchpoint} then
            isstype.iss[23:0] = WatchpointRelatedSyndrome(fault);
        end;

        if AArch64_InstructionSyndromeValid(fault) then
            if fault.accessdesc.ls64 then
                (isstype.iss2, isstype.iss[24:14]) = LS64InstructionSyndrome();
            else
                isstype.iss[24:14] = LSInstructionSyndrome();
            end;
        end;

        if IsFeatureImplemented(FEAT_NV2) && fault.accessdesc.acctype == AccessType_NV2 then
            isstype.iss[13] = '1';   // Fault is generated by use of VNCR_EL2
        end;

        if (IsFeatureImplemented(FEAT_LS64) &&
              fault.statuscode IN {Fault_AccessFlag, Fault_Translation, Fault_Permission}) then
            isstype.iss[12:11] = GetLoadStoreType();
        end;

        if fault.accessdesc.acctype IN {AccessType_DC, AccessType_IC, AccessType_AT} then
            isstype.iss[8] = '1';
        end;

        if fault.accessdesc.acctype IN {AccessType_DC, AccessType_IC, AccessType_AT} then
            isstype.iss[6] = '1';
        elsif fault.statuscode IN {Fault_HWUpdateAccessFlag, Fault_Exclusive} then
            isstype.iss[6] = ARBITRARY : bit;
        elsif fault.accessdesc.atomicop && IsExternalAbort(fault) then
            isstype.iss[6] = ARBITRARY : bit;
        else
            isstype.iss[6] = if fault.write then '1' else '0';
        end;
        isstype.iss2[9] = if fault.tagaccess then '1' else '0';
        if fault.statuscode == Fault_Permission then
            isstype.iss2[5] = if fault.dirtybit then '1' else '0';
            isstype.iss2[6] = if fault.overlay then '1' else '0';
            if isstype.iss[24] == '0' then
                isstype.iss[21] = if fault.toplevel then '1' else '0';
            end;
            isstype.iss2[7] = if fault.assuredonly then '1' else '0';
            isstype.iss2[10] = if fault.s1tagnotdata then '1' else '0';
        end;

    else
        if (fault.accessdesc.acctype == AccessType_IFETCH &&
              fault.statuscode == Fault_Permission) then
            isstype.iss2[5] = if fault.dirtybit then '1' else '0';
            isstype.iss[21] = if fault.toplevel then '1' else '0';
            isstype.iss2[7] = if fault.assuredonly then '1' else '0';
            isstype.iss2[6] = if fault.overlay then '1' else '0';
        end;
    end;
    if fault.hdbssf then
        isstype.iss2[11] = '1';
    end;

    if (IsFeatureImplemented(FEAT_PFAR) && IsExternalSyncAbort(fault) &&
          !(EL2Enabled() && (HCR_EL2().VM == '1' || HCR_EL2().DC == '1') && target_el == EL1)) then
        isstype.iss[14] = if IsPFARValid(fault) then '1' else '0';
    end;

    if IsExternalAbort(fault) then isstype.iss[9] = fault.extflag; end;
    isstype.iss[7] = if fault.s2fs1walk then '1' else '0';
    isstype.iss[5:0] = EncodeLDFSC(fault.statuscode, fault.level);

    return isstype;
end;

// AArch64_InstructionSyndromeValid()
// ==================================
// Returns TRUE if ESR_ELx.ISV is '1' for the given Fault.

func AArch64_InstructionSyndromeValid(fault : FaultRecord) => boolean
begin
    if !fault.accessdesc.lowestaddress then
        return FALSE;
    end;

    if fault.accessdesc.ls64 then
        return fault.statuscode IN {Fault_AccessFlag, Fault_Translation, Fault_Permission};
    end;

    if fault.accessdesc.acctype == AccessType_GCS then
        return FALSE;
    end;

    if (IsFeatureImplemented(FEAT_EAESR) && !IsSecondStage(fault) &&
          fault.statuscode IN {Fault_AccessFlag, Fault_Translation, Fault_Permission}) then
        return TRUE;
    end;

    if IsSecondStage(fault) && !fault.s2fs1walk then
        return (!IsExternalSyncAbort(fault) ||
                (!IsFeatureImplemented(FEAT_RAS) && IsExternalAbortOnWalk(fault) &&
                  ImpDefBool("ISV on second stage translation table walk")));
    end;

    return FALSE;
end;

// EncodeGPCSC()
// =============
// Function that gives the GPCSC code for types of GPT Fault

func EncodeGPCSC(gpcf : GPCFRecord) => bits(6)
begin
    assert gpcf.level IN {0,1};

    case gpcf.gpf of
        when GPCF_AddressSize => return '00000'::gpcf.level[0];
        when GPCF_Walk =>        return '00010'::gpcf.level[0];
        when GPCF_Fail =>        return '00110'::gpcf.level[0];
        when GPCF_EABT =>        return '01010'::gpcf.level[0];
    end;
end;

// LS64InstructionSyndrome()
// =========================
// Returns the syndrome information and LST for a Data Abort by a
// ST64B, ST64BV, ST64BV0, or LD64B instruction. The syndrome information
// includes the ISS2, extended syndrome field.

impdef func LS64InstructionSyndrome() => (bits(24), bits(11))
begin
    return (Zeros{24}, LSInstructionSyndrome());
end;

// WatchpointFARNotPrecise()
// =========================
// Returns TRUE If the lowest watchpointed address that is higher than or equal to the address
// recorded in EDWAR might not have been accessed by the instruction, other than the CONSTRAINED
// UNPREDICTABLE condition of watchpoint matching a range of addresses with lowest address 16 bytes
// rounded down and upper address rounded up to nearest 16 byte multiple,
// FALSE otherwise.

impdef func WatchpointFARNotPrecise(fault : FaultRecord) => boolean
begin
    if IsFeatureImplemented(FEAT_SVE) || IsFeatureImplemented(FEAT_SME) then
        return fault.watchptinfo.maybe_false_match;
    end;
    return FALSE;
end;

// AArch64_APAS()
// ==============
// Decode Xt and perform an APAS operation for the decoded record.

func AArch64_APAS(Xt : bits(64))
begin
    var apas : APASRecord;
    let nse2 : bit = '0';
    apas.paspace = DecodePASpace(nse2, Xt[62], Xt[63]);

    apas.pa = Xt[55:6] :: '000000';
    apas.target_attributes = Xt[2:0];

    if AArch64_LocationSupportsAPAS(apas) then
        APAS_OP(apas);
    end;
end;

// AArch64_LocationSupportsAPAS()
// ==============================
// Returns TRUE if the given memory location supports the APAS instruction.

impdef func AArch64_LocationSupportsAPAS(apas : APASRecord) => boolean
begin
    return TRUE;
end;

// APASRecord
// ==========
// Details related to an APAS operation.

type APASRecord of record {
    pa : bits(56),
    paspace : PASpace,
    target_attributes : bits(3)

};

// APAS_OP()
// =========
// Sets the PA Space of the address in the APASRecord to the target PA space. If the location
// does not support the APAS instruction or cannot be associated with the indicated PASpace,
// then the instruction has no effect on the location and does not generate an External abort.

impdef func APAS_OP(apas : APASRecord)
begin
    return;
end;

// AArch64_AT()
// ============
// Perform address translation as per AT instructions.

func AArch64_AT(address : bits(64), stage : TranslationStage, el_in : bits(2), ataccess : ATAccess)
begin
    var el : bits(2) = el_in;
    let effective_nse_ns : bits(2) = EffectiveSCR_EL3_NSE() :: EffectiveSCR_EL3_NS();
    if (IsFeatureImplemented(FEAT_RME) && PSTATE.EL == EL3 &&
          effective_nse_ns == '10' && el != EL3) then
        Undefined();
    end;
    // For stage 1 translation, when HCR_EL2().[E2H, TGE] is {1,1} and requested EL is EL1,
    // the EL2&0 translation regime is used.
    if ELIsInHost(EL0) && el == EL1 && stage == TranslationStage_1 then
        el = EL2;
    end;

    let ss : SecurityState = SecurityStateAtEL(el);

    let accdesc : AccessDescriptor = CreateAccDescAT(ss, el, ataccess);
    let aligned : boolean = TRUE;

    var fault : FaultRecord = NoFault(accdesc, address);
    var regime : Regime;
    if stage == TranslationStage_12 then
        regime = Regime_EL10;
    else
        regime = TranslationRegime(el);
    end;

    var addrdesc : AddressDescriptor;
    if (el == EL0 && ELUsingAArch32(EL1)) || (el != EL0 && ELUsingAArch32(el)) then
        if regime == Regime_EL2 || TTBCR().EAE == '1' then
            (fault, addrdesc) = AArch32_S1TranslateLD(fault, regime, address[31:0], aligned,
                                                      accdesc);
        else
            (fault, addrdesc, -) = AArch32_S1TranslateSD(fault, regime, address[31:0], aligned,
                                                         accdesc);
        end;
    else
        let size : integer = 1;
        (fault, addrdesc) = AArch64_S1Translate(fault, regime, address, size, aligned, accdesc);
    end;

    if stage == TranslationStage_12 && fault.statuscode == Fault_None then
        let s1aarch64 : boolean = TRUE;
        if ELUsingAArch32(EL1) && regime == Regime_EL10 && EL2Enabled() then
            addrdesc.vaddress = ZeroExtend{64}(address);
            (fault, addrdesc) = AArch32_S2Translate(fault, addrdesc, aligned, accdesc);
        elsif regime == Regime_EL10 && EL2Enabled() then
            (fault, addrdesc) = AArch64_S2Translate(fault, addrdesc, s1aarch64, aligned, accdesc);
        end;
    end;

    let is_ATS1Ex : boolean = stage != TranslationStage_12;
    if fault.statuscode != Fault_None then
        addrdesc = CreateFaultyAddressDescriptor(fault);
        // Take an exception on:
        // * A Synchronous External abort occurs on translation table walk
        // * A stage 2 fault occurs on a stage 1 walk
        // * A GPC Exception (FEAT_RME)
        // * A GPF from ATS1E{1,0}* when executed from EL1 and HCR_EL2.GPF == '1' (FEAT_RME)
        if (IsExternalAbort(fault) ||
              (PSTATE.EL == EL1 && fault.s2fs1walk) ||
               (IsFeatureImplemented(FEAT_RME) && fault.gpcf.gpf != GPCF_None && (
                ReportAsGPCException(fault) ||
                (EL2Enabled() && HCR_EL2().GPF == '1' && PSTATE.EL == EL1 && el IN {EL1, EL0} &&
                 is_ATS1Ex)
                ))) then
            if IsFeatureImplemented(FEAT_D128) then
                PAR_EL1()       = ARBITRARY : bits(128);
            else
                PAR_EL1()[63:0] = ARBITRARY : bits(64);
            end;
            AArch64_Abort(addrdesc.fault);
        end;
    end;

    AArch64_EncodePAR(regime, el, is_ATS1Ex, addrdesc);
    return;
end;

// AArch64_EncodePAR()
// ===================
// Encode PAR register with result of translation.

func AArch64_EncodePAR(regime : Regime, el : bits(2), is_ATS1Ex : boolean,
                       addrdesc : AddressDescriptor)
begin
    let paspace : PASpace = addrdesc.paddress.paspace;
    if IsFeatureImplemented(FEAT_D128) then
        PAR_EL1() = Zeros{128};
        if AArch64_isPARFormatD128(regime, is_ATS1Ex) then
            PAR_EL1().D128 = '1';
        else
            PAR_EL1().D128 = '0';
        end;
    else
        PAR_EL1()[63:0] = Zeros{64};
    end;

    if !IsFault(addrdesc) then
        PAR_EL1().F = '0';
        if IsFeatureImplemented(FEAT_RME) then
            if regime == Regime_EL3 then
                case paspace of
                    when PAS_Secure =>     PAR_EL1().[NSE,NS] = '00';
                    when PAS_NonSecure =>  PAR_EL1().[NSE,NS] = '01';
                    when PAS_Root =>       PAR_EL1().[NSE,NS] = '10';
                    when PAS_Realm =>      PAR_EL1().[NSE,NS] = '11';
                end;

            elsif SecurityStateForRegime(regime) == SS_Secure  then
                PAR_EL1().NSE = ARBITRARY : bit;
                PAR_EL1().NS = if paspace == PAS_Secure then '0' else '1';

            elsif SecurityStateForRegime(regime) == SS_Realm then
                if regime == Regime_EL10 && is_ATS1Ex then
                    PAR_EL1().NSE = ARBITRARY : bit;
                    PAR_EL1().NS  = ARBITRARY : bit;
                else
                    PAR_EL1().NSE = ARBITRARY : bit;
                    PAR_EL1().NS  = if paspace == PAS_Realm then '0' else '1';
                end;

            else
                PAR_EL1().NSE = ARBITRARY : bit;
                PAR_EL1().NS  = ARBITRARY : bit;
            end;
        else
            PAR_EL1()[11] = '1'; // RES1
            if SecurityStateForRegime(regime) == SS_Secure then
                PAR_EL1().NS = if paspace == PAS_Secure then '0' else '1';
            else
                PAR_EL1().NS = ARBITRARY : bit;
            end;
        end;
        PAR_EL1().SH   = ReportedPARShareability(PAREncodeShareability(addrdesc.memattrs));
        if IsFeatureImplemented(FEAT_D128) && PAR_EL1().D128 == '1' then
            PAR_EL1()[119:76] = addrdesc.paddress.address[55:12];
        else
            PAR_EL1()[55:12] = addrdesc.paddress.address[55:12];
        end;
        PAR_EL1().ATTR = ReportedPARAttrs(EncodePARAttrs(addrdesc.memattrs));
        PAR_EL1()[10] = ImpDefBit("Non-Faulting PAR");
    else
        PAR_EL1().F   = '1';
        PAR_EL1().DirtyBit    = if addrdesc.fault.dirtybit then '1' else '0';
        PAR_EL1().Overlay     = if addrdesc.fault.overlay then '1' else '0';
        PAR_EL1().TopLevel    = if addrdesc.fault.toplevel then '1' else '0';
        PAR_EL1().AssuredOnly = if addrdesc.fault.assuredonly then '1' else '0';
        PAR_EL1().FST = AArch64_PARFaultStatus(addrdesc.fault);
        PAR_EL1().PTW = if addrdesc.fault.s2fs1walk then '1' else '0';
        PAR_EL1().S   = if addrdesc.fault.secondstage then '1' else '0';
        PAR_EL1()[11] = '1'; // RES1
        PAR_EL1()[63:48] = ImpDefBits{16}("Faulting PAR");
    end;
    return;
end;

// AArch64_PARFaultStatus()
// ========================
// Fault status field decoding of 64-bit PAR.

func AArch64_PARFaultStatus(fault : FaultRecord) => bits(6)
begin
    var fst : bits(6);

    if fault.statuscode == Fault_Domain then
        // Report Domain fault
        assert fault.level IN {1,2};
        fst[1:0] = if fault.level == 1 then '01' else '10';
        fst[5:2] = '1111';
    else
        fst = EncodeLDFSC(fault.statuscode, fault.level);
    end;
    return fst;
end;

// AArch64_isPARFormatD128()
// =========================
// Check if last stage of translation uses VMSAv9-128.
// Last stage of translation is stage 2 if enabled, else it is stage 1.

func AArch64_isPARFormatD128(regime : Regime, is_ATS1Ex : boolean) => boolean
begin
    var isPARFormatD128 : boolean;
    // Regime_EL2 does not support VMSAv9-128
    if regime == Regime_EL2 || !IsFeatureImplemented(FEAT_D128) then
        isPARFormatD128 = FALSE;
    else
        isPARFormatD128 = FALSE;
        case regime of
            when Regime_EL3 =>
                isPARFormatD128 = TCR_EL3().D128 == '1';
            when Regime_EL20 =>
                isPARFormatD128 = IsTCR2EL2Enabled() && TCR2_EL2().D128 == '1';
            when Regime_EL10 =>
                if is_ATS1Ex || !EL2Enabled() || HCR_EL2().[VM,DC] == '00' then
                    isPARFormatD128 = IsTCR2EL1Enabled() && TCR2_EL1().D128 == '1';
                else
                    isPARFormatD128 = VTCR_EL2().D128 == '1';
                end;
        end;
    end;

    return isPARFormatD128;
end;

// GetPAR_EL1_D128()
// =================
// Query the PAR_EL1.D128 field

func GetPAR_EL1_D128() => bit
begin
    return if IsFeatureImplemented(FEAT_D128) then PAR_EL1().D128 else '0';
end;

// GetPAR_EL1_F()
// ==============
// Query the PAR_EL1.F field.

func GetPAR_EL1_F() => bit
begin
    var F : bit;

    F = PAR_EL1().F;
    return F;
end;

// MemBarrierOp
// ============
// Memory barrier instruction types.

type MemBarrierOp of enumeration {
                                  MemBarrierOp_DSB,     // Data Synchronization Barrier
                                  MemBarrierOp_DMB,     // Data Memory Barrier
                                  MemBarrierOp_ISB,     // Instruction Synchronization Barrier
                                  MemBarrierOp_SSBB,    // Speculative Synchronization Barrier to VA
                                  MemBarrierOp_PSSBB,   // Speculative Synchronization Barrier to PA
                                  MemBarrierOp_SB       // Speculation Barrier
                           };

// BFXPreferred()
// ==============
//
// Return TRUE if UBFX or SBFX is the preferred disassembly of a
// UBFM or SBFM bitfield instruction. Must exclude more specific
// aliases UBFIZ, SBFIZ, UXT[BH], SXT[BHW], LSL, LSR and ASR.

func BFXPreferred(sf : bit, uns : bit, imms : bits(6), immr : bits(6)) => boolean
begin

    // must not match UBFIZ/SBFIX alias
    if UInt(imms) < UInt(immr) then
        return FALSE;
    end;

    // must not match LSR/ASR/LSL alias (imms == 31 or 63)
    if imms == sf::'11111' then
        return FALSE;
    end;

    // must not match UXTx/SXTx alias
    if immr == '000000' then
        // must not match 32-bit UXT[BH] or SXT[BH]
        if sf == '0' && imms IN {'000111', '001111'} then
            return FALSE;
        end;
        // must not match 64-bit SXT[BHW]
        if sf::uns == '10' && imms IN {'000111', '001111', '011111'} then
            return FALSE;
        end;
    end;

    // must be UBFX/SBFX alias
    return TRUE;
end;

// AltDecodeBitMasks()
// ===================
// Alternative but logically equivalent implementation of DecodeBitMasks() that
// uses simpler primitives to compute tmask and wmask.

func AltDecodeBitMasks{M}(immN : bit, imms : bits(6), immr : bits(6),
                          immediate : boolean) => (bits(M), bits(M))
begin
    var tmask, wmask : bits(64);
    var tmask_and, wmask_and : bits(6);
    var tmask_or, wmask_or : bits(6);
    var levels : bits(6);

    // Compute log2 of element size
    // 2^len must be in range [2, M]
    if immN::NOT(imms) == '000000x' then Undefined(); end;
    let len : integer{} = HighestSetBitNZ(immN::NOT(imms));
    assert 2 <= (2^len) && (2^len) <= M;

    // Determine s, r and s - r parameters
    levels = ZeroExtend{6}(Ones{len});

    // For logical immediates an all-ones value of s is reserved
    // since it would generate a useless all-ones result (many times)
    if immediate && (imms AND levels) == levels then Undefined(); end;

    let s : integer{} = UInt(imms AND levels);
    let r : integer{} = UInt(immr AND levels);
    let diff : integer{} = s - r;    // 6-bit subtract with borrow

    // Compute "top mask"
    tmask_and = diff[5:0] OR NOT(levels);
    tmask_or  = diff[5:0] AND levels;

    tmask = Ones{64};
    tmask = ((tmask
              AND Replicate{64, 2}(Replicate{1}(tmask_and[0]) :: Ones{1}))
               OR  Replicate{64, 2}(Zeros{1} :: Replicate{1}(tmask_or[0])));
    // optimization of first step:
    // tmask = Replicate{64}(tmask_and[0] :: '1');
    tmask = ((tmask
              AND Replicate{64, 4}(Replicate{2}(tmask_and[1]) :: Ones{2}))
               OR  Replicate{64, 4}(Zeros{2} :: Replicate{2}(tmask_or[1])));
    tmask = ((tmask
              AND Replicate{64, 8}(Replicate{4}(tmask_and[2]) :: Ones{4}))
               OR  Replicate{64, 8}(Zeros{4} :: Replicate{4}(tmask_or[2])));
    tmask = ((tmask
              AND Replicate{64, 16}(Replicate{8}(tmask_and[3]) :: Ones{8}))
               OR  Replicate{64, 16}(Zeros{8} :: Replicate{8}(tmask_or[3])));
    tmask = ((tmask
              AND Replicate{64, 32}(Replicate{16}(tmask_and[4]) :: Ones{16}))
               OR  Replicate{64, 32}(Zeros{16} :: Replicate{16}(tmask_or[4])));
    tmask = ((tmask
              AND Replicate{64, 64}(Replicate{32}(tmask_and[5]) :: Ones{32}))
               OR  Replicate{64, 64}(Zeros{32} :: Replicate{32}(tmask_or[5])));

    // Compute "wraparound mask"
    wmask_and = immr OR NOT(levels);
    wmask_or  = immr AND levels;

    wmask = Zeros{64};
    wmask = ((wmask
              AND Replicate{64, 2}(Ones{1} :: Replicate{1}(wmask_and[0])))
               OR  Replicate{64, 2}(Replicate{1}(wmask_or[0]) :: Zeros{1}));
    // wmask = Replicate(wmask_or[0] : '0', 32);
    wmask = ((wmask
              AND Replicate{64, 4}(Ones{2} :: Replicate{2}(wmask_and[1])))
               OR  Replicate{64, 4}(Replicate{2}(wmask_or[1]) :: Zeros{2}));
    wmask = ((wmask
              AND Replicate{64, 8}(Ones{4} :: Replicate{4}(wmask_and[2])))
               OR  Replicate{64, 8}(Replicate{4}(wmask_or[2]) :: Zeros{4}));
    wmask = ((wmask
              AND Replicate{64, 16}(Ones{8} :: Replicate{8}(wmask_and[3])))
               OR  Replicate{64, 16}(Replicate{8}(wmask_or[3]) :: Zeros{8}));
    wmask = ((wmask
              AND Replicate{64, 32}(Ones{16} :: Replicate{16}(wmask_and[4])))
               OR  Replicate{64, 32}(Replicate{16}(wmask_or[4]) :: Zeros{16}));
    wmask = ((wmask
              AND Replicate{64, 64}(Ones{32} :: Replicate{32}(wmask_and[5])))
               OR  Replicate{64, 64}(Replicate{32}(wmask_or[5]) :: Zeros{32}));

    if diff[6] != '0' then // borrow from s - r
        wmask = wmask AND tmask;
    else
        wmask = wmask OR tmask;
    end;

    return (wmask[M-1:0], tmask[M-1:0]);
end;

// DecodeBitMasks()
// ================
// Decode AArch64 bitfield and logical immediate masks which use a similar encoding structure

func DecodeBitMasks{M}(immN : bit, imms : bits(6), immr : bits(6),
                       immediate : boolean) => (bits(M), bits(M))
begin
    var levels : bits(6);

    // Compute log2 of element size
    // 2^len must be in range [2, M]
    if immN::NOT(imms) == '000000x' then Undefined(); end;
    let len : integer{} = HighestSetBitNZ(immN::NOT(imms));
    assert 2 <= (2^len) && (2^len) <= M;

    // Determine s, r and s - r parameters
    levels = ZeroExtend{6}(Ones{len});

    // For logical immediates an all-ones value of s is reserved
    // since it would generate a useless all-ones result (many times)
    if immediate && (imms AND levels) == levels then Undefined(); end;

    let s : integer{} = UInt(imms AND levels);
    let r : integer{} = UInt(immr AND levels);
    let diff : integer{}  = s - r;    // 6-bit subtract with borrow

    let esize : integer{} = 1 << len;
    let d : integer{}     = UInt(diff[len-1:0]);
    let welem : bits(esize) = ZeroExtend{}(Ones{s + 1});
    let telem : bits(esize) = ZeroExtend{}(Ones{d + 1});
    let wmask : bits(M) = Replicate{}(ROR(welem, r));
    let tmask : bits(M) = Replicate{}(telem);
    return (wmask, tmask);
end;

// AArch64_DataMemZero()
// =====================
// Write Zero to data memory.

func AArch64_DataMemZero(regval : bits(64), vaddress : bits(64),
                         accdesc_in : AccessDescriptor, size : integer)
begin
    var accdesc : AccessDescriptor = accdesc_in;

    // If the instruction targets tags as a payload, confer with system register configuration
    // which may override this.
    if accdesc.tagaccess then
        accdesc.tagaccess = IsMTEEnabled(accdesc.el);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(vaddress, accdesc);
    end;

    let aligned : boolean = TRUE;
    var memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(vaddress,
                                                                   accdesc, aligned, size);

    if IsFault(memaddrdesc) then
        if !IsDebugException(memaddrdesc.fault) then
            memaddrdesc.fault.vaddress = regval;
        end;
        AArch64_Abort(memaddrdesc.fault);
    end;

    for i = 0 to size-1 do
        if accdesc.tagchecked then
            let ltag : bits(4)      = AArch64_LogicalAddressTag(vaddress);
            var fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, 1, ltag);
            if fault.statuscode != Fault_None then
                if ImpDefBool(
                      "DC_ZVA tag fault reported with lowest faulting address") then
                    AArch64_Abort(fault);
                else
                    fault.vaddress = regval;
                    AArch64_Abort(fault);
                end;
            end;
        end;
        let memstatus : PhysMemRetStatus = PhysMemWrite{8}(memaddrdesc, accdesc, Zeros{8});
        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, 1, accdesc);
        end;

        memaddrdesc.paddress.address = memaddrdesc.paddress.address + 1;
    end;
    return;
end;

// AArch64_WriteTagMem()
// =====================
// Write to tag memory.

func AArch64_WriteTagMem(regval : bits(64), vaddress : bits(64),
                         accdesc_in : AccessDescriptor, size : integer)
begin
    assert accdesc_in.tagaccess && !accdesc_in.tagchecked;

    var accdesc : AccessDescriptor = accdesc_in;

    let count : integer   = size >> LOG2_TAG_GRANULE;
    let tag : bits(4)     = AArch64_AllocationTagFromAddress(vaddress);
    let aligned : boolean = IsAlignedSize{64}(vaddress, TAG_GRANULE);
    assert aligned;

    accdesc.tagaccess = IsMTEEnabled(accdesc.el);

    var (memtagtype, memaddrdesc) = AArch64_TranslateTagAddress(vaddress, accdesc, aligned, size);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        if IsDebugException(memaddrdesc.fault) then
            AArch64_Abort(memaddrdesc.fault);
        else
            memaddrdesc.fault.vaddress = regval;
            AArch64_Abort(memaddrdesc.fault);
        end;
    end;

    if !accdesc.tagaccess || memtagtype != MemTag_AllocationTagged then
        return;
    end;

    var memstatus : PhysMemRetStatus;

    for i = 0 to count-1 do
        memstatus = PhysMemTagWrite(memaddrdesc, accdesc, tag);
        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, 1, accdesc);
        end;

        memaddrdesc.paddress.address = memaddrdesc.paddress.address + TAG_GRANULE;
        memaddrdesc.vaddress         = memaddrdesc.vaddress + TAG_GRANULE;
    end;

    return;
end;

// CompareOp
// =========
// Vector compare instruction types.

type CompareOp of enumeration {CompareOp_GT, CompareOp_GE, CompareOp_EQ,
                               CompareOp_LE, CompareOp_LT};

// CountOp
// =======
// Bit counting instruction types.

type CountOp of enumeration {CountOp_CLZ, CountOp_CLS, CountOp_CNT};

// EffectiveCPTA()
// ===============
// Returns the CPTA bit applied to Checked Pointer Arithmetic for Addition in the given EL.

func EffectiveCPTA(el : bits(2)) => bit
begin
    if !IsFeatureImplemented(FEAT_CPA2) then
        return '0';
    end;

    if Halted() then
        return '0';
    end;

    var cpta : bits(1);
    let regime : Regime = TranslationRegime(el);

    case regime of
        when Regime_EL3 =>
            cpta = SCTLR2_EL3().CPTA;
        when Regime_EL2 =>
            if IsSCTLR2EL2Enabled() then
                cpta = SCTLR2_EL2().CPTA;
            else
                cpta = '0';
            end;
        when Regime_EL20 =>
            if IsSCTLR2EL2Enabled() then
                cpta = if el == EL0 then SCTLR2_EL2().CPTA0 else SCTLR2_EL2().CPTA;
            else
                cpta = '0';
            end;
        when Regime_EL10 =>
            if IsSCTLR2EL1Enabled() then
                cpta = if el == EL0 then SCTLR2_EL1().CPTA0 else SCTLR2_EL1().CPTA;
            else
                cpta = '0';
            end;
        otherwise =>
            unreachable;
    end;

    return cpta;
end;

// EffectiveCPTM()
// ===============
// Returns the CPTM bit applied to Checked Pointer Arithmetic for Multiplication in the given EL.

func EffectiveCPTM(el : bits(2)) => bit
begin
    if !IsFeatureImplemented(FEAT_CPA2) then
        return '0';
    end;

    if EffectiveCPTA(el) == '0' then
        return '0';
    end;

    if Halted() then
        return '0';
    end;

    var cptm : bits(1);
    let regime : Regime = TranslationRegime(el);

    case regime of
        when Regime_EL3 =>
            cptm = SCTLR2_EL3().CPTM;
        when Regime_EL2 =>
            if IsSCTLR2EL2Enabled() then
                cptm = SCTLR2_EL2().CPTM;
            else
                cptm = '0';
            end;
        when Regime_EL20 =>
            if IsSCTLR2EL2Enabled() then
                cptm = if el == EL0 then SCTLR2_EL2().CPTM0 else SCTLR2_EL2().CPTM;
            else
                cptm = '0';
            end;
        when Regime_EL10 =>
            if IsSCTLR2EL1Enabled() then
                cptm = if el == EL0 then SCTLR2_EL1().CPTM0 else SCTLR2_EL1().CPTM;
            else
                cptm = '0';
            end;
        otherwise =>
            unreachable;
    end;

    return cptm;
end;

// PointerAddCheck()
// =================
// Apply Checked Pointer Arithmetic for addition.

func PointerAddCheck(result : bits(64), base : bits(64)) => bits(64)
begin
    return PointerCheckAtEL(PSTATE.EL, result, base, FALSE);
end;

// PointerAddCheckAtEL()
// =====================
// Apply Checked Pointer Arithmetic for addition at the specified EL.

func PointerAddCheckAtEL(el : bits(2), result : bits(64), base : bits(64)) => bits(64)
begin
    return PointerCheckAtEL(el, result, base, FALSE);
end;

// PointerCheckAtEL()
// ==================
// Apply Checked Pointer Arithmetic at the specified EL.

func PointerCheckAtEL(el : bits(2), result : bits(64), base : bits(64),
                      cptm_detected : boolean) => bits(64)
begin
    var rv : bits(64)  = result;

    let previous_detection : boolean = (base[55] != base[54]);
    let cpta_detected : boolean = (result[63:56] != base[63:56] || previous_detection);

    if ((cpta_detected && EffectiveCPTA(el) == '1') ||
          (cptm_detected && EffectiveCPTM(el) == '1')) then
        rv[63:55] = base[63:55];
        rv[54] = NOT(rv[55]);
    end;

    return rv;
end;

// PointerMultiplyAddCheck()
// =========================
// Apply Checked Pointer Arithmetic for multiplication.

func PointerMultiplyAddCheck(result : bits(64), base : bits(64),
                             cptm_detected : boolean) => bits(64)
begin
    return PointerCheckAtEL(PSTATE.EL, result, base, cptm_detected);
end;

// IsD128Enabled()
// ===============
// Returns true if 128-bit page descriptor is enabled

func IsD128Enabled(el : bits(2)) => boolean
begin
    var d128enabled : boolean;
    if IsFeatureImplemented(FEAT_D128) then
        case el of
            when EL0 =>
                if !ELIsInHost(EL0) then
                    d128enabled = IsTCR2EL1Enabled() && TCR2_EL1().D128 == '1';
                else
                    d128enabled = IsTCR2EL2Enabled() && TCR2_EL2().D128 == '1';
                end;
            when EL1 =>
                d128enabled = IsTCR2EL1Enabled() && TCR2_EL1().D128 == '1';
            when EL2 =>
                d128enabled = IsTCR2EL2Enabled() && IsInHost() && TCR2_EL2().D128 == '1';
            when EL3 =>
                d128enabled = TCR_EL3().D128 == '1';
        end;
    else
        d128enabled = FALSE;
    end;

    return d128enabled;
end;

// AArch64_CanTrapDC()
// ===================
// Determines whether the execution of the DC instruction can be trapped.

func AArch64_CanTrapDC(cachetype : CacheType, cacheop : CacheOp, opscope : CacheOpScope) => boolean
begin
    return (!AArch64_TreatDCAsNOP(cachetype, cacheop, opscope) || ImpDefBool(
            "When DC is treated as NOP, data cache maintenance operations are trapped"));
end;

// AArch64_DC()
// ============
// Perform Data Cache Operation.

func AArch64_DC(regval : bits(64), cachetype : CacheType,
                cacheop : CacheOp, opscope_in : CacheOpScope)
begin
    var opscope : CacheOpScope = opscope_in;
    var cache : CacheRecord;

    cache.acctype   = AccessType_DC;
    cache.cachetype = cachetype;
    cache.cacheop   = cacheop;
    cache.opscope   = opscope;

    if opscope == CacheOpScope_SetWay then
        let ss : SecurityState = SecurityStateAtEL(PSTATE.EL);
        cache.cpas = CPASAtSecurityState(ss);
        cache.shareability = Shareability_NSH;
        cache.(setnum, waynum, level) = DecodeSW(regval, cachetype);
        if (cacheop == CacheOp_Invalidate && PSTATE.EL == EL1 && EL2Enabled() &&
          (HCR_EL2().SWIO == '1' || HCR_EL2().[DC,VM] != '00')) then
            cache.cacheop = CacheOp_CleanInvalidate;
        end;

        CACHE_OP(cache);
        return;
    end;

    if EL2Enabled() && !IsInHost() then
        if PSTATE.EL IN {EL0, EL1} then
            cache.is_vmid_valid = TRUE;
            cache.vmid          = VMID();
        else
            cache.is_vmid_valid = FALSE;
        end;
    else
        cache.is_vmid_valid = FALSE;
    end;

    if PSTATE.EL == EL0 then
        cache.is_asid_valid = TRUE;
        cache.asid          = ASID();
    else
        cache.is_asid_valid = FALSE;
    end;

    if (opscope == CacheOpScope_PoPS &&
          ImpDefBool("Memory system does not support PoPS")) then
        opscope = CacheOpScope_PoC;
    end;
    if (opscope == CacheOpScope_PoDP &&
          ImpDefBool("Memory system does not support PoDP")) then
        opscope = CacheOpScope_PoP;
    end;
    if (opscope == CacheOpScope_PoP &&
          ImpDefBool("Memory system does not support PoP")) then
        opscope = CacheOpScope_PoC;
    end;
    var vaddress : bits(64) = regval;

    var size : integer = 0;        // by default no watchpoint address
    if cacheop == CacheOp_Invalidate then
        size = DataCacheWatchpointSize();
        vaddress = AlignDownSize{64}(regval, size as AddressSize);
    end;

    if opscope == CacheOpScope_PoE then
        cache.shareability     = Shareability_OSH;
        cache.paddress.address = regval[55:0];
        let nse2 : bit = if IsFeatureImplemented(FEAT_RME_GDI) then regval[61] else '0';
        cache.paddress.paspace = DecodePASpace(nse2, regval[62], regval[63]);
        cache.cpas             = CPASAtPAS(cache.paddress.paspace);

        // If a Reserved encoding is selected, the instruction is permitted to be treated as a NOP.
        if cache.paddress.paspace != PAS_Realm then
            ExecuteAsNOP();
        end;

        if ImpDefBool("Apply granule protection check on DC to PoE") then
            var memaddrdesc : AddressDescriptor;
            let accdesc : AccessDescriptor = CreateAccDescDC(cache);
            memaddrdesc.paddress     = cache.paddress;
            memaddrdesc.fault.gpcf   = GranuleProtectionCheck(memaddrdesc, accdesc);

            if memaddrdesc.fault.gpcf.gpf != GPCF_None then
                memaddrdesc.fault.statuscode = Fault_GPCFOnOutput;
                memaddrdesc.fault.paddress   = memaddrdesc.paddress;
                memaddrdesc.fault.vaddress   = ARBITRARY : bits(64);
                AArch64_Abort(memaddrdesc.fault);
            end;
        end;
    elsif opscope == CacheOpScope_PoPA then
        cache.shareability = Shareability_OSH;
        cache.paddress.address = regval[55:0];
        let nse2 : bit = if IsFeatureImplemented(FEAT_RME_GDI) then regval[61] else '0';
        cache.paddress.paspace = DecodePASpace(nse2, regval[62], regval[63]);

        // If {NSE2, NSE, NS} is reserved, then no cache entries are required
        // to be cleaned or invalidated.
        if cache.paddress.paspace IN {PAS_NA6, PAS_NA7} then
            ExecuteAsNOP();
        end;
        cache.cpas = CPASAtPAS(cache.paddress.paspace);
    else
        cache.vaddress  = vaddress;
        let aligned : boolean = TRUE;
        let accdesc : AccessDescriptor = CreateAccDescDC(cache);
        var memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(vaddress, accdesc,
                                                                       aligned, size);
        if IsFault(memaddrdesc) then
            memaddrdesc.fault.vaddress = regval;
            AArch64_Abort(memaddrdesc.fault);
        end;

        cache.paddress   = memaddrdesc.paddress;
        cache.cpas       = CPASAtPAS(memaddrdesc.paddress.paspace);

        if (opscope IN {
                         CacheOpScope_PoDP,
                         CacheOpScope_PoP,
                         CacheOpScope_PoC,
                         CacheOpScope_PoU
                      }) then
            cache.shareability = memaddrdesc.memattrs.shareability;
        else
            cache.shareability = Shareability_NSH;
        end;
    end;

    if (cacheop == CacheOp_Invalidate && PSTATE.EL == EL1 && EL2Enabled() &&
            HCR_EL2().[DC,VM] != '00') then
        cache.cacheop = CacheOp_CleanInvalidate;
    end;

    // If Secure state is not implemented, but RME is, the instruction acts as a NOP
    if cache.cpas == CPAS_Secure && !HaveSecureState() then
        return;
    end;

    CACHE_OP(cache);
    return;
end;

// AArch64_MemZero()
// =================

func AArch64_MemZero(regval : bits(64), cachetype : CacheType)
begin
    let size : integer{} = (if cachetype IN {CacheType_TagWrite, CacheType_TagZero}
                            then 4*(2^(UInt(DCZID_EL0().TBS)))
                            else 4*(2^(UInt(DCZID_EL0().BS))));
    assert size <= MAX_ZERO_BLOCK_SIZE;
    if IsFeatureImplemented(FEAT_MTE2) then
        assert size >= TAG_GRANULE;
    end;
    let vaddress : bits(64) = AlignDownSize{}(regval, size);

    let accdesc : AccessDescriptor = CreateAccDescDCZero(cachetype);

    if cachetype IN {CacheType_TagZero} then
        AArch64_WriteTagMem(Zeros{64}, vaddress, accdesc, size);
    end;

    if cachetype IN {CacheType_Tag, CacheType_TagWrite, CacheType_Data_Tag} then
        AArch64_WriteTagMem(regval, vaddress, accdesc, size);
    end;

    if cachetype IN {CacheType_Data, CacheType_Data_Tag} then
        AArch64_DataMemZero(regval, vaddress, accdesc, size);
    end;
    return;
end;

// AArch64_TreatDCAsNOP()
// ======================
// Determines whether the execution of the DC instruction is treated as a NOP.

func AArch64_TreatDCAsNOP(cachetype : CacheType, cacheop : CacheOp,
                          opscope : CacheOpScope) => boolean
begin
    // DC to PoU: IMPLEMENTATION DEFINED - treated as NOP if LoUU and LoUIS are 0
    if opscope == CacheOpScope_PoU && CLIDR_EL1().LoUU == '000' && CLIDR_EL1().LoUIS == '000' then
        return ImpDefBool("DC to PoU is treated as a NOP");
    end;

    // DC to PoC: IMPLEMENTATION DEFINED - treated as NOP if LoC is 0
    if opscope == CacheOpScope_PoC && CLIDR_EL1().LoC == '000' then
        return ImpDefBool("DC to PoC is treated as a NOP");
    end;

    // DC to PoP: IMPLEMENTATION DEFINED - treated as NOP if LoC is 0 and PoP unsupported
    if (opscope == CacheOpScope_PoP && CLIDR_EL1().LoC == '000' &&
          !ImpDefBool("Memory system supports PoP")) then
        return ImpDefBool("DC to PoP is treated as a NOP");
    end;

    // DC to PoDP: IMPLEMENTATION DEFINED - treated as NOP if LoC is 0 and PoP/PoDP unsupported
    if (opscope == CacheOpScope_PoDP && CLIDR_EL1().LoC == '000' &&
          !ImpDefBool("Memory system supports PoP") &&
          !ImpDefBool("Memory system supports PoDP")) then
        return ImpDefBool("DC to PoDP is treated as a NOP");
    end;

    return FALSE;
end;

// MemZero block size
// ==================

constant MAX_ZERO_BLOCK_SIZE : integer = 2048;

// AArch64_ExceptionReturn()
// =========================

func AArch64_ExceptionReturn(new_pc_in : bits(64), spsr : bits(64))
begin
    var new_pc : bits(64) = new_pc_in;

    if IsFeatureImplemented(FEAT_IESB) then
        var sync_errors : boolean = SCTLR_ELx().IESB == '1';
        if IsFeatureImplemented(FEAT_DoubleFault) then
            sync_errors = sync_errors || (SCR_EL3().[EA,NMEA] == '11' && PSTATE.EL == EL3);
        end;
        if sync_errors then
            SynchronizeErrors();
            let iesb_req : boolean = TRUE;
            TakeUnmaskedPhysicalSErrorInterrupts(iesb_req);
        end;
    end;

    var brbe_source_allowed : boolean = FALSE;
    var brbe_source_address : bits(64) = Zeros{};
    if IsFeatureImplemented(FEAT_BRBE) then
        brbe_source_allowed = BranchRecordAllowed(PSTATE.EL);
        brbe_source_address = PC64();
    end;

    if !IsFeatureImplemented(FEAT_ExS) || SCTLR_ELx().EOS == '1' then
        SynchronizeContext();
    end;

    // Attempts to change to an illegal state will invoke the Illegal Execution state mechanism
    let source_el : bits(2) = PSTATE.EL;
    let illegal_psr_state : boolean = IllegalExceptionReturn{64}(spsr);
    SetPSTATEFromPSR{64}(spsr, illegal_psr_state);
    ClearExclusiveLocal(ProcessorID());
    SendEventLocal();

    if illegal_psr_state && spsr[4] == '1' then
        // If the exception return is illegal, PC[63:32,1:0] are UNKNOWN
        new_pc[63:32] = ARBITRARY : bits(32);
        new_pc[1:0] = ARBITRARY : bits(2);
    elsif UsingAArch32() then                // Return to AArch32
        // ELR_ELx[1:0] or ELR_ELx[0] are treated as being 0, depending on the
        // target instruction set state
        if PSTATE.T == '1' then
            new_pc[0] = '0';                 // T32
        else
            new_pc[1:0] = '00';              // A32
        end;
    else                                     // Return to AArch64
        // ELR_ELx[63:56] might include a tag
        new_pc = AArch64_BranchAddr(new_pc, PSTATE.EL);
    end;

    if IsFeatureImplemented(FEAT_BRBE) then
        BRBEExceptionReturn(new_pc, source_el,
                            brbe_source_allowed, brbe_source_address);
    end;

    if UsingAArch32() then
        if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then ResetSVEState(); end;

        // 32 most significant bits are ignored.
        let branch_conditional : boolean = FALSE;
        BranchTo{32}(new_pc[31:0], BranchType_ERET, branch_conditional);
    else
        BranchToAddr{64}(new_pc, BranchType_ERET);
    end;

    CheckExceptionCatch(FALSE);              // Check for debug event on exception return
end;

// AArch64_ExclusiveMonitorsPass()
// ===============================
// Return TRUE if the Exclusives monitors for the current PE include all of the addresses
// associated with the virtual address region of size bytes starting at address.
// The immediately following memory write must be to the same addresses.

// It is IMPLEMENTATION DEFINED whether the detection of memory aborts happens
// before or after the check on the local Exclusives monitor. As a result a failure
// of the local monitor can occur on some implementations even if the memory
// access would give an memory abort.

func AArch64_ExclusiveMonitorsPass(address : bits(64), size : integer{1, 2, 4, 8, 16, 32},
                                   accdesc : AccessDescriptor) => boolean
begin
    let aligned : boolean = IsAlignedSize(address, size);

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, size) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    if !AArch64_IsExclusiveVA(address, ProcessorID(), size) then
        return FALSE;
    end;

    let memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc, aligned, size);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    var passed : boolean = IsExclusiveLocal(memaddrdesc.paddress, ProcessorID(), size);
    ClearExclusiveLocal(ProcessorID());

    if passed && memaddrdesc.memattrs.shareability != Shareability_NSH then
        passed = IsExclusiveGlobal(memaddrdesc.paddress, ProcessorID(), size);
    end;

    return passed;
end;

// AArch64_IsExclusiveVA()
// =======================
// An optional IMPLEMENTATION DEFINED test for an exclusive access to a virtual
// address region of size bytes starting at address.
//
// It is permitted (but not required) for this function to return FALSE and
// cause a store exclusive to fail if the virtual address region is not
// totally included within the region recorded by MarkExclusiveVA().
//
// It is always safe to return TRUE which will check the physical address only.

impdef func AArch64_IsExclusiveVA(address : bits(64),
                                  processorid : integer,
                                  size : integer) => boolean
begin
    return TRUE;
end;

// AArch64_MarkExclusiveVA()
// =========================
// Optionally record an exclusive access to the virtual address region of size bytes
// starting at address for processorid.

func AArch64_MarkExclusiveVA(address : bits(64), processorid : integer, size : integer)
begin
    return;
end;

// AArch64_SetExclusiveMonitors()
// ==============================
// Sets the Exclusives monitors for the current PE to record the addresses associated
// with the virtual address region of size bytes starting at address.

func AArch64_SetExclusiveMonitors(address : bits(64), size : integer{1, 2, 4, 8, 16, 32},
                                  accdesc : AccessDescriptor)
begin
    let aligned : boolean = IsAlignedSize(address, size);

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, size) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    let memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc, aligned, size);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        return;
    end;

    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        MarkExclusiveGlobal(memaddrdesc.paddress, ProcessorID(), size);
    end;

    MarkExclusiveLocal(memaddrdesc.paddress, ProcessorID(), size);

    AArch64_MarkExclusiveVA(address, ProcessorID(), size);
end;

// DecodeRegExtend()
// =================
// Decode a register extension option

func DecodeRegExtend(op : bits(3)) => ExtendType
begin
    case op of
        when '000' => return ExtendType_UXTB;
        when '001' => return ExtendType_UXTH;
        when '010' => return ExtendType_UXTW;
        when '011' => return ExtendType_UXTX;
        when '100' => return ExtendType_SXTB;
        when '101' => return ExtendType_SXTH;
        when '110' => return ExtendType_SXTW;
        when '111' => return ExtendType_SXTX;
    end;
end;

// ExtendReg()
// ===========
// Perform a register extension and shift

func ExtendReg{N}(reg : integer, exttype : ExtendType, shift : integer{0..4}) => bits(N)
begin
    let val : bits(N) = X{}(reg);
    var unsigned : boolean;
    var len : ESize;

    case exttype of
        when ExtendType_SXTB => unsigned = FALSE; len = 8;
        when ExtendType_SXTH => unsigned = FALSE; len = 16;
        when ExtendType_SXTW => unsigned = FALSE; len = 32;
        when ExtendType_SXTX => unsigned = FALSE; len = 64;
        when ExtendType_UXTB => unsigned = TRUE;  len = 8;
        when ExtendType_UXTH => unsigned = TRUE;  len = 16;
        when ExtendType_UXTW => unsigned = TRUE;  len = 32;
        when ExtendType_UXTX => unsigned = TRUE;  len = 64;
    end;

    // Sign or zero extend bottom LEN bits of register and shift left by SHIFT
    let nbits : integer{} = Min(len, N) as integer{8..N};
    let extval : bits(N) = Extend{}(val[nbits-1:0], unsigned);
    return LSL(extval, shift);
end;

// ExtendType
// ==========
// AArch64 register extend and shift.

type ExtendType of enumeration {ExtendType_SXTB, ExtendType_SXTH, ExtendType_SXTW, ExtendType_SXTX,
                                ExtendType_UXTB, ExtendType_UXTH, ExtendType_UXTW, ExtendType_UXTX};

// FPConvOp
// ========
// Floating-point convert/move instruction types.

type FPConvOp of enumeration {FPConvOp_CVT_FtoI, FPConvOp_CVT_ItoF,
                              FPConvOp_MOV_FtoI, FPConvOp_MOV_ItoF,
                              FPConvOp_CVT_FtoI_JS
};

// FPMaxMinOp
// ==========
// Floating-point min/max instruction types.

type FPMaxMinOp of enumeration {FPMaxMinOp_MAX, FPMaxMinOp_MIN,
                                FPMaxMinOp_MAXNUM, FPMaxMinOp_MINNUM};

// CheckFPMREnabled()
// ==================
// Check for Undefined instruction exception on indirect FPMR accesses.

func CheckFPMREnabled()
begin
    assert IsFeatureImplemented(FEAT_FPMR);

    if PSTATE.EL == EL0 then
        if !IsInHost() then
            if SCTLR_EL1().EnFPM == '0' then Undefined(); end;
        else
            if SCTLR_EL2().EnFPM == '0' then Undefined(); end;
        end;
    end;

    if PSTATE.EL IN {EL0, EL1} && EL2Enabled() && !IsInHost() then
        if !IsHCRXEL2Enabled() || HCRX_EL2().EnFPM == '0' then Undefined(); end;
    end;

    if PSTATE.EL != EL3 && HaveEL(EL3) then
        if SCR_EL3().EnFPM == '0' then Undefined(); end;
    end;
end;

// FPScale()
// =========

func FPScale{N}(op : bits(N), scale : integer, fpcr : FPCR_Type) => bits(N)
begin
    assert N IN {16,32,64};
    var result : bits(N);
    let (fptype,sign,value) : (FPType, bit, real) = FPUnpack{N}(op, fpcr);

    if fptype == FPType_SNaN || fptype == FPType_QNaN then
        result = FPProcessNaN{N}(fptype, op, fpcr);
    elsif fptype == FPType_Zero then
        result = FPZero{N}(sign);
    elsif fptype == FPType_Infinity then
        result = FPInfinity{N}(sign);
    else
        result = FPRound{N}(value * (2.0^scale), fpcr);
        FPProcessDenorm(fptype, N, fpcr);
    end;
    return result;
end;

// FPUnaryOp
// =========
// Floating-point unary instruction types.

type FPUnaryOp of enumeration {FPUnaryOp_ABS, FPUnaryOp_MOV,
                               FPUnaryOp_NEG, FPUnaryOp_SQRT};

// FPRSqrtStepFused()
// ==================

func FPRSqrtStepFused{N}(op1_in : bits(N), op2 : bits(N), fpcr_in : FPCR_Type) => bits(N)
begin
    assert N IN {16, 32, 64};
    var fpcr : FPCR_Type = fpcr_in;
    var result : bits(N);
    var op1 : bits(N) = op1_in;
    var done : boolean;
    op1 = FPNeg{N}(op1, fpcr);
    let altfp : boolean = IsFeatureImplemented(FEAT_AFP) && fpcr.AH == '1';
    let fpexc : boolean = !altfp;                    // Generate no floating-point exceptions
    if altfp then fpcr.[FIZ,FZ] = '11'; end;         // Flush denormal input and output to zero
    if altfp then fpcr.RMode = '00'; end;            // Use RNE rounding mode

    let (type1,sign1,value1) : (FPType, bit, real) = FPUnpack{N}(op1, fpcr, fpexc);
    let (type2,sign2,value2) : (FPType, bit, real) = FPUnpack{N}(op2, fpcr, fpexc);
    (done,result) = FPProcessNaNs{N}(type1, type2, op1, op2, fpcr, fpexc);
    let rounding : FPRounding = FPRoundingMode(fpcr);

    if !done then
        let inf1 : boolean = (type1 == FPType_Infinity);
        let inf2 : boolean = (type2 == FPType_Infinity);
        let zero1 : boolean = (type1 == FPType_Zero);
        let zero2 : boolean = (type2 == FPType_Zero);

        if (inf1 && zero2) || (zero1 && inf2) then
            result = FPOnePointFive{N}('0');
        elsif inf1 || inf2 then
            result = FPInfinity{N}(sign1 XOR sign2);
        else
            // Fully fused multiply-add and halve
            let result_value : real = (3.0 + (value1 * value2)) / 2.0;
            if result_value == 0.0 then
                // Sign of exact zero result depends on rounding mode
                let sign : bit = if rounding == FPRounding_NEGINF then '1' else '0';
                result = FPZero{N}(sign);
            else
                result = FPRound{N}(result_value, fpcr, rounding, fpexc);
            end;
        end;
    end;

    return result;
end;

// FPRecipStepFused()
// ==================

func FPRecipStepFused{N}(op1_in : bits(N), op2 : bits(N), fpcr_in : FPCR_Type) => bits(N)
begin
    assert N IN {16, 32, 64};
    var fpcr : FPCR_Type = fpcr_in;
    var op1 : bits(N)    = op1_in;
    var result : bits(N);
    var done : boolean;
    op1 = FPNeg{N}(op1, fpcr);

    let altfp : boolean = IsFeatureImplemented(FEAT_AFP) && fpcr.AH == '1';
    let fpexc : boolean = !altfp;                    // Generate no floating-point exceptions
    if altfp then fpcr.[FIZ,FZ] = '11'; end;         // Flush denormal input and output to zero
    if altfp then fpcr.RMode    = '00'; end;         // Use RNE rounding mode

    let (type1,sign1,value1) : (FPType, bit, real) = FPUnpack{N}(op1, fpcr, fpexc);
    let (type2,sign2,value2) : (FPType, bit, real) = FPUnpack{N}(op2, fpcr, fpexc);
    (done,result) = FPProcessNaNs{N}(type1, type2, op1, op2, fpcr, fpexc);
    let rounding : FPRounding = FPRoundingMode(fpcr);

    if !done then
        let inf1 : boolean  = (type1 == FPType_Infinity);
        let inf2 : boolean  = (type2 == FPType_Infinity);
        let zero1 : boolean = (type1 == FPType_Zero);
        let zero2 : boolean = (type2 == FPType_Zero);

        if (inf1 && zero2) || (zero1 && inf2) then
            result = FPTwo{N}('0');
        elsif inf1 || inf2 then
            result = FPInfinity{N}(sign1 XOR sign2);
        else
            // Fully fused multiply-add
            let result_value : real = 2.0 + (value1 * value2);
            if result_value == 0.0 then
                // Sign of exact zero result depends on rounding mode
                let sign : bit = if rounding == FPRounding_NEGINF then '1' else '0';
                result = FPZero{N}(sign);
            else
                result = FPRound{N}(result_value, fpcr, rounding, fpexc);
            end;
        end;
    end;

    return result;
end;

// AddGCSExRecord()
// ================
// Generates and then writes an exception record to the
// current Guarded control stack.

func AddGCSExRecord(elr : bits(64), spsr : bits(64), lr : bits(64))
begin
    var ptr : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_STORE, privileged);

    ptr = GetCurrentGCSPointer();

    // Store the record
    Mem{64}(ptr-8, accdesc) = lr;
    Mem{64}(ptr-16, accdesc) = spsr;
    Mem{64}(ptr-24, accdesc) = elr;
    Mem{64}(ptr-32, accdesc) = Zeros{60}::'1001';

    // Decrement the pointer value
    ptr = ptr - 32;

    SetCurrentGCSPointer(ptr);
    return;
end;

// AddGCSRecord()
// ==============
// Generates and then writes a record to the current Guarded
// control stack.

func AddGCSRecord(vaddress : bits(64))
begin
    var ptr : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_STORE, privileged);

    ptr = GetCurrentGCSPointer();

    // Store the record
    Mem{64}(ptr-8, accdesc) = vaddress;

    // Decrement the pointer value
    ptr = ptr - 8;

    SetCurrentGCSPointer(ptr);
    return;
end;

// CheckGCSExRecord()
// ==================
// Validates the provided values against the top entry of the
// current Guarded control stack.

func CheckGCSExRecord(elr : bits(64), spsr : bits(64), lr : bits(64), gcsinst_type : GCSInstruction)
begin
    var ptr : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_LOAD, privileged);
    ptr = GetCurrentGCSPointer();

    // Check the lowest doubleword is correctly formatted
    let recorded_first_dword : bits(64) = Mem{64}(ptr, accdesc);
    if recorded_first_dword != Zeros{60}::'1001' then
        GCSDataCheckException(gcsinst_type);
    end;

    // Check the ELR matches the recorded value
    let recorded_elr : bits(64) = Mem{64}(ptr+8, accdesc);
    if recorded_elr != elr then
        GCSDataCheckException(gcsinst_type);
    end;

    // Check the SPSR matches the recorded value
    let recorded_spsr : bits(64) = Mem{64}(ptr+16, accdesc);
    if recorded_spsr != spsr then
        GCSDataCheckException(gcsinst_type);
    end;

    // Check the LR matches the recorded value
    let recorded_lr : bits(64) = Mem{64}(ptr+24, accdesc);
    if recorded_lr != lr then
        GCSDataCheckException(gcsinst_type);
    end;

    // Increment the pointer value
    ptr = ptr + 32;

    SetCurrentGCSPointer(ptr);
    return;
end;

// CheckGCSSTREnabled()
// ====================
// Trap GCSSTR or GCSSTTR instruction if trapping is enabled.

func CheckGCSSTREnabled()
begin
    case PSTATE.EL of
        when EL0 =>
            if GCSCRE0_EL1().STREn == '0' then
                if EL2Enabled() && HCR_EL2().TGE == '1' then
                    GCSSTRTrapException(EL2);
                else
                    GCSSTRTrapException(EL1);
                end;
            end;
        when EL1 =>
            if GCSCR_EL1().STREn == '0' then
                GCSSTRTrapException(EL1);
            elsif (EL2Enabled() && (!HaveEL(EL3) || SCR_EL3().FGTEn == '1') &&
                    HFGITR_EL2().nGCSSTR_EL1 == '0') then
                GCSSTRTrapException(EL2);
            end;
        when EL2 =>
            if GCSCR_EL2().STREn == '0' then
                GCSSTRTrapException(EL2);
            end;
        when EL3 =>
            if GCSCR_EL3().STREn == '0' then
                GCSSTRTrapException(EL3);
            end;
    end;
    return;
end;

// EXLOCKException()
// =================
// Handle an EXLOCK exception condition.

func EXLOCKException()
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_GCSFail);
    except.syndrome.iss[24] = '0';
    except.syndrome.iss[23:20] = '0001';
    except.syndrome.iss[19:0] = Zeros{20};
    AArch64_TakeException(PSTATE.EL, except, preferred_exception_return, vect_offset);
end;

// GCSDataCheckException()
// =======================
// Handle a Guarded Control Stack data check fault condition.

func GCSDataCheckException(gcsinst_type : GCSInstruction)
begin
    var target_el : bits(2);
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;
    var rn_unknown : boolean  = FALSE;
    var is_ret : boolean      = FALSE;
    var is_reta : boolean     = FALSE;

    if PSTATE.EL == EL0 then
        target_el = if (EL2Enabled() && HCR_EL2().TGE == '1') then EL2 else EL1;
    else
        target_el = PSTATE.EL;
    end;
    var except : ExceptionRecord = ExceptionSyndrome(Exception_GCSFail);
    case gcsinst_type of
        when GCSInstType_PRET =>
            except.syndrome.iss[4:0] = '00000';
            is_ret = TRUE;
        when GCSInstType_POPM =>
            except.syndrome.iss[4:0] = '00001';
        when GCSInstType_PRETAA =>
            except.syndrome.iss[4:0] = '00010';
            is_reta = TRUE;
        when GCSInstType_PRETAB =>
            except.syndrome.iss[4:0] = '00011';
            is_reta = TRUE;
        when GCSInstType_SS1 =>
            except.syndrome.iss[4:0] = '00100';
        when GCSInstType_SS2 =>
            except.syndrome.iss[4:0] = '00101';
            rn_unknown = TRUE;
        when GCSInstType_POPCX =>
            rn_unknown = TRUE;
            except.syndrome.iss[4:0] = '01000';
        when GCSInstType_POPX =>
            except.syndrome.iss[4:0] = '01001';
    end;
    if rn_unknown == TRUE then
        except.syndrome.iss[9:5] = ARBITRARY : bits(5);
    elsif is_ret == TRUE then
        except.syndrome.iss[9:5] = ThisInstr()[9:5];
    elsif is_reta == TRUE then
        except.syndrome.iss[9:5] = '11110';
    else
        except.syndrome.iss[9:5] = ThisInstr()[4:0];
    end;
    except.syndrome.iss[24:10] = Zeros{15};
    except.vaddress = ARBITRARY : bits(64);
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// GCSEnabled()
// ============
// Returns TRUE if the Guarded control stack is enabled at
// the provided Exception level.

func GCSEnabled(el : bits(2)) => boolean
begin
    if UsingAArch32() then
        return FALSE;
    end;

    if HaveEL(EL3) && el != EL3 && SCR_EL3().GCSEn == '0' then
        return FALSE;
    end;

    if (el IN {EL0, EL1} && EL2Enabled() && !ELIsInHost(EL0) &&
        (!IsHCRXEL2Enabled() || HCRX_EL2().GCSEn == '0')) then
        return FALSE;
    end;

    return GCSPCRSelected(el);
end;

// GCSInstruction
// ==============

type GCSInstruction of enumeration {
    GCSInstType_PRET,    // Procedure return without Pointer authentication
    GCSInstType_POPM,    // GCSPOPM instruction
    GCSInstType_PRETAA,  // Procedure return with Pointer authentication that used key A
    GCSInstType_PRETAB,  // Procedure return with Pointer authentication that used key B
    GCSInstType_SS1,     // GCSSS1 instruction
    GCSInstType_SS2,     // GCSSS2 instruction
    GCSInstType_POPCX,   // GCSPOPCX instruction
    GCSInstType_POPX     // GCSPOPX instruction
};

// GCSPCREnabled()
// ===============
// Returns TRUE if the Guarded control stack is PCR enabled
// at the provided Exception level.

func GCSPCREnabled(el : bits(2)) => boolean
begin
    return GCSPCRSelected(el) && GCSEnabled(el);
end;

// GCSPCRSelected()
// ================
// Returns TRUE if the Guarded control stack is PCR selected
// at the provided Exception level.

func GCSPCRSelected(el : bits(2)) => boolean
begin
    case el of
        when EL0 => return GCSCRE0_EL1().PCRSEL == '1';
        when EL1 => return GCSCR_EL1().PCRSEL == '1';
        when EL2 => return GCSCR_EL2().PCRSEL == '1';
        when EL3 => return GCSCR_EL3().PCRSEL == '1';
    end;
    unreachable;
    return TRUE;
end;

// GCSPOPCX()
// ==========
// Called to pop and compare a Guarded control stack exception return record.

func GCSPOPCX()
begin
    let spsr : bits(64) = SPSR_ELx();
    CheckGCSExRecord(ELR_ELx(), spsr, X{64}(30), GCSInstType_POPCX);
    PSTATE.EXLOCK = if GetCurrentEXLOCKEN() then '1' else '0';
    return;
end;

// GCSPOPM()
// =========
// Called to pop a Guarded control stack procedure return record.

func GCSPOPM() => bits(64)
begin
    var ptr : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_LOAD, privileged);

    ptr = GetCurrentGCSPointer();
    let gcs_entry : bits(64) = Mem{64}(ptr, accdesc);

    if gcs_entry[1:0] != '00' then
        GCSDataCheckException(GCSInstType_POPM);
    end;

    ptr = ptr + 8;
    SetCurrentGCSPointer(ptr);
    return gcs_entry;
end;

// GCSPOPX()
// =========
// Called to pop a Guarded control stack exception return record.

func GCSPOPX()
begin
    var ptr : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_LOAD, privileged);
    ptr = GetCurrentGCSPointer();

    // Check the lowest doubleword is correctly formatted
    let recorded_first_dword : bits(64) = Mem{64}(ptr, accdesc);
    if recorded_first_dword != Zeros{60}::'1001' then
        GCSDataCheckException(GCSInstType_POPX);
    end;

    // Ignore these loaded values, however they might have
    // faulted which is why we load them anyway
    let recorded_elr : bits(64) = Mem{64}(ptr+8, accdesc);
    let recorded_spsr : bits(64) = Mem{64}(ptr+16, accdesc);
    let recorded_lr : bits(64) = Mem{64}(ptr+24, accdesc);

    // Increment the pointer value
    ptr = ptr + 32;

    SetCurrentGCSPointer(ptr);
    return;
end;

// GCSPUSHM()
// ==========
// Called to push a Guarded control stack procedure return record.

func GCSPUSHM(value : bits(64))
begin
    AddGCSRecord(value);
    return;
end;

// GCSPUSHX()
// ==========
// Called to push a Guarded control stack exception return record.

func GCSPUSHX()
begin
    let spsr : bits(64) = SPSR_ELx();
    AddGCSExRecord(ELR_ELx(), spsr, X{64}(30));
    PSTATE.EXLOCK = '0';
    return;
end;

// GCSReturnValueCheckEnabled()
// ============================
// Returns TRUE if the Guarded control stack has return value
// checking enabled at the current Exception level.

func GCSReturnValueCheckEnabled(el : bits(2)) => boolean
begin
    if UsingAArch32() then
        return FALSE;
    end;
    case el of
        when EL0 => return GCSCRE0_EL1().RVCHKEN == '1';
        when EL1 => return GCSCR_EL1().RVCHKEN == '1';
        when EL2 => return GCSCR_EL2().RVCHKEN == '1';
        when EL3 => return GCSCR_EL3().RVCHKEN == '1';
    end;
end;

// GCSSS1()
// ========
// Operational pseudocode for GCSSS1 instruction.

func GCSSS1(incoming_pointer : bits(64))
begin
    var outgoing_pointer, cmpoperand, operand, data : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCSSS1(privileged);
    outgoing_pointer = GetCurrentGCSPointer();
    // Valid cap entry is expected
    cmpoperand = incoming_pointer[63:12]::'000000000001';
    // In-progress cap entry should be stored if the comparison is successful
    operand = outgoing_pointer[63:3]::'101';

    data = MemAtomic{64}(incoming_pointer, cmpoperand, operand, accdesc);
    if data == cmpoperand then
        SetCurrentGCSPointer(incoming_pointer[63:3]::'000');
    else
        GCSDataCheckException(GCSInstType_SS1);
    end;
    return;
end;

// GCSSS2()
// ========
// Operational pseudocode for GCSSS2 instruction.

func GCSSS2() => bits(64)
begin
    var outgoing_pointer, incoming_pointer, outgoing_value : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc_ld : AccessDescriptor = CreateAccDescGCS(MemOp_LOAD, privileged);
    let accdesc_st : AccessDescriptor = CreateAccDescGCS(MemOp_STORE, privileged);
    incoming_pointer = GetCurrentGCSPointer();
    outgoing_value = Mem{64}(incoming_pointer, accdesc_ld);

    if outgoing_value[2:0] == '101' then  //in_progress token
        outgoing_pointer[63:3] = (outgoing_value[63:3]) - 1;
        outgoing_pointer[2:0] = '000';
        outgoing_value = outgoing_pointer[63:12]::'000000000001';
        Mem{64}(outgoing_pointer, accdesc_st) = outgoing_value;
        SetCurrentGCSPointer(incoming_pointer + 8);
        GCSSynchronizationBarrier();
    else
        GCSDataCheckException(GCSInstType_SS2);
    end;
    return outgoing_pointer;
end;

// GCSSTRTrapException()
// =====================
// Handle a trap on GCSSTR instruction condition.

func GCSSTRTrapException(target_el : bits(2))
begin
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer = 0x0;

    var except : ExceptionRecord = ExceptionSyndrome(Exception_GCSFail);
    except.syndrome.iss[24]      = '0';
    except.syndrome.iss[23:20]   = '0010';
    except.syndrome.iss[19:15]   = '00000';
    except.syndrome.iss[14:10]   = ThisInstr()[9:5];
    except.syndrome.iss[9:5]     = ThisInstr()[4:0];
    except.syndrome.iss[4:0]     = '00000';
    AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
end;

// GCSSynchronizationBarrier()
// ===========================
// Barrier instruction that synchronizes Guarded Control Stack
// accesses in relation to other load and store accesses

impdef func GCSSynchronizationBarrier()
begin
    return;
end;

// GetCurrentEXLOCKEN()
// ====================

func GetCurrentEXLOCKEN() => boolean
begin
    if Halted() || Restarting() then
        return FALSE;
    end;

    case PSTATE.EL of
        when EL0 =>
            unreachable;
        when EL1 =>
            return GCSCR_EL1().EXLOCKEN == '1';
        when EL2 =>
            return GCSCR_EL2().EXLOCKEN == '1';
        when EL3 =>
            return GCSCR_EL3().EXLOCKEN == '1';
    end;
end;

// GetCurrentGCSPointer()
// ======================
// Returns the value of the current Guarded control stack
// pointer register.

func GetCurrentGCSPointer() => bits(64)
begin
    var ptr : bits(64);

    case PSTATE.EL of
        when EL0 =>
            ptr = GCSPR_EL0().PTR::'000';
        when EL1 =>
            ptr = GCSPR_EL1().PTR::'000';
        when EL2 =>
            ptr = GCSPR_EL2().PTR::'000';
        when EL3 =>
            ptr = GCSPR_EL3().PTR::'000';
    end;
    return ptr;
end;

// LoadCheckGCSRecord()
// ====================
// Validates the provided address against the top entry of the
// current Guarded control stack.

func LoadCheckGCSRecord(vaddress : bits(64), gcsinst_type : GCSInstruction) => bits(64)
begin
    var ptr : bits(64);
    var recorded_va : bits(64);
    let privileged : boolean = PSTATE.EL != EL0;
    let accdesc : AccessDescriptor = CreateAccDescGCS(MemOp_LOAD, privileged);

    ptr = GetCurrentGCSPointer();
    recorded_va = Mem{64}(ptr, accdesc);
    if GCSReturnValueCheckEnabled(PSTATE.EL) && (recorded_va != vaddress) then
        GCSDataCheckException(gcsinst_type);
    end;

    return recorded_va;
end;

// SetCurrentGCSPointer()
// ======================
// Writes a value to the current Guarded control stack pointer register.

func SetCurrentGCSPointer(ptr : bits(64))
begin
    case PSTATE.EL of
        when EL0 =>
            GCSPR_EL0().PTR = ptr[63:3];
        when EL1 =>
            GCSPR_EL1().PTR = ptr[63:3];
        when EL2 =>
            GCSPR_EL2().PTR = ptr[63:3];
        when EL3 =>
            GCSPR_EL3().PTR = ptr[63:3];
    end;
    return;
end;

constant HACDBS_ERR_REASON_STRUCTF : bits(2) = '01';

constant HACDBS_ERR_REASON_IPAF : bits(2)    = '10';

constant HACDBS_ERR_REASON_IPHACF : bits(2)  = '11';

// IsHACDBSIRQAsserted()
// =====================
// Returns TRUE if HACDBSIRQ is asserted, and FALSE otherwise.

impdef func IsHACDBSIRQAsserted() => boolean
begin
    return FALSE;
end;

// ProcessHACDBSEntry()
// ====================
// Process a single entry entry from the HACDBS.

func ProcessHACDBSEntry()
begin
    if !IsFeatureImplemented(FEAT_HACDBS) then return; end;

    if (HaveEL(EL3) && SCR_EL3().HACDBSEn == '0') || HACDBSBR_EL2().EN == '0' then
        SetInterruptRequestLevel(InterruptID_HACDBSIRQ, LOW);
        return;
    end;

    if HCR_EL2().VM == '0' then return; end;

    if (UInt(HACDBSCONS_EL2().INDEX) >= (2 ^ (UInt(HACDBSBR_EL2().SZ) + 12)) DIVRM 8 ||
          HACDBSCONS_EL2().ERR_REASON != '00') then
        SetInterruptRequestLevel(InterruptID_HACDBSIRQ, HIGH);
        return;
    elsif IsHACDBSIRQAsserted() then
        SetInterruptRequestLevel(InterruptID_HACDBSIRQ, LOW);
    end;

    let hacdbs_size : integer{} = UInt(HACDBSBR_EL2().SZ);
    var baddr : bits(56) = HACDBSBR_EL2().BADDR[43 : 0] :: Zeros{12};
    baddr[11 + hacdbs_size : 12] = Zeros{hacdbs_size};

    var accdesc : AccessDescriptor = CreateAccDescHACDBS();

    var addrdesc : AddressDescriptor;
    addrdesc.paddress.address = baddr + (8 * UInt(HACDBSCONS_EL2().INDEX));
    let nse2 : bit = '0';     // NSE2 has the Effective value of 0 within a PE.
    addrdesc.paddress.paspace = DecodePASpace(nse2, EffectiveSCR_EL3_NSE(), EffectiveSCR_EL3_NS());

    // Accesses to the HACDBS use the same memory attributes as used for stage 2 translation walks.
    addrdesc.memattrs = WalkMemAttrs(VTCR_EL2().SH0, VTCR_EL2().IRGN0, VTCR_EL2().ORGN0);
    let emec : bit = (if IsFeatureImplemented(FEAT_MEC) &&
                         IsSCTLR2EL2Enabled() then SCTLR2_EL2().EMEC else '0');
    addrdesc.mecid = AArch64_S2TTWalkMECID(emec, accdesc.ss);

    var fault : FaultRecord = NoFault(accdesc);

    if IsFeatureImplemented(FEAT_RME) then
        fault.gpcf = GranuleProtectionCheck(addrdesc, accdesc);

        if fault.gpcf.gpf != GPCF_None then
            HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_STRUCTF;
            return;
        end;
    end;

    var memstatus : PhysMemRetStatus;
    var hacdbs_entry : bits(64);
    (memstatus, hacdbs_entry) = PhysMemRead{64}(addrdesc, accdesc);

    if IsFault(memstatus) then
        HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_STRUCTF;
        return;
    end;

    if BigEndian(accdesc.acctype) then
        hacdbs_entry = BigEndianReverse{64}(hacdbs_entry);
    end;

    // If the Valid field is clear, do not perform any cleaning operation
    // and increment HACDBSCONS_EL2.INDEX.
    if hacdbs_entry[0] == '0' then
        HACDBSCONS_EL2().INDEX = HACDBSCONS_EL2().INDEX + 1;
        return;
    end;

    accdesc = CreateAccDescTTEUpdate(accdesc);
    var ipa : AddressDescriptor;
    ipa.paddress.address = hacdbs_entry[55:12] :: Zeros{12};

    let nsipa : bit       = hacdbs_entry[11];
    let paspace : PASpace = DecodePASpace(nse2, EffectiveSCR_EL3_NSE(), EffectiveSCR_EL3_NS());
    ipa.paddress.paspace = (if accdesc.ss == SS_Secure && nsipa == '1' then PAS_NonSecure
                                                                       else paspace);

    let s1aarch64 : boolean = TRUE;
    let walkparams : S2TTWParams = AArch64_GetS2TTWParams(accdesc.ss, ipa.paddress.paspace,
                                                             s1aarch64);

    var descpaddr : AddressDescriptor;
    var walkstate : TTWState;
    var descriptor : bits(128);
    if walkparams.d128 == '1' then
        (fault, descpaddr, walkstate, descriptor) = AArch64_S2Walk{128}(fault, ipa, walkparams,
                                                                        accdesc);
    else
        (fault, descpaddr, walkstate, descriptor[63:0]) = AArch64_S2Walk{64}(fault, ipa, walkparams,
                                                                             accdesc);
    end;

    // If the Access flag on the Block or Page descriptor is set to 0, this does not generate
    // an Access flag fault and the PE can still perform the cleaning operation on that descriptor.
    if fault.statuscode == Fault_AccessFlag then
        fault.statuscode = Fault_None;
    elsif fault.statuscode != Fault_None then
        HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_IPAF;
        return;
    end;

    let hacdbs_level : integer = SInt(hacdbs_entry[3:1]);
    if walkstate.level != hacdbs_level || walkstate.contiguous == '1' then
        HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_IPHACF;
        return;
    end;

    // For the purpose of cleaning HACDBS entries, it is not required that HW update of dirty bit
    // is enabled for a descriptor to be qualified as writeable-clean or writeable-dirty.

    // Check if the descriptor is neither writeable-clean nor writeable-dirty.
    if walkparams.s2pie == '1' then
        let perms : S2AccessControls = AArch64_S2ComputePermissions(walkstate.permissions,
                                                                       walkparams, accdesc);
        if perms.w == '0' && perms.w_mmu == '0' then
            HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_IPHACF;
            return;
        end;

    // If DBM is 0, the descriptor is not writeable-clean or writeable-dirty.
    elsif descriptor[51] == '0' then
        HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_IPHACF;
        return;
    end;

    // If the descriptor is writeable-clean, do not perform any cleaning
    // operation and increment HACDBSCONS_EL2.INDEX.
    if descriptor[7] == '0' then
        HACDBSCONS_EL2().INDEX = HACDBSCONS_EL2().INDEX + 1;
        return;
    end;

    var new_descriptor : bits(128) = descriptor;
    new_descriptor[7] = '0';

    let descaccess : AccessDescriptor = CreateAccDescTTEUpdate(accdesc);
    if walkparams.d128 == '1' then
        (fault, -) = AArch64_MemSwapTableDesc{128}(fault, descriptor, new_descriptor, walkparams.ee,
                                                   descaccess, descpaddr);
    else
        (fault, -) = AArch64_MemSwapTableDesc{64}(fault, descriptor[63:0], new_descriptor[63:0],
                                                  walkparams.ee, descaccess, descpaddr);
    end;

    if fault.statuscode != Fault_None then
        HACDBSCONS_EL2().ERR_REASON = HACDBS_ERR_REASON_IPAF;
    else
        HACDBSCONS_EL2().INDEX = HACDBSCONS_EL2().INDEX + 1;
    end;

    return;
end;

// AArch64_CanTrapIC()
// ===================
// Determines whether the execution of the IC instruction can be trapped.

func AArch64_CanTrapIC(cachetype : CacheType, cacheop : CacheOp, opscope : CacheOpScope) => boolean
begin
    return (!AArch64_TreatICAsNOP(cachetype, cacheop, opscope) || ImpDefBool(
            "When IC is treated as NOP, data cache maintenance operations are trapped"));
end;

// AArch64_IC()
// ============
// Perform Instruction Cache Operation.

func AArch64_IC(opscope : CacheOpScope)
begin
    let regval : bits(64) = ARBITRARY : bits(64);
    AArch64_IC(regval, opscope);
end;

// AArch64_IC()
// ============
// Perform Instruction Cache Operation.

func AArch64_IC(regval : bits(64), opscope : CacheOpScope)
begin
    var cache : CacheRecord;

    cache.acctype   = AccessType_IC;
    cache.cachetype = CacheType_Instruction;
    cache.cacheop   = CacheOp_Invalidate;
    cache.opscope   = opscope;

    if opscope IN {CacheOpScope_ALLU,
                   CacheOpScope_ALLUIS_CnP,
                   CacheOpScope_ALLUIS} then
        let ss : SecurityState = SecurityStateAtEL(PSTATE.EL);
        cache.cpas = CPASAtSecurityState(ss);

        case opscope of
            when CacheOpScope_ALLU =>
                cache.shareability = Shareability_NSH;
            when CacheOpScope_ALLUIS =>
                cache.shareability = Shareability_ISH;
                // When executed at EL1, if the Effective value of HCRX_EL2.VTLBIDEn is '1',
                // then the operation is broadcast to the set of PEs selected by VTLBID0_EL2.TD0.
                // Otherwise, the operation is broadcast to all PEs in the Shareability domain.
                cache.domains = TLBIDomains(Broadcast_ISH, Zeros{16});
            when CacheOpScope_ALLUIS_CnP =>
                cache.shareability = Shareability_ISH;
                cache.domains = DEFAULT_TLBI_DOMAIN;
            otherwise =>
                unreachable;
        end;

        cache.regval = regval;
        CACHE_OP(cache);
    else
        assert opscope == CacheOpScope_PoU;

        if EL2Enabled() && !IsInHost() then
            if PSTATE.EL IN {EL0, EL1} then
                cache.is_vmid_valid = TRUE;
                cache.vmid          = VMID();
            else
                cache.is_vmid_valid = FALSE;
            end;
        else
            cache.is_vmid_valid = FALSE;
        end;

        if PSTATE.EL == EL0 then
            cache.is_asid_valid = TRUE;
            cache.asid          = ASID();
        else
            cache.is_asid_valid = FALSE;
        end;

        let vaddress : bits(64) = regval;
        cache.vaddress     = regval;

        let accdesc : AccessDescriptor = CreateAccDescIC(cache);
        let aligned : boolean = TRUE;
        let size : integer = 0;
        var memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(vaddress, accdesc,
                                                                       aligned, size);

        if IsFault(memaddrdesc) then
            memaddrdesc.fault.vaddress = regval;
            AArch64_Abort(memaddrdesc.fault);
        end;

        cache.cpas         = CPASAtPAS(memaddrdesc.paddress.paspace);
        cache.paddress     = memaddrdesc.paddress;
        cache.shareability = memaddrdesc.memattrs.shareability;
        if memaddrdesc.memattrs.shareability == Shareability_OSH then
            cache.shareability = Shareability_ISH;
        end;
        CACHE_OP(cache);
    end;
    return;
end;

// AArch64_TreatICAsNOP()
// ======================
// Determines whether the execution of the IC instruction is treated as a NOP.

func AArch64_TreatICAsNOP(cachetype : CacheType, cacheop : CacheOp,
                          opscope : CacheOpScope) => boolean
begin
    if CTR_EL0().DIC == '1' then
        return ImpDefBool("IC is treated as NOP");
    end;

    return FALSE;
end;

// ImmediateOp
// ===========
// Vector logical immediate instruction types.

type ImmediateOp of enumeration {ImmediateOp_MOVI, ImmediateOp_MVNI,
                                 ImmediateOp_ORR, ImmediateOp_BIC};

// LogicalOp
// =========
// Logical instruction types.

type LogicalOp of enumeration {LogicalOp_AND, LogicalOp_EOR, LogicalOp_ORR};

// AArch64_S1AMECFault()
// =====================
// Returns TRUE if a Translation fault should occur for Realm EL2 and Realm EL2&0
// stage 1 translated addresses to Realm PA space.

func AArch64_S1AMECFault{N}(walkparams : S1TTWParams, paspace : PASpace, regime : Regime,
                            descriptor : bits(N)) => boolean
begin
    assert N IN {64,128};
    let descriptor_amec : bit = (if walkparams.d128 == '1' then descriptor[108]
                                    else descriptor[63]);

    return (walkparams.[emec,amec] == '10' &&
            regime IN {Regime_EL2, Regime_EL20} &&
            paspace == PAS_Realm &&
            descriptor_amec == '1');
end;

// AArch64_S1DisabledOutputMECID()
// ===============================
// Returns the output MECID when stage 1 address translation is disabled.

func AArch64_S1DisabledOutputMECID(walkparams : S1TTWParams, regime : Regime,
                                   paspace : PASpace) => bits(16)
begin
    if walkparams.emec == '0' then
        return DEFAULT_MECID;
    end;

    if ! regime IN {Regime_EL2, Regime_EL20, Regime_EL10} then
        return DEFAULT_MECID;
    end;

    if paspace != PAS_Realm then
        return DEFAULT_MECID;
    end;

    if regime == Regime_EL10 then
        return VMECID_P_EL2().MECID;
    else
        return MECID_P0_EL2().MECID;
    end;
end;

// AArch64_S1OutputMECID()
// =======================
// Returns the output MECID when stage 1 address translation is enabled.

func AArch64_S1OutputMECID{N}(walkparams : S1TTWParams, regime : Regime, varange : VARange,
                              paspace : PASpace, descriptor : bits(N)) => bits(16)
begin
    assert N IN {64,128};

    if walkparams.emec == '0' then
        return DEFAULT_MECID;
    end;

    if paspace != PAS_Realm then
        return DEFAULT_MECID;
    end;

    let descriptor_amec : bit = (if walkparams.d128 == '1' then descriptor[108]
                                    else descriptor[63]);
    case regime of
        when Regime_EL3 =>
            return MECID_RL_A_EL3().MECID;
        when Regime_EL2 =>
            if descriptor_amec == '0' then
                return MECID_P0_EL2().MECID;
            else
                return MECID_A0_EL2().MECID;
            end;
        when Regime_EL20 =>
            if varange == VARange_LOWER then
                if descriptor_amec == '0' then
                    return MECID_P0_EL2().MECID;
                else
                    return MECID_A0_EL2().MECID;
                end;
            else
                if descriptor_amec == '0' then
                    return MECID_P1_EL2().MECID;
                else
                    return MECID_A1_EL2().MECID;
                end;
            end;
        // Stage 2 translation might later override the MECID according to AMEC configuration.
        when Regime_EL10 =>
            return VMECID_P_EL2().MECID;
    end;
end;

// AArch64_S1TTWalkMECID()
// =======================
// Returns the associated MECID for the stage 1 translation table walk of the given
// translation regime and Security state.

func AArch64_S1TTWalkMECID(emec : bit, regime : Regime, ss : SecurityState) => bits(16)
begin
    if emec == '0' then
        return DEFAULT_MECID;
    end;

    if ss != SS_Realm then
        return DEFAULT_MECID;
    end;

    case regime of
        when Regime_EL2 =>
            return MECID_P0_EL2().MECID;
        when Regime_EL20 =>
            if TCR_EL2().A1 == '0' then
                return MECID_P1_EL2().MECID;
            else
                return MECID_P0_EL2().MECID;
            end;
        // Stage 2 translation for a stage 1 walk might later override the
        // MECID according to AMEC configuration.
        when Regime_EL10 =>
            return VMECID_P_EL2().MECID;
        otherwise =>
            unreachable;
    end;
end;

// AArch64_S2OutputMECID()
// =======================
// Returns the output MECID for stage 2 address translation.

func AArch64_S2OutputMECID{N}(walkparams : S2TTWParams, paspace : PASpace,
                              descriptor : bits(N)) => bits(16)
begin
    assert N IN {64,128};

    if walkparams.emec == '0' then
        return DEFAULT_MECID;
    end;

    if paspace != PAS_Realm then
        return DEFAULT_MECID;
    end;

    let descriptor_amec : bit = (if walkparams.d128 == '1' then descriptor[108]
                                    else descriptor[63]);
    if descriptor_amec == '0' then
        return VMECID_P_EL2().MECID;
    else
        return VMECID_A_EL2().MECID;
    end;
end;

// AArch64_S2TTWalkMECID()
// =======================
// Returns the associated MECID for the stage 2 translation table walk of the
// given Security state.

func AArch64_S2TTWalkMECID(emec : bit, ss : SecurityState) => bits(16)
begin
    if emec == '0' then
        return DEFAULT_MECID;
    end;

    if ss != SS_Realm then
        return DEFAULT_MECID;
    end;

    //Stage 2 translation might later override the MECID according to AMEC configuration
    return VMECID_P_EL2().MECID;
end;

// AArch64_AccessIsTagChecked()
// ============================
// TRUE if a given access is tag-checked, FALSE otherwise.

func AArch64_AccessIsTagChecked(vaddr : bits(64), accdesc : AccessDescriptor) => boolean
begin
    assert accdesc.tagchecked;

    if UsingAArch32() then
        return FALSE;
    end;

    if !IsMTEEnabled(accdesc.el) then
        return FALSE;
    end;

    if PSTATE.TCO == '1' then
        return FALSE;
    end;

    if (Halted() && EDSCR().MA == '1' &&
          ConstrainUnpredictableBool(Unpredictable_NODTRTAGCHK)) then
        return FALSE;
    end;

    if (IsFeatureImplemented(FEAT_MTE_STORE_ONLY) && !accdesc.write &&
          StoreOnlyTagCheckingEnabled(accdesc.el)) then
        return FALSE;
    end;

    let is_instr : boolean = FALSE;
    if (EffectiveMTX(vaddr, is_instr, PSTATE.EL) == '0' &&
          EffectiveTBI(vaddr, is_instr, PSTATE.EL) == '0') then
        return FALSE;
    end;

    if (EffectiveTCMA(vaddr, PSTATE.EL) == '1' &&
          (vaddr[59:55] == '00000' || vaddr[59:55] == '11111')) then
        return FALSE;
    end;

    return TRUE;
end;

// AArch64_AddressWithAllocationTag()
// ==================================
// Generate a 64-bit value containing a Logical Address Tag from a 64-bit
// virtual address and an Allocation Tag.

func AArch64_AddressWithAllocationTag(address : bits(64), allocation_tag : bits(4)) => bits(64)
begin
    return address[63:60]::allocation_tag::address[55:0];
end;

// AArch64_AllocationTagCheck()
// ============================
// Performs an Allocation Tag Check operation for a memory access and
// returns whether the check passed.

func AArch64_AllocationTagCheck(memaddrdesc : AddressDescriptor, accdesc : AccessDescriptor,
                                ltag : bits(4)) => FaultRecord
begin
    var fault : FaultRecord = NoFault(accdesc, memaddrdesc.vaddress);
    if memaddrdesc.memattrs.tags == MemTag_AllocationTagged then
        var memstatus : PhysMemRetStatus;
        var readtag : bits(4);

        // Physical tagging needs no further translation, use the data PA to read the tag
        (memstatus, readtag) = PhysMemTagRead(memaddrdesc, accdesc);
        if IsFault(memstatus) then
            let iswrite : boolean = FALSE;
            return ExternalFault(memstatus, iswrite, memaddrdesc, 1, accdesc);
        end;

        if ltag != readtag then
            fault.statuscode = Fault_TagCheck;
        end;
    end;

    return fault;
end;

// AArch64_AllocationTagFromAddress()
// ==================================
// Generate an Allocation Tag from a 64-bit value containing a Logical Address Tag.

func AArch64_AllocationTagFromAddress(tagged_address : bits(64)) => bits(4)
begin
    return tagged_address[59:56];
end;

// AArch64_CanonicalTagCheck()
// ===========================
// Performs a Canonical Tag Check operation for a memory access and
// returns whether the check passed.

func AArch64_CanonicalTagCheck(memaddrdesc : AddressDescriptor, ltag : bits(4)) => boolean
begin
    let expected_tag : bits(4) = if memaddrdesc.vaddress[55] == '0' then '0000' else '1111';
    return ltag == expected_tag;
end;

// AArch64_CheckTag()
// ==================
// Performs a Tag Check operation for a memory access and returns a FaultRecord indicating if
// the check passed. If Tag Check Faults are asynchronously accumulated, a Tag Check Fault
// exception is recorded in TFSR_ELx.

func AArch64_CheckTag(memaddrdesc_in : AddressDescriptor, accdesc : AccessDescriptor,
                      size : integer, ltag : bits(4)) => FaultRecord
begin
    var memaddrdesc : AddressDescriptor = memaddrdesc_in;
    // NoFault() will set fault.write to FALSE to accesses that perform both a read and a write.
    var fault : FaultRecord             = NoFault(accdesc, memaddrdesc.vaddress);
    let granules : integer              = Max(size DIVRM TAG_GRANULE, 1);
    let forcesync : boolean             = accdesc.nonfault || (accdesc.firstfault &&
                                                              !accdesc.first);
    let tcf : TCFType                   = AArch64_EffectiveTCF(accdesc.el, accdesc.read);

    for i = 0 to granules - 1 do
        case memaddrdesc.memattrs.tags of
            when MemTag_AllocationTagged =>
                fault = AArch64_AllocationTagCheck(memaddrdesc, accdesc, ltag);
                if fault.statuscode == Fault_TagCheck then
                    if tcf == TCFType_Sync || forcesync then
                        fault.statuscode = Fault_TagCheck;
                        return fault;
                    elsif tcf == TCFType_Async then
                        AArch64_ReportTagCheckFault(accdesc.el, memaddrdesc.vaddress[55]);
                        fault.statuscode = Fault_None;
                        return fault;
                    else
                        // Tag Check Faults have no effect on the PE.
                        fault.statuscode = Fault_None;
                    end;
                elsif fault.statuscode != Fault_None then
                    return fault;
                end;
            when MemTag_CanonicallyTagged =>
                if !AArch64_CanonicalTagCheck(memaddrdesc, ltag) then
                    if tcf == TCFType_Sync || forcesync then
                        fault.statuscode = Fault_TagCheck;
                        return fault;
                    elsif tcf == TCFType_Async then
                        AArch64_ReportTagCheckFault(accdesc.el, memaddrdesc.vaddress[55]);
                        return fault;
                    else
                        // Tag Check Faults have no effect on the PE.
                        pass;
                    end;
                end;
            when MemTag_Untagged =>
                pass;
            otherwise =>
                unreachable;
        end;

        memaddrdesc.paddress.address = memaddrdesc.paddress.address + TAG_GRANULE;
        memaddrdesc.vaddress         = memaddrdesc.vaddress + TAG_GRANULE;
    end;

    return fault;
end;

// AArch64_IsUnprivAccessPriv()
// ============================
// Returns TRUE if an unprivileged access is privileged, and FALSE otherwise.

func AArch64_IsUnprivAccessPriv() => boolean
begin
    var privileged : boolean;

    case PSTATE.EL of
        when EL0 =>
            privileged = FALSE;
        when EL1 => privileged = EffectiveHCR_EL2_NVx()[1:0] == '11';
        when EL2 => privileged = !ELIsInHost(EL0);
        when EL3 =>
            privileged = TRUE;
    end;

    if IsFeatureImplemented(FEAT_UAO) && PSTATE.UAO == '1' then
        privileged = PSTATE.EL != EL0;
    end;

    return privileged;
end;

// AArch64_LogicalAddressTag()
// ===========================
// Extract the Logical Address Tag from an address

func AArch64_LogicalAddressTag(vaddr : bits(64)) => bits(4)
begin
    return vaddr[59:56];
end;

// AArch64_MemSingle - accessor
// ============================

accessor AArch64_MemSingle{size : integer{8, 16, 32, 64, 128, 256}}(address : bits(64),
                                                                    accdesc : AccessDescriptor,
                                                                    aligned : boolean
                                                                    ) <=> value : bits(size)
begin
    // Perform an atomic, little-endian read of 'size' bits.
    getter
        let bytes : integer{} = size DIV 8;
        var value : bits(size);
        var memaddrdesc : AddressDescriptor;
        var memstatus : PhysMemRetStatus;

        (value, memaddrdesc, memstatus) = AArch64_MemSingleRead{size}(address, accdesc, aligned);

        // Check for a fault from translation or the output of translation.
        if IsFault(memaddrdesc) then
            AArch64_Abort(memaddrdesc.fault);
        end;

        // Check for external aborts.
        if IsFault(memstatus) then
            HandleExternalAbort(memstatus, accdesc.write, memaddrdesc, bytes, accdesc);
        end;

        return value;
    end;

    // Perform an atomic, little-endian write of 'size' bits.
    setter
        let bytes : integer{} = size DIV 8;
        var memaddrdesc : AddressDescriptor;
        var memstatus : PhysMemRetStatus;

        (memaddrdesc, memstatus) = AArch64_MemSingleWrite{size}(address, accdesc, aligned, value);

        // Check for a fault from translation or the output of translation.
        if IsFault(memaddrdesc) then
            AArch64_Abort(memaddrdesc.fault);
        end;

        // Check for external aborts.
        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, bytes, accdesc);
        end;
    end;
end;

// AArch64_MemSingleRead()
// =======================
// Perform an atomic, little-endian read of 'size' bits.

func AArch64_MemSingleRead{size : integer{8, 16, 32, 64, 128, 256}}(address : bits(64),
                                                                    accdesc_in : AccessDescriptor,
                                                                    aligned : boolean
                                                                   ) => (bits(size),
                                                                         AddressDescriptor,
                                                                         PhysMemRetStatus)
begin
    var value : bits(size) = ARBITRARY : bits(size);
    var memstatus : PhysMemRetStatus = ARBITRARY : PhysMemRetStatus;
    let bytes : integer{} = size DIV 8;
    memstatus.statuscode = Fault_None;
    var accdesc : AccessDescriptor = accdesc_in;
    if IsFeatureImplemented(FEAT_LSE2) then
        let quantity : integer = MemSingleGranule();
        assert ((IsFeatureImplemented(FEAT_LS64WB) &&
                   bytes == 32 && accdesc.acctype == AccessType_ASIMD) ||
                  AllInAlignedQuantity(address, bytes, quantity));
    else
        assert IsAlignedSize(address, bytes);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    var memaddrdesc : AddressDescriptor;
    memaddrdesc = AArch64_TranslateAddress(address, accdesc, aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        return (value, memaddrdesc, memstatus);
    end;

    // Memory array access
    if accdesc.tagchecked then
        let ltag : bits(4) = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            memaddrdesc.fault = fault;
            return (value, memaddrdesc, memstatus);
        end;
    end;

    if accdesc.acctype != AccessType_IFETCH && SPESampleInFlight then
        let is_load : boolean = TRUE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;
    var atomic : boolean;
    if IsWBShareable(memaddrdesc.memattrs) then
        atomic = TRUE;
    elsif accdesc.exclusive then
        atomic = TRUE;
    elsif (accdesc.acctype == AccessType_SVE && accdesc.predicated &&
            bytes == 8 && IsAlignedSize(address, 8)) then
        // An SVE predicated load of a 128-bit element that is 64-bit aligned
        // is treated as a pair of 64-bit single-copy atomic accesses.
        // This is one of the 64-bit single-copy atomic access.
        atomic = TRUE;
    elsif aligned then
        atomic = !accdesc.ispair;
    else
        // Misaligned accesses within MemSingleGranule() byte aligned memory but
        // not Normal Cacheable Writeback are Atomic
        atomic = ImpDefBool("FEAT_LSE2: access is atomic");
    end;

    if atomic then
        (memstatus, value) = PhysMemRead{size}(memaddrdesc, accdesc);

    elsif accdesc.acctype == AccessType_ASIMD && bytes == 32 && accdesc.ispair then
        // A 32 byte LDP (SIMD&FP) that does not target Normal Inner Write-Back, Outer
        // Write-Back cacheable, Shareable memory is treated as four 8 byte atomic accesses.
        // As this access was not split in Mem(), it must be aligned to 32 bytes.
        assert IsAlignedSize(address, 32);
        accdesc.ispair = FALSE;
        for i = 0 to 3 do
            if !IsFault(memstatus) then     // Do not continue past a fault
                (memstatus, value[i*64+:64]) = PhysMemRead{64}(memaddrdesc, accdesc);
            end;

            if !IsFault(memstatus) then
                memaddrdesc.paddress.address = memaddrdesc.paddress.address + 8;
                memaddrdesc.vaddress         = memaddrdesc.vaddress + 8;
            end;
        end;

    elsif aligned && accdesc.ispair then
        let half : integer{} = (size DIV 2) as integer{32, 64, 128};
        (memstatus, value[0*:half]) = PhysMemRead{half}(memaddrdesc, accdesc);

        if !IsFault(memstatus) then
            memaddrdesc.paddress.address = memaddrdesc.paddress.address + (bytes DIV 2);
            memaddrdesc.vaddress         = memaddrdesc.vaddress + (bytes DIV 2);
            (memstatus, value[1*:half]) = PhysMemRead{half}(memaddrdesc, accdesc);
        end;

    else
        for i = 0 to bytes-1 do
            if !IsFault(memstatus) then     // Do not continue past a fault
                (memstatus, value[i*:8]) = PhysMemRead{8}(memaddrdesc, accdesc);
            end;

            if !IsFault(memstatus) then
                memaddrdesc.paddress.address = memaddrdesc.paddress.address + 1;
                memaddrdesc.vaddress         = memaddrdesc.vaddress + 1;
            end;

        end;
    end;

    if IsFault(memstatus) then
        return (value, memaddrdesc, memstatus);
    end;

    if accdesc.acctype == AccessType_IFETCH then
        memaddrdesc.fault = AArch64_CheckDebug(address, accdesc, bytes);
    end;

    return (value, memaddrdesc, memstatus);
end;

// AArch64_MemSingleWrite()
// ========================
// Perform an atomic, little-endian write of 'size' bits.

func AArch64_MemSingleWrite{size : integer{8, 16, 32, 64, 128, 256}}(address : bits(64),
                                                                     accdesc_in : AccessDescriptor,
                                                                     aligned : boolean,
                                                                     value : bits(size)
                                                         ) => (AddressDescriptor, PhysMemRetStatus)
begin
    var accdesc : AccessDescriptor = accdesc_in;
    let bytes : integer{} = size DIV 8;
    if IsFeatureImplemented(FEAT_LSE2) then
        let quantity : integer = MemSingleGranule();
        assert ((IsFeatureImplemented(FEAT_LS64WB) &&
                 bytes == 32 && accdesc.acctype == AccessType_ASIMD) ||
                 AllInAlignedQuantity(address, bytes, quantity));
    else
        assert IsAlignedSize(address, bytes);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    var memaddrdesc : AddressDescriptor;
    var memstatus : PhysMemRetStatus = ARBITRARY : PhysMemRetStatus;
    memaddrdesc = AArch64_TranslateAddress(address, accdesc, aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        return (memaddrdesc, memstatus);
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), bytes);
    end;

    if accdesc.tagchecked then
        let ltag : bits(4) = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            memaddrdesc.fault = fault;
            return (memaddrdesc, memstatus);
        end;
    end;

    if SPESampleInFlight then
        let is_load : boolean = FALSE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    var atomic : boolean;
    if IsWBShareable(memaddrdesc.memattrs) then
        atomic = TRUE;
    elsif accdesc.exclusive then
        atomic = TRUE;
    elsif (accdesc.acctype == AccessType_SVE && accdesc.predicated &&
            bytes == 8 && IsAlignedSize(address, 8)) then
        // An SVE predicated load of a 128-bit element that is 64-bit aligned
        // is treated as a pair of 64-bit single-copy atomic accesses.
        // This is one of the 64-bit single-copy atomic access.
        atomic = TRUE;
    elsif aligned then
        atomic = !accdesc.ispair;
    else
        // Misaligned accesses within MemSingleGranule() byte aligned memory but
        // not Normal Cacheable Writeback are Atomic
        atomic = ImpDefBool("FEAT_LSE2: access is atomic");
    end;
    if atomic then
        memstatus = PhysMemWrite{size}(memaddrdesc, accdesc, value);
        if IsFault(memstatus) then
            return (memaddrdesc, memstatus);
        end;

    elsif accdesc.acctype == AccessType_ASIMD && bytes == 32 && accdesc.ispair then
        // A 32 byte STP (SIMD&FP) that does not target Normal Inner Write-Back, Outer
        // Write-Back cacheable, Shareable memory is treated as four 8 byte atomic accesses.
        // As this access was not split in Mem(), it must be aligned to 32 bytes.
        assert IsAlignedSize(address, 32);
        accdesc.ispair = FALSE;
        for i = 0 to 3 do
            memstatus = PhysMemWrite{64}(memaddrdesc, accdesc, value[64*i+:64]);
            if IsFault(memstatus) then
                return (memaddrdesc, memstatus);
            end;
            memaddrdesc.paddress.address = memaddrdesc.paddress.address + 8;
            memaddrdesc.vaddress         = memaddrdesc.vaddress + 8;
        end;

    elsif aligned && accdesc.ispair then
        let half : integer{} = (size DIV 2) as integer{32, 64};
        memstatus = PhysMemWrite{half}(memaddrdesc, accdesc, value[0*:half]);
        if IsFault(memstatus) then
            return (memaddrdesc, memstatus);
        end;

        memaddrdesc.paddress.address = memaddrdesc.paddress.address + (bytes DIV 2);
        memaddrdesc.vaddress         = memaddrdesc.vaddress + (bytes DIV 2);
        memstatus = PhysMemWrite{half}(memaddrdesc, accdesc, value[1*:half]);
        if IsFault(memstatus) then
            return (memaddrdesc, memstatus);
        end;

    else
        for i = 0 to bytes-1 do
            memstatus = PhysMemWrite{8}(memaddrdesc, accdesc, value[i*:8]);
            if IsFault(memstatus) then
                return (memaddrdesc, memstatus);
            end;
            memaddrdesc.paddress.address = memaddrdesc.paddress.address + 1;
            memaddrdesc.vaddress         = memaddrdesc.vaddress + 1;
        end;
    end;

    return (memaddrdesc, memstatus);
end;

// AArch64_MemTag - accessor
// =========================

accessor AArch64_MemTag(address : bits(64), accdesc : AccessDescriptor) <=> value : bits(4)
begin
    // Load an Allocation Tag from memory.
    getter
        var value : bits(4);
        var memaddrdesc : AddressDescriptor;
        var memstatus : PhysMemRetStatus;
        (value, memaddrdesc, memstatus) = AArch64_MemTagRead(address, accdesc);

        if IsFault(memaddrdesc) then
            AArch64_Abort(memaddrdesc.fault);
        end;

        if IsFault(memstatus) then
            HandleExternalReadAbort(memstatus, memaddrdesc, 1, accdesc);
        end;

        return value;
    end;

    // Store an Allocation Tag to memory.
    setter
        var memaddrdesc : AddressDescriptor;
        var memstatus : PhysMemRetStatus;
        (memaddrdesc, memstatus) = AArch64_MemTagWrite(address, accdesc, value);

        if IsFault(memaddrdesc) then
            AArch64_Abort(memaddrdesc.fault);
        end;

        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, 1, accdesc);
        end;
    end;
end;

// AArch64_MemTagRead()
// ====================
// Load an Allocation Tag from memory.

func AArch64_MemTagRead(address : bits(64),
                        accdesc_in : AccessDescriptor
                       ) => (bits(4), AddressDescriptor, PhysMemRetStatus)
begin
    assert accdesc_in.tagaccess && !accdesc_in.tagchecked;

    var accdesc : AccessDescriptor      = accdesc_in;
    var tag : bits(4)                   = ARBITRARY : bits(4);
    var memaddrdesc : AddressDescriptor = ARBITRARY : AddressDescriptor;
    var memtagtype : MemTagType  = ARBITRARY : MemTagType;
    var memstatus : PhysMemRetStatus   = ARBITRARY : PhysMemRetStatus;

    let aligned : boolean = TRUE;

    accdesc.tagaccess = IsMTEEnabled(accdesc.el);

    (memtagtype, memaddrdesc) = AArch64_TranslateTagAddress(address, accdesc, aligned, TAG_GRANULE);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        return (tag, memaddrdesc, memstatus);
    end;

    if accdesc.tagaccess && memtagtype == MemTag_AllocationTagged then
        (memstatus, tag) = PhysMemTagRead(memaddrdesc, accdesc);
        return (tag, memaddrdesc, memstatus);
    elsif (IsFeatureImplemented(FEAT_MTE_CANONICAL_TAGS) &&
             accdesc.tagaccess && memtagtype == MemTag_CanonicallyTagged) then
        tag = if address[55] == '0' then '0000' else '1111';
        return (tag, memaddrdesc, memstatus);
    else
        // Otherwise read the tag as zero
        tag = '0000';
        return (tag, memaddrdesc, memstatus);
    end;
end;

// AArch64_MemTagWrite()
// =====================
// Store an Allocation Tag to memory.

func AArch64_MemTagWrite(address : bits(64),
                         accdesc_in : AccessDescriptor,
                         value : bits(4)) => (AddressDescriptor, PhysMemRetStatus)
begin
    assert accdesc_in.tagaccess && !accdesc_in.tagchecked;

    var accdesc : AccessDescriptor     = accdesc_in;
    var memaddrdesc : AddressDescriptor = ARBITRARY : AddressDescriptor;
    var memtagtype : MemTagType  = ARBITRARY : MemTagType;
    var memstatus : PhysMemRetStatus   = ARBITRARY : PhysMemRetStatus;

    let aligned : boolean = IsAlignedSize(address, TAG_GRANULE);

    // Stores of allocation tags must be aligned
    if !aligned then
        memaddrdesc.fault = AlignmentFault(accdesc, address);
        return (memaddrdesc, memstatus);
    end;

    accdesc.tagaccess = IsMTEEnabled(accdesc.el);

    (memtagtype, memaddrdesc) = AArch64_TranslateTagAddress(address, accdesc, aligned, TAG_GRANULE);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        memaddrdesc.fault.vaddress = memaddrdesc.vaddress;
        return (memaddrdesc, memstatus);
    end;

    if accdesc.tagaccess && memtagtype == MemTag_AllocationTagged then
        memstatus = PhysMemTagWrite(memaddrdesc, accdesc, value);
    end;
    return (memaddrdesc, memstatus);
end;

// AArch64_UnalignedAccessFaults()
// ===============================
// Determine whether the unaligned access generates an Alignment fault

func AArch64_UnalignedAccessFaults(accdesc : AccessDescriptor,
                                   address : bits(64),
                                   size : integer) => boolean
begin
    if AlignmentEnforced() then
        return TRUE;
    elsif accdesc.acctype == AccessType_GCS then
        return TRUE;
    elsif accdesc.rcw then
        return TRUE;
    elsif accdesc.ls64 then
        return TRUE;
    elsif (accdesc.exclusive || accdesc.atomicop)  then
        let quantity : integer = MemSingleGranule();
        return (!IsFeatureImplemented(FEAT_LSE2) ||
                  !AllInAlignedQuantity(address, size, quantity));
    elsif (accdesc.acqsc || accdesc.acqpc || accdesc.relsc) then
        // If nAA is 0, the address accessed by each register in the pair
        // must lie within a single 16-byte aligned block
        if accdesc.ispair then
            return  (SCTLR_ELx().nAA == '0' &&
                       (!AllInAlignedQuantity(address, size DIV 2, 16) ||
                        !AllInAlignedQuantity(address + size DIV 2, size DIV 2, 16)));
        else
            return  (SCTLR_ELx().nAA == '0' &&
                       !AllInAlignedQuantity(address, size, 16));
        end;
    else
        return FALSE;
    end;
end;

// AddressSupportsLS64()
// =====================
// Returns TRUE if the 64-byte block following the given address supports the
// LD64B and ST64B instructions, and FALSE otherwise.

impdef func AddressSupportsLS64(paddress : bits(56)) => boolean
begin
    return ImpDefBool("Memory location supports ST64B and LD64B");
end;

// AllInAlignedQuantity()
// ======================
// Returns TRUE if all accessed bytes are within one aligned quantity, FALSE otherwise.

readonly func AllInAlignedQuantity(address : bits(64),
                                   size : integer, alignment : integer) => boolean
begin
    return (AlignDownSize(address+(size-1), alignment as AddressSize) ==
            AlignDownSize(address, alignment as AddressSize));
end;

// CASCompare()
// ============
// Performs a comparison for CAS

func CASCompare{N}(oldvalue : bits(N),
                   comparevalue : bits(N),
                   newvalue : bits(N)) => (bits(N), boolean, bits(N))
begin
    var memresult : bits(N);
    var cmpfail : boolean;
    var regresult : bits(N) = oldvalue;

    if oldvalue == comparevalue then
        cmpfail = FALSE;
        memresult = newvalue;
        if !ConstrainUnpredictableBool(Unpredictable_CASRETURNOLDVALUE) then
            regresult = comparevalue;
        end;
    else
        cmpfail = TRUE;
        memresult = oldvalue;
    end;

    return (memresult, cmpfail, regresult);
end;

// CheckSPAlignment()
// ==================
// Check correct stack pointer alignment for AArch64 state.

func CheckSPAlignment()
begin
    let sp : bits(64) = SP{}();
    var stack_align_check : boolean;
    if PSTATE.EL == EL0 then
        stack_align_check = (SCTLR_ELx().SA0 != '0');
    else
        stack_align_check = (SCTLR_ELx().SA != '0');
    end;

    if stack_align_check && sp != AlignDownSize(sp, 16) then
        AArch64_SPAlignmentFault();
    end;

    return;
end;

// IsConventionalMemory()
// ======================
// Returns TRUE if the memory location is in Conventional memory, and FALSE otherwise.

impdef func IsConventionalMemory(addrdesc : AddressDescriptor) => boolean
begin
    return TRUE;
end;

// Mem - accessor
// ==============

accessor Mem{size : integer{8, 16, 32, 64, 128, 256}}(address : bits(64),
                                                      accdesc_in : AccessDescriptor
                                                ) <=>  value_in : bits(size)
begin
    // Perform a read of 'size' bits. The access byte order is reversed for a big-endian access.
    // Instruction fetches would call AArch64_MemSingle directly.
    getter
        var accdesc : AccessDescriptor = accdesc_in;
        let bytes : integer{} = size DIV 8;
        var value : bits(size);
        // Check alignment on size of element accessed, not overall access size
        let alignment : integer{} = (if accdesc.ispair && !accdesc.exclusive then bytes DIV 2
                                                                             else bytes);
        var aligned : boolean   = IsAlignedSize(address, alignment);
        let quantity : integer = MemSingleGranule();

        if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
            let fault : FaultRecord = AlignmentFault(accdesc, address);
            AArch64_Abort(fault);
        end;
        if accdesc.acctype == AccessType_ASIMD && bytes == 16 && IsAlignedSize(address, 8) then
            // If 128-bit SIMD&FP ordered access are treated as a pair of
            // 64-bit single-copy atomic accesses, then these single copy atomic
            // access can be observed in any order.
            let half : integer{} = (size DIV 2) as integer{64};
            let highaddress : bits(64) = AddressIncrement(address, bytes DIV 2, accdesc);
            value[0*:half] = AArch64_MemSingle{half}(address, accdesc, aligned);
            value[1*:half] = AArch64_MemSingle{half}(highaddress, accdesc, aligned);
        elsif (accdesc.acctype == AccessType_ASIMD && bytes == 32 &&
                accdesc.ispair && IsAlignedSize(address, 32)) then
            value = AArch64_MemSingle{size}(address, accdesc, aligned);
        elsif accdesc.acctype == AccessType_ASIMD && bytes == 32 && IsAlignedSize(address, 8) then
            // If a 32 byte LDP (SIMD&FP) access is not aligned to 32 bytes but aligned to
            // 8 bytes, it is treated as four 8 byte single-copy atomic accesses.
            accdesc.ispair = FALSE;
            aligned        = TRUE;
            for i = 0 to 3 do
                let blockaddress : bits(64) = AddressIncrement(address, i*8, accdesc);
                value[64*i+:64] = AArch64_MemSingle{64}(blockaddress, accdesc, aligned);
            end;
        elsif (IsFeatureImplemented(FEAT_LSE2) &&
            AllInAlignedQuantity(address, bytes, quantity)) then
            value = AArch64_MemSingle{size}(address, accdesc, aligned);
        elsif ((aligned && accdesc.ispair) ||
                  (accdesc.acctype == AccessType_SVE && accdesc.predicated &&
                     bytes == 16 && IsAlignedSize(address, 8))) then
            // Either: an aligned pair access, OR
            // an SVE predicated load of a 128-bit element that is 64-bit aligned,
            // which is treated as two 64-bit single-copy atomic accesses.
            accdesc.ispair = FALSE;
            let half : integer{} = (size DIV 2) as integer{32, 64, 128};
            let highaddress : bits(64) = AddressIncrement(address, bytes DIV 2, accdesc);
            if IsFeatureImplemented(FEAT_LRCPC3) && accdesc.highestaddressfirst then
                value[1*:half] = AArch64_MemSingle{half}(highaddress, accdesc, aligned);
                value[0*:half] = AArch64_MemSingle{half}(address, accdesc, aligned);
            else
                value[0*:half] = AArch64_MemSingle{half}(address, accdesc, aligned);
                value[1*:half] = AArch64_MemSingle{half}(highaddress, accdesc, aligned);
            end;
        elsif aligned then
            value = AArch64_MemSingle{size}(address, accdesc, aligned);
        else
            assert bytes > 1;
            if (IsFeatureImplemented(FEAT_LRCPC3) && accdesc.ispair &&
                    accdesc.highestaddressfirst) then
                let half : integer{} = (size DIV 2) as integer{32, 64, 128};
                var lowhalf, highhalf : bits(half);

                for i = 0 to (bytes DIV 2)-1 do
                    let byteaddress : bits(64) = AddressIncrement(address,
                                                                  (bytes DIV 2) + i, accdesc);
                    // Individual byte access can be observed in any order
                    highhalf[i*:8] = AArch64_MemSingle{8}(byteaddress, accdesc, aligned);
                end;
                for i = 0 to (bytes DIV 2)-1 do
                    let byteaddress : bits(64) = AddressIncrement(address, i, accdesc);
                    // Individual byte access can be observed in any order
                    lowhalf[i*:8] = AArch64_MemSingle{8}(byteaddress, accdesc, aligned);
                end;

                value = highhalf::lowhalf;

            else
                value[7:0] = AArch64_MemSingle{8}(address, accdesc, aligned);
                accdesc.lowestaddress = FALSE;

                // For subsequent bytes, if they cross to a new translation page which assigns
                // Device memory type, it is CONSTRAINED UNPREDICTABLE whether an unaligned access
                // will generate an Alignment Fault.
                let c : Constraint = ConstrainUnpredictable(Unpredictable_DEVPAGE2);
                assert c IN {Constraint_FAULT, Constraint_NONE};
                if c == Constraint_NONE then aligned = TRUE; end;

                for i = 1 to bytes-1 do
                    let byteaddress : bits(64) = AddressIncrement(address, i, accdesc);
                    value[i*:8] = AArch64_MemSingle{8}(byteaddress, accdesc, aligned);
                end;
            end;
        end;

        if BigEndian(accdesc.acctype) then
            value = BigEndianReverse{size}(value);
        end;

        return value;
    end;

    // Perform a write of 'size' bits. The byte order is reversed for a big-endian access.
    setter
        var value : bits(size) = value_in;
        let bytes : integer{} = size DIV 8;
        var accdesc : AccessDescriptor = accdesc_in;

        // Check alignment on size of element accessed, not overall access size
        let alignment : integer{} = (if accdesc.ispair && !accdesc.exclusive then bytes DIV 2
                                                                              else bytes);
        var aligned : boolean   = IsAlignedSize(address, alignment);
        let quantity : integer = MemSingleGranule();

        if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
            let fault : FaultRecord = AlignmentFault(accdesc, address);
            AArch64_Abort(fault);
        end;

        if BigEndian(accdesc.acctype) then
            value = BigEndianReverse{size}(value);
        end;
        if accdesc.acctype == AccessType_ASIMD && bytes == 16 && IsAlignedSize(address, 8) then
            let half : integer{} = (size DIV 2) as integer{64};
            // 128-bit SIMD&FP stores are treated as a pair of 64-bit single-copy atomic accesses
            // 64-bit aligned.
            let highaddress : bits(64) = AddressIncrement(address, (bytes DIV 2), accdesc);
            AArch64_MemSingle{half}(address, accdesc, aligned) = value[0+:half];
            AArch64_MemSingle{half}(highaddress, accdesc, aligned) = value[half+:half];
        elsif (accdesc.acctype == AccessType_ASIMD && bytes == 32 &&
                accdesc.ispair && IsAlignedSize(address, 32)) then
            AArch64_MemSingle{size}(address, accdesc, aligned) = value;
        elsif accdesc.acctype == AccessType_ASIMD && bytes == 32 && IsAlignedSize(address, 8) then
            // If a 32 byte STP (SIMD&FP) access is not aligned to 32 bytes but aligned to
            // 8 bytes, it is treated as four 8 byte single-copy atomic accesses.
            accdesc.ispair = FALSE;
            aligned        = TRUE;
            for i = 0 to 3 do
                let blockaddress : bits(64) = AddressIncrement(address, i*8, accdesc);
                AArch64_MemSingle{64}(blockaddress, accdesc, aligned) = value[64*i+:64];
            end;
        elsif (IsFeatureImplemented(FEAT_LSE2) &&
            AllInAlignedQuantity(address, bytes, quantity)) then
            AArch64_MemSingle{size}(address, accdesc, aligned) = value;
        elsif ((aligned && accdesc.ispair) ||
                  (accdesc.acctype == AccessType_SVE && accdesc.predicated &&
                     bytes == 16 && IsAlignedSize(address, 8))) then
            // Either: an aligned pair access, OR
            // an SVE predicated load of a 128-bit element that is 64-bit aligned,
            // which is treated as two 64-bit single-copy atomic accesses.
            let half : integer{} = (size DIV 2) as integer{32, 64, 128};
            accdesc.ispair = FALSE;
            let highaddress : bits(64) = AddressIncrement(address, (bytes DIV 2), accdesc);
            if IsFeatureImplemented(FEAT_LRCPC3) && accdesc.highestaddressfirst then
                AArch64_MemSingle{half}(highaddress, accdesc, aligned) = value[half+:half];
                AArch64_MemSingle{half}(address, accdesc, aligned) = value[0+:half];
            else
                AArch64_MemSingle{half}(address, accdesc, aligned) = value[0+:half];
                AArch64_MemSingle{half}(highaddress, accdesc, aligned) = value[half+:half];
            end;
        elsif aligned then
            AArch64_MemSingle{size}(address, accdesc, aligned) = value;
        else
            assert bytes > 1;
            if (IsFeatureImplemented(FEAT_LRCPC3) && accdesc.ispair &&
                    accdesc.highestaddressfirst) then
                let half : integer{} = (size DIV 2) as integer{32, 64};
                var lowhalf, highhalf : bits(half);
                (highhalf, lowhalf) = (value[half+:half], value[0+:half]);
                for i = 0 to (bytes DIV 2)-1 do
                    let byteaddress : bits(64) = AddressIncrement(address,
                                                                  (bytes DIV 2) + i, accdesc);
                    // Individual byte access can be observed in any order
                    AArch64_MemSingle{8}(byteaddress, accdesc, aligned) = highhalf[i*:8];
                end;
                for i = 0 to (bytes DIV 2)-1 do
                    let byteaddress : bits(64) = AddressIncrement(address,
                                                                  (bytes DIV 2) + i, accdesc);
                    // Individual byte access can be observed in any order,
                    // but implies observability of highhalf
                    AArch64_MemSingle{8}(byteaddress, accdesc, aligned) = lowhalf[i*:8];
                end;
            else
                AArch64_MemSingle{8}(address, accdesc, aligned) = value[7:0];
                accdesc.lowestaddress = FALSE;

                // For subsequent bytes, if they cross to a new translation page which assigns
                // Device memory type, it is CONSTRAINED UNPREDICTABLE whether an unaligned access
                // will generate an Alignment Fault.

                let c : Constraint = ConstrainUnpredictable(Unpredictable_DEVPAGE2);
                assert c IN {Constraint_FAULT, Constraint_NONE};
                if c == Constraint_NONE then aligned = TRUE; end;

                for i = 1 to bytes-1 do
                    let byteaddress : bits(64) = AddressIncrement(address, i, accdesc);
                    AArch64_MemSingle{8}(byteaddress, accdesc, aligned) = value[i*:8];
                end;
            end;
        end;
    end;
end;

// MemAtomic()
// ===========
// Performs load and store memory operations for a given virtual address.

func MemAtomic{size : integer{8, 16, 32, 64, 128}}(address : bits(64),
                                                   cmpoperand : bits(size),
                                                   operand : bits(size),
                                                   accdesc_in : AccessDescriptor
                                                  ) => bits(size)
begin
    assert accdesc_in.atomicop;

    let bytes : integer{} = (size DIV 8) as integer{1, 2, 4, 8, 16};

    var newvalue : bits(size);
    var oldvalue : bits(size);
    var accdesc : AccessDescriptor = accdesc_in;
    let aligned : boolean = IsAlignedSize(address, bytes);

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    // MMU or MPU lookup
    let memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc,
                                                                      aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    if (!IsWBShareable(memaddrdesc.memattrs) &&
            ConstrainUnpredictableBool(Unpredictable_Atomic_NOP)) then
        return ARBITRARY : bits(size);
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), bytes);
    end;

    // For Store-only Tag checking, the tag check is performed on the store.
    if (accdesc.tagchecked &&
          (!IsFeatureImplemented(FEAT_MTE_STORE_ONLY) ||
           !StoreOnlyTagCheckingEnabled(accdesc.el))) then
        let ltag : bits(4) = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            AArch64_Abort(fault);
        end;
    end;

    // All observers in the shareability domain observe the following load and store atomically.
    var memstatus : PhysMemRetStatus;
    (memstatus, oldvalue) = PhysMemRead{size}(memaddrdesc, accdesc);
    // Depending on the memory type of the physical address, the access might generate
    // either a synchronous External abort or an SError exception
    // among other CONSTRAINED UNPREDICTABLE choices.

    if IsFault(memstatus) then
        HandleExternalReadAbort(memstatus, memaddrdesc, bytes, accdesc);
    end;
    if BigEndian(accdesc.acctype) then
        oldvalue = BigEndianReverse{size}(oldvalue);
    end;

    var cmpfail : boolean = FALSE;
    var retvalue : bits(size) = oldvalue;
    if accdesc.acctype == AccessType_FP then
        newvalue = MemAtomicFP{size}(accdesc.modop, oldvalue, operand);
    else
        (newvalue, cmpfail, retvalue) = MemAtomicInt{size}(accdesc.modop, oldvalue,
                                                           operand, cmpoperand);
    end;

    let requirewrite : boolean = (!cmpfail ||
                                     ConstrainUnpredictableBool(Unpredictable_WRITEFAILEDCAS));

    if IsFeatureImplemented(FEAT_MTE_STORE_ONLY) && StoreOnlyTagCheckingEnabled(accdesc.el) then
        // If the compare on a CAS fails, then it is CONSTRAINED UNPREDICTABLE whether the
        // Tag check is performed.
        if accdesc.tagchecked && !requirewrite then
            accdesc.tagchecked = ConstrainUnpredictableBool(Unpredictable_STRONLYTAGCHECKEDCAS);
        end;

        if accdesc.tagchecked then
            let ltag : bits(4) = AArch64_LogicalAddressTag(address);
            var fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
            if fault.statuscode != Fault_None then
                // For a synchronous Tag Check Fault due to FEAT_MTE_STORE_ONLY, set WnR.
                fault.write = TRUE;
                AArch64_Abort(fault);
            end;
        end;
    end;

    if requirewrite then
        if BigEndian(accdesc.acctype) then
            newvalue = BigEndianReverse{size}(newvalue);
        end;
        memstatus = PhysMemWrite{size}(memaddrdesc, accdesc, newvalue);
        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, bytes, accdesc);
        end;
    end;

    if SPESampleInFlight then
        let is_load : boolean = FALSE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    // Load operations return the old (pre-operation) value.
    // Compare and Swap operations return the old (pre-operation) value. For a successful CAS,
    // this might be the value from the compare operand or from memory.
    return retvalue;
end;

// MemAtomicFP()
// =============
// Performs FP Atomic operation

func MemAtomicFP{N}(modop : MemAtomicOp, op1 : bits(N), op2 : bits(N)) => bits(N)
begin
    var fpcr : FPCR_Type = FPCR();
    let altfp : boolean  = FALSE;
    let fpexc : boolean  = FALSE;
    fpcr.[AH,DN]   = '01';
    fpcr.FZ        = fpcr.FZ OR fpcr.FIZ; // Treat FPCR.FIZ as equivalent to FPCR.FZ
    var result : bits(N);

    case modop of
        when MemAtomicOp_FPADD =>    result = FPAdd{N}(op1, op2, fpcr, fpexc);
        when MemAtomicOp_FPMAX =>    result = FPMax{N}(op1, op2, fpcr, altfp, fpexc);
        when MemAtomicOp_FPMIN =>    result = FPMin{N}(op1, op2, fpcr, altfp, fpexc);
        when MemAtomicOp_FPMAXNM =>  result = FPMaxNum{N}(op1, op2, fpcr, fpexc);
        when MemAtomicOp_FPMINNM =>  result = FPMinNum{N}(op1, op2, fpcr, fpexc);
        when MemAtomicOp_BFADD =>    result = BFAdd{N}(op1, op2, fpcr, fpexc);
        when MemAtomicOp_BFMAX =>    result = BFMax{N}(op1, op2, fpcr, altfp, fpexc);
        when MemAtomicOp_BFMIN =>    result = BFMin{N}(op1, op2, fpcr, altfp, fpexc);
        when MemAtomicOp_BFMAXNM =>  result = BFMaxNum{N}(op1, op2, fpcr, fpexc);
        when MemAtomicOp_BFMINNM =>  result = BFMinNum{N}(op1, op2, fpcr, fpexc);
    end;
    return result;
end;

// MemAtomicInt()
// ==============
// Performs Integer Atomic operation

func MemAtomicInt{N}(modop : MemAtomicOp, op1 : bits(N), op2 : bits(N), cmpop : bits(N)
                    ) => (bits(N), boolean, bits(N))
begin
    var result : bits(N);
    var cmpfail : boolean = FALSE;
    var retvalue : bits(N) = op1;

    case modop of
        when MemAtomicOp_ADD =>      result = op1 + op2;
        when MemAtomicOp_BIC =>      result = op1 AND NOT(op2);
        when MemAtomicOp_EOR =>      result = op1 XOR op2;
        when MemAtomicOp_ORR =>      result = op1 OR op2;
        when MemAtomicOp_SMAX =>     result = Max(SInt(op1), SInt(op2))[N-1:0];
        when MemAtomicOp_SMIN =>     result = Min(SInt(op1), SInt(op2))[N-1:0];
        when MemAtomicOp_UMAX =>     result = Max(UInt(op1), UInt(op2))[N-1:0];
        when MemAtomicOp_UMIN =>     result = Min(UInt(op1), UInt(op2))[N-1:0];
        when MemAtomicOp_SWP =>      result = op2;
        when MemAtomicOp_CAS =>      (result, cmpfail, retvalue) = CASCompare{N}(op1, cmpop, op2);
        when MemAtomicOp_GCSSS1 =>   (result, cmpfail, retvalue) = CASCompare{N}(op1, cmpop, op2);
    end;
    return (result, cmpfail, retvalue);
end;

// MemAtomicRCW()
// ==============
// Perform a single-copy-atomic access with Read-Check-Write operation

func MemAtomicRCW{size : integer{64, 128}}(address : bits(64), cmpoperand : bits(size),
                                           operand : bits(size), accdesc_in : AccessDescriptor
                                  ) => (bits(4), bits(size))
begin
    assert accdesc_in.atomicop;
    assert accdesc_in.rcw;

    let bytes : integer{} = (size DIV 8) as integer{8, 16};

    var nzcv : bits(4);
    var oldvalue : bits(size);
    var newvalue : bits(size);
    var accdesc : AccessDescriptor = accdesc_in;
    let aligned : boolean = IsAlignedSize(address, bytes);

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    // MMU or MPU lookup
    let memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc,
                                                                      aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    if (!IsWBShareable(memaddrdesc.memattrs) &&
            ConstrainUnpredictableBool(Unpredictable_Atomic_NOP)) then
        return (ARBITRARY : bits(4), ARBITRARY : bits(size));
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), bytes);
    end;

    // For Store-only Tag checking, the tag check is performed on the store.
    if (accdesc.tagchecked &&
          (!IsFeatureImplemented(FEAT_MTE_STORE_ONLY) ||
           !StoreOnlyTagCheckingEnabled(accdesc.el))) then
        let ltag : bits(4) = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            AArch64_Abort(fault);
        end;
    end;

    // All observers in the shareability domain observe the following load and store atomically.
    var memstatus : PhysMemRetStatus;
    (memstatus, oldvalue) = PhysMemRead{size}(memaddrdesc, accdesc);
    // Depending on the memory type of the physical address, the access might generate
    // either a synchronous External abort or an SError exception
    // among other CONSTRAINED UNPREDICTABLE choices.

    if IsFault(memstatus) then
        HandleExternalReadAbort(memstatus, memaddrdesc, bytes, accdesc);
    end;
    if BigEndian(accdesc.acctype) then
        oldvalue = BigEndianReverse{size}(oldvalue);
    end;

    var cmpfail : boolean = FALSE;
    var retvalue : bits(size) = oldvalue;
    case accdesc.modop of
        when MemAtomicOp_BIC => newvalue = oldvalue AND NOT(operand);
        when MemAtomicOp_ORR => newvalue = oldvalue OR operand;
        when MemAtomicOp_SWP => newvalue = operand;
        when MemAtomicOp_CAS =>
            (newvalue, cmpfail, retvalue) = CASCompare{size}(oldvalue, cmpoperand, operand);
    end;

    if cmpfail then
        nzcv = '1010'; // N = 1 indicates compare failure
    else
        nzcv = RCWCheck{size}(retvalue, newvalue, accdesc.rcws);
    end;

    // If RCWCheck() passes, it returns nzcv == '0010'
    let requirewrite : boolean = ((nzcv == '0010') ||
                                     (accdesc.modop == MemAtomicOp_CAS &&
                                      ConstrainUnpredictableBool(Unpredictable_WRITEFAILEDCAS)));

    if IsFeatureImplemented(FEAT_MTE_STORE_ONLY) && StoreOnlyTagCheckingEnabled(accdesc.el) then
        // If the RCW(S) check fails, or if the compare on a RCW(S)CAS fails,
        // then it is CONSTRAINED UNPREDICTABLE whether the Tag check is performed.
        if accdesc.tagchecked && !requirewrite then
            accdesc.tagchecked = ConstrainUnpredictableBool(Unpredictable_STRONLYTAGCHECKEDRCWSCAS);
        end;

        if accdesc.tagchecked then
            let ltag : bits(4) = AArch64_LogicalAddressTag(address);
            var fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
            if fault.statuscode != Fault_None then
                // For a synchronous Tag Check Fault due to FEAT_MTE_STORE_ONLY, set WnR.
                fault.write = TRUE;
                AArch64_Abort(fault);
            end;
        end;
    end;

    if requirewrite then
        if BigEndian(accdesc.acctype) then
            newvalue = BigEndianReverse{size}(newvalue);
        end;

        memstatus = PhysMemWrite{size}(memaddrdesc, accdesc, newvalue);

        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, bytes, accdesc);
        end;
    end;

    if SPESampleInFlight then
        let is_load : boolean = TRUE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    // Load operations return the old (pre-operation) value.
    // Compare and Swap operations return the old (pre-operation) value. For a successful CAS,
    // this might be the value from the compare operand or from memory.
    return (nzcv, retvalue);
end;

// MemLoad64B()
// ============
// Performs an atomic 64-byte read from a given virtual address.

func MemLoad64B(address : bits(64), accdesc_in : AccessDescriptor) => bits(512)
begin
    let size : integer{} = 512;
    let bytes : integer{} = size DIV 8;
    var data : bits(size);
    var accdesc : AccessDescriptor = accdesc_in;
    let aligned : boolean = IsAlignedSize(address, bytes);

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    var memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc,
                                                                   aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), bytes);
    end;

    if accdesc.tagchecked then
        let ltag : bits(4)      = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            AArch64_Abort(fault);
        end;
    end;

    var byte_atomic : boolean = FALSE;
    if ((memaddrdesc.memattrs.memtype == MemType_Device ||
          (memaddrdesc.memattrs.inner.attrs == MemAttr_NC &&
             memaddrdesc.memattrs.outer.attrs == MemAttr_NC)) &&
          !AddressSupportsLS64(memaddrdesc.paddress.address)) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_LS64UNSUPPORTED);
        assert c IN {Constraint_LIMITED_ATOMICITY, Constraint_FAULT};
        if c == Constraint_FAULT then
            // Generate a stage 1 Data Abort reported using the DFSC code of 110101.
            let fault : FaultRecord = ExclusiveFault(accdesc, address);
            AArch64_Abort(fault);
        else
            byte_atomic = TRUE;
        end;
    elsif IsWBShareable(memaddrdesc.memattrs) && !IsConventionalMemory(memaddrdesc) then
        if ImpDefBool("LD64B faults to iWBoWB non-Conventional memory") then
            // Generate a Data Abort reported using the DFSC code of 110101.
            let fault : FaultRecord = ExclusiveFault(accdesc, address);
            AArch64_Abort(fault);
        else
            byte_atomic = TRUE;
        end;
    end;

    if SPESampleInFlight then
        let is_load : boolean = TRUE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    var memstatus : PhysMemRetStatus;
    if byte_atomic then
        // Accesses are not single-copy atomic above the byte level.
        for i = 0 to bytes-1 do
            (memstatus, data[i*:8]) = PhysMemRead{8}(memaddrdesc, accdesc);
            if IsFault(memstatus) then
                HandleExternalReadAbort(memstatus, memaddrdesc, 1, accdesc);
            end;
            memaddrdesc.paddress.address = memaddrdesc.paddress.address + 1;
            memaddrdesc.vaddress         = memaddrdesc.vaddress + 1;
        end;
    else
        (memstatus, data) = PhysMemRead{size}(memaddrdesc, accdesc);
        if IsFault(memstatus) then
            HandleExternalReadAbort(memstatus, memaddrdesc, bytes, accdesc);
        end;
    end;

    return data;
end;

// MemSingleGranule()
// ==================
// When FEAT_LSE2 is implemented, for some memory accesses if all bytes
// of the accesses are within 16-byte quantity aligned to 16-bytes and
// satisfy additional requirements - then the access is guaranteed to
// be single copy atomic.
// However, when the accesses do not all lie within such a boundary, it
// is CONSTRAINED UNPREDICTABLE if the access is single copy atomic.
// In the pseudocode, this CONSTRAINED UNPREDICTABLE aspect is modeled via
// MemSingleGranule() which is IMPLEMENTATION DEFINED and, is at least 16 bytes
// and at most 4096 bytes.
// This is a limitation of the pseudocode.

func MemSingleGranule() => integer
begin
    let size : integer = ImpDefInt("Aligned quantity for atomic access");
    // access is assumed to be within 4096 byte aligned quantity to
    // avoid multiple translations for a single copy atomic access.
    assert (size >= 16) && (size <= 4096);
    return size;
end;

// MemStore64B()
// =============
// Performs an atomic 64-byte store to a given virtual address. Function does
// not return the status of the store.

func MemStore64B(address : bits(64), value : bits(512), accdesc_in : AccessDescriptor)
begin
    let size : integer{} = 512;
    let bytes : integer{} = size DIV 8;
    var accdesc : AccessDescriptor = accdesc_in;
    let aligned : boolean = IsAlignedSize(address, bytes);

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    var memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc,
                                                                   aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), 64);
    end;

    if accdesc.tagchecked then
        let ltag : bits(4)      = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            AArch64_Abort(fault);
        end;
    end;

    var byte_atomic : boolean = FALSE;
    if ((memaddrdesc.memattrs.memtype == MemType_Device ||
          (memaddrdesc.memattrs.inner.attrs == MemAttr_NC &&
             memaddrdesc.memattrs.outer.attrs == MemAttr_NC)) &&
          !AddressSupportsLS64(memaddrdesc.paddress.address)) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_LS64UNSUPPORTED);
        assert c IN {Constraint_LIMITED_ATOMICITY, Constraint_FAULT};
        if c == Constraint_FAULT then
            // Generate a Data Abort reported using the DFSC code of 110101.
            let fault : FaultRecord = ExclusiveFault(accdesc, address);
            AArch64_Abort(fault);
        else
            byte_atomic = TRUE;
        end;
    elsif IsWBShareable(memaddrdesc.memattrs) && !IsConventionalMemory(memaddrdesc) then
        if ImpDefBool("ST64B faults to iWBoWB non-Conventional memory") then
            // Generate a Data Abort reported using the DFSC code of 110101.
            let fault : FaultRecord = ExclusiveFault(accdesc, address);
            AArch64_Abort(fault);
        else
            byte_atomic = TRUE;
        end;
    end;

    if SPESampleInFlight then
        let is_load : boolean = FALSE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    var memstatus : PhysMemRetStatus;
    if byte_atomic then
        // Accesses are not single-copy atomic above the byte level.
        for i = 0 to bytes-1 do
            memstatus = PhysMemWrite{8}(memaddrdesc, accdesc, value[i*:8]);
            if IsFault(memstatus) then
                HandleExternalWriteAbort(memstatus, memaddrdesc, 1, accdesc);
            end;
            memaddrdesc.paddress.address = memaddrdesc.paddress.address + 1;
            memaddrdesc.vaddress         = memaddrdesc.vaddress + 1;
        end;
    else
        memstatus = PhysMemWrite{size}(memaddrdesc, accdesc, value);
        if IsFault(memstatus) then
            HandleExternalWriteAbort(memstatus, memaddrdesc, bytes, accdesc);
        end;
    end;

    return;
end;

// MemStore64BWithRet()
// ====================
// Performs an atomic 64-byte store to a given virtual address returning
// the status value of the operation.

func MemStore64BWithRet(address : bits(64), value : bits(512),
                        accdesc_in : AccessDescriptor) => bits(64)
begin
    let size : integer{} = 512;
    let bytes : integer{} = size DIV 8;
    var accdesc : AccessDescriptor = accdesc_in;
    let aligned : boolean = IsAlignedSize(address, bytes);

    if !aligned && AArch64_UnalignedAccessFaults(accdesc, address, bytes) then
        let fault : FaultRecord = AlignmentFault(accdesc, address);
        AArch64_Abort(fault);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    let memaddrdesc : AddressDescriptor = AArch64_TranslateAddress(address, accdesc,
                                                                    aligned, bytes);

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        AArch64_Abort(memaddrdesc.fault);
    end;

    // Effect on exclusives
    if memaddrdesc.memattrs.shareability != Shareability_NSH then
        ClearExclusiveByAddress(memaddrdesc.paddress, ProcessorID(), 64);
    end;

    if accdesc.tagchecked then
        let ltag : bits(4)      = AArch64_LogicalAddressTag(address);
        let fault : FaultRecord = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            AArch64_Abort(fault);
        end;
    end;

    var memstatus : PhysMemRetStatus;
    memstatus = PhysMemWrite{size}(memaddrdesc, accdesc, value);

    // If an access generated by ST64BV or ST64BV0 fails solely because the memory location
    // does not support 64-byte access, then memstatus does not indicate a fault,
    if IsFault(memstatus) then
        HandleExternalWriteAbort(memstatus, memaddrdesc, bytes, accdesc);
    end;

    if SPESampleInFlight then
        let is_load : boolean = FALSE;
        SPESampleLoadStore(is_load, accdesc, memaddrdesc);
    end;

    return memstatus.store64bstatus;
end;

// MemStore64BWithRetStatus()
// ==========================
// Generates the return status of memory write with ST64BV or ST64BV0
// instructions. The status indicates if the operation succeeded, failed,
// or was not supported at this memory location.

impdef func MemStore64BWithRetStatus() => bits(64)
begin
    return Zeros{64};
end;

// NVMem - accessor
// ================

accessor NVMem(offset : integer) <=> value : bits(64)
begin
    // This function is the load memory access for the transformed System register read access
    // when Enhanced Nested Virtualization is enabled with HCR_EL2.NV2 = 1.
    // The address for the load memory access is calculated using
    // the formula SignExtend(VNCR_EL2.BADDR : Offset[11:0], 64) where,
    //  * VNCR_EL2.BADDR holds the base address of the memory location, and
    //  * Offset is the unique offset value defined architecturally for each System register that
    //    supports transformation of register access to memory access.
    getter
        assert offset > 0 && offset MOD 8 == 0;
        let directread : boolean = FALSE;
        let baddr : bits(64)     = EffectiveBADDR(VNCR_EL2().BADDR :: Zeros{12}, directread);
        let address : bits(64)   = baddr + offset;
        let accdesc : AccessDescriptor = CreateAccDescNV2(MemOp_LOAD);
        return Mem{64}(address, accdesc);
    end;

    // This function is the store memory access for the transformed System register write access
    // when Enhanced Nested Virtualization is enabled with HCR_EL2.NV2 = 1.
    // The address for the store memory access is calculated using
    // the formula SignExtend(VNCR_EL2.BADDR : Offset[11:0], 64) where,
    //  * VNCR_EL2.BADDR holds the base address of the memory location, and
    //  * Offset is the unique offset value defined architecturally for each System register that
    //    supports transformation of register access to memory access.
    setter
        assert offset > 0 && offset MOD 8 == 0;
        let directread : boolean = FALSE;
        let baddr : bits(64)     = EffectiveBADDR(VNCR_EL2().BADDR :: Zeros{12}, directread);
        let address : bits(64)   = baddr + offset;
        let accdesc : AccessDescriptor = CreateAccDescNV2(MemOp_STORE);
        Mem{64}(address, accdesc) = value;
        return;
    end;
end;

accessor NVMem128(offset : integer) <=> value : bits(128)
begin
    getter
        assert offset > 0 && offset MOD 16 == 0;
        let directread : boolean = FALSE;
        let baddr : bits(64)     = EffectiveBADDR(VNCR_EL2().BADDR :: Zeros{12}, directread);
        let address : bits(64)   = baddr + offset;
        let accdesc : AccessDescriptor = CreateAccDescNV2(MemOp_LOAD);
        return Mem{128}(address, accdesc);
    end;

    setter
        assert offset > 0 && offset MOD 16 == 0;
        let directread : boolean = FALSE;
        let baddr : bits(64)     = EffectiveBADDR(VNCR_EL2().BADDR :: Zeros{12}, directread);
        let address : bits(64)   = baddr + offset;
        let accdesc : AccessDescriptor = CreateAccDescNV2(MemOp_STORE);
        Mem{128}(address, accdesc) = value;
    end;
end;

// PhysMemTagRead()
// ================
// This is the hardware operation which perform a single-copy atomic,
// Allocation Tag granule aligned, memory access from the tag in PA space.
//
// The function address the array using desc.paddress which supplies:
// * A 52-bit physical address
// * A single NS bit to select between Secure and Non-secure parts of the array.
//
// The accdesc descriptor describes the access type: normal, exclusive, ordered, streaming,
// etc and other parameters required to access the physical memory or for setting syndrome
// register in the event of an External abort.

impdef func PhysMemTagRead(desc : AddressDescriptor,
                           accdesc : AccessDescriptor) => (PhysMemRetStatus, bits(4))
begin
    return (ARBITRARY : PhysMemRetStatus, Zeros{4});
end;

// PhysMemTagWrite()
// =================
// This is the hardware operation which perform a single-copy atomic,
// Allocation Tag granule aligned, memory access to the tag in PA space.
//
// The function address the array using desc.paddress which supplies:
// * A 52-bit physical address
// * A single NS bit to select between Secure and Non-secure parts of the array.
//
// The accdesc descriptor describes the access type: normal, exclusive, ordered, streaming,
// etc and other parameters required to access the physical memory or for setting syndrome
// register in the event of an External abort.

impdef func PhysMemTagWrite(desc : AddressDescriptor,
                            accdesc : AccessDescriptor,
                            value : bits(4)) => PhysMemRetStatus
begin
    return ARBITRARY : PhysMemRetStatus;
end;

// StoreOnlyTagCheckingEnabled()
// =============================
// Returns TRUE if loads executed at the given Exception level are Tag unchecked.

func StoreOnlyTagCheckingEnabled(el : bits(2)) => boolean
begin
    assert IsFeatureImplemented(FEAT_MTE_STORE_ONLY);
    var tcso : bit;

    case el of
        when EL0 =>
            if !ELIsInHost(el) then
                tcso = SCTLR_EL1().TCSO0;
            else
                tcso = SCTLR_EL2().TCSO0;
            end;
        when EL1 =>
            tcso = SCTLR_EL1().TCSO;
        when EL2 =>
            tcso = SCTLR_EL2().TCSO;
        otherwise =>
            tcso = SCTLR_EL3().TCSO;
    end;

    return tcso == '1';
end;

// AArch64_MLBI_ALL()
// ==================
// Invalidate MLB entries associated with the current Security state.

func AArch64_MLBI_ALL(el : bits(2))
begin
    var r : MLBIRecord = NewMLBIRecord(MLBIOp_ALL);
    r.security   = SecurityStateAtEL(el);

    MLBI(r);

    return;
end;

// AArch64_MLBI_VMALL()
// ====================
// Invalidated MLB entries associated with the current Security state that match the
// indicated VMID (where applicable).

func AArch64_MLBI_VMALL(el : bits(2), vmid : bits(16))
begin
    var r : MLBIRecord = NewMLBIRecord(MLBIOp_VMALL);
    r.security   = SecurityStateAtEL(el);
    r.vmid       = vmid;

    MLBI(r);

    return;
end;

// AArch64_MLBI_VPID()
// ===================
// Invalidated MLB entries associated with the current Security state that match the
// indicated vPID in the parameter Xt.

func AArch64_MLBI_VPID(el : bits(2), vmid : bits(16), Xt : bits(64))
begin
    var r : MLBIRecord = NewMLBIRecord(MLBIOp_VPID);
    r.security   = SecurityStateAtEL(el);
    r.vmid       = vmid;
    r.vpid       = Xt[11:0];

    MLBI(r);

    return;
end;

// AArch64_MLBI_VPMG()
// ===================
// Invalidated MLB entries associated with the current Security state that match the
// indicated vPMG in the parameter Xt.

func AArch64_MLBI_VPMG(el : bits(2), vmid : bits(16), Xt : bits(64))
begin
    var r : MLBIRecord = NewMLBIRecord(MLBIOp_VPMG);
    r.security   = SecurityStateAtEL(el);
    r.vmid       = vmid;
    r.vpmg       = Xt[11:0];

    MLBI(r);

    return;
end;

// MLBI()
// ======
// Invalidates MLB entries.

impdef func MLBI(r : MLBIRecord)
begin
    return;
end;

// MLBIOp
// ======

type MLBIOp of enumeration {
    MLBIOp_ALL,
    MLBIOp_VMALL,
    MLBIOp_VPID,
    MLBIOp_VPMG,
};

// MLBRecord
// =========

type MLBIRecord of record {
    op : MLBIOp,
    security : SecurityState,
    vmid : bits(16),
    use_vmid : boolean,
    vpid : bits(12),
    vpmg : bits(12)

};

// NewMLBIRecord()
// ===============

func NewMLBIRecord(op : MLBIOp) => MLBIRecord
begin
    var r : MLBIRecord;
    r.op         = op;
    r.use_vmid   = FALSE;
    r.vmid       = Zeros{16};
    r.vpid       = Zeros{12};
    r.vpmg       = Zeros{12};

    return r;
end;

// ArchMaxMOPSBlockSize
// ====================
// Maximum number of bytes CPY/SET instructions can use

constant ArchMaxMOPSBlockSize : integer{} = 0x7FFF_FFFF_FFFF_FFFF;

// ArchMaxMOPSCPYSize
// ==================
// Maximum number of bytes CPY instructions can use

constant ArchMaxMOPSCPYSize : integer{} = 0x007F_FFFF_FFFF_FFFF;

// ArchMaxMOPSSETGSize
// ===================
// Maximum number of bytes SETG instructions can use

constant ArchMaxMOPSSETGSize : integer{} = 0x7FFF_FFFF_FFFF_FFF0;

// CPYFOptionA()
// =============
// Returns TRUE if the implementation uses Option A for the
// CPYF* instructions, and FALSE otherwise.

func CPYFOptionA() => boolean
begin
    return ImpDefBool("CPYF* instructions use Option A");
end;

// CPYOptionA()
// ============
// Returns TRUE if the implementation uses Option A for the
// CPY* instructions, and FALSE otherwise.

func CPYOptionA() => boolean
begin
    return ImpDefBool("CPY* instructions use Option A");
end;

// CPYParams
// =========

type CPYParams of record {
    stage : MOPSStage,
    implements_option_a : boolean,
    forward : boolean,
    cpysize : integer,
    stagecpysize : integer,
    toaddress : bits(64),
    fromaddress : bits(64),
    nzcv : bits(4),
    n : integer,
    d : integer,
    s : integer
};

// CPYPostSizeChoice()
// ===================
// Returns the size of the copy that is performed by the CPYE* instructions for this
// implementation given the parameters of the destination, source and size of the copy.

impdef func CPYPostSizeChoice(memcpy : CPYParams) => integer
begin
    return ARBITRARY : integer;
end;

// CPYPreSizeChoice()
// ==================
// Returns the size of the copy that is performed by the CPYP* instructions for this
// implementation given the parameters of the destination, source and size of the copy.

impdef func CPYPreSizeChoice(memcpy : CPYParams) => integer
begin
    return ARBITRARY : integer;
end;

// CPYSizeChoice()
// ===============
// Returns the size of the block this performed for an iteration of the copy given the
// parameters of the destination, source and size of the copy.

impdef func CPYSizeChoice(memcpy : CPYParams) => MOPSBlockSize
begin
    return ARBITRARY : MOPSBlockSize;
end;

// CheckCPYConstrainedUnpredictable()
// ==================================
// Check for CONSTRAINED UNPREDICTABLE behaviour in the CPY* and CPYF* instructions.

func CheckCPYConstrainedUnpredictable(n : integer, d : integer, s : integer)
begin
    if (s == n || s == d || n == d) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_MOPSOVERLAP);
        assert c IN {Constraint_UNDEF, Constraint_NOP};
        case c of
            when Constraint_UNDEF =>      Undefined();
            when Constraint_NOP =>        ExecuteAsNOP();
        end;
    end;

    if (d == 31 || s == 31 || n == 31) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_MOPS_R31);
        assert c IN {Constraint_UNDEF, Constraint_NOP};
        case c of
            when Constraint_UNDEF =>      Undefined();
            when Constraint_NOP =>        ExecuteAsNOP();
        end;
    end;
end;

// CheckMOPSEnabled()
// ==================
// Check for EL0 and EL1 access to the CPY* and SET* instructions.

func CheckMOPSEnabled()
begin
    if (PSTATE.EL IN {EL0, EL1} && EL2Enabled() && !ELIsInHost(EL0) &&
        (!IsHCRXEL2Enabled() || HCRX_EL2().MSCEn == '0')) then
        Undefined();
    end;

    if PSTATE.EL == EL0 && !IsInHost() && SCTLR_EL1().MSCEn == '0' then
        Undefined();
    end;

    if PSTATE.EL == EL0 && IsInHost() && SCTLR_EL2().MSCEn == '0' then
        Undefined();
    end;
end;

// CheckMemCpyParams()
// ===================
// Check if the parameters to a CPY* or CPYF* instruction are consistent with the
// PE state and well-formed.

func CheckMemCpyParams(memcpy : CPYParams, options : bits(4))
begin
    let from_epilogue : boolean = memcpy.stage == MOPSStage_Epilogue;

    // Check if this version is consistent with the state of the call.
    if ((memcpy.stagecpysize != 0 || MemStageCpyZeroSizeCheck()) &&
          (memcpy.cpysize != 0 || MemCpyZeroSizeCheck())) then
        let using_option_a : boolean = memcpy.nzcv[1] == '0';
        if memcpy.implements_option_a != using_option_a then
            let formatoption : bits(2) = '1':: (if memcpy.implements_option_a then '1' else '0');
            MismatchedMemCpyException(memcpy, options, formatoption);
        end;
    end;

    // Check if the parameters to this instruction are valid.
    if memcpy.stage == MOPSStage_Main then
        if MemCpyParametersIllformedM(memcpy) then
            let formatoption : bits(2) = '0':: (if memcpy.implements_option_a then '1' else '0');
            MismatchedMemCpyException(memcpy, options, formatoption);
        end;
    else
        let postsize : integer = CPYPostSizeChoice(memcpy);
        if memcpy.cpysize != postsize || MemCpyParametersIllformedE(memcpy) then
            let formatoption : bits(2) = '0':: (if memcpy.implements_option_a then '1' else '0');
            MismatchedMemCpyException(memcpy, options, formatoption);
        end;
    end;

    return;
end;

// CheckMemSetParams()
// ===================
// Check if the parameters to a SET* or SETG* instruction are consistent with the
// PE state and well-formed.

func CheckMemSetParams(memset : SETParams, options : bits(2))
begin
    let from_epilogue : boolean = memset.stage == MOPSStage_Epilogue;

    // Check if this version is consistent with the state of the call.
    if ((memset.stagesetsize != 0 || MemStageSetZeroSizeCheck()) &&
          (memset.setsize != 0 || MemSetZeroSizeCheck())) then
        let using_option_a : boolean = memset.nzcv[1] == '0';
        if memset.implements_option_a != using_option_a then
            let formatoption : bits(2) = '1':: (if memset.implements_option_a then '1' else '0');
            MismatchedMemSetException(memset, options, formatoption);
        end;
    end;

    // Check if the parameters to this instruction are valid.
    if memset.stage == MOPSStage_Main then
        if MemSetParametersIllformedM(memset) then
            let formatoption : bits(2) = '0':: (if memset.implements_option_a then '1' else '0');
            MismatchedMemSetException(memset, options, formatoption);
        end;
    else
        let postsize : integer = SETPostSizeChoice(memset);
        if memset.setsize != postsize || MemSetParametersIllformedE(memset) then
            let formatoption : bits(2) = '0':: (if memset.implements_option_a then '1' else '0');
            MismatchedMemSetException(memset, options, formatoption);
        end;
    end;

    return;
end;

// CheckSETConstrainedUnpredictable()
// ==================================
// Check for CONSTRAINED UNPREDICTABLE behaviour in the SET* and SETG* instructions.

func CheckSETConstrainedUnpredictable(n : integer, d : integer, s : integer)
begin
    if (s == n || s == d || n == d) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_MOPSOVERLAP);
        assert c IN {Constraint_UNDEF, Constraint_NOP};
        case c of
            when Constraint_UNDEF =>      Undefined();
            when Constraint_NOP =>        ExecuteAsNOP();
        end;
    end;

    if (d == 31 || n == 31) then
        let c : Constraint = ConstrainUnpredictable(Unpredictable_MOPS_R31);
        assert c IN {Constraint_UNDEF, Constraint_NOP};
        case c of
            when Constraint_UNDEF =>      Undefined();
            when Constraint_NOP =>        ExecuteAsNOP();
        end;
    end;
end;

// IsMemCpyForward()
// =================
// Returns TRUE if in a memcpy of size cpysize bytes from the source address fromaddress
// to destination address toaddress is done in the forward direction on this implementation.

func IsMemCpyForward(memcpy : CPYParams) => boolean
begin
    var forward : boolean;

    // Check for overlapping cases
    if ((UInt(memcpy.fromaddress[55:0]) > UInt(memcpy.toaddress[55:0])) &&
          (UInt(memcpy.fromaddress[55:0]) < UInt(ZeroExtend{64}(memcpy.toaddress[55:0]) +
             memcpy.cpysize))) then
        forward = TRUE;

    elsif ((UInt(memcpy.fromaddress[55:0]) < UInt(memcpy.toaddress[55:0])) &&
             (UInt(ZeroExtend{64}(memcpy.fromaddress[55:0]) + memcpy.cpysize) >
                UInt(memcpy.toaddress[55:0]))) then
        forward = FALSE;

    // Non-overlapping case
    else
        forward = ImpDefBool("CPY in the forward direction");
    end;

    return forward;
end;

// MOPSBlockSize
// ================

type MOPSBlockSize of integer{0..MaxMOPSBlockSize};

// MOPSStage
// =========

type MOPSStage of enumeration { MOPSStage_Prologue, MOPSStage_Main, MOPSStage_Epilogue };

// MaxBlockSizeCopiedBytes()
// =========================
// Returns the maximum number of bytes that can used in a single block of the copy.

func MaxBlockSizeCopiedBytes() => integer
begin
    return ImpDefInt("Maximum bytes used in a single block of a copy");
end;

// MaxMOPSBlockSize
// ================
// Maximum number of bytes CPY/SET instructions can use

config MaxMOPSBlockSize : integer{1..ArchMaxMOPSBlockSize} = 64;

// MemCpyBytes()
// =============
// Copies 'bytes' bytes of memory from fromaddress to toaddress.
// The integer return parameter indicates the number of bytes copied. The boolean return parameter
// indicates if a Fault or Abort occurred on the write. The AddressDescriptor and PhysMemRetStatus
// parameters contain Fault or Abort information for the caller to handle.

func MemCpyBytes(toaddress : bits(64),
                 fromaddress : bits(64),
                 forward : boolean,
                 bytes : MOPSBlockSize,
                 raccdesc : AccessDescriptor,
                 waccdesc : AccessDescriptor
                ) => (integer, boolean, AddressDescriptor, PhysMemRetStatus)
begin
    var rmemaddrdesc : AddressDescriptor;                 // AddressDescriptor for reads
    var rmemstatus : PhysMemRetStatus;                   // PhysMemRetStatus  for writes
    rmemaddrdesc.fault    = NoFault();
    rmemstatus.statuscode = Fault_None;

    var wmemaddrdesc : AddressDescriptor;                 // AddressDescriptor for writes
    var wmemstatus : PhysMemRetStatus;                   // PhysMemRetStatus  for writes
    wmemaddrdesc.fault    = NoFault();
    wmemstatus.statuscode = Fault_None;

    var value : bits(8*bytes);
    let aligned : boolean = TRUE;

    if forward then
        var read : integer  = 0;                          // Bytes read
        var write : integer = 0;                          // Bytes written

        // Read until all bytes are read or until a fault is encountered.
        while (read < bytes && !IsFault(rmemaddrdesc) && !IsFault(rmemstatus))
                                            looplimit MaxMOPSBlockSize do
            (value[8 * read +:8], rmemaddrdesc, rmemstatus) = AArch64_MemSingleRead{8}(
                                                                            fromaddress + read,
                                                                            raccdesc, aligned);
            read = read + 1;
        end;

        // Ensure no UNKNOWN data is written.
        if IsFault(rmemaddrdesc) || IsFault(rmemstatus) then
            read = read - 1;
        end;

        // Write all bytes that were read or until a fault is encountered.
        while write < read && !IsFault(wmemaddrdesc) && !IsFault(wmemstatus)
                                        looplimit MaxMOPSBlockSize  do
            (wmemaddrdesc, wmemstatus) = AArch64_MemSingleWrite{8}(toaddress + write,
                                                                waccdesc, aligned,
                                                                value[8 * write +:8]);
            write = write + 1;
        end;

        // Check all bytes were written.
        if IsFault(wmemaddrdesc) || IsFault(wmemstatus) then
            let fault_on_write : boolean = TRUE;
            return (write - 1, fault_on_write, wmemaddrdesc, wmemstatus);
        end;

        // Check all bytes were read.
        if IsFault(rmemaddrdesc) || IsFault(rmemstatus) then
            let fault_on_write : boolean = FALSE;
            return (read, fault_on_write, rmemaddrdesc, rmemstatus);
        end;

    else
        var read : integer  = bytes;                      // Bytes to read
        var write : integer = bytes;                      // Bytes to write

        // Read until all bytes are read or until a fault is encountered.
        while read > 0 && !IsFault(rmemaddrdesc) && !IsFault(rmemstatus)
                                            looplimit MaxMOPSBlockSize do
            read = read - 1;
            (value[8 * read +:8], rmemaddrdesc, rmemstatus) = AArch64_MemSingleRead{8}(
                                                                            fromaddress + read,
                                                                            raccdesc, aligned);
        end;

        // Ensure no UNKNOWN data is written.
        if IsFault(rmemaddrdesc) || IsFault(rmemstatus) then
            read = read + 1;
        end;

        // Write all bytes that were read or until a fault is encountered.
        while write > read && !IsFault(wmemaddrdesc) && !IsFault(wmemstatus)
                                                looplimit MaxMOPSBlockSize do
            write = write - 1;
            (wmemaddrdesc, wmemstatus) = AArch64_MemSingleWrite{8}(toaddress + write,
                                                                waccdesc, aligned,
                                                                value[8 * write +:8]);
        end;

        // Check all bytes were written.
        if IsFault(wmemaddrdesc) || IsFault(wmemstatus) then
            let fault_on_write : boolean = TRUE;
            return (bytes - (write + 1), fault_on_write, wmemaddrdesc, wmemstatus);
        end;

        // Check all bytes were read.
        if IsFault(rmemaddrdesc) || IsFault(rmemstatus) then
            let fault_on_write : boolean = FALSE;
            return (bytes - read, fault_on_write, rmemaddrdesc, rmemstatus);
        end;
    end;

    // Return any AddressDescriptor and PhysMemRetStatus.
    return (bytes, FALSE, wmemaddrdesc, wmemstatus);
end;

// MemCpyParametersIllformedE()
// ============================
// Returns TRUE if the inputs are not well formed (in terms of their size and/or alignment)
// for a CPYE* instruction for this implementation given the parameters of the destination,
// source and size of the copy.

impdef func MemCpyParametersIllformedE(memcpy : CPYParams) => boolean
begin
    return FALSE;
end;

// MemCpyParametersIllformedM()
// ============================
// Returns TRUE if the inputs are not well formed (in terms of their size and/or alignment)
// for a CPYM* instruction for this implementation given the parameters of the destination,
// source and size of the copy.

impdef func MemCpyParametersIllformedM(memcpy : CPYParams) => boolean
begin
    return FALSE;
end;

// MemCpyStageSize()
// =================
// Returns the number of bytes copied by the given stage of a CPY* or CPYF* instruction.

func MemCpyStageSize(memcpy : CPYParams) => integer
begin
    var stagecpysize : integer;

    if memcpy.stage == MOPSStage_Prologue then
        // IMP DEF selection of the amount covered by pre-processing.
        stagecpysize = CPYPreSizeChoice(memcpy);
        assert stagecpysize == 0 || (stagecpysize < 0) == (memcpy.cpysize < 0);

        if memcpy.cpysize > 0 then
            assert stagecpysize <= memcpy.cpysize;
        else
            assert stagecpysize >= memcpy.cpysize;
        end;

    else
        let postsize : integer = CPYPostSizeChoice(memcpy);
        assert postsize == 0 || (postsize < 0) == (memcpy.cpysize < 0);

        if memcpy.stage == MOPSStage_Main then
            stagecpysize = memcpy.cpysize - postsize;
        else
            stagecpysize = postsize;
        end;
    end;

    return stagecpysize;
end;

// MemCpyZeroSizeCheck()
// =====================
// Returns TRUE if the implementation option is checked on a copy of size zero remaining.

func MemCpyZeroSizeCheck() => boolean
begin
    return ImpDefBool("Implementation option is checked with a cpysize of 0");
end;

// MemSetBytes()
// =============
// Writes a byte of data to the given address 'bytes' times.
// The integer return parameter indicates the number of bytes set. The AddressDescriptor and
// PhysMemRetStatus parameters contain Fault or Abort information for the caller to handle.

func MemSetBytes(toaddress : bits(64), data : bits(8),
                 bytes : MOPSBlockSize,
                 accdesc : AccessDescriptor) => (integer, AddressDescriptor, PhysMemRetStatus)
begin
    var memaddrdesc : AddressDescriptor;
    var memstatus : PhysMemRetStatus;
    memaddrdesc.fault    = NoFault();
    memstatus.statuscode = Fault_None;

    let aligned : boolean = TRUE;
    var write : integer   = 0;                            // Bytes written

    // Write until all bytes are written or a fault is encountered.
    while write < bytes && !IsFault(memaddrdesc) && !IsFault(memstatus)
                                                looplimit MaxMOPSBlockSize do
        (memaddrdesc, memstatus) = AArch64_MemSingleWrite{8}(toaddress + write, accdesc,
                                                             aligned, data);
        write = write + 1;
    end;

    // Check all bytes were written.
    if IsFault(memaddrdesc) || IsFault(memstatus) then
        return (write - 1, memaddrdesc, memstatus);
    end;

    return (bytes, memaddrdesc, memstatus);
end;

// MemSetParametersIllformedE()
// ============================
// Returns TRUE if the inputs are not well formed (in terms of their size and/or
// alignment) for a SETE* or SETGE* instruction for this implementation given the
// parameters of the destination and size of the set.

impdef func MemSetParametersIllformedE(memset : SETParams) => boolean
begin
    return FALSE;
end;

// MemSetParametersIllformedM()
// ============================
// Returns TRUE if the inputs are not well formed (in terms of their size and/or
// alignment) for a SETM* or SETGM* instruction for this implementation given the
// parameters of the destination and size of the copy.

impdef func MemSetParametersIllformedM(memset : SETParams) => boolean
begin
    return FALSE;
end;

// MemSetStageSize()
// =================
// Returns the number of bytes set by the given stage of a SET* or SETG* instruction.

func MemSetStageSize(memset : SETParams) => integer
begin
    var stagesetsize : integer;

    if memset.stage == MOPSStage_Prologue then
        // IMP DEF selection of the amount covered by pre-processing.
        stagesetsize = SETPreSizeChoice(memset);
        assert stagesetsize == 0 || (stagesetsize < 0) == (memset.setsize < 0);

        if memset.is_setg then assert stagesetsize[3:0] == '0000'; end;

        if memset.setsize > 0 then
            assert stagesetsize <= memset.setsize;
        else
            assert stagesetsize >= memset.setsize;
        end;

    else
        let postsize : integer = SETPostSizeChoice(memset);
        assert postsize == 0 || (postsize < 0) == (memset.setsize < 0);
        if memset.is_setg then assert postsize[3:0] == '0000'; end;

        if memset.stage == MOPSStage_Main then
            stagesetsize = memset.setsize - postsize;
        else
            stagesetsize = postsize;
        end;
    end;

    return stagesetsize;
end;

// MemSetTags()
// ============
// Write Allocation Tags for each Tag Granule in 'size'.
// The integer return parameter indicates the number of Tag Granules written. The
// AddressDescriptor and PhysMemRetStatus parameters contain Fault or Abort information for
// the caller to handle.

func MemSetTags(toaddress : bits(64), tag : bits(4),
                size : integer, accdesc : AccessDescriptor
            ) => (integer, AddressDescriptor, PhysMemRetStatus)
begin
    assert IsAlignedSize{64}(toaddress, TAG_GRANULE) && size MOD TAG_GRANULE == 0;

    var memaddrdesc : AddressDescriptor;
    var memstatus : PhysMemRetStatus;
    memaddrdesc.fault     = NoFault();
    memstatus.statuscode  = Fault_None;
    var tagstep : integer = size DIV TAG_GRANULE;

    // Write until all tags are written or a fault is encountered.
    while tagstep > 0 && !IsFault(memaddrdesc) && !IsFault(memstatus)
                                                looplimit ArchMaxMOPSSETGSize DIV TAG_GRANULE do
        let tagaddr : bits(64) = toaddress + (tagstep - 1) * TAG_GRANULE;
        (memaddrdesc, memstatus) = AArch64_MemTagWrite(tagaddr, accdesc, tag);
        tagstep = tagstep - 1;
    end;

    if IsFault(memaddrdesc) || IsFault(memstatus) then
        tagstep = tagstep + 1;
    end;

    let tags_written : integer = (size DIV TAG_GRANULE) - tagstep;
    return (tags_written, memaddrdesc, memstatus);
end;

