// ProtectionEnabled()
// ===================
// Returns TRUE if the ProtectedBit is
// enabled in the current Exception level.

func ProtectionEnabled(el : bits(2)) => boolean
begin
    assert HaveEL(el);
    let regime : bits(2) = S1TranslationRegime(el);
    assert(!ELUsingAArch32(regime));
    if (!IsD128Enabled(el)) then
        case regime of
            when EL1 =>
                return IsTCR2EL1Enabled() && TCR2_EL1().PnCH == '1';
            when EL2 =>
                return IsTCR2EL2Enabled() && TCR2_EL2().PnCH == '1';
            when EL3 =>
                return TCR_EL3().PnCH == '1';
        end;
    else
        return TRUE;
    end;
    return FALSE;
end;

// RCWCheck()
// ==========
// Returns nzcv based on : if the new value for RCW/RCWS instructions satisfy RCW and/or RCWS checks
// Z is set to 1 if RCW checks fail
// C is set to 0 if RCWS checks fail

func RCWCheck{N}(old : bits(N), new : bits(N), soft : boolean) => bits(4)
begin
    assert N IN {64,128};
    let protectedbit : integer = if N == 128 then RCW128_PROTECTED_BIT else RCW64_PROTECTED_BIT;
    var rcw_fail : boolean        = FALSE;
    var rcws_fail : boolean       = FALSE;
    var rcw_state_fail : boolean  = FALSE;
    var rcws_state_fail : boolean = FALSE;
    var rcw_mask_fail : boolean   = FALSE;
    var rcws_mask_fail : boolean  = FALSE;

    //Effective RCWMask calculation
    var rcwmask : bits(N) = RCWMASK_EL1()[N-1:0];
    if N == 64 then
        rcwmask[49:18] = Replicate{32}(rcwmask[17]);
        rcwmask[0] = '0';
    else
        rcwmask[55:17] = Replicate{39}(rcwmask[16]);
        rcwmask[126:125,120:119,107:101,90:56,1:0] = Zeros{48};
    end;

    //Effective RCWSMask calculation
    var rcwsoftmask : bits(N) = RCWSMASK_EL1()[N-1:0];
    if N == 64 then
        rcwsoftmask[49:18] = Replicate{32}(rcwsoftmask[17]);
        rcwsoftmask[0] = '0';
        if(ProtectionEnabled(PSTATE.EL)) then
            rcwsoftmask[52] = '0';
        end;
    else
        rcwsoftmask[55:17] = Replicate{39}(rcwsoftmask[16]);
        rcwsoftmask[126:125,120:119,107:101,90:56,1:0] = Zeros{48};
        rcwsoftmask[114] = '0';
    end;

    //RCW Checks
    //State Check
    if (ProtectionEnabled(PSTATE.EL)) then
        if old[protectedbit] == '1' then
            rcw_state_fail = new[protectedbit,0] != old[protectedbit,0];
        elsif old[protectedbit] == '0' then
            rcw_state_fail = new[protectedbit] != old[protectedbit];
        end;
    end;

    //Mask Check
    if (ProtectionEnabled(PSTATE.EL)) then
        if old[protectedbit,0] == '11' then
            rcw_mask_fail = !IsZero((new XOR old) AND NOT(rcwmask));
        end;
    end;

    //RCWS Checks
    if soft then
        //State Check
        if old[0] == '1' then
            rcws_state_fail = new[0] != old[0];
        elsif (!ProtectionEnabled(PSTATE.EL) ||
              (ProtectionEnabled(PSTATE.EL) && old[protectedbit] == '0')) then
            rcws_state_fail = new[0] != old[0] ;
        end;
        //Mask Check
        if old[0] == '1' then
            rcws_mask_fail = !IsZero((new XOR old) AND NOT(rcwsoftmask));
        end;
    end;

    rcw_fail = rcw_state_fail  || rcw_mask_fail ;
    rcws_fail = rcws_state_fail || rcws_mask_fail;

    let n : bit = '0';
    let z : bit = if rcw_fail then '1' else '0';
    let c : bit = if rcws_fail then '0' else '1';
    let v : bit = '0';
    return n::z::c::v;
end;

// FPReduce()
// ==========
// Perform the floating-point operation 'op' on pairs of elements from the input vector,
// reducing the vector to a scalar result.

func FPReduce{esize, N}(op : ReduceOp, input : bits(N),
                        fpcr : FPCR_Type) => bits(esize) recurselimit 8
begin
    var hi : bits(esize);
    var lo : bits(esize);
    var result : bits(esize);
    let half : integer{} = N DIV 2;

    if N == esize then
        return input[esize-1:0];
    end;

    hi = FPReduce{esize, (N - N DIV 2)}(op, input[N-1:half], fpcr);
    lo = FPReduce{esize, N DIV 2}(op, input[half-1:0], fpcr);
    case op of
        when ReduceOp_FMINNUM =>
            result = FPMinNum{esize}(lo, hi, fpcr);
        when ReduceOp_FMAXNUM =>
            result = FPMaxNum{esize}(lo, hi, fpcr);
        when ReduceOp_FMIN =>
            result = FPMin{esize}(lo, hi, fpcr);
        when ReduceOp_FMAX =>
            result = FPMax{esize}(lo, hi, fpcr);
        when ReduceOp_FADD =>
            result = FPAdd{esize}(lo, hi, fpcr);
    end;

    return result;
end;

// IntReduce()
// ===========
// Perform the integer operation 'op' on pairs of elements from the input vector,
// reducing the vector to a scalar result.

func IntReduce{esize, N}(op : ReduceOp, input : bits(N)) => bits(esize) recurselimit 8
begin
    var hi : bits(esize);
    var lo : bits(esize);
    var result : bits(esize);
    let half : integer{} = N DIV 2;
    if N == esize then
        return input[esize-1:0];
    end;

    hi = IntReduce{esize, (N - N DIV 2)}(op, input[N-1:half]);
    lo = IntReduce{esize, N DIV 2}(op, input[half-1:0]);
    case op of
        when ReduceOp_ADD =>
            result = lo + hi;
    end;

    return result;
end;

// ReduceOp
// ========
// Vector reduce instruction types.

type ReduceOp of enumeration {ReduceOp_FMINNUM, ReduceOp_FMAXNUM,
                              ReduceOp_FMIN, ReduceOp_FMAX,
                              ReduceOp_FADD, ReduceOp_ADD};

// AArch64_MaybeZeroRegisterUppers()
// =================================
// On taking an exception to  AArch64 from AArch32, it is CONSTRAINED UNPREDICTABLE whether the top
// 32 bits of registers visible at any lower Exception level using AArch32 are set to zero.

func AArch64_MaybeZeroRegisterUppers()
begin
    assert UsingAArch32();         // Always called from AArch32 state before entering AArch64 state

    var first : integer;
    var last : integer;
    var include_R15 : boolean;
    if PSTATE.EL == EL0 && !ELUsingAArch32(EL1) then
        first = 0;  last = 14;  include_R15 = FALSE;
    elsif PSTATE.EL IN {EL0, EL1} && EL2Enabled() && !ELUsingAArch32(EL2) then
        first = 0;  last = 30;  include_R15 = FALSE;
    else
        first = 0;  last = 30;  include_R15 = TRUE;
    end;

    for n = first to last do
        if (n != 15 || include_R15) && ConstrainUnpredictableBool(Unpredictable_ZEROUPPER) then
            _R[[n]][63:32] = Zeros{32};
        end;
    end;

    return;
end;

// AArch64_ResetGeneralRegisters()
// ===============================

func AArch64_ResetGeneralRegisters()
begin

    for i = 0 to 30 do
        X{64}(i) = ARBITRARY : bits(64);
    end;
end;

// AArch64_ResetSIMDFPRegisters()
// ==============================

func AArch64_ResetSIMDFPRegisters()
begin

    for i = 0 to 31 do
        V{128}(i) = ARBITRARY : bits(128);
    end;
end;

// AArch64_ResetSpecialRegisters()
// ===============================

func AArch64_ResetSpecialRegisters()
begin

    // AArch64 special registers
    SP_EL0()       = ARBITRARY : bits(64);
    SP_EL1()       = ARBITRARY : bits(64);

    SPSR_EL1()     = ARBITRARY : bits(64);
    ELR_EL1()      = ARBITRARY : bits(64);
    if HaveEL(EL2) then
        SP_EL2()   = ARBITRARY : bits(64);
        SPSR_EL2() = ARBITRARY : bits(64);
        ELR_EL2()  = ARBITRARY : bits(64);
    end;

    // AArch32 special registers that are not architecturally mapped to AArch64 registers
    if HaveAArch32EL(EL1) then
        SPSR_fiq()[31:0] = ARBITRARY : bits(32);
        SPSR_irq()[31:0] = ARBITRARY : bits(32);
        SPSR_abt()[31:0] = ARBITRARY : bits(32);
        SPSR_und()[31:0] = ARBITRARY : bits(32);
    end;

    // External debug special registers
    DLR_EL0()   = ARBITRARY : bits(64);
    DSPSR_EL0() = ARBITRARY : bits(64);

    return;
end;

// AArch64_ResetSystemRegisters()
// ==============================

impdef func AArch64_ResetSystemRegisters(cold_reset : boolean)
begin
    return;
end;

// PC64 - getter
// =============
// Read 64-bit program counter.

func PC64() => bits(64)
begin
    return _PC;
end;

// SP - accessor
// =============

accessor SP{width}() <=> value : bits(width)
begin
    // Write a 32-bit or 64-bit value to the current stack pointer.
    setter
        assert width IN {64, 32};
        if PSTATE.SP == '0' then
            SP_EL0() = ZeroExtend{64}(value);
        else
            case PSTATE.EL of
                when EL0 =>  SP_EL0() = ZeroExtend{64}(value);
                when EL1 =>  SP_EL1() = ZeroExtend{64}(value);
                when EL2 =>  SP_EL2() = ZeroExtend{64}(value);
                when EL3 =>  SP_EL3() = ZeroExtend{64}(value);
            end;
        end;
    end;

    // Read the least-significant 32 or 64 bits from the current stack pointer.
    getter
        assert width IN {64, 32};
        if PSTATE.SP == '0' then
            return SP_EL0()[width-1:0];
        else
            case PSTATE.EL of
                when EL0 =>  return SP_EL0()[width-1:0];
                when EL1 =>  return SP_EL1()[width-1:0];
                when EL2 =>  return SP_EL2()[width-1:0];
                when EL3 =>  return SP_EL3()[width-1:0];
            end;
        end;
    end;
end;

// X - accessor
// ============

accessor X{width}(n : integer) <=> value : bits(width)
begin
    // Write a 32-bit or 64-bit value to a general-purpose register.
    setter
        assert n >= 0 && n <= 31;
        assert width IN {32,64};
        if n != 31 then
            _R[[n]] = ZeroExtend{64}(value);
        end;
        return;
    end;

    // Read the least-significant 8, 16, 32, or 64 bits from a general-purpose register.
    getter
        assert n >= 0 && n <= 31;
        let rw : integer{} = width as integer{8, 16, 32, 64};
        if n != 31 then
            return _R[[n]][rw-1:0];
        else
            return Zeros{rw};
        end;
    end;
end;

// X - accessor
// ============

accessor X{width}(lr : integer, hr : integer) <=> value : bits(width)
begin
    // Write a 128-bit value to two general-purpose registers.
    setter
        assert width == 128;
        let half : integer{} = width DIV 2;
        X{half}(lr)          = value[0+:half];
        X{half}(hr)          = value[half+:half];
        return;
    end;

    // Read 128 bits from two separate general-purpose registers.
    getter
        assert width == 128;
        let half : integer{} = width DIV 2;
        return X{half}(hr) :: X{half}(lr);
    end;
end;

// DecodeShift()
// =============
// Decode shift encodings

func DecodeShift(op : bits(2)) => ShiftType
begin
    case op of
        when '00' =>  return ShiftType_LSL;
        when '01' =>  return ShiftType_LSR;
        when '10' =>  return ShiftType_ASR;
        when '11' =>  return ShiftType_ROR;
    end;
end;

// ShiftReg()
// ==========
// Perform shift of a register operand

func ShiftReg{N}(reg : integer, shiftype : ShiftType, amount : integer) => bits(N)
begin
    var result : bits(N) = X{}(reg);
    case shiftype of
        when ShiftType_LSL => result = LSL(result, amount);
        when ShiftType_LSR => result = LSR(result, amount);
        when ShiftType_ASR => result = ASR(result, amount);
        when ShiftType_ROR => result = ROR(result, amount);
    end;
    return result;
end;

// ShiftType
// =========
// AArch64 register shifts.

type ShiftType of enumeration {ShiftType_LSL, ShiftType_LSR, ShiftType_ASR, ShiftType_ROR};

// CounterToPredicate()
// ====================

func CounterToPredicate{width}(pred : bits(16)) => bits(width)
begin
    var count : integer;
    var esize : ESize;
    var elements : integer;
    let VL : VecLen  = CurrentVL();
    let PL : PredLen = VL DIV 8;
    let maxbit : integer{} = FloorLog2(PL * 4) as integer{0..14};
    var result : bits(PL*4);
    let invert : boolean = pred[15] == '1';

    assert width == PL || width == PL*2 || width == PL*3 || width == PL*4;

    case pred[3:0] of
        when '0000' =>
            return Zeros{width};
        when 'xxx1' =>
            count = UInt(pred[maxbit:1]);
            esize = 8;
        when 'xx10' =>
            count = UInt(pred[maxbit:2]);
            esize = 16;
        when 'x100' =>
            count = UInt(pred[maxbit:3]);
            esize = 32;
        when '1000' =>
            count = UInt(pred[maxbit:4]);
            esize = 64;
    end;

    elements = (VL * 4) DIV esize;
    result = Zeros{PL*4};
    let psize : integer{} = esize DIV 8;
    for e = 0 to elements-1 do
        var pbit : bit = if e < count then '1' else '0';
        if invert then
            pbit = NOT(pbit);
        end;
        result[e*:psize] = ZeroExtend{psize}(pbit);
    end;

    return result[width-1:0];
end;

// EncodePredCount()
// =================

func EncodePredCount{width}(esize : ESize, elements : integer,
                            count_in : integer, invert_in : boolean) => bits(width)
begin
    var count : integer  = count_in;
    var invert : boolean = invert_in;
    let PL : PredLen = CurrentVL() DIV 8;
    assert width == PL;
    assert count >=0 && count <= elements;
    var pred : bits(16);

    if count == 0 then
        return Zeros{width};
    end;

    if invert then
        count = elements - count;
    elsif count == elements then
        count = 0;
        invert = TRUE;
    end;

    let inv : bit = (if invert then '1' else '0');
    case esize of
        when 8 =>  pred = inv :: count[13:0] ::    '1';
        when 16 => pred = inv :: count[12:0] ::   '10';
        when 32 => pred = inv :: count[11:0] ::  '100';
        when 64 => pred = inv :: count[10:0] :: '1000';
    end;

    return ZeroExtend{width}(pred);
end;

// Lookup Table
// ============

var _ZT0 : bits(ZT0_LEN);

// PredCountTest()
// ===============

func PredCountTest(elements : integer, count : integer, invert : boolean) => bits(4)
begin
    var n, z, c, v : bit;
    z = (if count == 0 then '1' else '0');              // none active
    if !invert then
        n = (if count != 0 then '1' else '0');          // first active
        c = (if count == elements then '0' else '1');   // NOT last active
    else
        n = (if count == elements then '1' else '0');   // first active
        c = (if count != 0 then '0' else '1');          // NOT last active
    end;
    v = '0';

    return n::z::c::v;
end;

// System Registers
// ================

var _ZA : array [[256]] of bits(MAX_VL);

// ZAhslice - accessor
// ===================

accessor ZAhslice{width}(tile : integer, esize : ESize, slice : integer) <=> value : bits(width)
begin
    getter
        let tiles : integer = esize DIV 8;
        assert tile >= 0 && tile < tiles;
        let slices : integer = CurrentSVL() DIV esize;
        assert slice >= 0 && slice < slices;

        return ZAvector{width}(tile + slice * tiles);
    end;
    setter
        let tiles : integer = esize DIV 8;
        assert tile >= 0 && tile < tiles;
        let slices : integer = CurrentSVL() DIV esize;
        assert slice >= 0 && slice < slices;

        ZAvector{width}(tile + slice * tiles) = value;
    end;
end;

// ZAslice - accessor
// ==================

accessor ZAslice{width}(tile : integer, esize : ESize,
                        vertical : boolean, slice : integer) <=> value : bits(width)
begin
    getter
        var result : bits(width);

        if vertical then
            result = ZAvslice{width}(tile, esize, slice);
        else
            result = ZAhslice{width}(tile, esize, slice);
        end;

        return result;
    end;
    setter
        if vertical then
            ZAvslice{width}(tile, esize, slice) = value;
        else
            ZAhslice{width}(tile, esize, slice) = value;
        end;
    end;
end;

// ZAtile - accessor
// =================

accessor ZAtile{width}(tile : integer, esize : ESize) <=> value : bits(width)
begin
    getter
        let SVL : VecLen = CurrentSVL();
        let slices : integer = SVL DIV esize;
        assert width == SVL * slices;
        var result : bits(width);

        for slice = 0 to slices-1 do
            result[slice*:SVL] = ZAhslice{SVL}(tile, esize, slice);
        end;

        return result;
    end;
    setter
        let SVL : VecLen = CurrentSVL();
        let slices : integer = SVL DIV esize;
        assert width == SVL * slices;

        for slice = 0 to slices-1 do
            ZAhslice{SVL}(tile, esize, slice) = value[slice*:SVL];
        end;
    end;
end;

// ZAvector - accessor
// ===================

accessor ZAvector{width}(index : integer) <=> value : bits(width)
begin
    getter
        assert width == CurrentSVL();
        assert index >= 0 && index < (width DIV 8);

        return _ZA[[index]][width-1:0];
    end;

    setter
        assert width == CurrentSVL();
        assert index >= 0 && index < (width DIV 8);

        if ConstrainUnpredictableBool(Unpredictable_SMEZEROUPPER) then
            _ZA[[index]] = ZeroExtend{MAX_VL}(value);
        else
            _ZA[[index]][width-1:0] = value;
        end;
    end;
end;

// ZAvslice - accessor
// ===================

accessor ZAvslice{width}(tile : integer, esize : ESize, slice : integer) <=> value : bits(width)
begin
    getter
        let slices : integer = CurrentSVL() DIV esize;
        var result : bits(width);

        for s = 0 to slices-1 do
            let hslice : bits(width) = ZAhslice{}(tile, esize, s);
            result[s*:esize] = hslice[slice*:esize];
        end;

        return result;
    end;

    setter
        let slices : integer = CurrentSVL() DIV esize;

        for s = 0 to slices-1 do
            var hslice : bits(width) = ZAhslice{}(tile, esize, s);
            hslice[slice*:esize] = value[s*:esize];
            ZAhslice{width}(tile, esize, s) = hslice;
        end;
    end;
end;

// ZT0 - accessor
// ==============

accessor ZT0{width}() <=> value : bits(width)
begin
    getter
        assert width == ZT0_LEN;
        return _ZT0[width-1:0];
    end;
    setter
        assert width == ZT0_LEN;
        _ZT0[width-1:0] = value;
    end;
end;

// AArch32_IsFPEnabled()
// =====================
// Returns TRUE if access to the SIMD&FP instructions or System registers are
// enabled at the target exception level in AArch32 state and FALSE otherwise.

func AArch32_IsFPEnabled(el : bits(2)) => boolean
begin
    if el == EL0 && !ELUsingAArch32(EL1) then
        return AArch64_IsFPEnabled(el);
    end;

    if HaveEL(EL3) && ELUsingAArch32(EL3) && CurrentSecurityState() == SS_NonSecure then
        // Check if access disabled in NSACR
        if NSACR().cp10 == '0' then return FALSE; end;
    end;

    if el IN {EL0, EL1} then
        // Check if access disabled in CPACR
        var disabled : boolean;
        case CPACR().cp10 of
            when '00' => disabled = TRUE;
            when '01' => disabled = el == EL0;
            when '10' => disabled = ConstrainUnpredictableBool(Unpredictable_RESCPACR);
            when '11' => disabled = FALSE;
        end;
        if disabled then return FALSE; end;
    end;

    if el IN {EL0, EL1, EL2} && EL2Enabled() then
        if !ELUsingAArch32(EL2) then
            return AArch64_IsFPEnabled(EL2);
        end;
        if HCPTR().TCP10 == '1' then return FALSE; end;
    end;

    if HaveEL(EL3) && !ELUsingAArch32(EL3) then
        // Check if access disabled in CPTR_EL3
        if CPTR_EL3().TFP == '1' then return FALSE; end;
    end;

    return TRUE;
end;

// AArch64_IsFPEnabled()
// =====================
// Returns TRUE if access to the SIMD&FP instructions or System registers are
// enabled at the target exception level in AArch64 state and FALSE otherwise.

func AArch64_IsFPEnabled(el : bits(2)) => boolean
begin
    // Check if access disabled in CPACR_EL1
    if el IN {EL0, EL1} && !IsInHost() then
        // Check SIMD&FP at EL0/EL1
        var disabled : boolean;
        case CPACR_EL1().FPEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = el == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then return FALSE; end;
    end;

    // Check if access disabled in CPTR_EL2
    if el IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            var disabled : boolean;
            case CPTR_EL2().FPEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = el == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then return FALSE; end;
        else
            if CPTR_EL2().TFP == '1' then return FALSE; end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().TFP == '1' then return FALSE; end;
    end;

    return TRUE;
end;

// ActivePredicateElement()
// ========================
// Returns TRUE if the predicate bit is 1 and FALSE otherwise

func ActivePredicateElement{N}(pred : bits(N), e : integer, esize : integer) => boolean
begin
    assert esize IN {8, 16, 32, 64, 128};
    let n : integer = e * (esize DIV 8);
    assert n >= 0 && n < N;
    return pred[n] == '1';
end;

// AllElementsActive()
// ===================
// Return TRUE if all the elements are active in the mask. Otherwise,
// return FALSE.

func AllElementsActive{N}(mask : bits(N), esize : integer) => boolean
begin
    let elements : integer = N DIV (esize DIV 8);
    var active : integer = 0;
    for e = 0 to elements-1 do
        if ActivePredicateElement{N}(mask, e, esize) then active = active + 1; end;
    end;
    return active == elements;
end;

// AnyActiveElement()
// ==================
// Return TRUE if there is at least one active element in mask. Otherwise,
// return FALSE.

func AnyActiveElement{N}(mask : bits(N), esize : integer) => boolean
begin
    return LastActiveElement{N}(mask, esize) >= 0;
end;

// BitDeposit()
// ============
// Deposit the least significant bits from DATA into result positions
// selected by nonzero bits in MASK, setting other result bits to zero.

func BitDeposit{N}(data : bits(N), mask : bits(N)) => bits(N)
begin
    var res : bits(N) = Zeros{};
    var db : integer = 0;
    for rb = 0 to N-1 do
        if mask[rb] == '1' then
            res[rb] = data[db];
            db      = db + 1;
        end;
    end;
    return res;
end;

// BitExtract()
// ============
// Extract and pack DATA bits selected by the nonzero bits in MASK into
// the least significant result bits, setting other result bits to zero.

func BitExtract{N}(data : bits(N), mask : bits(N)) => bits(N)
begin
    var res : bits(N) = Zeros{};
    var rb : integer = 0;
    for db = 0 to N-1 do
        if mask[db] == '1' then
            res[rb] = data[db];
            rb      = rb + 1;
        end;
    end;
    return res;
end;

// BitGroup()
// ==========
// Extract and pack DATA bits selected by the nonzero bits in MASK into
// the least significant result bits, and pack unselected bits into the
// most significant result bits.

func BitGroup{N}(data : bits(N), mask : bits(N)) => bits(N)
begin
    var res : bits(N);
    var rb : integer = 0;

    // compress masked bits to right
    for db = 0 to N-1 do
        if mask[db] == '1' then
            res[rb] = data[db];
            rb      = rb + 1;
        end;
    end;
    // compress unmasked bits to left
    for db = 0 to N-1 do
        if mask[db] == '0' then
            res[rb] = data[db];
            rb      = rb + 1;
        end;
    end;
    return res;
end;

// CheckNonStreamingSVEEnabled()
// =============================
// Checks for traps on SVE instructions that are not legal when executed in Streaming mode.

func CheckNonStreamingSVEEnabled()
begin
    CheckSVEEnabled();

    if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' && !IsFullA64Enabled() then
        SMEAccessTrap(SMEExceptionType_Streaming, PSTATE.EL);
    end;
end;

// CheckOriginalSVEEnabled()
// =========================
// Checks for traps on SVE instructions and instructions that access SVE System
// registers.

func CheckOriginalSVEEnabled()
begin
    assert IsFeatureImplemented(FEAT_SVE);
    var disabled : boolean;

    if (HaveEL(EL3) && (CPTR_EL3().EZ == '0' || CPTR_EL3().TFP == '1') &&
          EL3SDDUndefPriority()) then
        Undefined();
    end;

    // Check if access disabled in CPACR_EL1
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        // Check SVE at EL0/EL1
        case CPACR_EL1().ZEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then SVEAccessTrap(EL1); end;

        // Check SIMD&FP at EL0/EL1
        case CPACR_EL1().FPEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then AArch64_AdvSIMDFPAccessTrap(EL1); end;
    end;

    // Check if access disabled in CPTR_EL2
    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            // Check SVE at EL2
            case CPTR_EL2().ZEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then SVEAccessTrap(EL2); end;

            // Check SIMD&FP at EL2
            case CPTR_EL2().FPEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        else
            if CPTR_EL2().TZ == '1'  then SVEAccessTrap(EL2); end;
            if CPTR_EL2().TFP == '1' then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().EZ == '0' then
            if EL3SDDUndef() then Undefined(); end;
            SVEAccessTrap(EL3);
        end;

        if CPTR_EL3().TFP == '1' then
            if EL3SDDUndef() then Undefined(); end;
            AArch64_AdvSIMDFPAccessTrap(EL3);
        end;
    end;
end;

// CheckSMEAccess()
// ================
// Check that access to SME System registers is enabled.

func CheckSMEAccess()
begin
    var disabled : boolean;

    if HaveEL(EL3) && CPTR_EL3().ESM == '0' && EL3SDDUndefPriority() then
        Undefined();
    end;

    // Check if access disabled in CPACR_EL1
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        // Check SME at EL0/EL1
        case CPACR_EL1().SMEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then SMEAccessTrap(SMEExceptionType_AccessTrap, EL1); end;
    end;

    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            // Check SME at EL2
            case CPTR_EL2().SMEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then SMEAccessTrap(SMEExceptionType_AccessTrap, EL2); end;
        else
            if CPTR_EL2().TSM == '1' then SMEAccessTrap(SMEExceptionType_AccessTrap, EL2); end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().ESM == '0' then
            if EL3SDDUndef() then Undefined(); end;
            SMEAccessTrap(SMEExceptionType_AccessTrap, EL3);
        end;
    end;
end;

// CheckSMEAndZAEnabled()
// ======================

func CheckSMEAndZAEnabled()
begin
    CheckSMEEnabled();

    if PSTATE.ZA == '0' then
        SMEAccessTrap(SMEExceptionType_InactiveZA, PSTATE.EL);
    end;
end;

// CheckSMEEnabled()
// =================

func CheckSMEEnabled()
begin
    var disabled : boolean;

    if HaveEL(EL3) && CPTR_EL3().[ESM,TFP] != '10' && EL3SDDUndefPriority() then
        Undefined();
    end;

    // Check if access disabled in CPACR_EL1
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        // Check SME at EL0/EL1
        case CPACR_EL1().SMEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then SMEAccessTrap(SMEExceptionType_AccessTrap, EL1); end;

        // Check SIMD&FP at EL0/EL1
        case CPACR_EL1().FPEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = PSTATE.EL == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then AArch64_AdvSIMDFPAccessTrap(EL1); end;
    end;

    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            // Check SME at EL2
            case CPTR_EL2().SMEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then SMEAccessTrap(SMEExceptionType_AccessTrap, EL2); end;

            // Check SIMD&FP at EL2
            case CPTR_EL2().FPEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = PSTATE.EL == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        else
            if CPTR_EL2().TSM == '1' then SMEAccessTrap(SMEExceptionType_AccessTrap, EL2); end;
            if CPTR_EL2().TFP == '1' then AArch64_AdvSIMDFPAccessTrap(EL2); end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().ESM == '0' then
            if EL3SDDUndef() then Undefined(); end;
            SMEAccessTrap(SMEExceptionType_AccessTrap, EL3);
        end;

        if CPTR_EL3().TFP == '1' then
            if EL3SDDUndef() then Undefined(); end;
            AArch64_AdvSIMDFPAccessTrap(EL3);
        end;
    end;
end;

// CheckSMEZT0Enabled()
// ====================
// Checks for ZT0 enabled.

func CheckSMEZT0Enabled()
begin
    if HaveEL(EL3) && SMCR_EL3().EZT0 == '0' && EL3SDDUndefPriority() then
        Undefined();
    end;

    // Check if ZA and ZT0 are inactive in PSTATE
    if PSTATE.ZA == '0' then
        SMEAccessTrap(SMEExceptionType_InactiveZA, PSTATE.EL);
    end;

    // Check if EL0/EL1 accesses to ZT0 are disabled in SMCR_EL1
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        if SMCR_EL1().EZT0 == '0' then
            SMEAccessTrap(SMEExceptionType_InaccessibleZT0, EL1);
        end;
    end;

    // Check if EL0/EL1/EL2 accesses to ZT0 are disabled in SMCR_EL2
    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        if SMCR_EL2().EZT0 == '0' then
            SMEAccessTrap(SMEExceptionType_InaccessibleZT0, EL2);
        end;
    end;

    // Check if all accesses to ZT0 are disabled in SMCR_EL3
    if HaveEL(EL3) then
        if SMCR_EL3().EZT0 == '0' then
            if EL3SDDUndef() then Undefined(); end;
            SMEAccessTrap(SMEExceptionType_InaccessibleZT0, EL3);
        end;
    end;
end;

// CheckSVEEnabled()
// =================
// Checks for traps on SVE instructions and instructions that
// access SVE System registers.

func CheckSVEEnabled()
begin
    if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then
        CheckSMEEnabled();
    elsif IsFeatureImplemented(FEAT_SME) && !IsFeatureImplemented(FEAT_SVE) then
        CheckStreamingSVEEnabled();
    else
        CheckOriginalSVEEnabled();
    end;
end;

// CheckStreamingSVEAndZAEnabled()
// ===============================

func CheckStreamingSVEAndZAEnabled()
begin
    CheckStreamingSVEEnabled();

    if PSTATE.ZA == '0' then
        SMEAccessTrap(SMEExceptionType_InactiveZA, PSTATE.EL);
    end;
end;

// CheckStreamingSVEEnabled()
// ==========================

func CheckStreamingSVEEnabled()
begin
    CheckSMEEnabled();

    if PSTATE.SM == '0' then
        SMEAccessTrap(SMEExceptionType_NotStreaming, PSTATE.EL);
    end;
end;

// CmpOp
// =====

type CmpOp of enumeration { Cmp_EQ, Cmp_NE, Cmp_GE, Cmp_GT, Cmp_LT, Cmp_LE, Cmp_UN };

// CurrentNSVL
// ===========
// Non-Streaming VL

readonly func CurrentNSVL() => VecLen
begin
    var vl : integer;

    if PSTATE.EL == EL1 || (PSTATE.EL == EL0 && !IsInHost()) then
        vl = UInt(ZCR_EL1().LEN);
    end;

    if PSTATE.EL == EL2 || (PSTATE.EL == EL0 && IsInHost()) then
        vl = UInt(ZCR_EL2().LEN);
    elsif PSTATE.EL IN {EL0, EL1} && EL2Enabled() then
        vl = Min(vl, UInt(ZCR_EL2().LEN));
    end;

    if PSTATE.EL == EL3 then
        vl = UInt(ZCR_EL3().LEN);
    elsif HaveEL(EL3) then
        vl = Min(vl, UInt(ZCR_EL3().LEN));
    end;

    return ImplementedSVEVectorLength((vl + 1) * 128);
end;

// CurrentSVL
// ==========
// Streaming SVL

readonly func CurrentSVL() => VecLen
begin
    var vl : integer;

    if PSTATE.EL == EL1 || (PSTATE.EL == EL0 && !IsInHost()) then
        vl = UInt(SMCR_EL1().LEN);
    end;

    if PSTATE.EL == EL2 || (PSTATE.EL == EL0 && IsInHost()) then
        vl = UInt(SMCR_EL2().LEN);
    elsif PSTATE.EL IN {EL0, EL1} && EL2Enabled() then
        vl = Min(vl, UInt(SMCR_EL2().LEN));
    end;

    if PSTATE.EL == EL3 then
        vl = UInt(SMCR_EL3().LEN);
    elsif HaveEL(EL3) then
        vl = Min(vl, UInt(SMCR_EL3().LEN));
    end;

    return ImplementedSMEVectorLength((vl + 1) * 128);
end;

// CurrentVL
// =========

readonly func CurrentVL() => VecLen
begin
    return (if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then CurrentSVL()
                                                                  else CurrentNSVL());
end;

// DecodePredCount()
// =================

func DecodePredCount(bitpattern : bits(5), esize : integer) => integer
begin
    let elements : integer = CurrentVL() DIV esize;
    var numElem : integer;
    case bitpattern of
        when '00000' => numElem = FloorPow2(elements);
        when '00001' => numElem = if elements >= 1 then 1 else 0;
        when '00010' => numElem = if elements >= 2 then 2 else 0;
        when '00011' => numElem = if elements >= 3 then 3 else 0;
        when '00100' => numElem = if elements >= 4 then 4 else 0;
        when '00101' => numElem = if elements >= 5 then 5 else 0;
        when '00110' => numElem = if elements >= 6 then 6 else 0;
        when '00111' => numElem = if elements >= 7 then 7 else 0;
        when '01000' => numElem = if elements >= 8 then 8 else 0;
        when '01001' => numElem = if elements >= 16 then 16 else 0;
        when '01010' => numElem = if elements >= 32 then 32 else 0;
        when '01011' => numElem = if elements >= 64 then 64 else 0;
        when '01100' => numElem = if elements >= 128 then 128 else 0;
        when '01101' => numElem = if elements >= 256 then 256 else 0;
        when '11101' => numElem = elements - (elements MOD 4);
        when '11110' => numElem = elements - (elements MOD 3);
        when '11111' => numElem = elements;
        otherwise    => numElem = 0;
    end;
    return numElem;
end;

// ElemFFR - accessor
// ==================

accessor ElemFFR(e : integer, esize : ESize) <=> value : bit
begin
    getter
        return PredicateElement{MAX_PL}(_FFR, e, esize);
    end;
    setter
        let psize : integer{} = esize DIV 8;
        _FFR[e*:psize] = ZeroExtend{psize}(value);
    end;
end;

// FFR - accessor
// ==============

accessor FFR{width}() <=> value : bits(width)
begin
    getter
        assert width == CurrentVL() DIV 8;
        return _FFR[width-1:0];
    end;

    setter
        assert width == CurrentVL() DIV 8;
        if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
            _FFR = ZeroExtend{MAX_PL}(value);
        else
            _FFR[width-1:0] = value;
        end;
    end;
end;

// FPCompareNE()
// =============

func FPCompareNE{N}(op1 : bits(N), op2 : bits(N), fpcr : FPCR_Type) => boolean
begin
    assert N IN {16,32,64};
    var result : boolean;
    let (type1,sign1,value1) : (FPType, bit, real) = FPUnpack{N}(op1, fpcr);
    let (type2,sign2,value2) : (FPType, bit, real) = FPUnpack{N}(op2, fpcr);
    let op1_nan : boolean = type1 IN {FPType_SNaN, FPType_QNaN};
    let op2_nan : boolean = type2 IN {FPType_SNaN, FPType_QNaN};

    if op1_nan || op2_nan then
        result = TRUE;
        if type1 == FPType_SNaN || type2 == FPType_SNaN then
            FPProcessException(FPExc_InvalidOp, fpcr);
        end;
    else // All non-NaN cases can be evaluated on the values produced by FPUnpack()
        result = (value1 != value2);
        FPProcessDenorms(type1, type2, N, fpcr);
    end;
    return result;
end;

// FPCompareUN()
// =============

func FPCompareUN{N}(op1 : bits(N), op2 : bits(N), fpcr : FPCR_Type) => boolean
begin
    assert N IN {16,32,64};
    let (type1,sign1,value1) : (FPType, bit, real) = FPUnpack{N}(op1, fpcr);
    let (type2,sign2,value2) : (FPType, bit, real) = FPUnpack{N}(op2, fpcr);

    if type1 == FPType_SNaN || type2 == FPType_SNaN then
        FPProcessException(FPExc_InvalidOp, fpcr);
    end;

    let result : boolean = (type1 IN {FPType_SNaN, FPType_QNaN} ||
                                type2 IN {FPType_SNaN, FPType_QNaN});
    if !result then
        FPProcessDenorms(type1, type2, N, fpcr);
    end;

    return result;
end;

// FPConvertSVE()
// ==============

func FPConvertSVE{M, N}(op : bits(N), fpcr_in : FPCR_Type, rounding : FPRounding) => bits(M)
begin
    var fpcr : FPCR_Type = fpcr_in;
    fpcr.AHP = '0';
    return FPConvert{M, N}(op, fpcr, rounding);
end;

// FPConvertSVE()
// ==============

func FPConvertSVE{M, N}(op : bits(N), fpcr_in : FPCR_Type) => bits(M)
begin
    var fpcr : FPCR_Type = fpcr_in;
    fpcr.AHP = '0';
    return FPConvert{M, N}(op, fpcr, FPRoundingMode(fpcr));
end;

// FPExpA()
// ========

func FPExpA{N}(op : bits(N)) => bits(N)
begin
    assert N IN {16,32,64};
    var result : bits(N);
    var coeff : bits(N);
    let idx : integer = if N == 16 then UInt(op[4:0]) else UInt(op[5:0]);
    coeff = FPExpCoefficient{N}(idx);
    if N == 16 then
        result[15:0] = '0'::op[9:5]::coeff[9:0];
    elsif N == 32 then
        result[31:0] = '0'::op[13:6]::coeff[22:0];
    else // N == 64
        result[63:0] = '0'::op[16:6]::coeff[51:0];
    end;

    return result;
end;

