// FPLogB()
// ========

func FPLogB{N}(op : bits(N), fpcr : FPCR_Type) => bits(N)
begin
    assert N IN {16,32,64};
    var result : integer;
    var (fptype,sign,value) : (FPType, bit, real) = FPUnpack{N}(op, fpcr);

    if fptype == FPType_SNaN || fptype == FPType_QNaN || fptype == FPType_Zero then
        FPProcessException(FPExc_InvalidOp, fpcr);
        result = -(2^(N-1));            // MinInt, 100..00
    elsif fptype == FPType_Infinity then
        result = 2^(N-1) - 1;           // MaxInt, 011..11
    else
        // FPUnpack has already scaled a subnormal input
        value = Abs(value);
        (value, result) = NormalizeReal(value);

        FPProcessDenorm(fptype, N, fpcr);
    end;
    return result[N-1:0];
end;

// FPMinNormal()
// =============

func FPMinNormal{N}(sign : bit) => bits(N)
begin
    assert N IN {16,32,64};
    let E : integer{}  = (if N == 16 then 5 else (if N == 32 then 8 else 11));
    let F : integer{}  = N - (E + 1);
    let exp : bits(E)  = Zeros{E-1}::'1';
    let frac : bits(F) = Zeros{};
    return sign :: exp :: frac;
end;

// FPOne()
// =======

func FPOne{N}(sign : bit) => bits(N)
begin
    assert N IN {16,32,64};
    let E : integer{}  = (if N == 16 then 5 else (if N == 32 then 8 else 11));
    let F : integer{}  = N - (E + 1);
    let exp : bits(E)  = '0'::Ones{E-1};
    let frac : bits(F) = Zeros{};
    return sign :: exp :: frac;
end;

// FPPointFive()
// =============

func FPPointFive{N}(sign : bit) => bits(N)
begin
    assert N IN {16,32,64};
    let E : integer{}  = (if N == 16 then 5 else (if N == 32 then 8 else 11));
    let F : integer{}  = N - (E + 1);
    let exp : bits(E)  = '0'::Ones{E-2}::'0';
    let frac : bits(F) = Zeros{};
    return sign :: exp :: frac;
end;

// FPReducePredicated()
// ====================

func FPReducePredicated{esize, N, M}(op : ReduceOp, input : bits(N), mask : bits(M),
                                     identity : bits(esize), fpcr : FPCR_Type) => bits(esize)
begin
    assert(N == M * 8);
    assert IsPow2(N);
    var operand : bits(N);
    let elements : integer = N DIV esize;

    for e = 0 to elements-1 do
        if e * esize < N && ActivePredicateElement{M}(mask, e, esize) then
            operand[e*:esize] = input[e*:esize];
        else
            operand[e*:esize] = identity;
        end;
    end;

    return FPReduce{esize, N}(op, operand, fpcr);
end;

// FPTrigMAdd()
// ============

func FPTrigMAdd{N}(x_in : integer, op1 : bits(N), op2_in : bits(N), fpcr : FPCR_Type) => bits(N)
begin
    assert N IN {16,32,64};
    var coeff : bits(N);
    var op2 : bits(N) = op2_in;
    var x : integer = x_in;
    assert x >= 0;
    assert x < 8;

    if op2[N-1] == '1' then
        x = x + 8;
    end;

    coeff = FPTrigMAddCoefficient{N}(x);
    // Safer to use EffectiveFPCR() in case the input fpcr argument
    // is modified as opposed to actual value of FPCR

    op2                    = FPAbs{N}(op2, EffectiveFPCR());
    let result : bits(N)   = FPMulAdd{}(coeff, op1, op2, fpcr);
    return result;
end;

// FPTrigMAddCoefficient()
// =======================

func FPTrigMAddCoefficient{N}(index : integer) => bits(N)
begin
    assert N IN {16,32,64};
    var result : integer;

    if N == 16 then
        case index of
            when  0 => result = 0x3c00;
            when  1 => result = 0xb155;
            when  2 => result = 0x2030;
            when  3 => result = 0x0000;
            when  4 => result = 0x0000;
            when  5 => result = 0x0000;
            when  6 => result = 0x0000;
            when  7 => result = 0x0000;
            when  8 => result = 0x3c00;
            when  9 => result = 0xb800;
            when 10 => result = 0x293a;
            when 11 => result = 0x0000;
            when 12 => result = 0x0000;
            when 13 => result = 0x0000;
            when 14 => result = 0x0000;
            when 15 => result = 0x0000;
        end;
    elsif N == 32 then
        case index of
            when  0 => result = 0x3f800000;
            when  1 => result = 0xbe2aaaab;
            when  2 => result = 0x3c088886;
            when  3 => result = 0xb95008b9;
            when  4 => result = 0x36369d6d;
            when  5 => result = 0x00000000;
            when  6 => result = 0x00000000;
            when  7 => result = 0x00000000;
            when  8 => result = 0x3f800000;
            when  9 => result = 0xbf000000;
            when 10 => result = 0x3d2aaaa6;
            when 11 => result = 0xbab60705;
            when 12 => result = 0x37cd37cc;
            when 13 => result = 0x00000000;
            when 14 => result = 0x00000000;
            when 15 => result = 0x00000000;
        end;
    else // N == 64
        case index of
            when  0 => result = 0x3ff0000000000000;
            when  1 => result = 0xbfc5555555555543;
            when  2 => result = 0x3f8111111110f30c;
            when  3 => result = 0xbf2a01a019b92fc6;
            when  4 => result = 0x3ec71de351f3d22b;
            when  5 => result = 0xbe5ae5e2b60f7b91;
            when  6 => result = 0x3de5d8408868552f;
            when  7 => result = 0x0000000000000000;
            when  8 => result = 0x3ff0000000000000;
            when  9 => result = 0xbfe0000000000000;
            when 10 => result = 0x3fa5555555555536;
            when 11 => result = 0xbf56c16c16c13a0b;
            when 12 => result = 0x3efa01a019b1e8d8;
            when 13 => result = 0xbe927e4f7282f468;
            when 14 => result = 0x3e21ee96d2641b13;
            when 15 => result = 0xbda8f76380fbb401;
        end;
    end;

    return result[N-1:0];
end;

// FPTrigSMul()
// ============

func FPTrigSMul{N}(op1 : bits(N), op2 : bits(N), fpcr : FPCR_Type) => bits(N)
begin
    assert N IN {16,32,64};
    var result : bits(N) = FPMul{}(op1, op1, fpcr);
    let fpexc = FALSE;
    let (fptype, sign, value) : (FPType, bit, real) = FPUnpack{N}(result, fpcr, fpexc);

    if ! fptype IN {FPType_QNaN, FPType_SNaN} then
        result[N-1] = op2[0];
    end;

    return result;
end;

// FPTrigSSel()
// ============

func FPTrigSSel{N}(op1 : bits(N), op2 : bits(N)) => bits(N)
begin
    assert N IN {16,32,64};
    var result : bits(N);

    if op2[0] == '1' then
        result = FPOne{N}(op2[1]);
    elsif op2[1] == '1' then
        result = FPNeg{N}(op1, EffectiveFPCR());
    else
        result = op1;
    end;

    return result;
end;

// FirstActive()
// =============

func FirstActive{N}(mask : bits(N), x : bits(N), esize : integer) => bit
begin
    let elements : integer = N DIV (esize DIV 8);
    for e = 0 to elements-1 do
        if ActivePredicateElement{N}(mask, e, esize) then
            return PredicateElement{N}(x, e, esize);
        end;
    end;
    return '0';
end;

// HaveSVE2FP8DOT2()
// =================
// Returns TRUE if SVE2 FP8 dot product to half-precision instructions
// are implemented, FALSE otherwise.

func HaveSVE2FP8DOT2() => boolean
begin
    return ((IsFeatureImplemented(FEAT_SVE2) && IsFeatureImplemented(FEAT_FP8DOT2)) ||
            IsFeatureImplemented(FEAT_SSVE_FP8DOT2));
end;

// HaveSVE2FP8DOT4()
// =================
// Returns TRUE if SVE2 FP8 dot product to single-precision instructions
// are implemented, FALSE otherwise.

func HaveSVE2FP8DOT4() => boolean
begin
    return ((IsFeatureImplemented(FEAT_SVE2) && IsFeatureImplemented(FEAT_FP8DOT4)) ||
            IsFeatureImplemented(FEAT_SSVE_FP8DOT4));
end;

// HaveSVE2FP8FMA()
// ================
// Returns TRUE if SVE2 FP8 multiply-accumulate to half-precision and single-precision
// instructions are implemented, FALSE otherwise.

func HaveSVE2FP8FMA() => boolean
begin
    return ((IsFeatureImplemented(FEAT_SVE2) && IsFeatureImplemented(FEAT_FP8FMA)) ||
            IsFeatureImplemented(FEAT_SSVE_FP8FMA));
end;

// ImplementedSMEVectorLength()
// ============================
// Reduce SVE/SME vector length to a supported value (power of two)

readonly func ImplementedSMEVectorLength(nbits_in : integer) => VecLen
begin
    let maxbits : VecLen = MaxImplementedSVL();
    assert 128 <= maxbits && maxbits <= 2048 && IsPow2(maxbits);
    var nbits : integer = Min(nbits_in, maxbits);
    assert 128 <= nbits && nbits <= 2048 && AlignDownSize(nbits, 128) == nbits;

    // Search for a supported power-of-two VL less than or equal to nbits
    while nbits > 128 && !SupportedPowerTwoSVL(nbits) looplimit 7 do
        nbits = nbits - 128;
    end;

    // Return the smallest supported power-of-two VL
    while nbits < maxbits && !SupportedPowerTwoSVL(nbits) looplimit 7 do
        nbits = nbits * 2;
    end;

    return nbits as VecLen;
end;

// ImplementedSVEVectorLength()
// ============================
// Reduce SVE vector length to a supported value (power of two)

readonly func ImplementedSVEVectorLength(nbits_in : integer) => VecLen
begin
    let maxbits : integer = MaxImplementedVL();
    assert 128 <= maxbits && maxbits <= 2048 && IsPow2(maxbits);
    var nbits : integer = Min(nbits_in, maxbits);
    assert 128 <= nbits && nbits <= 2048 && AlignDownSize(nbits, 128) == nbits;

    while !IsPow2(nbits) looplimit 7 do
        nbits = nbits - 128;
    end;
    return nbits as VecLen;
end;

// InStreamingMode()
// =================

func InStreamingMode() => boolean
begin
    return IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1';
end;

// IntReducePredicated()
// =====================

func IntReducePredicated{esize, N, M}(op : ReduceOp, input : bits(N),
                                      mask : bits(M), identity : bits(esize)) => bits(esize)
begin
    assert(N == M * 8);
    assert IsPow2(N);
    var operand : bits(N);
    let elements : integer = N DIV esize;

    for e = 0 to elements-1 do
        if e * esize < N && ActivePredicateElement{M}(mask, e, esize) then
            operand[e*:esize] = input[e*:esize];
        else
            operand[e*:esize] = identity;
        end;
    end;

    return IntReduce{esize, N}(op, operand);
end;

// IsFPEnabled()
// =============
// Returns TRUE if accesses to the Advanced SIMD and floating-point
// registers are enabled at the target exception level in the current
// execution state and FALSE otherwise.

func IsFPEnabled(el : bits(2)) => boolean
begin
    if ELUsingAArch32(el) then
        return AArch32_IsFPEnabled(el);
    else
        return AArch64_IsFPEnabled(el);
    end;
end;

// IsFullA64Enabled()
// ==================
// Returns TRUE if full A64 is enabled in Streaming mode and FALSE othersise.

func IsFullA64Enabled() => boolean
begin
    if !IsFeatureImplemented(FEAT_SME_FA64) then return FALSE; end;

    // Check if full A64 disabled in SMCR_EL1
    if PSTATE.EL IN {EL0, EL1} && !IsInHost() then
        // Check full A64 at EL0/EL1
        if SMCR_EL1().FA64 == '0' then return FALSE; end;
    end;

    // Check if full A64 disabled in SMCR_EL2
    if PSTATE.EL IN {EL0, EL1, EL2} && EL2Enabled() then
        if SMCR_EL2().FA64 == '0' then return FALSE; end;
    end;

    // Check if full A64 disabled in SMCR_EL3
    if HaveEL(EL3) then
        if SMCR_EL3().FA64 == '0' then return FALSE; end;
    end;

    return TRUE;
end;

// IsOriginalSVEEnabled()
// ======================
// Returns TRUE if access to SVE functionality is enabled at the target
// exception level and FALSE otherwise.

func IsOriginalSVEEnabled(el : bits(2)) => boolean
begin
    var disabled : boolean;
    if ELUsingAArch32(el) then
        return FALSE;
    end;

    // Check if access disabled in CPACR_EL1
    if el IN {EL0, EL1} && !IsInHost() then
        // Check SVE at EL0/EL1
        case CPACR_EL1().ZEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = el == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then return FALSE; end;
    end;

    // Check if access disabled in CPTR_EL2
    if el IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            case CPTR_EL2().ZEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = el == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then return FALSE; end;
        else
            if CPTR_EL2().TZ == '1' then return FALSE; end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().EZ == '0' then return FALSE; end;
    end;

    return TRUE;
end;

// IsSMEEnabled()
// ==============
// Returns TRUE if access to SME functionality is enabled at the target
// exception level and FALSE otherwise.

func IsSMEEnabled(el : bits(2)) => boolean
begin
    var disabled : boolean;
    if ELUsingAArch32(el) then
        return FALSE;
    end;

    // Check if access disabled in CPACR_EL1
    if el IN {EL0, EL1} && !IsInHost() then
        // Check SME at EL0/EL1
        case CPACR_EL1().SMEN of
            when 'x0' => disabled = TRUE;
            when '01' => disabled = el == EL0;
            when '11' => disabled = FALSE;
        end;
        if disabled then return FALSE; end;
    end;

    // Check if access disabled in CPTR_EL2
    if el IN {EL0, EL1, EL2} && EL2Enabled() then
        if ELIsInHost(EL2) then
            case CPTR_EL2().SMEN of
                when 'x0' => disabled = TRUE;
                when '01' => disabled = el == EL0 && HCR_EL2().TGE == '1';
                when '11' => disabled = FALSE;
            end;
            if disabled then return FALSE; end;
        else
            if CPTR_EL2().TSM == '1' then return FALSE; end;
        end;
    end;

    // Check if access disabled in CPTR_EL3
    if HaveEL(EL3) then
        if CPTR_EL3().ESM == '0' then return FALSE; end;
    end;

    return TRUE;
end;

// IsSVEEnabled()
// ==============
// Returns TRUE if access to SVE registers is enabled at the target exception
// level and FALSE otherwise.

func IsSVEEnabled(el : bits(2)) => boolean
begin
    if IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' then
        return IsSMEEnabled(el);
    elsif IsFeatureImplemented(FEAT_SVE) then
        return IsOriginalSVEEnabled(el);
    else
        return FALSE;
    end;
end;

// LastActive()
// ============

func LastActive{N}(mask : bits(N), x : bits(N), esize : integer) => bit
begin
    let elements : integer = N DIV (esize DIV 8);
    for e = elements-1 downto 0 do
        if ActivePredicateElement{N}(mask, e, esize) then
            return PredicateElement{N}(x, e, esize);
        end;
    end;
    return '0';
end;

// LastActiveElement()
// ===================

func LastActiveElement{N}(mask : bits(N), esize : integer) => integer
begin
    let elements : integer = N DIV (esize DIV 8);
    for e = elements-1 downto 0 do
        if ActivePredicateElement{N}(mask, e, esize) then return e; end;
    end;
    return -1;
end;

// MaxImplementedAnyVL()
// =====================

readonly func MaxImplementedAnyVL() => integer
begin
    if IsFeatureImplemented(FEAT_SME) && IsFeatureImplemented(FEAT_SVE) then
        return Max(MaxImplementedVL(), MaxImplementedSVL());
    end;
    if IsFeatureImplemented(FEAT_SME) then
        return MaxImplementedSVL();
    end;
    return MaxImplementedVL();
end;

// MaxImplementedSVL()
// ===================

readonly func MaxImplementedSVL() => VecLen
begin
    return ImpDefInt("Max implemented SVL") as VecLen;
end;

// MaxImplementedVL()
// ==================

readonly func MaxImplementedVL() => integer
begin
    return ImpDefInt("Max implemented VL");
end;

// MaybeZeroSVEUppers()
// ====================

func MaybeZeroSVEUppers(target_el : bits(2))
begin
    var lower_enabled : boolean;

    if UInt(target_el) <= UInt(PSTATE.EL) || !IsSVEEnabled(target_el) then
        return;
    end;

    if target_el == EL3 then
        if EL2Enabled() then
            lower_enabled = IsFPEnabled(EL2);
        else
            lower_enabled = IsFPEnabled(EL1);
        end;
    elsif target_el == EL2 then
        assert EL2Enabled() && !ELUsingAArch32(EL2);
        if HCR_EL2().TGE == '0' then
            lower_enabled = IsFPEnabled(EL1);
        else
            lower_enabled = IsFPEnabled(EL0);
        end;
    else
        assert target_el == EL1 && !ELUsingAArch32(EL1);
        lower_enabled = IsFPEnabled(EL0);
    end;

    if lower_enabled then
        let VL : integer{} = if IsSVEEnabled(PSTATE.EL) then CurrentVL() else 128;
        let PL : integer{} = VL DIV 8;
        for n = 0 to 31 do
            if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
                _Z[[n]] = ZeroExtend{MAX_VL}(_Z[[n]][VL-1:0]);
            end;
        end;
        for n = 0 to 15 do
            if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
                _P[[n]] = ZeroExtend{MAX_PL}(_P[[n]][PL-1:0]);
            end;
        end;
        if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
            _FFR = ZeroExtend{MAX_PL}(_FFR[PL-1:0]);
        end;
        if IsFeatureImplemented(FEAT_SME) && PSTATE.ZA == '1' then
            let SVL : integer{}          = CurrentSVL();
            let accessiblevecs : integer = SVL DIV 8;
            let allvecs : integer        = MaxImplementedSVL() DIV 8;

            for n = 0 to accessiblevecs - 1 do
                if ConstrainUnpredictableBool(Unpredictable_SMEZEROUPPER) then
                    _ZA[[n]] = ZeroExtend{MAX_VL}(_ZA[[n]][SVL-1:0]);
                end;
            end;
            for n = accessiblevecs to allvecs - 1 do
                if ConstrainUnpredictableBool(Unpredictable_SMEZEROUPPER) then
                    _ZA[[n]] = Zeros{MAX_VL};
                end;
            end;
        end;
    end;
end;

// MemNF
// =====

func MemNF{size : integer{8, 16, 32, 64, 128}}(address : bits(64),
                                               accdesc : AccessDescriptor
                                              ) => (bits(size), boolean)
begin
    let bytes : integer{} = size DIV 8;
    var value : bits(size);
    var bad : boolean;

    var aligned : boolean = IsAlignedSize{64}(address, bytes);

    if !aligned && AlignmentEnforced() then
        return (ARBITRARY : bits(size), TRUE);
    end;

    let atomic : boolean = aligned || bytes == 1;

    if !atomic then
        (value[7:0], bad) = MemSingleNF{8}(address, accdesc, aligned);

        if bad then
            return (ARBITRARY : bits(size), TRUE);
        end;

        // For subsequent bytes, if they cross to a new translation page which assigns
        // Device memory type, it is CONSTRAINED UNPREDICTABLE whether an unaligned access
        // will generate an Alignment Fault.
        if !aligned then
            let c : Constraint = ConstrainUnpredictable(Unpredictable_DEVPAGE2);
            assert c IN {Constraint_FAULT, Constraint_NONE};
            if c == Constraint_NONE then aligned = TRUE; end;
        end;

        for i = 1 to bytes-1 do
            (value[i*:8], bad) = MemSingleNF{8}(address+i, accdesc, aligned);

            if bad then
                return (ARBITRARY : bits(size), TRUE);
            end;
        end;
    else
        (value, bad) = MemSingleNF{size}(address, accdesc, aligned);
        if bad then
            return (ARBITRARY : bits(size), TRUE);
        end;
    end;

    if BigEndian(accdesc.acctype) then
        value = BigEndianReverse{size}(value);
    end;

    return (value, FALSE);
end;

// MemSingleNF
// ===========

func MemSingleNF{size : integer{8, 16, 32, 64, 128}}(address : bits(64),
                                                     accdesc_in : AccessDescriptor,
                                                     aligned : boolean) => (bits(size), boolean)
begin
    assert accdesc_in.acctype == AccessType_SVE;
    assert accdesc_in.nonfault || (accdesc_in.firstfault && !accdesc_in.first);

    let bytes : integer{} = size DIV 8;
    var value : bits(size);
    var memaddrdesc : AddressDescriptor;
    var memstatus : PhysMemRetStatus;
    var accdesc : AccessDescriptor = accdesc_in;
    var fault : FaultRecord = NoFault(accdesc, address);

    // Implementation may suppress NF load for any reason
    if ConstrainUnpredictableBool(Unpredictable_NONFAULT) then
        return (ARBITRARY : bits(size), TRUE);
    end;

    // If the instruction encoding permits tag checking, confer with system register configuration
    // which may override this.
    if accdesc.tagchecked then
        accdesc.tagchecked = AArch64_AccessIsTagChecked(address, accdesc);
    end;

    // MMU or MPU
    memaddrdesc = AArch64_TranslateAddress(address, accdesc, aligned, bytes);

    // Non-fault load from Device memory must not be performed externally
    if memaddrdesc.memattrs.memtype == MemType_Device then
        return (ARBITRARY : bits(size), TRUE);
    end;

    // Check for aborts or debug exceptions
    if IsFault(memaddrdesc) then
        return (ARBITRARY : bits(size), TRUE);
    end;

    if accdesc.tagchecked then
        let ltag : bits(4) = AArch64_LogicalAddressTag(address);
        fault = AArch64_CheckTag(memaddrdesc, accdesc, bytes, ltag);
        if fault.statuscode != Fault_None then
            return (ARBITRARY : bits(size), TRUE);
        end;
    end;

    (memstatus, value) = PhysMemRead{size}(memaddrdesc, accdesc);
    if IsFault(memstatus) then
        let iswrite : boolean = FALSE;
        if IsExternalAbortTakenSynchronously(memstatus, iswrite, memaddrdesc, bytes, accdesc) then
            return (ARBITRARY : bits(size), TRUE);
        end;
        fault.merrorstate = memstatus.merrorstate;
        fault.extflag    = memstatus.extflag;
        fault.statuscode = memstatus.statuscode;
        PendSErrorInterrupt(fault);
    end;

    return (value, FALSE);
end;

// NoneActive()
// ============

func NoneActive{N}(mask : bits(N), x : bits(N), esize : integer) => bit
begin
    let elements : integer = N DIV (esize DIV 8);
    for e = 0 to elements-1 do
        if ActivePredicateElement{N}(mask, e, esize) && ActivePredicateElement{N}(x, e, esize) then
            return '0';
        end;
    end;
    return '1';
end;

// P - accessor
// ============

accessor P{width}(n : integer) <=> value : bits(width)
begin
    getter
        assert n >= 0 && n <= 31;
        assert width == CurrentVL() DIV 8;
        return _P[[n]][width-1:0];
    end;

    setter
        assert n >= 0 && n <= 31;
        assert width == CurrentVL() DIV 8;
        if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
            _P[[n]] = ZeroExtend{MAX_PL}(value);
        else
            _P[[n]][width-1:0] = value;
        end;
    end;
end;

// PredLen
// =======

type PredLen of integer{16, 32, 64, 128, 256};

// PredTest()
// ==========

func PredTest{N}(mask : bits(N), result : bits(N), esize : integer) => bits(4)
begin
    let n : bit = FirstActive{N}(mask, result, esize);
    let z : bit = NoneActive{N}(mask, result, esize);
    let c : bit = NOT LastActive{N}(mask, result, esize);
    let v : bit = '0';
    return n::z::c::v;
end;

// PredicateElement()
// ==================
// Returns the predicate bit

func PredicateElement{N}(pred : bits(N), e : integer, esize : integer) => bit
begin
    assert esize IN {8, 16, 32, 64, 128};
    let n : integer = e * (esize DIV 8);
    assert n >= 0 && n < N;
    return pred[n];
end;

// ResetSMEState()
// ===============

func ResetSMEState(newenable : bit)
begin
    let vectors : integer = MAX_VL DIV 8;
    if newenable == '1' then
        for n = 0 to vectors - 1 do
            _ZA[[n]] = Zeros{MAX_VL};
        end;
        if IsFeatureImplemented(FEAT_SME2) then
            _ZT0 = Zeros{ZT0_LEN};
        end;
    else
        for n = 0 to vectors - 1 do
            _ZA[[n]] = ARBITRARY : bits(MAX_VL);
        end;
        if IsFeatureImplemented(FEAT_SME2) then
            _ZT0 = ARBITRARY : bits(ZT0_LEN);
        end;
    end;
end;

// ResetSVERegisters()
// ===================

func ResetSVERegisters()
begin
    for n = 0 to 31 do
        _Z[[n]] = ARBITRARY : bits(MAX_VL);
    end;
    for n = 0 to 15 do
        _P[[n]] = ARBITRARY : bits(MAX_PL);
    end;
    _FFR = ARBITRARY : bits(MAX_PL);
end;

// ResetSVEState()
// ===============

func ResetSVEState()
begin
    for n = 0 to 31 do
        _Z[[n]] = Zeros{MAX_VL};
    end;
    for n = 0 to 15 do
        _P[[n]] = Zeros{MAX_PL};
    end;
    _FFR = Zeros{MAX_PL};
    FPSR() = ZeroExtend{64}(0x0800009f[31:0]);
    FPMR() = Zeros{64};
end;

// SMEAccessTrap()
// ===============
// Trapped access to SME registers due to CPACR_EL1, CPTR_EL2, or CPTR_EL3.

func SMEAccessTrap(etype : SMEExceptionType, target_el_in : bits(2))
begin
    var target_el : bits(2) = target_el_in;
    assert UInt(target_el) >= UInt(PSTATE.EL);
    if target_el == EL0 then
        target_el = EL1;
    end;
    var route_to_el2 : boolean;
    route_to_el2 = PSTATE.EL == EL0 && target_el == EL1 && EL2Enabled() && HCR_EL2().TGE == '1';

    var except : ExceptionRecord              = ExceptionSyndrome(Exception_SMEAccessTrap);
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer                 = 0x0;

    case etype of
        when SMEExceptionType_AccessTrap =>
            except.syndrome.iss[2:0] = '000';
        when SMEExceptionType_Streaming =>
            except.syndrome.iss[2:0] = '001';
        when SMEExceptionType_NotStreaming =>
            except.syndrome.iss[2:0] = '010';
        when SMEExceptionType_InactiveZA =>
            except.syndrome.iss[2:0] = '011';
        when SMEExceptionType_InaccessibleZT0 =>
            except.syndrome.iss[2:0] = '100';
    end;

    if route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
    end;
end;

// SMEExceptionType
// ================
type SMEExceptionType of enumeration {
    SMEExceptionType_AccessTrap,        // SME functionality trapped or disabled
    SMEExceptionType_Streaming,         // Illegal instruction in Streaming SVE mode
    SMEExceptionType_NotStreaming,      // Illegal instruction not in Streaming SVE mode
    SMEExceptionType_InactiveZA,        // Illegal instruction when ZA is inactive
    SMEExceptionType_InaccessibleZT0,   // Access to ZT0 is disabled
};

// SVCR
// ====

accessor SVCR() <=> value : SVCR_Type
begin
    // Returns PSTATE.[ZA, SM]
    getter
        let value : SVCR_Type = Zeros{62} :: PSTATE.ZA :: PSTATE.SM;
        return value;
    end;

    // Sets PSTATE.[ZA, SM]
    setter
        SetPSTATE_SM(value[0]);
        SetPSTATE_ZA(value[1]);
        return;
    end;
end;

// SVEAccessTrap()
// ===============
// Trapped access to SVE registers due to CPACR_EL1, CPTR_EL2, or CPTR_EL3.

func SVEAccessTrap(target_el : bits(2))
begin
    assert UInt(target_el) >= UInt(PSTATE.EL) && target_el != EL0 && HaveEL(target_el);
    let route_to_el2 : boolean = target_el == EL1 && EL2Enabled() && HCR_EL2().TGE == '1';

    let except : ExceptionRecord              = ExceptionSyndrome(Exception_SVEAccessTrap);
    let preferred_exception_return : bits(64) = ThisInstrAddr{}();
    let vect_offset : integer{}               = 0x0;

    if route_to_el2 then
        AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
    else
        AArch64_TakeException(target_el, except, preferred_exception_return, vect_offset);
    end;
end;

// SVEMoveMaskPreferred()
// ======================
// Return FALSE if a bitmask immediate encoding would generate an immediate
// value that could also be represented by a single DUP instruction.
// Used as a condition for the preferred MOV<-DUPM alias.

func SVEMoveMaskPreferred(imm13 : bits(13)) => boolean
begin
    var imm : bits(64);
    (imm, -) = DecodeBitMasks{64}(imm13[12], imm13[5:0], imm13[11:6], TRUE);

    // Check for 8 bit immediates
    if !IsZero(imm[7:0]) then
        // Check for 'ffffffffffffffxy' or '00000000000000xy'
        if IsZero(imm[63:7]) || IsOnes(imm[63:7]) then
            return FALSE;
        end;

        // Check for 'ffffffxyffffffxy' or '000000xy000000xy'
        if imm[63:32] == imm[31:0] && (IsZero(imm[31:7]) || IsOnes(imm[31:7])) then
            return FALSE;
        end;

        // Check for 'ffxyffxyffxyffxy' or '00xy00xy00xy00xy'
        if (imm[63:32] == imm[31:0] && imm[31:16] == imm[15:0] &&
              (IsZero(imm[15:7]) || IsOnes(imm[15:7]))) then
            return FALSE;
        end;

        // Check for 'xyxyxyxyxyxyxyxy'
        if imm[63:32] == imm[31:0] && imm[31:16] == imm[15:0] && (imm[15:8] == imm[7:0]) then
            return FALSE;
        end;

    // Check for 16 bit immediates
    else
        // Check for 'ffffffffffffxy00' or '000000000000xy00'
        if IsZero(imm[63:15]) || IsOnes(imm[63:15]) then
            return FALSE;
        end;

        // Check for 'ffffxy00ffffxy00' or '0000xy000000xy00'
        if imm[63:32] == imm[31:0] && (IsZero(imm[31:7]) || IsOnes(imm[31:7])) then
            return FALSE;
        end;

        // Check for 'xy00xy00xy00xy00'
        if imm[63:32] == imm[31:0] && imm[31:16] == imm[15:0] then
            return FALSE;
        end;
    end;

    return TRUE;
end;

// SetPSTATE_SM()
// ==============

func SetPSTATE_SM(value : bit)
begin
    if PSTATE.SM != value then
        ResetSVEState();
        PSTATE.SM = value;
    end;
end;

// SetPSTATE_ZA()
// ==============

func SetPSTATE_ZA(value : bit)
begin
    if PSTATE.ZA != value then
        ResetSMEState(value);
        PSTATE.ZA = value;
    end;
end;

// SupportedPowerTwoSVL()
// ======================
// Return an IMPLEMENTATION DEFINED specific value
// returns TRUE if SVL is supported and is a power of two, FALSE otherwise

readonly impdef func SupportedPowerTwoSVL(nbits : integer) => boolean
begin
    return IsPow2(nbits) && (nbits <= MAX_VL);
end;

// System Registers
// ================

constant MAX_VL : VecLen = 2048;

constant MAX_PL : PredLen = 256;

constant ZT0_LEN : integer{} = 512;

var _Z : array [[32]] of bits(MAX_VL);

var _P : array [[16]] of bits(MAX_PL);

var _FFR : bits(MAX_PL);

// VecLen
// ======

type VecLen of integer{128, 256, 512, 1024, 2048};

// Z - accessor
// ============

accessor Z{width}(n : integer) <=> value : bits(width)
begin
    getter
        assert n >= 0 && n <= 31;
        assert width == CurrentVL();
        return _Z[[n]][width-1:0];
    end;
    setter
        assert n >= 0 && n <= 31;
        assert width == CurrentVL();
        if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
            _Z[[n]] = ZeroExtend{MAX_VL}(value);
        else
            _Z[[n]][width-1:0] = value;
        end;
    end;
end;

// SysLOp()
// ========

func SysLOp(op1 : bits(3), CRn : bits(4), CRm : bits(4), op2 : bits(3)) => SystemLOp
begin
    case op1::CRn::CRm::op2 of
        when '000 1100 0011 000' => return Sysl_GICR;   // CDIA
        when '000 1100 0011 001' => return Sysl_GICR;   // CDNMIA
        otherwise                => return Sysl_SYSL;
    end;
end;

// SystemLOp
// =========
// System instruction with result types.

type SystemLOp of enumeration {
    Sysl_GICR,
    Sysl_SYSL
};

// SystemOp
// ========
// System instruction types.

type SystemOp of enumeration {
    Sys_AT,
    Sys_BRB,
    Sys_DC,
    Sys_GIC,
    Sys_GSB,
    Sys_IC,
    Sys_TLBI,
    Sys_SYS
};

// SystemOp128()
// =============
// System instruction types.

type SystemOp128 of enumeration {Sys_TLBIP, Sys_SYSP};

// ELR_EL - accessor
// =================

accessor ELR_EL(el : bits(2)) <=> value : bits(64)
begin
    getter
        var r : bits(64);
        case el of
            when EL1 =>  r = ELR_EL1();
            when EL2 =>  r = ELR_EL2();
            when EL3 =>  r = ELR_EL3();
            otherwise => unreachable;
        end;
        return r;
    end;
    setter
        let r : bits(64) = value;
        case el of
            when EL1 =>  ELR_EL1() = r;
            when EL2 =>  ELR_EL2() = r;
            when EL3 =>  ELR_EL3() = r;
            otherwise => unreachable;
        end;
    end;
end;

// ELR_ELx - accessor
// ==================

accessor ELR_ELx() <=> value : bits(64)
begin
    getter
        assert PSTATE.EL != EL0;
        return ELR_EL(PSTATE.EL);
    end;
    setter
        assert PSTATE.EL != EL0;
        ELR_EL(PSTATE.EL) = value;
    end;
end;

