// AArch64_CheckDAIFAccess()
// =========================
// Check that an AArch64 MSR/MRS access to the DAIF flags is permitted.

func AArch64_CheckDAIFAccess(field : PSTATEField)
begin
    if PSTATE.EL == EL0 && field IN {PSTATEField_DAIFSet, PSTATEField_DAIFClr} then
        if IsInHost() || SCTLR_EL1().UMA == '0' then
            if EL2Enabled() && HCR_EL2().TGE == '1' then
                AArch64_SystemAccessTrap(EL2, 0x18);
            else
                AArch64_SystemAccessTrap(EL1, 0x18);
            end;
        end;
    end;
end;

// AArch64_ChooseEIRGNonExcludedTag()
// ==================================
// Return a tag derived from SEED and and EIRGSTATE, excluding any tags in the
// given mask.

func AArch64_ChooseEIRGNonExcludedTag(exclude : bits(16)) => bits(4)
begin
    assert GCR_EL1().RRND == '0';

    if IsOnes(exclude) then
        return '0000';
    end;

    var bins : array[[16]] of bits(4);

    var N : integer = 0;
    for i = 0 to 15 do
        if exclude[i] == '0' then
            bins[[N]] = i[3:0];
            N = N + 1;
        end;
    end;

    let seed : bits(16) = RGSR_EL1().SEED[15:0];
    var eirgstate : integer = UInt(RGSR_EL1().TAG);

    eirgstate = eirgstate + 1;
    if eirgstate >= N then
        eirgstate = 0;
    end;

    let lbin : integer = (eirgstate + (N * UInt(seed)) >> 16) MOD N;

    RGSR_EL1().TAG = eirgstate[3:0];

    let top : bit = seed[5] XOR seed[3] XOR seed[2] XOR seed[0];
    RGSR_EL1().SEED[15:0] = top::seed[15:1];

    return bins[[lbin]];
end;

// AArch64_ChooseNonExcludedTag()
// ==============================
// Return a tag derived from the start and the offset values, excluding
// any tags in the given mask.

func AArch64_ChooseNonExcludedTag(tag_in : bits(4), offset_in : bits(4),
                                  exclude : bits(16)) => bits(4)
begin
    var tag : bits(4) = tag_in;
    var offset : bits(4) = offset_in;

    if IsOnes(exclude) then
        return '0000';
    end;

    if offset == '0000' then
        while exclude[UInt(tag)] == '1' looplimit 16 do
            tag = tag + '0001';
        end;
    end;

    while offset != '0000' looplimit 16 do
        offset = offset - '0001';
        tag = tag + '0001';
        while exclude[UInt(tag)] == '1' looplimit 16 do
            tag = tag + '0001';
        end;
    end;

    return tag;
end;

// AArch64_ChooseNonExludedTagOrZero()
// ===================================
// Return a tag derived from the start and the offset values, excluding any
// tags in the given mask, or zero if Allocation Tag access is not enabled.

func AArch64_ChooseNonExcludedTagOrZero(tag : bits(4), offset : bits(4),
                                        exclude : bits(16)) => bits(4)
begin
    if IsMTEEnabled(PSTATE.EL) then
        return AArch64_ChooseNonExcludedTag(tag, offset, exclude);
    else
        return '0000';
    end;
end;

// AArch64_ChooseTagOrZero()
// =========================
// Return a tag, excluding any tags in the given mask, , or zero if Allocation
// Tag access is not enabled.

func AArch64_ChooseTagOrZero(exclude : bits(16)) => bits(4)
begin
    if IsMTEEnabled(PSTATE.EL) then
        if GCR_EL1().RRND == '1' then
            if IsOnes(exclude) then
                return '0000';
            else
                return ChooseRandomNonExcludedTag(exclude);
            end;
        else
            if IsFeatureImplemented(FEAT_MTE_EIRG) then
                return AArch64_ChooseEIRGNonExcludedTag(exclude);
            end;
            let start_tag : bits(4) = RGSR_EL1().TAG;
            let offset : bits(4)    = AArch64_RandomTag();

            RGSR_EL1().TAG = AArch64_ChooseNonExcludedTag(start_tag, offset, exclude);

            return RGSR_EL1().TAG;
        end;
    else
        return '0000';
    end;
end;

// AArch64_ExecutingERETInstr()
// ============================
// Returns TRUE if current instruction is ERET.

func AArch64_ExecutingERETInstr() => boolean
begin
    let instr : bits(32) = ThisInstr();
    return instr[31:12] == '11010110100111110000';
end;

