// AArch64_TLBIP_IPAS2()
// =====================
// Invalidate by IPA all stage 2 only TLB entries in the indicated broadcast
// domain matching the indicated VMID in the indicated regime with the indicated security state.
// Note: stage 1 and stage 2 combined entries are not in the scope of this operation.
// IPA and related parameters of the are derived from Xt.

func AArch64_TLBIP_IPAS2(security : SecurityState, regime : Regime, vmid : bits(16),
                         broadcast_in : Broadcast, level : TLBILevel, attr : TLBIMemAttr,
                         Xt : bits(128))
begin
    assert PSTATE.EL IN {EL3, EL2};
    var broadcast : Broadcast = broadcast_in;

    var r : TLBIRecord;
    r.op           = TLBIOp_IPAS2;
    r.from_aarch64 = TRUE;
    r.security     = security;
    r.regime       = regime;
    r.vmid         = vmid;
    r.use_vmid     = TRUE;
    r.level        = level;
    r.attr         = attr;
    r.ttl          = Xt[47:44];
    r.address      = ZeroExtend{64}(Xt[107:64] :: Zeros{12});
    if IsFeatureImplemented(FEAT_TLBID) && Xt[32] == '1' then
        r.d64      = TRUE;
        r.d128     = r.ttl == '00xx';
    else
        r.d64      = r.ttl == '00xx';
        r.d128     = TRUE;
    end;

    case security of
        when SS_NonSecure =>
            r.ipaspace = PAS_NonSecure;
        when SS_Secure =>
            r.ipaspace = if Xt[63] == '1' then PAS_NonSecure else PAS_Secure;
        when SS_Realm =>
            r.ipaspace = PAS_Realm;
        otherwise =>
            // Root security state does not have stage 2 translation
            unreachable;
    end;

    TLBI(r);
    let domains : bits(16) = TLBIDomains(broadcast, Xt[15:0]);
    if (broadcast == Broadcast_OSH &&
          (IsBroadcast_OSHnISH(regime) || OSHDomainExceedsNIS(domains))) then
        broadcast = Broadcast_OSHnISH;
    end;

    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r, domains); end;

    return;
end;

// AArch64_TLBIP_RIPAS2()
// ======================
// Range invalidate by IPA all stage 2 only TLB entries in the indicated
// broadcast domain matching the indicated VMID in the indicated regime with the indicated
// security state.
// Note: stage 1 and stage 2 combined entries are not in the scope of this operation.
// The range of IPA and related parameters of the are derived from Xt.

func AArch64_TLBIP_RIPAS2(security : SecurityState, regime : Regime, vmid : bits(16),
                          broadcast_in : Broadcast, level : TLBILevel, attr : TLBIMemAttr,
                          Xt : bits(128))
begin
    assert PSTATE.EL IN {EL3, EL2, EL1};
    var broadcast : Broadcast = broadcast_in;

    var r : TLBIRecord;
    r.op           = TLBIOp_RIPAS2;
    r.from_aarch64 = TRUE;
    r.security     = security;
    r.regime       = regime;
    r.vmid         = vmid;
    r.use_vmid     = TRUE;
    r.level        = level;
    r.attr         = attr;
    r.ttl[1:0]     = Xt[38:37];
    if IsFeatureImplemented(FEAT_TLBID) && Xt[32] == '1' then
        r.d64      = TRUE;
        r.d128     = r.ttl[1:0] == '00';
    else
        r.d64      = r.ttl[1:0] == '00';
        r.d128     = TRUE;
    end;

    var valid : boolean;
    (valid, r.tg, r.address, r.end_address) = TLBIPRange(regime, Xt);

    if !valid then return; end;

    case security of
        when SS_NonSecure =>
            r.ipaspace = PAS_NonSecure;
        when SS_Secure =>
            r.ipaspace = if Xt[63] == '1' then PAS_NonSecure else PAS_Secure;
        when SS_Realm =>
            r.ipaspace = PAS_Realm;
        otherwise =>
            // Root security state does not have stage 2 translation
            unreachable;
    end;

    TLBI(r);
    let domains : bits(16) = TLBIDomains(broadcast, Xt[15:0]);
    if (broadcast == Broadcast_OSH &&
          (IsBroadcast_OSHnISH(regime) || OSHDomainExceedsNIS(domains))) then
        broadcast = Broadcast_OSHnISH;
    end;

    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r, domains); end;

    return;
end;

