    r.level        = level;
    r.attr         = attr;
    r.ttl          = Xt[47:44];
    r.address      = ZeroExtend{64}(Xt[43:0] :: Zeros{12});
    r.d64          = TRUE;
    r.d128         = r.ttl == '00xx';

    TLBI(r);
    if broadcast == Broadcast_OSH && IsBroadcast_OSHnISH(regime) then
        broadcast = Broadcast_OSHnISH;
    end;
    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r); end;

