end;

// AArch64_TLBI_VMALL()
// ====================
// Invalidate all stage 1 entries for the indicated translation regime with the
// the indicated security state for all TLBs within the indicated broadcast
// domain that match the indicated VMID (where applicable).
// Note: stage 1 and stage 2 combined entries are in the scope of this operation.
// Note: stage 2 only entries are not in the scope of this operation.

func AArch64_TLBI_VMALL(security : SecurityState, regime : Regime,
                        vmid : bits(16), broadcast_in : Broadcast,
                        attr : TLBIMemAttr, Xt : bits(64))
begin
    assert PSTATE.EL IN {EL3, EL2, EL1};
    var broadcast : Broadcast = broadcast_in;

    var r : TLBIRecord;
    r.op           = TLBIOp_VMALL;
    r.from_aarch64 = TRUE;
    r.security     = security;
    r.regime       = regime;
    r.level        = TLBILevel_Any;
    r.vmid         = vmid;
    r.use_vmid     = UseVMID(regime);
    r.attr         = attr;

    TLBI(r);
    let domains : bits(16) = TLBIDomains(broadcast, Xt[15:0]);
    if (broadcast == Broadcast_OSH &&
          (IsBroadcast_OSHnISH(regime) || OSHDomainExceedsNIS(domains))) then
        broadcast = Broadcast_OSHnISH;
    end;

    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r, domains); end;

    return;
end;

// AArch64_TLBI_VMALLS12()
// =======================
// Invalidate all stage 1 and stage 2 entries for the indicated translation
// regime with the indicated security state for all TLBs within the indicated
// broadcast domain that match the indicated VMID.

func AArch64_TLBI_VMALLS12(security : SecurityState, regime : Regime,
                           vmid : bits(16), broadcast_in : Broadcast,
                           attr : TLBIMemAttr, Xt : bits(64))
begin
    assert PSTATE.EL IN {EL3, EL2};
    var broadcast : Broadcast = broadcast_in;

    var r : TLBIRecord;
    r.op           = TLBIOp_VMALLS12;
    r.from_aarch64 = TRUE;
    r.security     = security;
    r.regime       = regime;
    r.level        = TLBILevel_Any;
    r.vmid         = vmid;
    r.use_vmid     = TRUE;
    r.attr         = attr;

    TLBI(r);
    let domains : bits(16) = TLBIDomains(broadcast, Xt[15:0]);
    if (broadcast == Broadcast_OSH &&
          (IsBroadcast_OSHnISH(regime) || OSHDomainExceedsNIS(domains))) then
        broadcast = Broadcast_OSHnISH;
    end;

    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r, domains); end;

    return;
end;

// AArch64_TLBI_VMALLWS2()
// =======================
// Remove stage 2 dirty state from entries for the indicated translation regime
// with the indicated security state for all TLBs within the indicated broadcast
// domain that match the indicated VMID.

func AArch64_TLBI_VMALLWS2(security : SecurityState, regime : Regime, vmid : bits(16),
                           broadcast_in : Broadcast, attr : TLBIMemAttr,
                           Xt : bits(64))
begin
    assert PSTATE.EL IN {EL3, EL2};
    assert regime == Regime_EL10;

    if security == SS_Secure && HaveEL(EL3) && SCR_EL3().EEL2 == '0' then
        return;
    end;

    var broadcast : Broadcast = broadcast_in;

    var r : TLBIRecord;
    r.op           = TLBIOp_VMALLWS2;
    r.from_aarch64 = TRUE;
    r.security     = security;
    r.regime       = regime;
    r.level        = TLBILevel_Any;
    r.vmid         = vmid;
    r.use_vmid     = TRUE;
    r.attr         = attr;

    TLBI(r);
    let domains : bits(16) = TLBIDomains(broadcast, Xt[15:0]);
    if (broadcast == Broadcast_OSH &&
          (IsBroadcast_OSHnISH(regime) || OSHDomainExceedsNIS(domains))) then
        broadcast = Broadcast_OSHnISH;
    end;

    if broadcast != Broadcast_NSH then BroadcastTLBI(broadcast, r, domains); end;

    return;
end;

// DecodeTLBITG()
// ==============
// Decode translation granule size in TLBI range instructions

func DecodeTLBITG(tg : bits(2)) => TGx
begin
    case tg of
        when '01' =>   return TGx_4KB;
        when '10' =>   return TGx_16KB;
        when '11' =>   return TGx_64KB;
    end;
end;

// GPTTLBIMatch()
// ==============
// Determine whether the GPT TLB entry lies within the scope of invalidation

func GPTTLBIMatch(tlbi : TLBIRecord, gpt_entry : GPTEntry) => boolean
begin
    assert tlbi.op IN {TLBIOp_RPA, TLBIOp_PAALL};

    var match : boolean;
    let entry_size_mask : bits(64)     = ZeroExtend{}(Ones{gpt_entry.size});
    let entry_end_address : bits(64)   = (ZeroExtend{64}(gpt_entry.pa[55:0] OR
                                             entry_size_mask[55:0]));
    let entry_start_address : bits(64) = (ZeroExtend{64}(gpt_entry.pa[55:0] AND NOT
                                             entry_size_mask[55:0]));

    case tlbi.op of
        when TLBIOp_RPA =>
            match = (UInt(tlbi.address[55:0]) <= UInt(entry_end_address[55:0]) &&
                     UInt(tlbi.end_address[55:0]) > UInt(entry_start_address[55:0]) &&
                     (tlbi.level == TLBILevel_Any || gpt_entry.level == 1));
        when TLBIOp_PAALL =>
            match = TRUE;
    end;

    return match;
end;

// HasLargeAddress()
// =================
// Returns TRUE if the regime is configured for 52 bit addresses, FALSE otherwise.

func HasLargeAddress(regime : Regime) => boolean
begin
    if !IsFeatureImplemented(FEAT_LPA2) then
        return FALSE;
    end;
    case regime of
        when Regime_EL3 =>
            return TCR_EL3().DS == '1';
        when Regime_EL2 =>
            return TCR_EL2().DS == '1';
        when Regime_EL20 =>
            return TCR_EL2().DS == '1';
        when Regime_EL10 =>
            return TCR_EL1().DS == '1';
        otherwise =>
            unreachable;
    end;
end;

// IsBroadcast_OSHnISH()
// =====================
// Returns TRUE if a TLBI *OS* instruction affects TLBs in the Outer shareability domain,
// but not in the Inner shareability domain.

func IsBroadcast_OSHnISH(regime : Regime) => boolean
begin
    case regime of
        when Regime_EL3  => return FALSE;
        when Regime_EL20 => return IsSCTLR2EL2Enabled() && SCTLR2_EL2().TLBOSNIS == '1';
        when Regime_EL10 => return IsSCTLR2EL1Enabled() && SCTLR2_EL1().TLBOSNIS == '1';
        otherwise        => unreachable;
    end;
end;

// OSHDomainExceedsNIS()
// =====================
// Returns TRUE if a TLBI *OS* instruction affects TLBs in the Outer shareability domain,
// but not in the Inner shareability domain.

func OSHDomainExceedsNIS(domains : bits(16)) => boolean
begin
    // If the TLBID value exceeds the supported value in TLBIDIDR_EL1.NIS, then no TLBs in the
    // Inner Shareable shareability domain are guaranteed to be affected by the TLBI operation.
    let nis : integer{} = UInt(TLBIDIDR_EL1().NIS);
    return nis < 16 && !IsZero(domains[15:nis]);
end;

// ResTLBIRTTL()
// =============
// Determine whether the TTL field in TLBI instructions that do apply
// to a range of addresses contains a reserved value

func ResTLBIRTTL(tg : bits(2), ttl : bits(2)) => boolean
begin
    case ttl of
        when '00' => return TRUE;
        when '01' => return DecodeTLBITG(tg) == TGx_16KB && !IsFeatureImplemented(FEAT_LPA2);
        otherwise => return FALSE;
    end;
end;

// ResTLBITTL()
// ============
// Determine whether the TTL field in TLBI instructions that do not apply
// to a range of addresses contains a reserved value

func ResTLBITTL(ttl : bits(4)) => boolean
begin
    case ttl of
        when '00xx' => return TRUE;
        when '0100' => return !IsFeatureImplemented(FEAT_LPA2);
        when '1000' => return TRUE;
        when '1001' => return !IsFeatureImplemented(FEAT_LPA2);
        when '1100' => return TRUE;
        otherwise =>   return FALSE;
    end;
end;

// TGBits()
// ========
// Return the number of least-significant address bits within a single Translation Granule.

func TGBits(tg : bits(2)) => AddressSize
begin
    case tg of
        when '01' => return 12; // 4KB
        when '10' => return 14; // 16KB
        when '11' => return 16; // 64KB
        otherwise =>
            unreachable;
    end;
end;

// TLBIDomains()
// =============
// Determine the domains the TLBI operation is broadcast to

func TLBIDomains(broadcast_in : Broadcast, tlbid_in : bits(16)) => bits(16)
begin
    assert broadcast_in != Broadcast_OSHnISH;

    var broadcast : Broadcast = broadcast_in;
    var tlbid : bits(16)      = tlbid_in;

    if !IsFeatureImplemented(FEAT_TLBID) then return DEFAULT_TLBI_DOMAIN; end;
    if broadcast == Broadcast_NSH        then return DEFAULT_TLBI_DOMAIN; end;
    if broadcast == Broadcast_ISH_CnP    then return DEFAULT_TLBI_DOMAIN; end;
    if PSTATE.EL == EL3                  then return DEFAULT_TLBI_DOMAIN; end;

    let nos : integer{} = UInt(TLBIDIDR_EL1().NOS);
    assert nos <= 16;
    if broadcast == Broadcast_OSH && nos == 0 then
        return DEFAULT_TLBI_DOMAIN;
    end;

    let nis : integer{} = UInt(TLBIDIDR_EL1().NIS);
    assert nis <= 16;
    if broadcast == Broadcast_ISH && nis == 0 then
        return DEFAULT_TLBI_DOMAIN;
    end;

    if PSTATE.EL == EL2 then
        if broadcast == Broadcast_OSH then
            return ZeroExtend{16}(tlbid[nos-1:0]);
        else    // Broadcast_ISH
            return ZeroExtend{16}(tlbid[nis-1:0]);
        end;
    end;

    assert PSTATE.EL == EL1;

    if broadcast == Broadcast_ForcedISH then
        // For a TLBI instruction without an IS or OS qualifier executed at EL1, if HCR_EL2.FB
        // is 1 then the process for a TLBI IS instruction is followed as though TLBID is zero.
        broadcast = Broadcast_ISH;
        tlbid     = Zeros{16};
    end;

    assert broadcast IN {Broadcast_ISH, Broadcast_OSH};

    // If the Effective value of VTLBID(OS)En is 0 the TLBID field is not transformed.
    if ((HaveEL(EL3) && SCR_EL3().VTLBIDEn == '0') || !IsHCRXEL2Enabled() ||
          (broadcast == Broadcast_OSH && HCRX_EL2().VTLBIDOSEn == '0') ||
          (broadcast == Broadcast_ISH && HCRX_EL2().VTLBIDEn == '0')) then
        if broadcast == Broadcast_OSH then
            return ZeroExtend{16}(tlbid[nos-1:0]);
        else    // Broadcast_ISH
            return ZeroExtend{16}(tlbid[nis-1:0]);
        end;
    end;

    if broadcast == Broadcast_OSH then
        let nvos : integer{} = UInt(TLBIDIDR_EL1().NVOS);
        assert (nos <= 8 && nvos <= 5) || (nos <= 16 && nvos <= 4);

        // If NVOS is 0, the TLBID field is ignored as only VTLBIDOS_EL2(n).TD0 is implemented.
        let d : integer{} = if nvos == 0 then 0 else UInt(tlbid[nvos-1:0]);
        let s : integer{} = if nos <= 8 then 8 else 4;
        let n : integer = d DIVRM s;
        let m : integer = d MOD s;

        var vtlbid : bits(16);
        if nos <= 8 then
            vtlbid = ZeroExtend{16}(VTLBIDOS_EL2(n)[8*m+:8]);
        else
            vtlbid = VTLBIDOS_EL2(n)[16*m+:16];
        end;

        return ZeroExtend{16}(vtlbid[nos-1:0]);
    else    // Broadcast_ISH
        let nvis : integer{} = UInt(TLBIDIDR_EL1().NVIS);
        assert (nis <= 8 && nvis <= 5) || (nis <= 16 && nvis <= 4);

        // If NVIS is 0, the TLBID field is ignored as only VTLBID_EL2(n).TD0 is implemented.
        let d : integer{} = if nvis == 0 then 0 else UInt(tlbid[nvis-1:0]);
        let s : integer{} = if nis <= 8 then 8 else 4;
        let n : integer = d DIVRM s;
        let m : integer = d MOD s;

        var vtlbid : bits(16);
        if nis <= 8 then
            vtlbid = ZeroExtend{16}(VTLBID_EL2(n)[8*m+:8]);
        else
            vtlbid = VTLBID_EL2(n)[16*m+:16];
        end;

        return ZeroExtend{16}(vtlbid[nis-1:0]);
    end;
end;

// TLBIMatch() // =========== // Determine whether the TLB entry lies within the scope of invalidation
