// ============

type CrossTriggerOut of enumeration {CrossTriggerOut_DebugRequest, CrossTriggerOut_RestartRequest,
                                     CrossTriggerOut_IRQ,          CrossTriggerOut_RSVD3,
                                     CrossTriggerOut_TraceExtIn0,  CrossTriggerOut_TraceExtIn1,
