// AArch64_BranchAddr()
// ====================
// Return the virtual address with tag bits removed.
// This is typically used when the address will be stored to the program counter.

func AArch64_BranchAddr(vaddress : bits(64), el : bits(2)) => bits(64)
begin
    assert !UsingAArch32();
    let msbit : integer{} = AddrTop(vaddress, TRUE, el);
    if msbit == 63 then
        return vaddress;
    elsif (el IN {EL0, EL1} || IsInHost()) && vaddress[msbit] == '1' then
        return SignExtend{64}(vaddress[msbit:0]);
    else
        return ZeroExtend{64}(vaddress[msbit:0]);
    end;
end;

// AddrTop()
// =========
// Return the MSB number of a virtual address in the stage 1 translation regime for "el".
// If EL1 is using AArch64 then addresses from EL0 using AArch32 are zero-extended to 64 bits.

func AddrTop(address : bits(64), IsInstr : boolean, el : bits(2)) => AddressSize
begin
    assert HaveEL(el);
    let regime : bits(2) = S1TranslationRegime(el);
    if ELUsingAArch32(regime) then
        // AArch32 translation regime.
        return 31;
    else
        if EffectiveTBI(address, IsInstr, el) == '1' then
            return 55;
        else
            return 63;
        end;
    end;
end;

// AddressSize
// ============

type AddressSize of integer{3..64};

// AlignmentEnforced()
// ===================
// For the active translation regime, determine if alignment is required by all accesses

func AlignmentEnforced() => boolean
begin
    let regime : Regime = TranslationRegime(PSTATE.EL);
    var A : bit;
    case regime of
        when Regime_EL30 => A = SCTLR().A;
        when Regime_EL3 =>  A = SCTLR_EL3().A;
        when Regime_EL2 =>  A = if ELUsingAArch32(EL2) then HSCTLR().A else SCTLR_EL2().A;
        when Regime_EL20 => A = SCTLR_EL2().A;
        when Regime_EL10 => A = if ELUsingAArch32(EL1) then SCTLR().A  else SCTLR_EL1().A;
        otherwise => unreachable;
    end;
    return A == '1';
end;

// Allocation hints
// ================

constant MemHint_No : bits(2)  = '00';   // No Read-Allocate, No Write-Allocate

constant MemHint_WA : bits(2)  = '01';   // No Read-Allocate, Write-Allocate

constant MemHint_RA : bits(2)  = '10';   // Read-Allocate, No Write-Allocate

constant MemHint_RWA : bits(2) = '11';   // Read-Allocate, Write-Allocate

// BigEndian()
// ===========

func BigEndian(acctype : AccessType) => boolean
begin
    var bigend : boolean;
    if IsFeatureImplemented(FEAT_NV2) && acctype == AccessType_NV2 then
        return SCTLR_EL2().EE == '1';
    end;

    if UsingAArch32() then
        bigend = (PSTATE.E != '0');
    elsif PSTATE.EL == EL0 then
        bigend = (SCTLR_ELx().E0E != '0');
    else
        bigend = (SCTLR_ELx().EE != '0');
    end;
    return bigend;
end;

// BigEndianReverse()
// ==================

func BigEndianReverse{width}(value : bits(width)) => bits(width)
begin
    assert width IN {8, 16, 32, 64, 128, 256};

    if width == 8 then return value; end;
    return Reverse{width}(value, 8);
end;

