    accdesc.acqsc           = acqsc;
    accdesc.relsc           = memop == MemOp_STORE;
    accdesc.limitedordered  = TRUE;
    accdesc.read            = memop == MemOp_LOAD;
    accdesc.write           = memop == MemOp_STORE;
    accdesc.pan             = TRUE;
    accdesc.tagchecked      = tagchecked;
    accdesc.Rt              = Rt;

    return accdesc;
end;

// CreateAccDescLS64()
// ===================
// Access descriptor for accelerator-supporting memory accesses

func CreateAccDescLS64(memop : MemOp, withstatus : boolean,
                       tagchecked : boolean) => AccessDescriptor
begin
    var accdesc : AccessDescriptor = NewAccDesc(AccessType_GPR);

    accdesc.read            = memop == MemOp_LOAD;
    accdesc.write           = memop == MemOp_STORE;
    accdesc.pan             = TRUE;
    accdesc.ls64            = TRUE;
    accdesc.withstatus      = withstatus;
    accdesc.tagchecked      = tagchecked;
    return accdesc;
end;

// CreateAccDescMOPS()
// ===================
// Access descriptor for data memory copy and set instructions

func CreateAccDescMOPS(memop : MemOp, privileged : boolean,
                       nontemporal : boolean) => AccessDescriptor
begin
    var accdesc : AccessDescriptor = NewAccDesc(AccessType_GPR);

    accdesc.el              = if !privileged then EL0 else PSTATE.EL;
    accdesc.nontemporal     = nontemporal;
    accdesc.read            = memop == MemOp_LOAD;
    accdesc.write           = memop == MemOp_STORE;
    accdesc.pan             = TRUE;
    accdesc.mops            = TRUE;
    accdesc.tagchecked      = TRUE;

    return accdesc;
end;

// CreateAccDescMPAMv2VID()
// ========================
// Access descriptor for memory accesses to the MVMS or MITT structures.

func CreateAccDescMPAMv2VID(pspace : PARTIDSpaceType) => AccessDescriptor
begin
    var mpaminfo : MPAMinfo;
    mpaminfo.mpam_sp = pspace;
    mpaminfo.partid  = MPAM2_EL2().PARTID;
    mpaminfo.pmg     = MPAM2_EL2().PMG;

    var accdesc : AccessDescriptor = NewAccDesc(AccessType_MPAMv2VID, mpaminfo);
    accdesc.read     = TRUE;
    return accdesc;
end;

// CreateAccDescNV2()
// ==================
// Access descriptor nested virtualization memory indirection loads/stores

func CreateAccDescNV2(memop : MemOp) => AccessDescriptor
begin
    var accdesc : AccessDescriptor = NewAccDesc(AccessType_NV2);

    accdesc.el              = EL2;
    accdesc.ss              = SecurityStateAtEL(EL2);
    accdesc.read            = memop == MemOp_LOAD;
    accdesc.write           = memop == MemOp_STORE;

    return accdesc;
end;

// CreateAccDescRCW()
// ==================
// Access descriptor for atomic read-check-write memory accesses

func CreateAccDescRCW(modop : MemAtomicOp, soft : boolean, acquire : boolean,
                      release : boolean, tagchecked : boolean,
                      Rt : integer, Rs : integer) => AccessDescriptor
begin
    let Rt2 : integer = -1;
    let Rs2 : integer = -1;

    return CreateAccDescRCW(modop, soft, acquire, release, tagchecked, Rt, Rt2, Rs, Rs2);
end;

func CreateAccDescRCW(modop : MemAtomicOp, soft : boolean, acquire : boolean,
                      release : boolean, tagchecked : boolean, Rt : integer, Rt2 : integer,
                      Rs : integer, Rs2 : integer) => AccessDescriptor
begin
    var accdesc : AccessDescriptor = NewAccDesc(AccessType_GPR);

    accdesc.acqsc           = acquire;
    accdesc.relsc           = release;
    accdesc.rcw             = TRUE;
    accdesc.rcws            = soft;
    accdesc.atomicop        = TRUE;
    accdesc.modop           = modop;
    accdesc.read            = TRUE;
    accdesc.write           = TRUE;
    accdesc.pan             = TRUE;
    accdesc.tagchecked      = tagchecked;
    accdesc.Rt              = Rt;
    accdesc.Rt2             = Rt2;
    accdesc.Rs              = Rs;
    accdesc.Rs2             = Rs2;

    return accdesc;
end;

