// NewAccDesc()
// ============
// Create a new AccessDescriptor with initialised fields

func NewAccDesc(acctype : AccessType) => AccessDescriptor
begin
    let mpaminfo : MPAMinfo = GenMPAMCurEL(acctype);
    return NewAccDesc(acctype, mpaminfo);
end;

func NewAccDesc(acctype : AccessType, mpam : MPAMinfo) => AccessDescriptor
begin
    var accdesc : AccessDescriptor;

    accdesc.acctype             = acctype;
    accdesc.el                  = PSTATE.EL;
    accdesc.ss                  = SecurityStateAtEL(PSTATE.EL);
    accdesc.acqsc               = FALSE;
    accdesc.acqpc               = FALSE;
    accdesc.relsc               = FALSE;
    accdesc.limitedordered      = FALSE;
    accdesc.exclusive           = FALSE;
    accdesc.rcw                 = FALSE;
    accdesc.rcws                = FALSE;
    accdesc.atomicop            = FALSE;
    accdesc.nontemporal         = FALSE;
    accdesc.read                = FALSE;
    accdesc.write               = FALSE;
    accdesc.pan                 = FALSE;
    accdesc.nonfault            = FALSE;
    accdesc.firstfault          = FALSE;
    accdesc.first               = FALSE;
    accdesc.contiguous          = FALSE;
    accdesc.predicated          = FALSE;
    accdesc.streamingsve        = FALSE;
    accdesc.ls64                = FALSE;
    accdesc.withstatus          = FALSE;
    accdesc.mops                = FALSE;
    accdesc.a32lsmd             = FALSE;
    accdesc.tagchecked          = FALSE;
    accdesc.tagaccess           = FALSE;
    accdesc.stzgm               = FALSE;
    accdesc.mpam                = mpam;
    accdesc.Rs                  = -1;
    accdesc.Rs2                 = -1;
    accdesc.Rt                  = -1;
    accdesc.Rt2                 = -1;
    accdesc.ispair              = FALSE;
    accdesc.highestaddressfirst = FALSE;
    accdesc.lowestaddress       = TRUE;

    return accdesc;
end;

// PASpace
// =======
// Physical address spaces

type PASpace of enumeration {
    PAS_Root,
    PAS_SystemAgent,
    PAS_NonSecureProtected,
    PAS_NA6,                // Reserved
    PAS_NA7,                // Reserved
    PAS_Realm,
    PAS_Secure,
    PAS_NonSecure
};

// PhysMemRead()
// =============
// Returns the value read from memory, and a status.
// Returned value is UNKNOWN if an External abort occurred while reading the
// memory.
// Otherwise the PhysMemRetStatus statuscode is Fault_None.

impdef func PhysMemRead{size : integer{8, 16, 32, 64, 128, 256, 512}}(
                                                    desc : AddressDescriptor,
                                                    accdesc : AccessDescriptor
                                            ) => (PhysMemRetStatus, bits(size))
begin
    return (ARBITRARY : PhysMemRetStatus, ARBITRARY : bits(size));
end;

// PhysMemRetStatus
// ================
// Fields that relate only to return values of PhysMem functions.

type PhysMemRetStatus of record {
    statuscode : Fault,       // Fault Status
    extflag : bit,            // IMPLEMENTATION DEFINED syndrome for External aborts
    merrorstate : ErrorState, // Optional error state returned on a physical memory access
    store64bstatus : bits(64) // Status of 64B store

};

// PhysMemWrite()
// ==============
// Writes the value to memory, and returns the status of the write.
// If there is an External abort on the write, the PhysMemRetStatus indicates this.
// Otherwise the statuscode of PhysMemRetStatus is Fault_None.

impdef func PhysMemWrite{size : integer{8, 16, 32, 64, 128, 256, 512}}(desc : AddressDescriptor,
                                                                       accdesc : AccessDescriptor,
                                                value : bits(size)) => PhysMemRetStatus
begin
    return ARBITRARY : PhysMemRetStatus;
end;

// PrefetchHint
// ============
// Prefetch hint types.

type PrefetchHint of enumeration {Prefetch_READ, Prefetch_WRITE, Prefetch_EXEC};

// S1AccessControls
// ================
// Effective access controls defined by stage 1 translation

type S1AccessControls of record {
    r : bit,                 // Stage 1 base read permission
    w : bit,                 // Stage 1 base write permission
    x : bit,                 // Stage 1 base execute permission
    gcs : bit,               // Stage 1 GCS permission
    overlay : boolean,       // Stage 1 FEAT_S1POE overlay applies
    or : bit,                // Stage 1 FEAT_S1POE overlay read permission
    ow : bit,                // Stage 1 FEAT_S1POE overlay write permission
    ox : bit,                // Stage 1 FEAT_S1POE overlay execute permission
    wxn : bit                // Stage 1 write permission implies execute-never

};

// Shareability
// ============

type Shareability of enumeration {
    Shareability_NSH,
    Shareability_ISH,
    Shareability_OSH
};

// SpeculativeStoreBypassBarrierToPA()
// ===================================

impdef func SpeculativeStoreBypassBarrierToPA()
begin
    // Since there is no speculation in ASL model, this is a NOP.
    return;
end;

// SpeculativeStoreBypassBarrierToVA()
// ===================================

impdef func SpeculativeStoreBypassBarrierToVA()
begin
    // Since there is no speculation in ASL model, this is a NOP.
    return;
end;

// Tag Granule size
// ================

constant LOG2_TAG_GRANULE : integer{} = 4;

constant TAG_GRANULE : integer{} = 1 << LOG2_TAG_GRANULE;

// VARange
// =======
// Virtual address ranges

type VARange of enumeration {
    VARange_LOWER,
    VARange_UPPER
};

// AltPARTIDSpace()
// ================
// From the Security state, EL and ALTSP configuration, determine
// whether to primary space or the alt space is selected and which
// PARTID space is the alternative space. Return that alternative
// PARTID space if selected or the primary space if not.

func AltPARTIDSpace(el : bits(2), security : SecurityState,
                    primaryPIDSpace : PARTIDSpaceType) => PARTIDSpaceType
begin
    case security of
        when SS_NonSecure =>
            assert el != EL3;
            return primaryPIDSpace;
        when SS_Secure =>
            assert el != EL3;
            if primaryPIDSpace == PIDSpace_NonSecure then
                return primaryPIDSpace;
            end;
            return AltPIDSecure(el, primaryPIDSpace);
        when SS_Root =>
            assert el == EL3;
            if MPAM3_EL3().ALTSP_EL3 == '1' then
                if MPAM3_EL3().RT_ALTSP_NS == '1' then
                    return PIDSpace_NonSecure;
                else
                    return PIDSpace_Secure;
                end;
            else
                return primaryPIDSpace;
            end;
        when SS_Realm =>
            assert el != EL3;
            return AltPIDRealm(el, primaryPIDSpace);
        otherwise =>
            unreachable;
    end;
end;

// AltPIDRealm()
// =============
// Compute PARTID space as either the primary PARTID space or
// alternative PARTID space in the Realm Security state.
// Helper for AltPARTIDSpace.

func AltPIDRealm(el : bits(2), primaryPIDSpace : PARTIDSpaceType) => PARTIDSpaceType
begin
    var PIDSpace : PARTIDSpaceType = primaryPIDSpace;
    case el of
        when EL0 =>
            if ELIsInHost(EL0) then
                if !UsePrimarySpaceEL2() then
                    PIDSpace = PIDSpace_NonSecure;
                end;
            elsif !UsePrimarySpaceEL10() then
                PIDSpace = PIDSpace_NonSecure;
            end;
        when EL1 =>
            if !UsePrimarySpaceEL10() then
                PIDSpace = PIDSpace_NonSecure;
            end;
        when EL2 =>
            if !UsePrimarySpaceEL2() then
                PIDSpace = PIDSpace_NonSecure;
            end;
        otherwise =>
            unreachable;
    end;
    return PIDSpace;
end;

// AltPIDSecure()
// ==============
// Compute PARTID space as either the primary PARTID space or
// alternative PARTID space in the Secure Security state.
// Helper for AltPARTIDSpace.

func AltPIDSecure(el : bits(2), primaryPIDSpace : PARTIDSpaceType) => PARTIDSpaceType
begin
    var PIDSpace : PARTIDSpaceType = primaryPIDSpace;
    case el of
        when EL0 =>
            if EL2Enabled() then
                if ELIsInHost(EL0) then
                    if !UsePrimarySpaceEL2() then
                        PIDSpace = PIDSpace_NonSecure;
                    end;
                elsif !UsePrimarySpaceEL10() then
                    PIDSpace = PIDSpace_NonSecure;
                end;
            elsif MPAM3_EL3().ALTSP_HEN == '0' && MPAM3_EL3().ALTSP_HFC == '1' then
                PIDSpace = PIDSpace_NonSecure;
            end;
        when EL1 =>
            if EL2Enabled() then
                if !UsePrimarySpaceEL10() then
                    PIDSpace = PIDSpace_NonSecure;
                end;
            elsif MPAM3_EL3().ALTSP_HEN == '0' && MPAM3_EL3().ALTSP_HFC == '1' then
                PIDSpace = PIDSpace_NonSecure;
            end;
        when EL2 =>
            if !UsePrimarySpaceEL2() then
                PIDSpace = PIDSpace_NonSecure;
            end;
        otherwise =>
            unreachable;
    end;
    return PIDSpace;
end;

// DefaultMPAMInfo()
// =================
// Returns default MPAM info.  The partidspace argument sets
// the PARTID space of the default MPAM information returned.

func DefaultMPAMInfo(partidspace : PARTIDSpaceType) => MPAMinfo
begin
    var defaultinfo : MPAMinfo;
    defaultinfo.mpam_sp = partidspace;
    defaultinfo.partid  = DEFAULT_PARTID;
    defaultinfo.pmg     = DEFAULT_PMG;
    return defaultinfo;
end;

// GenMPAM()
// =========
// Returns MPAMinfo for Exception level el.
// If mpamdata.sm is TRUE returns MPAM information using MPAMSM_EL1.
// If mpamdata.trb is TRUE returns MPAM information using TRBMPAM_EL1.
// If mpamdata.in_d is TRUE and alternative ID is enabled returns MPAM information
// using MPAMn_ELx.[altPARTID, altPMG].
// Otherwise returns MPAM information using MPAMn_ELx.

func GenMPAM(el_in : bits(2), mpamdata : MPAMdata, pspace : PARTIDSpaceType) => MPAMinfo
begin
    var returninfo : MPAMinfo;
    var partidel : PARTIDType;
    var perr : boolean;
    var el : bits(2) = el_in;

    // Check if the guest OS application is locked by the EL2 hypervisor to
    // only use the EL1 virtual machine's PARTIDs.
    if (!IsFeatureImplemented(FEAT_MPAMv2) && el == EL0 && EL2Enabled() &&
          MPAMHCR_EL2().GSTAPP_PLK == '1' && HCR_EL2().TGE == '0') then
        el = EL1;
    end;

    (partidel, perr)      = GenPARTID(el, mpamdata, pspace);
    let groupel : PMGType = GenPMG(el, mpamdata, perr, pspace);

    returninfo.mpam_sp = pspace;
    returninfo.partid  = partidel;
    returninfo.pmg     = groupel;
    return returninfo;
end;

// GenMPAMAtEL()
// =============
// Returns MPAMinfo for the specified EL.
// May be called if MPAM is not implemented (but in an version that supports
// MPAM), MPAM is disabled, or in AArch32_  In AArch32, convert the mode to
// EL if can and use that to drive MPAM information generation.  If mode
// cannot be converted, MPAM is not implemented, or MPAM is disabled return
// default MPAM information for the current security state.

func GenMPAMAtEL(acctype : AccessType, el : bits(2)) => MPAMinfo
begin
    var mpamEL : bits(2);
    var pspace : PARTIDSpaceType;
    let security : SecurityState = SecurityStateAtEL(el);
    var mpamdata : MPAMdata      = GenNewMPAMData();
    if IsFeatureImplemented(FEAT_MPAMv2_MSC) && IsFeatureImplemented(FEAT_RME) then
        pspace = PIDSpace_NonSecure;
    else
        pspace = PARTIDSpaceFromSS(security);
    end;
    if pspace == PIDSpace_NonSecure && !MPAMIsEnabled() then
        return DefaultMPAMInfo(pspace);
    end;
    mpamEL = if acctype == AccessType_NV2 then EL2 else el;
    case acctype of
        when AccessType_IFETCH, AccessType_IC =>
            mpamdata.in_d = TRUE;
        when AccessType_SME =>
            mpamdata.sm = (ImpDefBool("Shared SMCU") ||
                           ImpDefBool("MPAMSM_EL1 label precedence"));
        when AccessType_FP, AccessType_ASIMD, AccessType_SVE =>
            mpamdata.sm = (IsFeatureImplemented(FEAT_SME) && PSTATE.SM == '1' &&
                           (ImpDefBool("Shared SMCU") ||
                            ImpDefBool("MPAMSM_EL1 label precedence")));
        when AccessType_TRBE =>
            if !SelfHostedTraceEnabled() then
                if !IsFeatureImplemented(FEAT_TRBE_MPAM) || TRBMPAM_EL1().EN == '0' then
                    return DefaultMPAMInfo(pspace);
                else
                    mpamdata.trb = TRUE;
                end;
            end;
            if !IsFeatureImplemented(FEAT_MPAMv2) && mpamdata.trb then
                var ss : SecurityState;
                case TRBMPAM_EL1().MPAM_SP of
                    when '00' => ss = SS_Secure;
                    when '01' => ss = SS_NonSecure;
                    when '10' => ss = SS_Root;
                    when '11' => ss = SS_Realm;
                end;
                pspace = PARTIDSpaceFromSS(ss);
            end;
        otherwise =>
            // Other access types are DATA accesses
            mpamdata.in_d = FALSE;
    end;
    if (IsFeatureImplemented(FEAT_RME) && !IsFeatureImplemented(FEAT_MPAMv2) &&
          MPAMIDR_EL1().HAS_ALTSP == '1') then
        // Substitute alternative PARTID space if selected
        pspace = AltPARTIDSpace(mpamEL, security, pspace);
    end;
    if IsFeatureImplemented(FEAT_MPAMv0p1) && MPAMIDR_EL1().HAS_FORCE_NS == '1' then
        if MPAM3_EL3().FORCE_NS == '1' && security == SS_Secure then
            pspace = PIDSpace_NonSecure;
        end;
    end;
    if ((IsFeatureImplemented(FEAT_MPAMv0p1) || IsFeatureImplemented(FEAT_MPAMv1p1)) &&
          MPAMIDR_EL1().HAS_SDEFLT == '1') then
        if MPAM3_EL3().SDEFLT == '1' && security == SS_Secure then
            return DefaultMPAMInfo(pspace);
        end;
    end;
    if !MPAMIsEnabled() then
        return DefaultMPAMInfo(pspace);
    else
        return GenMPAM(mpamEL, mpamdata, pspace);
    end;
end;

// GenMPAMCurEL()
// ==============
// Returns MPAMinfo for the current EL and security state.
// May be called if MPAM is not implemented (but in an version that supports
// MPAM), MPAM is disabled, or in AArch32_  In AArch32, convert the mode to
// EL if can and use that to drive MPAM information generation.  If mode
// cannot be converted, MPAM is not implemented, or MPAM is disabled return
// default MPAM information for the current security state.

func GenMPAMCurEL(acctype : AccessType) => MPAMinfo
begin
    return GenMPAMAtEL(acctype, PSTATE.EL);
end;

// GenNewMPAMData()
// ================

func GenNewMPAMData() => MPAMdata
begin
    var mpamdata : MPAMdata;
    mpamdata.in_d   = FALSE;
    mpamdata.sm  = FALSE;
    mpamdata.trb = FALSE;
    return mpamdata;
end;

// GenPARTID()
// ===========
// Returns physical PARTID and error boolean for Exception level el.
// If mpamdata.sm is TRUE then PARTID is from MPAMSM_EL1.
// If mpamdata.trb is TRUE then PARTID is from TRBMPAM_EL1.
// If mpamdata.in_d is TRUE and alternative ID is enabled then PARTID is from MPAMn_ELx.altPARTID.
// Otherwise, the PARTID is from MPAMn_ELx.

func GenPARTID(el : bits(2), mpamdata : MPAMdata, pspace : PARTIDSpaceType) => (PARTIDType, boolean)
begin
    var partidel : PARTIDType = GetMPAM_PARTID(el, mpamdata);
    if IsFeatureImplemented(FEAT_MPAMv2) then
        if PARTIDIsVirtual(el, mpamdata) then
            if !IsZero(MPAMVIDSR_EL2().FSC) then
                return (DEFAULT_PARTID, TRUE);
            end;
            // When the virtual identifier is greater than or equal to 2^12,
            // it is CONSTRAINED UNPREDICTABLE whether the virtual identifier is truncated
            // to its least significant 12 bits for translation, or it is replaced
            // by the default virtual identifier
            if (UInt(partidel) >= 2^12 &&
                  !ConstrainUnpredictableBool(Unpredictable_MPAM_TRUNCATE_VID)) then
                partidel = DEFAULT_PARTID;
            end;
            return TranslatevPARTID(partidel[11:0], mpamdata, el, pspace);
        else
            return (partidel, FALSE);
        end;
    end;

    let partid_max : PARTIDType = (if mpamdata.trb then TRBDEVID1().PARTID_MAX
                                   else MPAMIDR_EL1().PARTID_MAX);
    if UInt(partidel) > UInt(partid_max) then
        return (DEFAULT_PARTID, TRUE);
    end;
    if MPAMIsVirtual(el, mpamdata) then
        return MAP_vPARTID(partidel);
    else
        return (partidel, FALSE);
    end;
end;

// GenPMG()
// ========
// Returns PMG for Exception level el.
// if mpamdata.sm is TRUE then PMG is from MPAMSM_EL1.
// If mpamdata.trb is TRUE then PMG is from TRBMPAM_EL1.
// If mpamdata.in_d is TRUE and alternative id is enabled, then the PMG is from MPAMn_ELx.altPMG.
// Otherwise, PMG is from MPAMn_ELx.
// If PARTID generation (GenPARTID) encountered an error, GenPMG() should be
// called with partid_err as TRUE.

func GenPMG(el : bits(2), mpamdata : MPAMdata, partid_err : boolean,
            pspace : PARTIDSpaceType) => PMGType
begin
    if (!IsFeatureImplemented(FEAT_MPAMv2) && partid_err &&
          ConstrainUnpredictableBool(Unpredictable_USE_DEFAULT_PMG)) then
        return DEFAULT_PMG;
    end;
    var groupel : PMGType = GetMPAM_PMG(el, mpamdata);
    if IsFeatureImplemented(FEAT_MPAMv2) then
        if PMGIsVirtual(el, mpamdata) then
            if !IsZero(MPAMVIDSR_EL2().FSC) then
                return DEFAULT_PMG;
            end;
            // When the virtual identifier is greater than or equal to 2^12,
            // it is CONSTRAINED UNPREDICTABLE whether the virtual identifier is truncated
            // to its least significant 12 bits for translation, or it is replaced
            // by the default virtual identifier
            if (UInt(groupel) >= 2^12 &&
                  !ConstrainUnpredictableBool(Unpredictable_MPAM_TRUNCATE_VID)) then
                groupel = DEFAULT_PMG;
            end;
            return TranslatevPMG(groupel[11:0], mpamdata, el, pspace);
        else
            return groupel;
        end;
    end;

    let pmg_max : integer = (if mpamdata.trb then UInt(TRBDEVID1().PMG_MAX)
                             else UInt(MPAMIDR_EL1().PMG_MAX));
    if UInt(groupel) <= pmg_max then
        return groupel;
    end;
    return DEFAULT_PMG;
end;

// GetMPAM_PARTID()
// ================
// Returns a PARTID
// If mpamdata.sm is TRUE then PARTID is from MPAMSM_EL1.
// If mpamdata.trb is TRUE then PARTID is from TRBMPAM_EL1.
// If mpamdata.in_d is TRUE and alternative ID is enabled then PARTID is from MPAMn_ELx.altPARTID.
// Otherwise, the PARTID is from MPAMn_ELx.

func GetMPAM_PARTID(MPAMn : bits(2), mpamdata : MPAMdata) => PARTIDType
begin
    if mpamdata.sm then
        return (if IsFeatureImplemented(FEAT_MPAMv2) then MPAMSM_EL1().PARTID
                                                     else MPAMSM_EL1().PARTID_D);
    end;

    if mpamdata.trb then
        return TRBMPAM_EL1().PARTID;
    end;

    if (IsFeatureImplemented(FEAT_MPAMv2_ALT_ID) && mpamdata.in_d &&
          MPAMIDR_EL1().HAS_INSTR_ALT_ID == '1') then
        case MPAMn of
            when '11' =>
                if MPAMCTL_EL3().EN_ALT_IPARTID == '1' then
                    return MPAM3_EL3().altPARTID;
                else
                    return MPAM3_EL3().PARTID;
                end;
            when '10' =>
                if !EL2Enabled() then
                    return DEFAULT_PARTID;
                elsif MPAMCTL_EL2().EN_ALT_IPARTID == '1' then
                    return MPAM2_EL2().altPARTID;
                else
                    return MPAM2_EL2().PARTID;
                end;
            when '01' =>
                if MPAMCTL_EL1().EN_ALT_IPARTID == '1' then
                    return MPAM1_EL1().altPARTID;
                else
                    return MPAM1_EL1().PARTID;
                end;
            when '00' =>
                if MPAMCTL_EL1().EN_ALT_IPARTID_EL0 == '1' then
                    return MPAM0_EL1().altPARTID;
                else
                    return MPAM0_EL1().PARTID;
                end;
        end;
    end;

    if IsFeatureImplemented(FEAT_MPAMv2) then
        case MPAMn of
            when '11' => return MPAM3_EL3().PARTID;
            when '10' => return (if EL2Enabled() then MPAM2_EL2().PARTID else DEFAULT_PARTID);
            when '01' => return MPAM1_EL1().PARTID;
            when '00' => return MPAM0_EL1().PARTID;
        end;
    end;

    if mpamdata.in_d then
        case MPAMn of
            when '11' => return MPAM3_EL3().PARTID_I;
            when '10' => return (if EL2Enabled() then MPAM2_EL2().PARTID_I else DEFAULT_PARTID);
            when '01' => return MPAM1_EL1().PARTID_I;
            when '00' => return MPAM0_EL1().PARTID_I;
        end;
    else
        case MPAMn of
            when '11' => return MPAM3_EL3().PARTID_D;
            when '10' => return (if EL2Enabled() then MPAM2_EL2().PARTID_D else DEFAULT_PARTID);
            when '01' => return MPAM1_EL1().PARTID_D;
            when '00' => return MPAM0_EL1().PARTID_D;
        end;
    end;
end;

// GetMPAM_PMG()
// =============
// Returns a PMG.
// if mpamdata.sm is TRUE then PMG is from MPAMSM_EL1.
// If mpamdata.trb is TRUE then PMG is from TRBMPAM_EL1.
// If mpamdata.in_d is TRUE and alternative id is enabled, then the PMG is from MPAMn_ELx.altPMG.
// Otherwise, PMG is from MPAMn_ELx.

func GetMPAM_PMG(MPAMn : bits(2), mpamdata : MPAMdata) => PMGType
begin
    if mpamdata.sm then
        return (if IsFeatureImplemented(FEAT_MPAMv2) then MPAMSM_EL1().PMG
                                                     else ZeroExtend{16}(MPAMSM_EL1().PMG_D));
    end;

    if mpamdata.trb then
        return TRBMPAM_EL1().PMG;
    end;

    if (IsFeatureImplemented(FEAT_MPAMv2_ALT_ID) && mpamdata.in_d &&
          MPAMIDR_EL1().HAS_INSTR_ALT_ID == '1') then
        case MPAMn of
            when '11' =>
                if MPAMCTL_EL3().EN_ALT_IPMG == '1' then
                    return MPAM3_EL3().altPMG;
                else
                    return MPAM3_EL3().PMG;
                end;
            when '10' =>
                if !EL2Enabled() then
                    return DEFAULT_PMG;
                elsif MPAMCTL_EL2().EN_ALT_IPMG == '1' then
                    return MPAM2_EL2().altPMG;
                else
                    return MPAM2_EL2().PMG;
                end;
            when '01' =>
                if MPAMCTL_EL1().EN_ALT_IPMG == '1' then
                    return MPAM1_EL1().altPMG;
                else
                    return MPAM1_EL1().PMG;
                end;
            when '00' =>
                if MPAMCTL_EL1().EN_ALT_IPMG_EL0 == '1' then
                    return MPAM0_EL1().altPMG;
                else
                    return MPAM0_EL1().PMG;
                end;
        end;
    end;

    if IsFeatureImplemented(FEAT_MPAMv2) then
        case MPAMn of
            when '11' => return MPAM3_EL3().PMG;
            when '10' => return (if EL2Enabled() then MPAM2_EL2().PMG else DEFAULT_PMG);
            when '01' => return MPAM1_EL1().PMG;
            when '00' => return MPAM0_EL1().PMG;
        end;
    end;

    if mpamdata.in_d then
        case MPAMn of
            when '11'=>
                return ZeroExtend{16}(MPAM3_EL3().PMG_I);
            when '10' =>
                return (if EL2Enabled() then ZeroExtend{16}(MPAM2_EL2().PMG_I) else DEFAULT_PMG);
            when '01' =>
                return ZeroExtend{16}(MPAM1_EL1().PMG_I);
            when '00' =>
                return ZeroExtend{16}(MPAM0_EL1().PMG_I);
        end;
    else
        case MPAMn of
            when '11' =>
                return ZeroExtend{16}(MPAM3_EL3().PMG_D);
            when '10' =>
                return (if EL2Enabled() then ZeroExtend{16}(MPAM2_EL2().PMG_D) else DEFAULT_PMG);
            when '01' =>
                return ZeroExtend{16}(MPAM1_EL1().PMG_D);
            when '00' =>
                return ZeroExtend{16}(MPAM0_EL1().PMG_D);
        end;
    end;
end;

// MAP_vPARTID()
// =============
// Performs conversion of virtual PARTID into physical PARTID
// Contains all of the error checking and implementation
// choices for the conversion.

func MAP_vPARTID(vpartid : PARTIDType) => (PARTIDType, boolean)
begin
    // should not ever be called if EL2 is not implemented
    // or is implemented but not enabled in the current
    // security state.
    var ret : PARTIDType;
    var err : boolean;
    var virt : integer    = UInt(vpartid);
    let vpmrmax : integer = UInt(MPAMIDR_EL1().VPMR_MAX);

    // vpartid_max is largest vpartid supported
    let vpartid_max : integer = (vpmrmax << 2) + 3;

    // One of many ways to reduce vpartid to value less than vpartid_max.
    if UInt(vpartid) > vpartid_max then
        virt = virt MOD (vpartid_max+1);
    end;

    // Check for valid mapping entry.
    if MPAMVPMV_EL2()[virt] == '1' then
        // vpartid has a valid mapping, access the map.
        ret = mapvpmw(virt);
        err = FALSE;

    // Check for default virtual PARTID valid
    elsif MPAMVPMV_EL2()[0] == '1' then
        // Use default mapping for vpartid == 0.
        ret = MPAMVPM0_EL2()[0 +: 16];
        err = FALSE;

    // Neither is valid, use default physical PARTID.
    else
        ret = DEFAULT_PARTID;
        err = TRUE;
    end;

    // Check that the physical PARTID is in-range.
    // This physical PARTID came from a virtual mapping entry.
    let partid_max : integer = UInt(MPAMIDR_EL1().PARTID_MAX);
    if UInt(ret) > partid_max then
        // Out of range, so return default physical PARTID
        ret = DEFAULT_PARTID;
        err = TRUE;
    end;
    return (ret, err);
end;

// Defines the MPAM _engine_. The _engine_ produces the MPAM labels for memory
// accesses from the state information stored in the MPAM System registers.

// The MPAM _engine_ runs in all states and with the MPAM AArch64 system
// registers and PE execution state controlling its behavior.

// MPAM Types
// ==========

type PARTIDType of bits(16);

type PMGType of bits(16);

type PARTIDSpaceType of enumeration {
    PIDSpace_Secure,
    PIDSpace_Root,
    PIDSpace_Realm,
    PIDSpace_NonSecure
};

type MPAMinfo of record {
     mpam_sp : PARTIDSpaceType,
     partid : PARTIDType,
     pmg : PMGType
};

constant DEFAULT_PARTID : PARTIDType = 0[15:0];

constant DEFAULT_PMG : PMGType = 0[15:0];

type MPAMdata of record {
    in_d : boolean,       // TRUE for instruction accesses
    sm : boolean,         // TRUE for SME, SVE, SIMD&FP access, and SVE prefetch
                          // instructions, when the PE is in Streaming mode
    trb : boolean         // TRUE for TRBE accesses using External mode when TRBMPAM_EL1.EN is 0b1
};

// MPAMIsEnabled()
// ===============
// Returns TRUE if MPAM is enabled.

func MPAMIsEnabled() => boolean
begin
    let el : bits(2) = HighestEL();
    if IsFeatureImplemented(FEAT_MPAMv2) then
        case el of
            when EL3 => return MPAMCTL_EL3().MPAMEN == '1';
            when EL2 => return MPAMCTL_EL2().MPAMEN == '1';
            when EL1 => return MPAMCTL_EL1().MPAMEN == '1';
        end;
    end;

    case el of
        when EL3 => return MPAM3_EL3().MPAMEN == '1';
        when EL2 => return MPAM2_EL2().MPAMEN == '1';
        when EL1 => return MPAM1_EL1().MPAMEN == '1';
    end;
end;

// MPAMIsVirtual()
// ===============
// If FEAT_MPAMv2 is not implemented, returns TRUE if MPAM is configured to be virtual
// at the given el.

func MPAMIsVirtual(el : bits(2), mpamdata : MPAMdata) => boolean
begin
    if mpamdata.trb then
        return FALSE;
    end;

    return (MPAMIDR_EL1().HAS_HCR == '1' && EL2Enabled() &&
            ((el == EL0 && MPAMHCR_EL2().EL0_VPMEN == '1' && !ELIsInHost(EL0)) ||
             (el == EL1 && MPAMHCR_EL2().EL1_VPMEN == '1')));
end;

// PARTIDIsVirtual()
// =================
// Returns TRUE if MPAMv2 PARTID is configured to be virtual at the given el.

func PARTIDIsVirtual(el : bits(2), mpamdata : MPAMdata) => boolean
begin
    if !IsFeatureImplemented(FEAT_MPAMv2_VID) then
        return FALSE;
    end;
    if mpamdata.trb then
        return FALSE;
    end;

    if !EL2Enabled() then
        return FALSE;
    end;
    if mpamdata.sm then
        return MPAMHCR_EL2().SMVPMEN == '1';
    end;
    return MPAMHCR_EL2().VPMEN == '1' && (el == EL1 || (el == EL0 && !ELIsInHost(EL0)));
end;

// PARTIDSpaceFromSS()
// ===================
// Returns the primary PARTID space from the Security State.

func PARTIDSpaceFromSS(security : SecurityState) => PARTIDSpaceType
begin
    case security of
        when SS_NonSecure =>
            return PIDSpace_NonSecure;
        when SS_Root =>
            return PIDSpace_Root;
        when SS_Realm =>
            return PIDSpace_Realm;
        when SS_Secure =>
            return PIDSpace_Secure;
        otherwise =>
            unreachable;
    end;
end;

// PMGIsVirtual()
// ==============
// Returns TRUE if MPAMv2 PMG is configured to be virtual at the given el.

func PMGIsVirtual(el : bits(2), mpamdata : MPAMdata) => boolean
begin
    if !IsFeatureImplemented(FEAT_MPAMv2_VID) then
        return FALSE;
    end;
    if mpamdata.trb then
        return FALSE;
    end;

    if !EL2Enabled() then
        return FALSE;
    end;
    if mpamdata.sm then
        return MPAMHCR_EL2().SMVMMEN == '1';
    end;
    return MPAMHCR_EL2().VMMEN == '1' && (el == EL1 || (el == EL0 && !ELIsInHost(EL0)));
end;

// ReportVIDFault()
// ================
// Report a GPCF or External abort on an MVMS or MITT access.

func ReportVIDFault(mpamdata : MPAMdata, el : bits(2),
                    fault_address : bits(56), fsc : bits(2))
begin
    assert el == '0x';
    MPAMVIDSR_EL2().FADDR = fault_address;
    MPAMVIDSR_EL2().FSC   = fsc;
    MPAMVIDSR_EL2().FIR   = if mpamdata.sm then '10' else el;
end;

// TranslatevPARTID()
// ==================
// Given a virtual PARTID, return the corresponding physical PARTID from MITT

func TranslatevPARTID(virtual_pid : bits(12), mpamdata : MPAMdata, el : bits(2),
                      pspace : PARTIDSpaceType) => (PARTIDType, boolean)
begin
    let mvms_baddr : bits(56) = MPAMVIDCR_EL2().BADDR :: Zeros{12};
    let mvms_offset : integer         = UInt(virtual_pid[11]) << 3;
    let mvms_addr : bits(56)  = mvms_baddr + mvms_offset;

    let mvms_entry_size : integer{} = 64;
    var mvms_entry : bits(64);
    var mvms_err : boolean;
    (mvms_entry, mvms_err) = VIDFetch{mvms_entry_size}(mvms_addr, pspace, mpamdata, el);
    if mvms_err || mvms_entry[0] == '0' then
        return (DEFAULT_PARTID, mvms_err);
    end;

    let mitt_baddr : bits(56) = mvms_entry[55:12] :: Zeros{12};
    let mitt_offset : integer         = UInt(virtual_pid[10:0]) << 1;
    let mitt_addr : bits(56)  = mitt_baddr + mitt_offset;

    let mitt_entry_size : integer{} = 16;
    var physical_pid : bits(16);
    var mitt_err : boolean;
    (physical_pid, mitt_err)      = VIDFetch{mitt_entry_size}(mitt_addr, pspace, mpamdata, el);
    if mitt_err then physical_pid = DEFAULT_PARTID; end;
    return (physical_pid, mitt_err);
end;

// TranslatevPMG()
// ===============
// Given a virtual PMG, return the corresponding physical PMG from MITT

func TranslatevPMG(virtual_pmg : bits(12), mpamdata : MPAMdata, el : bits(2),
                   pspace : PARTIDSpaceType) => PMGType
begin
    let mvms_baddr : bits(56) = MPAMVIDCR_EL2().BADDR :: Zeros{12};
    let mvms_offset : integer         = (UInt(virtual_pmg[11]) << 3) + 0x20;
    let mvms_addr : bits(56)  = mvms_baddr + mvms_offset;

    let mvms_entry_size : integer{} = 64;
    var mvms_entry : bits(64);
    var mvms_err : boolean;
    (mvms_entry, mvms_err) = VIDFetch{mvms_entry_size}(mvms_addr, pspace, mpamdata, el);
    if mvms_err || mvms_entry[0] == '0' then
        return DEFAULT_PMG;
    end;

    let mitt_baddr : bits(56) = mvms_entry[55:12] :: Zeros{12};
    let mitt_offset : integer         = UInt(virtual_pmg[10:0]) << 1;
    let mitt_addr : bits(56)  = mitt_baddr + mitt_offset;

    let mitt_entry_size : integer{} = 16;
    var physical_pmg : bits(16);
    var mitt_err : boolean;
    (physical_pmg, mitt_err)      = VIDFetch{mitt_entry_size}(mitt_addr, pspace, mpamdata, el);
    if mitt_err then physical_pmg = DEFAULT_PMG; end;
    return physical_pmg;
end;

// UsePrimarySpaceEL10()
// =====================
// Checks whether Primary space is configured in the
// MPAM3_EL3 and MPAM2_EL2 ALTSP control bits that affect
// MPAM ALTSP use at EL1 and EL0.

func UsePrimarySpaceEL10() => boolean
begin
    if MPAM3_EL3().ALTSP_HEN == '0' then
        return MPAM3_EL3().ALTSP_HFC == '0';
    end;
    return !MPAMIsEnabled() || !EL2Enabled() || MPAM2_EL2().ALTSP_HFC == '0';
end;

// UsePrimarySpaceEL2()
// ====================
// Checks whether Primary space is configured in the
// MPAM3_EL3 and MPAM2_EL2 ALTSP control bits that affect
// MPAM ALTSP use at EL2.

func UsePrimarySpaceEL2() => boolean
begin
    if MPAM3_EL3().ALTSP_HEN == '0' then
        return MPAM3_EL3().ALTSP_HFC == '0';
    end;
    return !MPAMIsEnabled() || MPAM2_EL2().ALTSP_EL2 == '0';
end;

// VIDFetch()
// ==========
// Given a physical address in the MVMS or MITT, perform a read of 'size'

func VIDFetch{size : integer{16, 64}}(paddress : bits(56),
                                      pspace : PARTIDSpaceType, mpamdata : MPAMdata,
                                      el : bits(2)) => (bits(size), boolean)
begin
    assert EL2Enabled() && IsFeatureImplemented(FEAT_MPAMv2_VID);
    let accdesc : AccessDescriptor = CreateAccDescMPAMv2VID(pspace);
    var addrdesc : AddressDescriptor;
    addrdesc.paddress.address = paddress;
    let nse2 : bit            = '0';
    addrdesc.paddress.paspace = DecodePASpace(nse2, EffectiveSCR_EL3_NSE(), EffectiveSCR_EL3_NS());
    addrdesc.memattrs         = WalkMemAttrs(VTCR_EL2().SH0, VTCR_EL2().IRGN0, VTCR_EL2().ORGN0);
    let emec : bit            = (if IsFeatureImplemented(FEAT_MEC) &&
                                    IsSCTLR2EL2Enabled() then SCTLR2_EL2().EMEC else '0');
    addrdesc.mecid            = AArch64_S2TTWalkMECID(emec, accdesc.ss);

    if IsFeatureImplemented(FEAT_RME) then
        var fault : FaultRecord = NoFault(accdesc);
        fault.gpcf              = GranuleProtectionCheck(addrdesc, accdesc);
        if fault.gpcf.gpf != GPCF_None then
            let fsc : bits(2) = '01';
            ReportVIDFault(mpamdata, el, paddress, fsc);
            let err : boolean = TRUE;
            return (ARBITRARY : bits(size), err);
        end;
    end;

    var memstatus : PhysMemRetStatus;
    var data : bits(size);
    (memstatus, data) = PhysMemRead{size}(addrdesc, accdesc);

    if IsFault(memstatus) then
        assert IsExternalAbort(memstatus.statuscode);
        let fsc : bits(2) = '10';
        ReportVIDFault(mpamdata, el, paddress, fsc);
        let err : boolean = TRUE;
        return (ARBITRARY : bits(size), err);
    end;

    let err : boolean = FALSE;
    return (data, err);
end;

// mapvpmw()
// =========
// Map a virtual PARTID into a physical PARTID using
// the MPAMVPMn_EL2 registers.
// vpartid is now assumed in-range and valid (checked by caller)
// returns physical PARTID from mapping entry.

func mapvpmw(vpartid : integer) => PARTIDType
begin
    var vpmw : bits(64);
    let wd : integer = vpartid DIVRM 4;
    case wd of
        when 0    => vpmw = MPAMVPM0_EL2();
        when 1    => vpmw = MPAMVPM1_EL2();
        when 2    => vpmw = MPAMVPM2_EL2();
        when 3    => vpmw = MPAMVPM3_EL2();
        when 4    => vpmw = MPAMVPM4_EL2();
        when 5    => vpmw = MPAMVPM5_EL2();
        when 6    => vpmw = MPAMVPM6_EL2();
        when 7    => vpmw = MPAMVPM7_EL2();
        otherwise => vpmw = Zeros{64};
    end;
    // vpme_lsb selects LSB of field within register
    let vpme_lsb : integer = (vpartid MOD 4) * 16;
    return vpmw[vpme_lsb +: 16];
end;

// ASID
// ====
// Effective ASID.

func ASID() => bits(16)
begin
    if ELIsInHost(EL0) then
        if TCR_EL2().A1 == '1' then
            return TTBR1_EL2().ASID;
        else
            return TTBR0_EL2().ASID;
        end;
    end;
    if !ELUsingAArch32(EL1) then
        if TCR_EL1().A1 == '1' then
            return TTBR1_EL1().ASID;
        else
            return TTBR0_EL1().ASID;
        end;
    else
        if TTBCR().EAE == '0' then
            return ZeroExtend{16}(CONTEXTIDR().ASID);
        else
            if TTBCR().A1 == '1' then
                return ZeroExtend{16}(TTBR1().ASID);
            else
                return ZeroExtend{16}(TTBR0().ASID);
            end;
        end;
    end;
end;

// ExecutionCntxt
// ===============
// Context information for prediction restriction operation.

type ExecutionCntxt of record {
    is_vmid_valid : boolean,        // is vmid valid for current context
    all_vmid      : boolean,        // should the operation be applied for all vmids
    vmid          : bits(16), // if all_vmid = FALSE, vmid to which operation is applied
    is_asid_valid : boolean,        // is asid valid for current context
    all_asid      : boolean,        // should the operation be applied for all asids
    asid          : bits(16), // if all_asid = FALSE, ASID to which operation is applied
    target_el     : bits(2),        // target EL at which operation is performed
    security      : SecurityState,
    restriction   : RestrictType    // type of restriction operation
};

// RESTRICT_PREDICTIONS()
// ======================
// Clear all speculated values.

impdef func RESTRICT_PREDICTIONS(c : ExecutionCntxt)
begin
    return;
end;

// RestrictType
// ============
// Type of restriction on speculation.

type RestrictType of enumeration {
    RestrictType_DataValue,
    RestrictType_ControlFlow,
    RestrictType_CachePrefetch,
    RestrictType_Other              // Any other trained speculation mechanisms than those above
};

// TargetSecurityState()
// =====================
// Decode the target security state for the prediction context.

func TargetSecurityState(NS : bit, NSE : bit) => SecurityState
begin
    let curr_ss : SecurityState =  SecurityStateAtEL(PSTATE.EL);
    if curr_ss == SS_NonSecure then
        return SS_NonSecure;
    elsif curr_ss == SS_Secure then
        case NS of
            when '0' => return SS_Secure;
            when '1' => return SS_NonSecure;
        end;
    elsif IsFeatureImplemented(FEAT_RME) then
        if curr_ss == SS_Root then
            case NSE::NS of
                when '00' => return SS_Secure;
                when '01' => return SS_NonSecure;
                when '11' => return SS_Realm;
                when '10' => return SS_Root;
            end;
        elsif curr_ss == SS_Realm then
            return SS_Realm;
        end;
    end;
    unreachable;
end;

// BranchTo()
// ==========
// Set program counter to a new address, with a branch type.
// Parameter branch_conditional indicates whether the executed branch has a conditional encoding.
// In AArch64 state the address might include a tag in the top eight bits.

func BranchTo{N}(target : bits(N), branch_type : BranchType, branch_conditional : boolean)
begin
    Hint_Branch(branch_type);
    if N == 32 then
        assert UsingAArch32();
        _PC = ZeroExtend{64}(target);
    else
        assert N == 64 && !UsingAArch32();
        let target_vaddress : bits(64) = AArch64_BranchAddr(target[63:0], PSTATE.EL);
        if (IsFeatureImplemented(FEAT_BRBE) &&
              branch_type IN {BranchType_DIR, BranchType_INDIR,
                              BranchType_DIRCALL, BranchType_INDCALL,
                              BranchType_RET}) then
            BRBEBranch(branch_type, branch_conditional, target_vaddress);
        end;
        let branch_taken : boolean = TRUE;

        if IsFeatureImplemented(FEAT_SPE) then
            SPEBranch{N}(target, branch_type, branch_conditional, branch_taken);
        end;

        _PC = target_vaddress;
    end;
    return;
end;

// BranchToAddr()
// ==============
// Set program counter to a new address, with a branch type.
// In AArch64 state the address does not include a tag in the top eight bits.

func BranchToAddr{N}(target : bits(N), branch_type : BranchType)
begin
    Hint_Branch(branch_type);
    if N == 32 then
        assert UsingAArch32();
        _PC = ZeroExtend{64}(target);
    else
        assert N == 64 && !UsingAArch32();
        _PC = target[63:0];
    end;
    return;
end;

// Branchtypetaken
// ===============
var Branchtypetaken : BranchType;

// SIMD and Floating-point registers
// +++++++++++++++++++++++++++++++++

// ESize
// =====

type ESize of integer{8, 16, 32, 64, 128};

// EffectiveFPCR()
// ===============
// Returns the effective FPCR value

func EffectiveFPCR() => FPCR_Type
begin
    return FPCR();
end;

// Hint_Branch()
// =============
// Report the hint passed to BranchTo() and BranchToAddr(), for consideration when processing
// the next instruction.

impdef func Hint_Branch(hint : BranchType)
begin
    Branchtypetaken = hint;
    return;
end;

// NextInstrAddr()
// ===============
// Return address of the sequentially next instruction.

impdef func NextInstrAddr{N}() => bits(N)
begin
    return Zeros{N};
end;

// ResetExternalDebugRegisters()
// =============================
// Reset the External Debug registers in the Core power domain.

impdef func ResetExternalDebugRegisters(cold_reset : boolean)
begin
    return;
end;

// ThisInstrAddr()
// ===============
// Return address of the current instruction.

func ThisInstrAddr{N}() => bits(N)
begin
    assert N == 64 || (N == 32 && UsingAArch32());
    return _PC[N-1:0];
end;

// UnimplementedIDRegister()
// =========================
// Trap access to unimplemented encodings in the feature ID register space.

func UnimplementedIDRegister()
begin
    if IsFeatureImplemented(FEAT_IDST) then
        var target_el : bits(2) = PSTATE.EL;
        if PSTATE.EL == EL0 then
            target_el = if EL2Enabled() && HCR_EL2().TGE == '1' then EL2 else EL1;
        end;
        AArch64_SystemAccessTrap(target_el, 0x18);
    end;
    Undefined();
end;

// V - accessor
// ============

accessor V{width : ESize}(n : integer) <=> value : bits(width)
begin
    // Read from SIMD&FP register with implicit slice of 8, 16
    // 32, 64 or 128 bits.
    getter
        assert n >= 0 && n <= 31;
        return _Z[[n]][width-1:0];
    end;

    // Write to SIMD&FP register with implicit extension from
    // 8, 16, 32, 64 or 128 bits.
    setter
        assert n >= 0 && n <= 31;
        let vlen : VecLen = if IsSVEEnabled(PSTATE.EL) then CurrentVL() else 128;
        if ConstrainUnpredictableBool(Unpredictable_SVEZEROUPPER) then
            _Z[[n]] = ZeroExtend{MAX_VL}(value);
        else
            _Z[[n]][vlen-1:0] = ZeroExtend{vlen}(value);
        end;
    end;
end;

// Vpart - accessor
// ================

accessor Vpart{width : ESize}(n : integer, part : integer) <=> value : bits(width)
begin
    // Reads a 128-bit SIMD&FP register in up to two parts:
    //  part 0 returns the bottom 8, 16, 32 or 64 bits of a value held in the register;
    //  part 1 returns the top half of the bottom 64 bits or the top half of the 128-bit
    //  value held in the register.
    getter
        assert n >= 0 && n <= 31;
        assert part IN {0, 1};
        if part == 0 then
            assert width < 128;
            return V{width}(n);
        else
            assert width IN {32,64};
            let vreg : bits(128) = V{}(n);
            return vreg[(width * 2)-1:width];
        end;
    end;

    setter
    // Writes a 128-bit SIMD&FP register in up to two parts:
    //  part 0 zero extends a 8, 16, 32, or 64-bit value to fill the whole register;
    //  part 1 inserts a 64-bit value into the top half of the register.
        assert n >= 0 && n <= 31;
        assert part IN {0, 1};
        if part == 0 then
            assert width < 128;
            V{width}(n) = value;
        else
            assert width == 64;
            let vreg : bits(64) = V{}(n);
            V{128}(n) = value[63:0] :: vreg;
        end;
    end;
end;

// _PC - the program counter
// =========================

var _PC : bits(64);

// _R - the general-purpose register file array
// ============================================

var _R : array [[31]] of bits(64);

// SPSR_ELx - accessor
// ===================

accessor SPSR_ELx() <=> value :  bits(64)
begin
    getter
        var result : bits(64);
        case PSTATE.EL of
                when EL1  => result = SPSR_EL1()[63:0];
                when EL2  => result = SPSR_EL2()[63:0];
                when EL3  => result = SPSR_EL3()[63:0];
                otherwise => unreachable;
        end;
        return result;
    end;
    setter
        case PSTATE.EL of
            when EL1  => SPSR_EL1()[63:0] = value[63:0];
            when EL2  => SPSR_EL2()[63:0] = value[63:0];
            when EL3  => SPSR_EL3()[63:0] = value[63:0];
            otherwise => unreachable;
        end;
        return;
    end;
end;

// SPSR_curr - accessor
// ====================

accessor SPSR_curr() <=> value : bits(32)
begin
    getter
        var result : bits(32);
        case PSTATE.M of
            when M32_FIQ     =>  result = SPSR_fiq()[31:0];
            when M32_IRQ     =>  result = SPSR_irq()[31:0];
            when M32_Svc     =>  result = SPSR_svc()[31:0];
            when M32_Monitor =>  result = SPSR_mon()[31:0];
            when M32_Abort   =>  result = SPSR_abt()[31:0];
            when M32_Hyp     =>  result = SPSR_hyp()[31:0];
            when M32_Undef   =>  result = SPSR_und()[31:0];
            otherwise        =>  unreachable;
        end;
        return result;
    end;

    setter
        case PSTATE.M of
            when M32_FIQ     => SPSR_fiq()[31:0] = value[31:0];
            when M32_IRQ     => SPSR_irq()[31:0] = value[31:0];
            when M32_Svc     => SPSR_svc()[31:0] = value[31:0];
            when M32_Monitor => SPSR_mon()[31:0] = value[31:0];
            when M32_Abort   => SPSR_abt()[31:0] = value[31:0];
            when M32_Hyp     => SPSR_hyp()[31:0] = value[31:0];
            when M32_Undef   => SPSR_und()[31:0] = value[31:0];
            otherwise        => unreachable;
        end;
    end;
end;

// AArch64_ChkFeat()
// =================
// Indicates the status of some features

func AArch64_ChkFeat(feat_select : bits(64)) => bits(64)
begin
    var feat_en : bits(64) = Zeros{};
    feat_en[0] = if IsFeatureImplemented(FEAT_GCS) && GCSEnabled(PSTATE.EL) then '1' else '0';
    return feat_select AND NOT(feat_en);
end;

// AddressAdd()
// ============
// Add an address with an offset and return the result.
// If FEAT_CPA2 is implemented, the pointer arithmetic is checked.

func AddressAdd(base : bits(64), offset : integer, accdesc : AccessDescriptor) => bits(64)
begin
    return AddressAdd(base, offset[63:0], accdesc);
end;

func AddressAdd(base : bits(64), offset : bits(64), accdesc : AccessDescriptor) => bits(64)
begin
    var result : bits(64) = base + offset;
    result = PointerAddCheckAtEL(accdesc.el, result, base);
    return result;
end;

// AddressInNaturallyAlignedBlock()
// ================================
// Returns TRUE if the given addresses are in the same naturally aligned block, and FALSE otherwise.
// An address is in a naturally aligned block if it meets any of the below conditions:
// * is a power-of-two size.
// * Is no larger than the DC ZVA block size if ESR_ELx.FnP is being set to 0b0, or EDHSR is not
//   implemented or EDHSR.FnP is being set to 0b0 (as appropriate).
// * Is no larger than the smallest implemented translation granule if ESR_ELx.FnP, or EDHSR.FnP
//   (as appropriate) is being set to 0b1.
// * Contains a watchpointed address accessed by the memory access or set of contiguous memory
//   accesses that triggered the watchpoint.

impdef func AddressInNaturallyAlignedBlock(address1 : bits(64), address2 : bits(64)) => boolean
begin
    // Returns TRUE if address in within a naturally aligned block of memory as the watchpointed
    // location, else FALSE.
    return FALSE;
end;

// AddressIncrement()
// ==================
// Increment an address and return the result.
// If FEAT_CPA2 is implemented, the pointer arithmetic may be checked.

func AddressIncrement(base : bits(64), increment : integer, accdesc : AccessDescriptor) => bits(64)
begin
    return AddressIncrement(base, increment[63:0], accdesc);
end;

func AddressIncrement(base : bits(64), increment : bits(64), accdesc : AccessDescriptor) => bits(64)
begin
    var result : bits(64) = base + increment;
    // Checking the Pointer Arithmetic on an increment is equivalent to checking the
    // bytes in a sequential access crossing the 0xXXFF_FFFF_FFFF_FFFF boundary.
    if ConstrainUnpredictableBool(Unpredictable_CPACHECK) then
        result = PointerAddCheckAtEL(accdesc.el, result, base);
    end;
    return result;
end;

// BranchTargetCheck()
// ===================
// This function is executed checks if the current instruction is a valid target for a branch
// taken into, or inside, a guarded page. It is executed on every cycle once the current
// instruction has been decoded and the values of InGuardedPage and BTypeCompatible have been
// determined for the current instruction.

func BranchTargetCheck()
begin
    assert IsFeatureImplemented(FEAT_BTI) && !UsingAArch32();

    // The branch target check considers the following state variables:
    // * InGuardedPage, which is evaluated during instruction fetch.
    // * BTypeCompatible, which is evaluated during instruction decode.
    if Halted() then
        return;
    elsif IsZero(PSTATE.BTYPE) then
        return;
    elsif InGuardedPage && !BTypeCompatible then
        let pc : bits(64) = ThisInstrAddr{}();
        AArch64_BranchTargetException(pc[51:0]);
    end;
end;

// ClearEventRegister()
// ====================
// Clear the Event Register of this PE.

func ClearEventRegister()
begin
    EventRegister = '0';
    return;
end;

// ConditionHolds()
// ================
// Return TRUE iff COND currently holds

func ConditionHolds(cond : bits(4)) => boolean
begin
    // Evaluate base condition.
    var result : boolean;
    case cond[3:1] of
        when '000' => result = (PSTATE.Z == '1');                          // EQ or NE
        when '001' => result = (PSTATE.C == '1');                          // CS or CC
        when '010' => result = (PSTATE.N == '1');                          // MI or PL
        when '011' => result = (PSTATE.V == '1');                          // VS or VC
        when '100' => result = (PSTATE.C == '1' && PSTATE.Z == '0');       // HI or LS
        when '101' => result = (PSTATE.N == PSTATE.V);                     // GE or LT
        when '110' => result = (PSTATE.N == PSTATE.V && PSTATE.Z == '0');  // GT or LE
        when '111' => result = TRUE;                                       // AL
    end;

    // Condition flag values in the set '111x' indicate always true
    // Otherwise, invert condition if necessary.
    if cond[0] == '1' && cond != '1111' then
        result = !result;
    end;

    return result;
end;

// ConsumptionOfSpeculativeDataBarrier()
// =====================================

impdef func ConsumptionOfSpeculativeDataBarrier()
begin
    return;
end;

// CurrentInstrSet()
// =================

readonly func CurrentInstrSet() => InstrSet
begin
    var result : InstrSet;
    if UsingAArch32() then
        result = if PSTATE.T == '0' then InstrSet_A32 else InstrSet_T32;
        // PSTATE.J is RES0. Implementation of T32EE or Jazelle state not permitted.
    else
        result = InstrSet_A64;
    end;
    return result;
end;

// CurrentSecurityState()
// ======================
// Returns the effective security state at the exception level based off current settings.

readonly func CurrentSecurityState() => SecurityState
begin
    return SecurityStateAtEL(PSTATE.EL);
end;

// DSBAlias
// ========
// Aliases of DSB.

type DSBAlias of enumeration {DSBAlias_SSBB, DSBAlias_PSSBB, DSBAlias_DSB};

// EL0-3
// =====
// PSTATE.EL Exception level bits.

constant EL3 : bits(2) = '11';

constant EL2 : bits(2) = '10';

constant EL1 : bits(2) = '01';

constant EL0 : bits(2) = '00';

// EL2Enabled()
// ============
// Returns TRUE if EL2 is present and executing
// - with the PE in Non-secure state when Non-secure EL2 is implemented, or
// - with the PE in Realm state when Realm EL2 is implemented, or
// - with the PE in Secure state when Secure EL2 is implemented and enabled, or
// - when EL3 is not implemented.

readonly func EL2Enabled() => boolean
begin
    var scr_ns : bit;
    if HaveEL(EL3) then
        if ELUsingAArch32(EL3) then
            scr_ns = SCR().NS;
        else
            scr_ns = SCR_EL3().NS;
        end;
    end;

    return HaveEL(EL2) && (!HaveEL(EL3) || scr_ns == '1' || IsSecureEL2Enabled());
end;

// EL3SDDUndef()
// =============
// Returns TRUE if in Debug state and EDSCR.SDD is set.

func EL3SDDUndef() => boolean
begin
    if Halted() && EDSCR().SDD == '1' then
        assert (PSTATE.EL != EL3  &&
                  (IsFeatureImplemented(FEAT_RME) || CurrentSecurityState() != SS_Secure));
        return TRUE;
    else
        return FALSE;
    end;
end;

// EL3SDDUndefPriority()
// =====================
// Returns TRUE if in Debug state, EDSCR.SDD is set, and an EL3 trap by an
// EL3 control register has priority over other traps.
// The IMPLEMENTATION DEFINED priority may be different for each case.

func EL3SDDUndefPriority() => boolean
begin
    return EL3SDDUndef() && ImpDefBool("EL3 trap priority when SDD == '1'");
end;

// ELFromM32()
// ===========

func ELFromM32(mode : bits(5)) => (boolean,bits(2))
begin
    // Convert an AArch32 mode encoding to an Exception level.
    // Returns (valid,EL):
    //   'valid' is TRUE if 'mode[4:0]' encodes a mode that is both valid for this implementation
    //           and the current value of SCR.NS/SCR_EL3.NS.
    //   'EL'    is the Exception level decoded from 'mode'.
    var el : bits(2);
    // Check for modes that are not valid for this implementation
    var valid : boolean = !BadMode(mode);
    let effective_nse_ns : bits(2) = EffectiveSCR_EL3_NSE() :: EffectiveSCR_EL3_NS();

    case mode of
        when M32_Monitor =>
            el = EL3;
        when M32_Hyp =>
            el = EL2;
        when M32_FIQ, M32_IRQ, M32_Svc, M32_Abort, M32_Undef, M32_System =>
            // If EL3 is implemented and using AArch32, then these modes are EL3 modes in Secure
            // state, and EL1 modes in Non-secure state. If EL3 is not implemented or is using
            // AArch64, then these modes are EL1 modes.
            el = (if HaveEL(EL3) && !HaveAArch64() && SCR().NS == '0' then EL3 else EL1);
        when M32_User =>
            el = EL0;
        otherwise =>
            valid = FALSE;           // Passed an illegal mode value
    end;

    if valid && el == EL2 && HaveEL(EL3) then
        if ELUsingAArch32(EL3) && SCR().NS == '0' then
            valid = FALSE; // EL2 only valid in Non-secure state in AArch32
        elsif !ELUsingAArch32(EL3) && SCR_EL3().NS == '0' then
            valid = FALSE; // EL2 only valid in Non-secure state in AArch32
        end;
    elsif valid && IsFeatureImplemented(FEAT_RME) && effective_nse_ns == '10' then
        valid = FALSE;               // Illegal Exception Return from EL3 if SCR_EL3.[NSE,NS]
                                     // selects a reserved encoding
    end;

    if !valid then el = ARBITRARY : bits(2); end;
    return (valid, el);
end;

// ELFromSPSR()
// ============

// Convert an SPSR value encoding to an Exception level.
// Returns (valid,EL):
//   'valid' is TRUE if 'spsr[4:0]' encodes a valid mode for the current state.
//   'EL'    is the Exception level decoded from 'spsr'.

func ELFromSPSR{N}(spsr : bits(N)) => (boolean,bits(2))
begin
    var el : bits(2);
    var valid : boolean;
    if spsr[4] == '0' then      // AArch64 state
        el = spsr[3:2];
        if (IsFeatureImplemented(FEAT_NV3) && spsr[3:2] == '10' && PSTATE.EL == EL1 &&
              EffectiveHCRX_EL2_NVTGE() == '1') then
            el = EL1;
        end;

        let effective_nse_ns : bits(2) = EffectiveSCR_EL3_NSE() :: EffectiveSCR_EL3_NS();
        if !HaveAArch64() then
            valid = FALSE;      // No AArch64 support
        elsif !HaveEL(el) then
            valid = FALSE;      // Exception level not implemented
        elsif spsr[1] == '1' then
            valid = FALSE;      // M[1] must be 0
        elsif el == EL0 && spsr[0] == '1' then
            valid = FALSE;      // for EL0, M[0] must be 0
        elsif IsFeatureImplemented(FEAT_RME) && el != EL3 && effective_nse_ns == '10' then
            valid = FALSE;      // Only EL3 valid in Root state
        elsif el == EL2 && HaveEL(EL3) && !IsSecureEL2Enabled() && EffectiveSCR_EL3_NS() == '0' then
            valid = FALSE;      // Unless Secure EL2 is enabled, EL2 valid only in Non-secure state
        else
            valid = TRUE;
        end;
    elsif HaveAArch32() then    // AArch32 state
        (valid, el) = ELFromM32(spsr[4:0]);
    else
        valid = FALSE;
    end;

    if !valid then el = ARBITRARY : bits(2); end;
    return (valid,el);
end;

// ELIsInHost()
// ============

readonly func ELIsInHost(el : bits(2)) => boolean
begin
    if !IsFeatureImplemented(FEAT_VHE) || ELUsingAArch32(EL2) then
        return FALSE;
    end;
    case el of
        when EL3 =>
            return FALSE;
        when EL2 =>
            return EL2Enabled() && EffectiveHCR_EL2_E2H() == '1';
        when EL1 =>
            return FALSE;
        when EL0 =>
            return EL2Enabled() && EffectiveHCR_EL2_E2H()::HCR_EL2().TGE == '11';
        otherwise =>
            unreachable;
    end;
end;

// ELStateUsingAArch32()
// =====================

readonly func ELStateUsingAArch32(el : bits(2), secure : boolean) => boolean
begin
    // See ELStateUsingAArch32K() for description. Must only be called in circumstances where
    // result is valid (typically, that means 'el IN {EL1,EL2,EL3}').
    let (known, aarch32) : (boolean, boolean) = ELStateUsingAArch32K(el, secure);
    assert known;
    return aarch32;
end;

// ELStateUsingAArch32K()
// ======================
// Returns (known, aarch32):
//   'known'   is FALSE for EL0 if the current Exception level is not EL0 and EL1 is
//             using AArch64, since it cannot determine the state of EL0; TRUE otherwise.
//   'aarch32' is TRUE if the specified Exception level is using AArch32; FALSE otherwise.

readonly func ELStateUsingAArch32K(el : bits(2), secure : boolean) => (boolean, boolean)
begin
    assert HaveEL(el);

    if !HaveAArch32EL(el) then
        return (TRUE, FALSE);   // Exception level is using AArch64
    elsif secure && el == EL2 then
        return (TRUE, FALSE);   // Secure EL2 is using AArch64
    elsif !HaveAArch64() then
        return (TRUE, TRUE);    // Highest Exception level, therefore all levels are using AArch32
    end;

    // Remainder of function deals with the interprocessing cases when highest
    // Exception level is using AArch64_

    if el == EL3 then
        return (TRUE, FALSE);
    end;

    if (HaveEL(EL3) && SCR_EL3().RW == '0' &&
          (!secure || !IsFeatureImplemented(FEAT_SEL2) || SCR_EL3().EEL2 == '0')) then
        // AArch32 below EL3.
        return (TRUE, TRUE);
    end;

    if el == EL2 then
        return (TRUE, FALSE);
    end;

    if (HaveEL(EL2) && !ELIsInHost(EL0) && HCR_EL2().RW == '0' &&
          (!secure || (IsFeatureImplemented(FEAT_SEL2) && SCR_EL3().EEL2 == '1'))) then
        // AArch32 below EL2.
        return (TRUE, TRUE);
    end;

    if el == EL1 then
        return (TRUE, FALSE);
    end;

    // The execution state of EL0 is only known from PSTATE.nRW when executing at EL0.
    if PSTATE.EL == EL0 then
        return (TRUE, PSTATE.nRW == '1');
    else
        return (FALSE, ARBITRARY : boolean);
    end;
end;

// ELUsingAArch32()
// ================

readonly func ELUsingAArch32(el : bits(2)) => boolean
                                     recurselimit 1
begin
    return ELStateUsingAArch32(el, IsSecureBelowEL3());
end;

// ELUsingAArch32K()
// =================

readonly func ELUsingAArch32K(el : bits(2)) => (boolean,boolean)
begin
    return ELStateUsingAArch32K(el, IsSecureBelowEL3());
end;

// EffectiveEA()
// =============
// Returns effective SCR_EL3.EA value

func EffectiveEA() => bit
begin
    if !HaveEL(EL3) || Halted() then
        return '0';
    else
        return if HaveAArch64() then SCR_EL3().EA else SCR().EA;
    end;
end;

// EffectiveHCR_EL2_E2H()
// ======================
// Return the Effective HCR_EL2.E2H value.

readonly func EffectiveHCR_EL2_E2H() => bit
begin
    if !IsFeatureImplemented(FEAT_VHE) then
        return '0';
    end;

    if !IsFeatureImplemented(FEAT_E2H0) then
        return '1';
    end;

    return HCR_EL2().E2H;
end;

// EffectiveHCR_EL2_NVx()
// ======================
// Return the Effective value of HCR_EL2().[NV2,NV1,NV].

func EffectiveHCR_EL2_NVx() => bits(3)
begin
    if !EL2Enabled() || !IsFeatureImplemented(FEAT_NV) then
        return '000';
    end;

    var nv1 : bit = HCR_EL2().NV1;
    if (!IsFeatureImplemented(FEAT_E2H0) &&
          ImpDefBool("HCR_EL2.NV1 is implemented as RAZ")) then
        nv1 = '0';
    end;

    if HCR_EL2().NV == '0' then
        if nv1 == '1' then
            case ConstrainUnpredictable(Unpredictable_NVNV1) of
                when Constraint_NVNV1_00 => return '000';
                when Constraint_NVNV1_01 => return '010';
                when Constraint_NVNV1_11 => return '011';
            end;
        else
            return '000';
        end;
    end;

    if !IsFeatureImplemented(FEAT_NV2) then
        return '0' :: nv1 :: '1';
    end;

    var nv2 : bit = HCR_EL2().NV2;
    if (nv2 == '0' && ImpDefBool(
          "Programming HCR_EL2.<NV,NV2> to '10' behaves as '11'")) then
        nv2 = '1';
    end;

    return nv2 :: nv1 :: '1';
end;

// EffectiveSCR_EL3_NS()
// =====================
// Return Effective SCR_EL3.NS value.

readonly func EffectiveSCR_EL3_NS() => bit
begin
    if !HaveSecureState() then
        return '1';
    elsif !HaveEL(EL3) then
        return '0';
    elsif ELUsingAArch32(EL3) then
        return SCR().NS;
    else
        return SCR_EL3().NS;
    end;
end;

// EffectiveSCR_EL3_NSE()
// ======================
// Return Effective SCR_EL3.NSE value.

readonly func EffectiveSCR_EL3_NSE() => bit
begin
    return if !IsFeatureImplemented(FEAT_RME) then '0' else SCR_EL3().NSE;
end;

// EffectiveSCR_EL3_RW()
// =====================
// Returns effective SCR_EL3.RW value

func EffectiveSCR_EL3_RW() => bit
begin
    if !HaveAArch64() then
        return '0';
    end;
    if !HaveAArch32EL(EL2) && !HaveAArch32EL(EL1) then
        return '1';
    end;
    if HaveAArch32EL(EL1) then
        if !HaveAArch32EL(EL2) && EffectiveSCR_EL3_NS() == '1' then
            return '1';
        end;
        if (IsFeatureImplemented(FEAT_SEL2) && SCR_EL3().EEL2 == '1' &&
              EffectiveSCR_EL3_NS() == '0') then
            return '1';
        end;
    end;
    return SCR_EL3().RW;
end;

// EffectiveTGE()
// ==============
// Returns effective TGE value

func EffectiveTGE() => bit
begin
    if EL2Enabled() then
        return if ELUsingAArch32(EL2) then HCR().TGE else HCR_EL2().TGE;
    else
        return '0';        // Effective value of TGE is zero
    end;
end;

noreturn impdef func EndOfInstruction()
begin
    throw EndOfInstructionException{-};
end;

// EndOfInstruction()
// ==================
// Terminate processing of the current instruction.

type EndOfInstructionException of exception{-};

// EnterLowPowerState()
// ====================
// PE enters a low-power state.

impdef func EnterLowPowerState()
begin
    return;
end;

// EventRegister
// =============
// Event Register for this PE.

var EventRegister : bits(1);

// ExceptionalOccurrenceTargetState
// ================================
// Enumeration to represent the target state of an Exceptional Occurrence.
// The Exceptional Occurrence can be either Exception or Debug State entry.

type ExceptionalOccurrenceTargetState of enumeration {
    AArch32_NonDebugState,
    AArch64_NonDebugState,
    DebugState
};

// ExecuteAsNOP()
// ==============

func ExecuteAsNOP()
begin
    EndOfInstruction();
end;

// FIQPending()
// ============
// Returns a tuple indicating if there is any pending physical FIQ
// and if the pending FIQ has superpriority.

impdef func FIQPending() => (boolean, boolean)
begin
    return (FALSE, FALSE);
end;

// GetAccumulatedFPExceptions()
// ============================
// Returns FP exceptions accumulated by the PE.

impdef func GetAccumulatedFPExceptions() => bits(8)
begin
    return ARBITRARY : bits(8);
end;

// GetLoadStoreType()
// ==================
// Returns the Load/Store Type. Used when a Translation fault,
// Access flag fault, or Permission fault generates a Data Abort.

impdef func GetLoadStoreType() => bits(2)
begin
    return ARBITRARY : bits(2);
end;

// GetPSRFromPSTATE()
// ==================
// Return a PSR value which represents the current PSTATE

func GetPSRFromPSTATE{N}(targetELState : ExceptionalOccurrenceTargetState) => bits(N)
begin
    if UsingAArch32() && targetELState == AArch32_NonDebugState then
        assert N == 32;
    else
        assert N == 64;
    end;

    var spsr : bits(N) = Zeros{};
    if IsFeatureImplemented(FEAT_UINJ) && targetELState == DebugState then
        spsr[36] = PSTATE.UINJ;
    end;
    spsr[31:28] = PSTATE.[N,Z,C,V];
    if IsFeatureImplemented(FEAT_PAN) then spsr[22] = PSTATE.PAN; end;
    spsr[20]     = PSTATE.IL;
    if PSTATE.nRW == '1' then                           // AArch32 state
        if IsFeatureImplemented(FEAT_SEBEP) && targetELState != AArch32_NonDebugState then
            spsr[33] = PSTATE.PPEND;
        end;
        spsr[27]     = PSTATE.Q;
        spsr[26:25]  = PSTATE.IT[1:0];
        if IsFeatureImplemented(FEAT_SSBS) then spsr[23] = PSTATE.SSBS; end;
        if IsFeatureImplemented(FEAT_DIT) then
            if targetELState == AArch32_NonDebugState then
                spsr[21] = PSTATE.DIT;
            else                                        // AArch64_NonDebugState or DebugState
                spsr[24] = PSTATE.DIT;
            end;
        end;
        if targetELState IN {AArch64_NonDebugState, DebugState} then
            spsr[21] = PSTATE.SS;
        end;
        spsr[19:16]  = PSTATE.GE;
        spsr[15:10]  = PSTATE.IT[7:2];
        spsr[9]      = PSTATE.E;
        spsr[8:6]    = PSTATE.[A,I,F];                  // No PSTATE.D in AArch32 state
        spsr[5]      = PSTATE.T;
        assert PSTATE.M[4] == PSTATE.nRW;               // bit [4] is the discriminator
        spsr[4:0]    = PSTATE.M;
    else                                                // AArch64 state
        if IsFeatureImplemented(FEAT_PAuth_LR) then spsr[35] = PSTATE.PACM; end;
        if IsFeatureImplemented(FEAT_GCS) then spsr[34] = PSTATE.EXLOCK; end;
        if IsFeatureImplemented(FEAT_SEBEP) then spsr[33] = PSTATE.PPEND; end;
        if (IsFeatureImplemented(FEAT_EBEP) || IsFeatureImplemented(FEAT_SPE_EXC) ||
              IsFeatureImplemented(FEAT_TRBE_EXC)) then
            spsr[32] = PSTATE.PM;
        end;
        if IsFeatureImplemented(FEAT_MTE) then spsr[25] = PSTATE.TCO; end;
        if IsFeatureImplemented(FEAT_DIT) then spsr[24] = PSTATE.DIT; end;
        if IsFeatureImplemented(FEAT_UAO) then spsr[23] = PSTATE.UAO; end;
        spsr[21]    = PSTATE.SS;
        if IsFeatureImplemented(FEAT_NMI) then spsr[13] = PSTATE.ALLINT; end;
        if IsFeatureImplemented(FEAT_SSBS) then spsr[12] = PSTATE.SSBS; end;
        if IsFeatureImplemented(FEAT_BTI) then spsr[11:10] = PSTATE.BTYPE; end;
        spsr[9:6]    = PSTATE.[D,A,I,F];
        spsr[4]      = PSTATE.nRW;
        spsr[3:2]    = PSTATE.EL;
        spsr[0]      = PSTATE.SP;
    end;
    return spsr;
end;

// HaveAArch32()
// =============
// Return TRUE if AArch32 state is supported at at least EL0.

readonly func HaveAArch32() => boolean
begin
    return IsFeatureImplemented(FEAT_AA32EL0);
end;

// HaveAArch32EL()
// ===============
// Return TRUE if Exception level 'el' supports AArch32 in this implementation

readonly func HaveAArch32EL(el : bits(2)) => boolean
begin
    case el of
        when EL0 => return IsFeatureImplemented(FEAT_AA32EL0);
        when EL1 => return IsFeatureImplemented(FEAT_AA32EL1);
        when EL2 => return IsFeatureImplemented(FEAT_AA32EL2);
        when EL3 => return IsFeatureImplemented(FEAT_AA32EL3);
    end;
end;

// HaveAArch64()
// =============
// Return TRUE if the highest Exception level is using AArch64 state.

readonly func HaveAArch64() => boolean
begin
    return (IsFeatureImplemented(FEAT_AA64EL0)
            || IsFeatureImplemented(FEAT_AA64EL1)
            || IsFeatureImplemented(FEAT_AA64EL2)
            || IsFeatureImplemented(FEAT_AA64EL3)
            );
end;

// HaveEL()
// ========
// Return TRUE if Exception level 'el' is supported

readonly func HaveEL(el : bits(2)) => boolean
begin
    case el of
        when EL1,EL0 =>
            return TRUE;                         // EL1 and EL0 must exist
        when EL2 =>
            return IsFeatureImplemented(FEAT_AA64EL2) || IsFeatureImplemented(FEAT_AA32EL2);
        when EL3 =>
            return IsFeatureImplemented(FEAT_AA64EL3) || IsFeatureImplemented(FEAT_AA32EL3);
        otherwise =>
            unreachable;
    end;
end;

// HaveELUsingSecurityState()
// ==========================
// Returns TRUE if Exception level 'el' with Security state 'secure' is supported,
// FALSE otherwise.

readonly func HaveELUsingSecurityState(el : bits(2), secure : boolean) => boolean
begin

    case el of
        when EL3 =>
            assert secure;
            return HaveEL(EL3);
        when EL2 =>
            if secure then
                return HaveEL(EL2) && IsFeatureImplemented(FEAT_SEL2);
            else
                return HaveEL(EL2);
            end;
        otherwise =>
            return (HaveEL(EL3) ||
                    (secure == ImpDefBool("Secure-only implementation")));
    end;
end;

// HaveSecureState()
// =================
// Return TRUE if Secure State is supported.

readonly func HaveSecureState() => boolean
begin
    if !HaveEL(EL3) then
        return SecureOnlyImplementation();
    end;
    if IsFeatureImplemented(FEAT_RME) && !IsFeatureImplemented(FEAT_SEL2) then
        return FALSE;
    end;
    return TRUE;
end;

// HighestEL()
// ===========
// Returns the highest implemented Exception level.

readonly func HighestEL() => bits(2)
begin
    if HaveEL(EL3) then
        return EL3;
    elsif HaveEL(EL2) then
        return EL2;
    else
        return EL1;
    end;
end;

