// =========
// AArch32 PSTATE.M mode bits.

constant M32_User : bits(5)    = '10000';

constant M32_FIQ : bits(5)     = '10001';

constant M32_IRQ : bits(5)     = '10010';

constant M32_Svc : bits(5)     = '10011';

constant M32_Monitor : bits(5) = '10110';

constant M32_Abort : bits(5)   = '10111';

constant M32_Hyp : bits(5)     = '11010';

constant M32_Undef : bits(5)   = '11011';

constant M32_System : bits(5)  = '11111';

