// PLOfEL()
// ========

func PLOfEL(el : bits(2)) => PrivilegeLevel
begin
    case el of
        when EL3 =>  return if !HaveAArch64() then PL1 else PL3;
        when EL2 =>  return PL2;
        when EL1 =>  return PL1;
        when EL0 =>  return PL0;
    end;
end;

// PSTATE // ====== // PE state bits. // There is no significance to the field order.
var PSTATE : collection { N : bits (1), // Negative condition flag Z : bits (1), // Zero condition flag C : bits (1), // Carry condition flag V : bits (1), // Overflow condition flag D : bits (1), // Debug mask bit [AArch64 only] A : bits (1), // SError interrupt mask bit I : bits (1), // IRQ mask bit F : bits (1), // FIQ mask bit EXLOCK : bits (1), // Lock exception return state PAN : bits (1), // Privileged Access Never Bit [v8.1] UAO : bits (1), // User Access Override [v8.2] DIT : bits (1), // Data Independent Timing [v8.4] TCO : bits (1), // Tag Check Override [v8.5, AArch64 only] PM : bits (1), // PMU exception Mask PPEND : bits (1), // synchronous PMU exception to be observed BTYPE : bits (2), // Branch Type [v8.5] PACM : bits (1), // PAC instruction modifier ZA : bits (1), // Accumulation array enabled [SME] SM : bits (1), // Streaming SVE mode enabled [SME] ALLINT : bits (1), // Interrupt mask bit UINJ : bits (1), // Undefined Exception Injection SS : bits (1), // Software step bit IL : bits (1), // Illegal Execution state bit EL : bits (2), // Exception level nRW : bits (1), // Execution state: 0=AArch64, 1=AArch32 SP : bits (1), // Stack pointer select: 0=SP0, 1=SPx [AArch64 only] Q : bits (1), // Cumulative saturation flag [AArch32 only] GE : bits (4), // Greater than or Equal flags [AArch32 only] SSBS : bits (1), // Speculative Store Bypass Safe IT : bits (8), // If-then bits, RES0 in CPSR [AArch32 only] J : bits (1), // J bit, RES0 [AArch32 only, RES0 in SPSR and CPSR] T : bits (1), // T32 bit, RES0 in CPSR [AArch32 only] E : bits (1), // Endianness bit [AArch32 only] M : bits (5); // Mode field [AArch32 only]
};

// PhysicalCountInt()
// ==================
// Returns the integral part of physical count value of the System counter.

func PhysicalCountInt() => bits(64)
begin
    return PhysicalCount[87:24];
end;

// PrivilegeLevel
// ==============
// Privilege Level abstraction.

type PrivilegeLevel of enumeration {PL3, PL2, PL1, PL0};

// RestoredITBits()
// ================
// Get the value of PSTATE.IT to be restored on this exception return.

func RestoredITBits{N}(spsr : bits(N)) => bits(8)
begin
    let it : bits(8) = spsr[15:10,26:25];

    // When PSTATE.IL is set, it is CONSTRAINED UNPREDICTABLE whether the IT bits are each set
    // to zero or copied from the SPSR.
    if PSTATE.IL == '1' then
        if ConstrainUnpredictableBool(Unpredictable_ILZEROIT) then return '00000000';
        else return it;
        end;
    end;

    // The IT bits are forced to zero when they are set to a reserved value.
    if !IsZero(it[7:4]) && IsZero(it[3:0]) then
        return '00000000';
    end;

    // The IT bits are forced to zero when returning to A32 state, or when returning to an EL
    // with the ITD bit set to 1, and the IT bits are describing a multi-instruction block.
    let itd : bit = if PSTATE.EL == EL2 then HSCTLR().ITD else SCTLR().ITD;
    if (spsr[5] == '0' && !IsZero(it)) || (itd == '1' && !IsZero(it[2:0])) then
        return '00000000';
    else
        return it;
    end;
end;

// SecureOnlyImplementation()
// ==========================
// Returns TRUE if the security state is always Secure for this implementation.

readonly func SecureOnlyImplementation() => boolean
begin
    return ImpDefBool("Secure-only implementation");
end;

// SecurityState
// =============
// The Security state of an execution context

type SecurityState of enumeration {
    SS_NonSecure,
    SS_Root,
    SS_Realm,
    SS_Secure
};

// SecurityStateAtEL()
// ===================
// Returns the effective security state at the exception level based off current settings.

readonly func SecurityStateAtEL(EL : bits(2)) => SecurityState
begin
    if IsFeatureImplemented(FEAT_RME) then
        if EL == EL3 then return SS_Root; end;
        let effective_nse_ns : bits(2) = EffectiveSCR_EL3_NSE() :: EffectiveSCR_EL3_NS();
        case effective_nse_ns of
            when '00' =>
                if IsFeatureImplemented(FEAT_SEL2) then
                    return SS_Secure;
                else
                    unreachable;
                end;
            when '01' =>
                return SS_NonSecure;
            when '11' =>
                return SS_Realm;
            otherwise =>
                unreachable;
        end;
    end;

    if !HaveEL(EL3) then
        if SecureOnlyImplementation() then
            return SS_Secure;
        else
            return SS_NonSecure;
        end;
    elsif EL == EL3 then
        return SS_Secure;
    else
        // For EL2 call only when EL2 is enabled in current security state
        assert(EL != EL2 || EL2Enabled());
        if !ELUsingAArch32(EL3) then
            return if EffectiveSCR_EL3_NS() == '1' then SS_NonSecure else SS_Secure;
        else
            return if SCR().NS == '1' then SS_NonSecure else SS_Secure;
        end;
    end;
end;

