                           // Reserved PMECR_EL1.SSE value
                           Unpredictable_RESPMSSE,
                           // Enable for PMU Profiling exception and PMUIRQ
                           Unpredictable_RESPMEE,
                           // Enables for SPE Profiling exceptions and PMSIRQ
                           Unpredictable_RESPMSEE,
                           // Enables for TRBE Profiling exceptions and PMSIRQ
                           Unpredictable_RESTRFEE,
                           // Operands for CPY*/SET* instructions overlap
                           Unpredictable_MOPSOVERLAP,
                           // Operands for CPY*/SET* instructions use 0b11111
                           // as a register specifier
                           Unpredictable_MOPS_R31,
                           // Chooses which value to return in a non failed Atomic Compare and Swap
                           Unpredictable_CASRETURNOLDVALUE,
                           // Enables write of the newvalue in a failed Atomic Compare and Swap
                           Unpredictable_WRITEFAILEDCAS,
                           // Store-only Tag checking on a failed Atomic Compare and Swap
                           Unpredictable_STRONLYTAGCHECKEDCAS,
                           // Store-only Tag checking on a failed RCW(S) checks
                           // or RCW(S) Atomic Compare and Swap
                           Unpredictable_STRONLYTAGCHECKEDRCWSCAS,
                           // Reserved MDCR_EL3.ETBAD value
                           Unpredictable_RES_ETBAD,
                           // Invalid Streaming Mode filter bits
                           Unpredictable_RES_PMU_VS,
                           // Apply Checked Pointer Arithmetic on a sequential access to bytes
                           // that cross the 0xXXFF_FFFF_FFFF_FFFF boundary.
                           Unpredictable_CPACHECK,
                           // Reserved PMEVTYPER_EL0(n).[TC,TE,TC2] values
                           Unpredictable_RESTC,
                           // When FEAT_MTE is implemented, if Memory access mode is enabled
                           // and PSTATE.TCO is 0,  Reads and writes to the external debug
                           // interface DTR registers are CONSTRAINED UNPREDICTABLE for tagcheck
                           Unpredictable_NODTRTAGCHK,
                           // Use the default PMG when the default PARTID is generated
                           // due to MPAM error
                           Unpredictable_USE_DEFAULT_PMG,
                           // If the atomic instructions are not atomic in regard to other
                           // agents that access memory, then the instruction can have one or
                           // more of the following effects
                           Unpredictable_Atomic_SYNC_ABORT,
                           Unpredictable_Atomic_SERROR,
                           Unpredictable_Atomic_NOP,
                           Unpredictable_Atomic_MMU_IMPDEF_FAULT,
                           // Truncate virtual identifier to bottom 12 bits if it exceeds 2^12
                           Unpredictable_MPAM_TRUNCATE_VID,
                           // Accessing DBGDSCRint via MRC in debug state
                           Unpredictable_MRC_APSR_TARGET,
                           // Accessing Banked register not accessible from the PE mode
                           Unpredictable_BankedRegister,
                           // Accessing unimplemented Banked register
                           Unpredictable_UnimplementedRegister,
};

// AdvSIMDExpandImm()
// ==================

func AdvSIMDExpandImm(op : bit, cmode : bits(4), imm8 : bits(8)) => bits(64)
begin
    var imm64 : bits(64);
    case cmode[3:1] of
        when '000' =>
            imm64 = Replicate{64}(Zeros{24}::imm8);
        when '001' =>
            imm64 = Replicate{64}(Zeros{16}::imm8::Zeros{8});
        when '010' =>
            imm64 = Replicate{64}(Zeros{8}::imm8::Zeros{16});
        when '011' =>
            imm64 = Replicate{64}(imm8::Zeros{24});
        when '100' =>
            imm64 = Replicate{64}(Zeros{8}::imm8);
        when '101' =>
            imm64 = Replicate{64}(imm8::Zeros{8});
        when '110' =>
            if cmode[0] == '0' then
                imm64 = Replicate{64}(Zeros{16}::imm8::Ones{8});
            else
                imm64 = Replicate{64}(Zeros{8}::imm8::Ones{16});
            end;
        when '111' =>
            if cmode[0] == '0' && op == '0' then
                imm64 = Replicate{64}(imm8);
            end;
            if cmode[0] == '0' && op == '1' then
                let imm8a : bits(8) = Replicate{}(imm8[7]);
                let imm8b : bits(8) = Replicate{}(imm8[6]);
                let imm8c : bits(8) = Replicate{}(imm8[5]);
                let imm8d : bits(8) = Replicate{}(imm8[4]);
                let imm8e : bits(8) = Replicate{}(imm8[3]);
                let imm8f : bits(8) = Replicate{}(imm8[2]);
                let imm8g : bits(8) = Replicate{}(imm8[1]);
                let imm8h : bits(8) = Replicate{}(imm8[0]);
                imm64 = imm8a::imm8b::imm8c::imm8d::imm8e::imm8f::imm8g::imm8h;
            end;
            if cmode[0] == '1' && op == '0' then
                let imm32 : bits(32) = (imm8[7]::NOT(imm8[6])::Replicate{5}(imm8[6])::
                                            imm8[5:0]::Zeros{19});
                imm64 = Replicate{64}(imm32);
            end;
            if cmode[0] == '1' && op == '1' then
                if UsingAArch32() then ReservedEncoding(); end;
                imm64 = imm8[7]::NOT(imm8[6])::Replicate{8}(imm8[6])::imm8[5:0]::Zeros{48};
            end;
    end;

    return imm64;
end;

// MatMulAdd()
// ===========
//
// Signed or unsigned 8-bit integer matrix multiply and add to 32-bit integer matrix
// result[2, 2] = addend[2, 2] + (op1[2, 8] * op2[8, 2])

func MatMulAdd(addend : bits(128), op1 : bits(128), op2 : bits(128), op1_unsigned : boolean,
             op2_unsigned : boolean) => bits(128)
begin

    var result : bits(128);
    var sum : bits(32);
    var prod : integer;

    for i = 0 to 1 do
        for j = 0 to 1 do
            sum = addend[(2*i + j)*:32];
            for k = 0 to 7 do
                let opelt1 : bits(8) = op1[(8*i + k)*:8];
                let opelt2 : bits(8) = op2[(8*j + k)*:8];
                let element1 : integer = if op1_unsigned then UInt(opelt1) else SInt(opelt1);
                let element2 : integer = if op2_unsigned then UInt(opelt2) else SInt(opelt2);
                prod = element1 * element2;
                sum  = sum + prod;
            end;
            result[(2*i + j)*:32] = sum;
        end;
    end;

    return result;
end;

// PolynomialMult()
// ================

func PolynomialMult{M, N}(op1 : bits(M), op2 : bits(N)) => bits(M+N)
begin
    var result : bits(N + M) = Zeros{M+N};
    let extended_op2 : bits(N + M) = ZeroExtend{M+N}(op2);
    for i=0 to M-1 do
        if op1[i] == '1' then
            result = result XOR LSL(extended_op2, i);
        end;
    end;
    return result;
end;

// SatQ()
// ======

func SatQ{N}(i : integer, unsigned : boolean) => (bits(N), boolean)
begin
    let (result, sat) : (bits(N), boolean) = (if unsigned then UnsignedSatQ{N}(i)
                                                          else SignedSatQ{N}(i));
    return (result, sat);
end;

// ShiftSat()
// ==========

func ShiftSat(shift : integer, esize : integer) => integer
begin
    if shift > esize+1 then return esize+1;
    elsif shift < -(esize+1) then return -(esize+1); end;
    return shift;
end;

// SignedSat()
// ===========

func SignedSat{N}(i : integer) => bits(N)
begin
    let (result, -) = SignedSatQ{N}(i);
    return result;
end;

// SignedSatQ()
// ============

func SignedSatQ{N}(i : integer) => (bits(N), boolean)
begin
    var result : integer;
    var saturated : boolean;
    if i > 2^(N-1) - 1 then
        result = 2^(N-1) - 1;  saturated = TRUE;
    elsif i < -(2^(N-1)) then
        result = -(2^(N-1));  saturated = TRUE;
    else
        result = i;  saturated = FALSE;
    end;
    return (result[N-1:0], saturated);
end;

// UnsignedRSqrtEstimate()
// =======================

func UnsignedRSqrtEstimate{N}(operand : bits(N)) => bits(N)
begin
    assert N == 32;
    var result : bits(N);
    if operand[N-1:N-2] == '00' then  // Operands <= 0x3FFFFFFF produce 0xFFFFFFFF
        result = Ones{N};
    else
        // input is in the range 0x40000000 .. 0xffffffff representing [0.25 .. 1.0)
        // estimate is in the range 256 .. 511 representing [1.0 .. 2.0)
        let increasedprecision : boolean = FALSE;
        let estimate : integer = RecipSqrtEstimate(UInt(operand[31:23]), increasedprecision);
        // result is in the range 0x80000000 .. 0xff800000 representing [1.0 .. 2.0)
        result = estimate[8:0] :: Zeros{N-9};
    end;

    return result;
end;

// UnsignedRecipEstimate()
// =======================

func UnsignedRecipEstimate{N}(operand : bits(N)) => bits(N)
begin
    assert N == 32;
    var result : bits(N);
    if operand[N-1] == '0' then  // Operands <= 0x7FFFFFFF produce 0xFFFFFFFF
        result = Ones{N};
    else
        // input is in the range 0x80000000 .. 0xffffffff representing [0.5 .. 1.0)

        // estimate is in the range 256 to 511 representing [1.0 .. 2.0)
        let increasedprecision : boolean = FALSE;
        let estimate : integer = RecipEstimate(UInt(operand[31:23]), increasedprecision);

        // result is in the range 0x80000000 .. 0xff800000 representing [1.0 .. 2.0)
        result = estimate[8:0] :: Zeros{N-9};
    end;

    return result;
end;

// UnsignedSat()
// =============

func UnsignedSat{N}(i : integer) => bits(N)
begin
    let (result, -) = UnsignedSatQ{N}(i);
    return result;
end;

// UnsignedSatQ()
// ==============

func UnsignedSatQ{N}(i : integer) => (bits(N), boolean)
begin
    var result : integer;
    var saturated : boolean;
    if i > 2^N - 1 then
        result = 2^N - 1;  saturated = TRUE;
    elsif i < 0 then
        result = 0;  saturated = TRUE;
    else
        result = i;  saturated = FALSE;
    end;
    return (result[N-1:0], saturated);
end;

// DebugMemWrite()
// ===============
// Write data to memory one byte at a time. Starting at the passed virtual address.
// Used by SPE and TRBE.

func DebugMemWrite(vaddress : bits(64), accdesc : AccessDescriptor,
                   aligned : boolean, data : bits(8)) => (PhysMemRetStatus, AddressDescriptor)
begin

    var memstatus : PhysMemRetStatus = ARBITRARY : PhysMemRetStatus;

    // Translate virtual address
    var addrdesc : AddressDescriptor;
    let size : integer = 1;
    addrdesc = AArch64_TranslateAddress(vaddress, accdesc, aligned, size);

    if IsFault(addrdesc) then
        return (memstatus, addrdesc);
    end;

    memstatus = PhysMemWrite{8}(addrdesc, accdesc, data);

    return (memstatus, addrdesc);
end;

// DebugWriteExternalAbort()
// =========================
// Populate the syndrome register for an External abort caused by a call of DebugMemWrite().

func DebugWriteExternalAbort(memstatus : PhysMemRetStatus, addrdesc : AddressDescriptor,
                             start_vaddr : bits(64))
begin

    let iswrite : boolean = TRUE;

    var handle_as_SError : boolean = FALSE;
    case addrdesc.fault.accessdesc.acctype of
        when AccessType_SPE =>
            handle_as_SError = ImpDefBool("Report SPE ExtAbort as SError");
        when AccessType_TRBE =>
            handle_as_SError = ImpDefBool("Report TRBE ExtAbort as SError");
        otherwise =>
            unreachable;
    end;

    let ttw_abort : boolean = addrdesc.fault.statuscode IN {Fault_SyncExternalOnWalk,
                                                               Fault_SyncParityOnWalk};
    let statuscode : Fault = (if ttw_abort then addrdesc.fault.statuscode
                                 else memstatus.statuscode);

    if statuscode IN {Fault_AsyncExternal, Fault_AsyncParity} || handle_as_SError then
        // Report the abort as an SError
        var fault : FaultRecord = NoFault();
        let parity : boolean = statuscode IN {Fault_SyncParity, Fault_AsyncParity,
                                                 Fault_SyncParityOnWalk};
        fault.statuscode = if parity then Fault_AsyncParity else Fault_AsyncExternal;
        if IsFeatureImplemented(FEAT_RAS) then
            fault.merrorstate = memstatus.merrorstate;
        end;
        let extflag : bit = if ttw_abort then addrdesc.fault.extflag else memstatus.extflag;
        fault.extflag = extflag;
        fault.accessdesc.acctype = addrdesc.fault.accessdesc.acctype;
        PendSErrorInterrupt(fault);
        return;
    end;

    // Generate a buffer management event, modifying the existing syndrome.
    var handle_async : boolean = FALSE;
    var syndrome : bits(64);
    case addrdesc.fault.accessdesc.acctype of
        when AccessType_SPE =>
            handle_async = ImpDefBool("Report SPE ExtAbort asynchronously");
            assert !IsFeatureImplemented(FEAT_SPE_EXC);
            syndrome = PMBSR_EL1();
        when AccessType_TRBE =>
            handle_async = ImpDefBool("Report TRBE ExtAbort asynchronously");
            assert !IsFeatureImplemented(FEAT_TRBE_EXC);
            syndrome = TRBSR_EL1();
        otherwise =>
            unreachable;
    end;

    var ec : bits(6);
    if (IsFeatureImplemented(FEAT_RME) && addrdesc.fault.gpcf.gpf != GPCF_None &&
          addrdesc.fault.gpcf.gpf != GPCF_Fail) then
        ec = '011110';
    else
        ec = if addrdesc.fault.secondstage then '100101' else '100100';
    end;

    let mss2 : bits(24) = Zeros{};
    var mss : bits(16) = Zeros{};
    if handle_async then                // FSC bits
        mss[5:0] = '010001';
    else
        mss[5:0] = EncodeLDFSC(statuscode, addrdesc.fault.level);
    end;

    // The following values are always updated in the syndrome register.
    if (addrdesc.fault.accessdesc.acctype == AccessType_SPE &&
          (handle_async || start_vaddr != addrdesc.vaddress)) then
        syndrome[19] = '1';             // DL bit (SPE only)
    end;

    syndrome[18] = '1';                 // EA bit

    // The following values are not modified if a previous buffer management event
    // has not been handled. Note that in this simple sequential model, this test
    // will never fail.
    if syndrome[17] == '0' then         // Check previous 'S' bit.
        syndrome[55:32] = mss2;         // MSS2 bits
        syndrome[31:26] = ec;           // EC bits
        if addrdesc.fault.accessdesc.acctype == AccessType_TRBE then
            syndrome[22] = '1';         // IRQ bit (TRBE only)
        end;
        syndrome[17] = '1';             // S bit
        syndrome[15:0] = mss;           // MSS bits
    end;

    case addrdesc.fault.accessdesc.acctype of
        when AccessType_SPE =>
            PMBSR_EL1() = syndrome;
        when AccessType_TRBE =>
            TRBSR_EL1() = syndrome;
        otherwise =>
            unreachable;
    end;
end;

// DebugWriteFault()
// =================
// Populate the syndrome register for a fault caused by a call of DebugMemWrite().

func DebugWriteFault(vaddress : bits(64), fault : FaultRecord)
begin
    var ec : bits(6);
    if (IsFeatureImplemented(FEAT_RME) && fault.gpcf.gpf != GPCF_None &&
          fault.gpcf.gpf != GPCF_Fail) then
        ec = '011110';
    else
        ec = if fault.secondstage then '100101' else '100100';
    end;

    var mss2 : bits(24) = Zeros{};
    if fault.statuscode == Fault_Permission then
        mss2[8] = if fault.toplevel then '1' else '0';      // TopLevel bit
        mss2[7] = if fault.assuredonly then '1' else '0';   // AssuredOnly bit
        mss2[6] = if fault.overlay then '1' else '0';       // Overlay bit
        mss2[5] = if fault.dirtybit then '1' else '0';      // DirtyBit
    end;

    var mss : bits(16) = Zeros{};
    if !(IsFeatureImplemented(FEAT_RME) && fault.gpcf.gpf != GPCF_None &&
           fault.gpcf.gpf != GPCF_Fail) then
        mss[5:0] = EncodeLDFSC(fault.statuscode, fault.level);  // FSC bits
    end;

    // Generate a buffer management event, modifying the existing syndrome.
    var target_el : bits(2);
    var syndrome : bits(64);
    case fault.accessdesc.acctype of
        when AccessType_SPE =>
            target_el = ReportSPEEvent(ec, mss[5:0]);
            syndrome = PMBSR_EL(target_el);
        when AccessType_TRBE =>
            target_el = ReportTRBEEvent(ec, mss[5:0]);
            syndrome = TRBSR_EL(target_el);
        otherwise =>
            unreachable;
    end;

    // The following values are not modified if a previous buffer management event
    // has not been handled. Note that in this simple sequential model, this test
    // will never fail.
    if syndrome[17] == '0' then         // Check previous 'S' bit.
        syndrome[55:32] = mss2;         // MSS2 bits
        syndrome[31:26] = ec;           // EC bits
        if fault.accessdesc.acctype == AccessType_TRBE then
            syndrome[22] = '1';         // IRQ bit (TRBE only)
        end;
        syndrome[17] = '1';             // S bit
        syndrome[15:0] = mss;           // MSS bits
    end;

    // For SPE, PMBPTR_EL1 points to the address that generated the fault, and writing
    // to memory never started. Therefore, there isno data loss and DL is unchanged.

    case fault.accessdesc.acctype of
        when AccessType_SPE =>
            PMBSR_EL(target_el) = syndrome;

        when AccessType_TRBE =>
            TRBSR_EL(target_el) = syndrome;

        otherwise =>
            unreachable;
    end;

    return;
end;

// GetTimestamp()
// ==============
// Returns the Timestamp depending on the type

func GetTimestamp(timeStampType : TimeStamp) => bits(64)
begin
    case timeStampType of
        when TimeStamp_Physical =>
            return PhysicalCountInt();
        when TimeStamp_Virtual =>
            return PhysicalCountInt() - CNTVOFF_EL2();
        when TimeStamp_OffsetPhysical =>
            let physoff : bits(64) = if PhysicalOffsetIsValid() then CNTPOFF_EL2() else Zeros{64};
            return PhysicalCountInt() - physoff;
        when TimeStamp_None =>
            return Zeros{64};
        when TimeStamp_CoreSight =>
            return ImpDefBits{64}("CoreSight timestamp");
        otherwise =>
            unreachable;
    end;
end;

// PhysicalOffsetIsValid()
// =======================
// Returns whether the Physical offset for the timestamp is valid

func PhysicalOffsetIsValid() => boolean
begin
    if !HaveAArch64() then
        return FALSE;
    elsif !HaveEL(EL2) || !IsFeatureImplemented(FEAT_ECV_POFF) then
        return FALSE;
    elsif HaveEL(EL3) && EffectiveSCR_EL3_NS() == '1' && EffectiveSCR_EL3_RW() == '0' then
        return FALSE;
    elsif HaveEL(EL3) && SCR_EL3().ECVEn == '0' then
        return FALSE;
    elsif CNTHCTL_EL2().ECV == '0' then
        return FALSE;
    else
        return TRUE;
    end;
end;

// TRBCRManStopWrite()
// ===================
// Called on a write of 1 to TRBCR.ManStop.

func TRBCRManStopWrite()
begin
    TraceUnitFlush();
    OtherTRBEManagementEvent('000011');
    TryAssertTRBIRQ();
end;

// BranchNotTaken()
// ================
// Called when a branch is not taken.

func BranchNotTaken(branchtype : BranchType, branch_conditional : boolean)
begin
    let branchtaken : boolean = FALSE;
    if IsFeatureImplemented(FEAT_SPE) then
        SPEBranch{64}(ARBITRARY : bits(64), branchtype, branch_conditional, branchtaken);
    end;
    return;
end;

// AllowExternalTraceBufferAccess()
// ================================
// Returns TRUE if an external debug interface access to the Trace Buffer
// registers is allowed for the given Security state, FALSE otherwise.
// The access may also be subject to OS Lock, power-down, etc.

func AllowExternalTraceBufferAccess(addrdesc : AddressDescriptor) => boolean
begin
    assert IsFeatureImplemented(FEAT_TRBE_EXT);
    // FEAT_Debugv8p4 is always implemented when FEAT_TRBE_EXT is implemented.
    assert IsFeatureImplemented(FEAT_Debugv8p4);

    var etbad : bits(2) = if HaveEL(EL3) then MDCR_EL3().ETBAD else '11';

    // Check for reserved values
    if !IsFeatureImplemented(FEAT_RME) && etbad IN {'01','10'} then
        (-, etbad) = ConstrainUnpredictableBits{2}(Unpredictable_RES_ETBAD);
        // The value returned by ConstrainUnpredictableBits must be a
        // non-reserved value
        assert etbad IN {'00', '11'};
    end;

    case etbad of
        when '00' =>
            if IsFeatureImplemented(FEAT_RME) then
                return addrdesc.paddress.paspace == PAS_Root;
            else
                return addrdesc.paddress.paspace == PAS_Secure;
            end;
        when '01' =>
            assert IsFeatureImplemented(FEAT_RME);
            return addrdesc.paddress.paspace IN {PAS_Root, PAS_Realm};
        when '10' =>
            assert IsFeatureImplemented(FEAT_RME);
            return addrdesc.paddress.paspace IN {PAS_Root, PAS_Secure};
        when '11' =>
            return TRUE;
    end;
end;

// CheckForTRBEException()
// =======================
// Take a TRBE Profiling exception if pending, permitted, and unmasked.

func CheckForTRBEException()
begin
    if !IsFeatureImplemented(FEAT_TRBE_EXC) || !SelfHostedTraceEnabled() then
        return;
    end;

    if Halted() || Restarting() then
        return;
    end;

    var route_to_el3 : boolean = FALSE;
    var route_to_el2 : boolean = FALSE;
    var route_to_el1 : boolean = FALSE;

    if HaveEL(EL3) && MDCR_EL3().TRBEE == '1x' then
        let pending : boolean = TRBSR_EL3().IRQ == '1';
        let masked  : boolean = PSTATE.EL       == EL3;
        route_to_el3 = pending && !masked;
    end;

    var owning_ss : SecurityState;
    var owning_el : bits(2);
    (owning_ss, owning_el) = TraceBufferOwner();
    let in_owning_ss : boolean = IsCurrentSecurityState(owning_ss);

    if EffectiveTRFCR_EL2_EE() IN {'1x'} then
        let pending : boolean = TRBSR_EL2().IRQ == '1';
        let masked : boolean = (!in_owning_ss || PSTATE.EL == EL3 ||
                                   (PSTATE.EL == EL2 && (TRFCR_EL2().EE != '11' ||
                                                         TRFCR_EL2().KE == '0' ||
                                                         PSTATE.PM == '1')));
        route_to_el2 = pending && !masked;
    end;

    if EffectiveTRFCR_EL1_EE() == '11' then
        let pending : boolean = TRBSR_EL1().IRQ == '1';
        let masked  : boolean = (!in_owning_ss || PSTATE.EL IN {EL3, EL2} ||
                                   (PSTATE.EL == EL1 && (TRFCR_EL1().KE == '0' ||
                                                         PSTATE.PM == '1')));
        if EffectiveTGE() == '1' then
            route_to_el2 = route_to_el2 || (pending && !masked);
        else
            route_to_el1 = pending && !masked;
        end;
    end;

    let fsc : bits(5) = '00010';        // TRBE exception
    let synchronous : boolean = FALSE;

    // The relative priorities of the following checks is IMPLEMENTATION DEFINED
    if route_to_el3 then
        TakeProfilingException(EL3, fsc, synchronous);
    end;
    if route_to_el2 then
        TakeProfilingException(EL2, fsc, synchronous);
    end;
    if route_to_el1 then
        TakeProfilingException(EL1, fsc, synchronous);
    end;
end;

// CheckMDCR_EL3_NSTBTrap()
// ========================
// Check if the register access is trappable by MDCR_EL3.[NSTBE, NSTB]

func CheckMDCR_EL3_NSTBTrap() => boolean
begin
    var state_bits : bits(3);
    var reserved   : boolean;
    (state_bits, reserved) = EffectiveMDCR_EL3_NSTB();
    return ((reserved && ConstrainUnpredictableBool(Unpredictable_RESERVEDNSxB_Trap)) ||
             state_bits[0] == '0' || state_bits[1] != SCR_EL3().NS ||
             (IsFeatureImplemented(FEAT_RME) && state_bits[2] != SCR_EL3().NSE));
end;

// CollectTrace()
// ==============
// Called for each byte generated by the trace unit.
// Returns TRUE if the Trace Buffer Unit accepts or discards the trace
// data, and FALSE if the Trace Buffer Unit rejects the trace data.

func CollectTrace(datum : bits(8)) => boolean recurselimit ElementStreamSize
begin
    if !TraceBufferEnabled() then  // Trace buffer disabled
        // 'datum' is discarded
        if HaveImpDefTraceOutput() then
            return ImpDefTraceOutput(datum);
        else
            return TRUE;           // Discard the trace byte
        end;
    end;

    // If the TRBE cannot accept the trace data, it must return FALSE
    if TRBEInternalBufferFull() then
        return FALSE;
    end;

    if TraceBufferRunning() then   // Accept the data
        let address            : bits(64) = TRBPTR_EL1();
        var ttw_abort          : boolean = FALSE;
        let ttw_abort_as_fault : boolean = (ImpDefBool(
                                            "Report TRBE ExtAbort on TTW as fault"));
        var addrdesc : AddressDescriptor;
        var memstatus : PhysMemRetStatus;

        if !SelfHostedTraceEnabled() then
            // The Trace Buffer Unit is using External mode.
            if IsFeatureImplemented(FEAT_RME) && !ExternalRootInvasiveDebugEnabled() then
                if IsZero(GPCCR_EL3().[TBGPCD, GPC]) then
                    return FALSE;
                end;
            end;

            let pas : bits(2) = TRBMAR_EL1().PAS;
            let paspace : PASpace = DecodePASpace('0', pas[1], pas[0]);
            var valid_config : boolean = IsPASValid(pas) && InvasiveDebugPermittedPAS(paspace);
            if IsFeatureImplemented(FEAT_TRBE_MPAM) && TRBMPAM_EL1().EN == '1' then
                let mpam_sp : bits(2) = TRBMPAM_EL1().MPAM_SP;
                let mpam_pa : PASpace = DecodePASpace('0', mpam_sp[1], mpam_sp[0]);
                valid_config = (valid_config && IsPASValid(mpam_sp) &&
                                InvasiveDebugPermittedPAS(mpam_pa));
            end;

            if !valid_config then
                OtherTRBEManagementEvent('000000');
                TryAssertTRBIRQ();
                return TRUE;
            end;

            let el : bits(2) = ARBITRARY : bits(2);
            let ss : SecurityState = ARBITRARY : SecurityState;
            let accdesc : AccessDescriptor = CreateAccDescTRBE(ss, el);

            var pa : FullAddress;
            pa.address = address[55:0];
            pa.paspace = paspace;
            let memattrs : MemoryAttributes = S1DecodeMemAttrs(TRBMAR_EL1().Attr,
                                                                  TRBMAR_EL1().SH, TRUE);
            addrdesc = CreateAddressDescriptor(pa, memattrs, accdesc);
            addrdesc.mecid = DEFAULT_MECID;
            if IsFeatureImplemented(FEAT_RME) && !ExternalRootInvasiveDebugEnabled() then
                let gpcf : GPCFRecord = GranuleProtectionCheck(addrdesc, accdesc);
                if gpcf.gpf == GPCF_None then
                    memstatus = PhysMemWrite{8}(addrdesc, accdesc, datum);
                else
                    addrdesc.fault.gpcf       = gpcf;
                    addrdesc.fault.statuscode = Fault_GPCFOnOutput;
                end;
            else
                memstatus = PhysMemWrite{8}(addrdesc, accdesc, datum);
            end;
        else
            // The Trace Buffer Unit is using Self-hosted mode.
            var owning_ss : SecurityState;
            var owning_el : bits(2);
            (owning_ss, owning_el) = TraceBufferOwner();
            let accdesc : AccessDescriptor = CreateAccDescTRBE(owning_ss, owning_el);

            let aligned : boolean = TRUE;
            (memstatus, addrdesc) = DebugMemWrite(address, accdesc, aligned, datum);

            ttw_abort = addrdesc.fault.statuscode IN {Fault_SyncExternalOnWalk,
                                                      Fault_SyncParityOnWalk};
        end;

        if IsFault(addrdesc.fault.statuscode) && (!ttw_abort || ttw_abort_as_fault) then
            DebugWriteFault(address, addrdesc.fault);
            TryAssertTRBIRQ();
            return TRUE;
        elsif IsFault(memstatus) || (ttw_abort && !ttw_abort_as_fault) then
            DebugWriteExternalAbort(memstatus, addrdesc, address);
            TryAssertTRBIRQ();
            return TRUE;
        end;

        // Check for Trigger Event
        let target_el : bits(2) = DefaultTRBEEvent();
        let triggered : boolean = TRBSR_EL(target_el).TRG == '1';
        if triggered && !IsZero(TRBTRG_EL1().TRG) then
            TRBTRG_EL1().TRG = (TRBTRG_EL1().TRG - 1)[31:0];
            if IsZero(TRBTRG_EL1().TRG) && TRBLIMITR_EL1().TM != '11' then
                TraceUnitFlush();
                TraceUnitFlushOnTriggerComplete();
            end;
        end;

        // Increment the pointer
        var next_address : bits(64) = TRBPTR_EL1() + 1;
        if next_address[63:12] == TRBLIMITR_EL1().LIMIT then
            next_address = TRBBASER_EL1().BASE::Zeros{12};
            TRBSR_EL(target_el).WRAP = '1';
            CTI_SignalEvent(CrossTriggerIn_TRBEWrap);
            if TRBLIMITR_EL1().FM == '00' then     // Fill mode
                let bsc : bits(6) = '000001'; // Buffer full event
                OtherTRBEManagementEvent(bsc);
            elsif TRBLIMITR_EL1().FM != '11' then  // Not Circular Buffer mode
                if TRBSR_EL(target_el).IRQ == '0' then
                    TRBSR_EL(target_el).IRQ = '1';   // Assert interrupt or exception
                    CTI_SignalEvent(CrossTriggerIn_TRBEMgmt);
                end;
            end;
        end;
        TRBPTR_EL1() = next_address[63:0];

        TryAssertTRBIRQ();
    end;
    return TRUE;
end;

// DefaultTRBEEvent()
// ==================
// Return the target ELx for an indirect write to TRBSR_ELx for an Other buffer management
// event or anything other than a buffer management event.

func DefaultTRBEEvent() => bits(2)
begin
    return ReportTRBEEvent(Zeros{6}, ARBITRARY : bits(6));
end;

// DetectedTraceTrigger()
// ======================
// Called when the trace unit detects a trace trigger

func DetectedTraceTrigger()
begin
    if TraceBufferRunning() then
        let target_el : bits(2) = DefaultTRBEEvent();
        if TRBSR_EL(target_el).TRG == '0' then
            TRBSR_EL(target_el).TRG = '1';
            if IsZero(TRBTRG_EL1().TRG) && TRBLIMITR_EL1().TM != '11' then
                TraceUnitFlush();
                TraceUnitFlushOnTriggerComplete();
            end;
        end;
    end;
end;

// EffectiveMDCR_EL3_NSTB()
// ========================
// Return the Effective value of MDCR_EL3().[NSTBE, NSTB] field and whether it is a reserved value.

func EffectiveMDCR_EL3_NSTB() => (bits(3), boolean)
begin
    var state_bits : bits(3);
    var reserved   : boolean = FALSE;

    if IsFeatureImplemented(FEAT_RME) then
        state_bits = MDCR_EL3().[NSTBE, NSTB];
        if state_bits == '10x' || (!IsFeatureImplemented(FEAT_Secure) && state_bits == '00x') then
            // Reserved value
            reserved = TRUE;
            (-, state_bits) = ConstrainUnpredictableBits{3}(Unpredictable_RESERVEDNSxB);
        end;
    else
        state_bits = '0' :: MDCR_EL3().NSTB;
    end;

    return (state_bits, reserved);
end;

// EffectiveTRBLIMITR_EL1_nVM()
// ============================

func EffectiveTRBLIMITR_EL1_nVM() => bit
begin
    if !SelfHostedTraceEnabled() then
        // If SelfHostedTraceEnabled() is FALSE, then this function is only called when
        // FEAT_TRBE_EXT is implemented.
        assert IsFeatureImplemented(FEAT_TRBE_EXT);
        return '1';
    end;
    if IsFeatureImplemented(FEAT_TRBEv1p1) && HaveEL(EL2) then
        let (owning_ss, owning_el) = TraceBufferOwner();
        if ((owning_ss != SS_Secure || IsSecureEL2Enabled()) && owning_el == EL1 &&
              TRFCR_EL2().DnVM == '1') then
            return '0';
        end;
    end;
    return TRBLIMITR_EL1().nVM;
end;

// EffectiveTRFCR_EL1_EE()
// =======================
// Return the Effective value of TRFCR_EL1.EE for the purpose of controlling the
// TRBE Profiling exception.

func EffectiveTRFCR_EL1_EE() => bits(2)
begin
    if EffectiveTRFCR_EL2_EE() == '00' then
        return '00';
    end;

    var ee : bits(2) = TRFCR_EL1().EE;
    if ee IN {'01', '10'} then            // Reserved value
        if IsFeatureImplemented(FEAT_NV) then
            ee[0] = ee[1];
        else
            var c : Constraint;
            (c, ee) = ConstrainUnpredictableBits{2}(Unpredictable_RESTRFEE);
            assert c IN {Constraint_DISABLED, Constraint_UNKNOWN};
            if c == Constraint_DISABLED then
                ee = '00';
            end;
            // Otherwise the value returned by ConstrainUnpredictableBits must be
            // a non-reserved value
        end;
    end;

    return ee;
end;

// EffectiveTRFCR_EL2_EE()
// =======================
// Return the Effective value of TRFCR_EL2.EE.

func EffectiveTRFCR_EL2_EE() => bits(2)
begin
    if !IsFeatureImplemented(FEAT_TRBE_EXC) || !SelfHostedTraceEnabled() then
        return '00';
    end;

    if HaveEL(EL3) && MDCR_EL3().TRBEE == '00' then
        return '00';
    end;

    let check_el2 : boolean = HaveEL(EL2) && (EffectiveSCR_EL3_NS() == '1' ||
                                                 IsSecureEL2Enabled());
    return if check_el2 then TRFCR_EL2().EE else '01';
end;

